def _version_lt(installed: str, minimum: str) -> bool:
    """
    [v2.7.1 FIX] Compare two version strings numerically (tuple of int parts) so that
    e.g. '0.45.0' is correctly seen as < '0.450.0' and '2.10.0' > '2.9.0'. Used as the
    fallback when the 'packaging' library is unavailable; previously a plain string
    comparison was used, which is lexicographic and wrong (e.g. '0.9' > '0.45').
    Returns True if `installed` is older than `minimum`. Falls back to string
    comparison only if the versions cannot be parsed as dotted integers.
    """
    def _parse(v: str):
        parts = []
        for chunk in str(v).split('.'):
            num = ''
            for ch in chunk:
                if ch.isdigit():
                    num += ch
                else:
                    break
            parts.append(int(num) if num else 0)
        return tuple(parts)

    try:
        ti, tm = _parse(installed), _parse(minimum)
        # Pad to equal length so (2, 3) and (2, 3, 0) compare as equal.
        length = max(len(ti), len(tm))
        ti = ti + (0,) * (length - len(ti))
        tm = tm + (0,) * (length - len(tm))
        return ti < tm
    except Exception:
        return str(installed) < str(minimum)

def check_dependencies(auto_install: bool = False, verbose: bool = True) -> dict:
    """
    [v2.6.0] Vérifie que toutes les dépendances requises sont installées.
    
    Améliorations v2.6.0:
    - Vérification des versions minimales (Qiskit >= 2.3.0, Runtime >= 0.45.0)
    - Catégorisation des packages (core, viz, util, opt, addons)
    - Installation interactive avec options
    - Support IBM Addons (M3, AQC-Tensor, MPF, OBP, SQD, Cutting)
    
    Args:
        auto_install: Si True, propose d'installer les packages manquants
        verbose: Affiche les détails de la vérification
        
    Returns:
        Dict avec status de chaque package
    """
    results = {"installed": [], "missing": [], "outdated": [], "details": {}, "addons_status": {}}
    
    if verbose:
        print("\n" + "═" * 72)
        print(f"  📦 VÉRIFICATION DES DÉPENDANCES QMC FRAMEWORK v{__version__}")
        print("═" * 72)
    
    categories = {"core": [], "viz": [], "util": [], "opt": [], "addons": []}
    
    for pkg_name, pkg_info in REQUIRED_PACKAGES.items():
        # Décompactage selon le format (peut avoir 4, 5 ou 6 éléments)
        if len(pkg_info) == 6:
            import_name, pip_name, required, desc, min_ver, category = pkg_info
        elif len(pkg_info) == 4:
            import_name, pip_name, required, desc = pkg_info
            min_ver, category = None, "core"
        else:
            import_name, pip_name, required, desc, min_ver = pkg_info
            category = "core"
        
        status = {"required": required, "min_version": min_ver, "pip_name": pip_name}
        
        try:
            # Cas spécial: weasyprint nécessite GTK et affiche des messages sur stderr
            # On utilise find_spec pour vérifier l'installation sans importer
            if import_name == "weasyprint":
                import importlib.util
                spec = importlib.util.find_spec("weasyprint")
                if spec is None:
                    raise ImportError("weasyprint not found")
                # Si trouvé, on considère comme installé (on vérifiera GTK à l'usage)
                status["installed"] = True
                status["version"] = "installed"
                status["outdated"] = False
                results["installed"].append(pkg_name)
                results["details"][pkg_name] = status
                categories.get(category, categories["core"]).append((pkg_name, status, desc, required))
                continue
            
            # Supprimer les warnings ET stderr pour les autres packages problématiques
            import io
            with warnings.catch_warnings():
                warnings.filterwarnings('ignore')
                old_stderr = sys.stderr
                sys.stderr = io.StringIO()  # Capturer stderr
                try:
                    module = __import__(import_name)
                finally:
                    sys.stderr = old_stderr  # Restaurer stderr
            installed_ver = getattr(module, '__version__', 'unknown')
            status["installed"] = True
            status["version"] = installed_ver
            
            # Vérifier version minimale
            if min_ver and installed_ver != 'unknown':
                try:
                    from packaging import version
                    status["outdated"] = version.parse(installed_ver) < version.parse(min_ver)
                except ImportError:
                    # [v2.7.1 FIX] numeric (tuple-of-int) compare instead of lexicographic string compare
                    status["outdated"] = _version_lt(installed_ver, min_ver)
            else:
                status["outdated"] = False
            
            if status["outdated"]:
                results["outdated"].append((pkg_name, pip_name, min_ver))
            else:
                results["installed"].append(pkg_name)
                
        except ImportError:
            status["installed"] = False
            status["version"] = None
            status["outdated"] = False
            results["missing"].append((pip_name, desc, required))
        except (OSError, Exception):
            # WeasyPrint lance OSError si GTK manque - traiter comme non installé
            status["installed"] = False
            status["version"] = None
            status["outdated"] = False
            results["missing"].append((pip_name, desc, required))
        
        results["details"][pkg_name] = status
        categories.get(category, categories["core"]).append((pkg_name, status, desc, required))
    
    if verbose:
        # Affichage par catégorie
        cat_names = {
            "core": "🔴 CORE (Obligatoires)",
            "viz": "🟡 VISUALIZATION",
            "util": "🔵 UTILITIES",
            "opt": "⚪ OPTIONAL",
            "addons": "🟣 IBM ADDONS v2.6.0 (Optimisations avancées)"
        }
        
        for cat_key, cat_title in cat_names.items():
            if categories[cat_key]:
                print(f"\n  {cat_title}")
                print("  " + "─" * 60)
                for pkg_name, status, desc, required in categories[cat_key]:
                    if status["installed"]:
                        if status.get("outdated"):
                            icon = "⚠️"
                            ver = f"v{status['version']} (min: {status['min_version']})"
                        else:
                            icon = "✅"
                            ver = f"v{status['version']}" if status.get('version') else "OK"
                    else:
                        icon = "❌" if required else "⭕"
                        ver = "MANQUANT"
                    
                    # Pour les addons, afficher aussi la description courte
                    if cat_key == "addons":
                        short_desc = desc.split(':')[0] if ':' in desc else desc[:30]
                        print(f"  {icon} {pkg_name:<30} {ver:<15} ({short_desc})")
                    else:
                        print(f"  {icon} {pkg_name:<25} {ver}")
        
        # Section spéciale pour les IBM Addons manquants
        addons_missing = [pkg for pkg, status, desc, req in categories.get("addons", []) if not status["installed"]]
        if addons_missing:
            print(f"\n  💡 Pour installer tous les IBM Addons:")
            print(f"     {IBM_ADDONS_INSTALL_CMD}")
        
        print("\n" + "═" * 72)
    
    # Packages manquants critiques
    critical_missing = [p for p, d, r in results["missing"] if r]
    outdated_pkgs = results["outdated"]
    # [v2.7.1 FIX] Classify addons by their actual REQUIRED_PACKAGES category (not by
    # string-matching the pip name). 'mthree' is an IBM addon but its pip name has no
    # 'addon' substring, so it was wrongly bucketed as optional. Use the addons category.
    addon_pip_names = {status.get("pip_name") for _, status, _, _ in categories.get("addons", [])}
    addons_missing = [p for p, d, r in results["missing"] if p in addon_pip_names]
    optional_missing = [p for p, d, r in results["missing"] if not r and p not in addons_missing]
    
    # Stocker le statut des addons
    results["addons_status"] = {
        "installed": [pkg for pkg, status, _, _ in categories.get("addons", []) if status["installed"]],
        "missing": addons_missing
    }
    
    if critical_missing or outdated_pkgs:
        packages_to_install = critical_missing + [p for p, _, _ in outdated_pkgs]
        pip_cmd = f"pip install {' '.join(packages_to_install)}"
        
        if verbose:
            if critical_missing:
                print(f"  ❌ {len(critical_missing)} package(s) REQUIS manquant(s)")
            if outdated_pkgs:
                print(f"  ⚠️  {len(outdated_pkgs)} package(s) obsolète(s)")
            print(f"\n  📦 Commande d'installation:")
            print(f"  {pip_cmd}\n")
        
        if auto_install and sys.stdin.isatty():
            print("  Options:")
            print("    [1] Installer les packages REQUIS uniquement")
            print("    [2] Installer REQUIS + OPTIONNELS")
            print("    [3] Installer REQUIS + IBM ADDONS (recommandé pour v2.6.0)")
            print("    [4] Installer TOUT (requis + optionnels + IBM addons)")
            print("    [5] Afficher les commandes et quitter")
            print("    [6] Continuer sans installer")
            print()
            
            try:
                choice = input("  Votre choix [1/2/3/4/5/6]: ").strip()
                
                if choice in ("1", "2", "3", "4"):
                    if choice == "2":
                        packages_to_install.extend(optional_missing)
                    elif choice == "3":
                        packages_to_install.extend(addons_missing)
                    elif choice == "4":
                        packages_to_install.extend(optional_missing)
                        packages_to_install.extend(addons_missing)
                    
                    pip_cmd = f"pip install {' '.join(packages_to_install)}"
                    
                    print(f"\n  🔄 Installation en cours...")
                    print(f"  📦 {pip_cmd}\n")
                    try:
                        subprocess.check_call([sys.executable, "-m", "pip", "install"] + packages_to_install)
                        print(f"  ✅ Installation réussie!")
                        return check_dependencies(auto_install=False, verbose=False)
                    except subprocess.CalledProcessError as e:
                        print(f"  ❌ Erreur d'installation: {e}")
                        sys.exit(1)
                elif choice == "5":
                    all_missing = [p for p, d, r in results["missing"]]
                    print(f"\n  # Packages requis:")
                    print(f"  pip install {' '.join(critical_missing)}")
                    if optional_missing:
                        print(f"\n  # Packages optionnels:")
                        print(f"  pip install {' '.join(optional_missing)}")
                    if addons_missing:
                        print(f"\n  # IBM Addons v2.6.0:")
                        print(f"  {IBM_ADDONS_INSTALL_CMD}")
                    print()
                    
            except (EOFError, KeyboardInterrupt):
                pass
    
    elif verbose:
        print(f"  ✅ Toutes les dépendances requises sont satisfaites!")
    
    if verbose:
        print("═" * 60 + "\n")
    
    return results


def ensure_dependencies():
    """
    [v2.6.0] Vérifie les dépendances critiques au chargement du module.
    
    Propose l'installation interactive avec validation utilisateur si des
    packages manquent ou sont obsolètes.
    
    Variables d'environnement:
        QMC_SKIP_DEP_CHECK=true    - Désactive la vérification
        QMC_AUTO_INSTALL_DEPS=true - Installation automatique sans demander
        QMC_SILENT_DEP_CHECK=true  - Mode silencieux (pas de banner)
    
    Améliorations v2.6.0:
    - Support du nouveau format avec versions minimales
    - Options d'installation interactives améliorées
    - Affichage clair par catégorie
    - Support IBM Addons (M3, AQC-Tensor, MPF, OBP, SQD, Cutting)
    - Mode silencieux pour scripts automatisés
    """
    # Skip si demandé
    skip_check = os.environ.get("QMC_SKIP_DEP_CHECK", "").lower() in ("true", "1", "yes")
    if skip_check:
        return
    
    silent_mode = os.environ.get("QMC_SILENT_DEP_CHECK", "").lower() in ("true", "1", "yes")
    
    critical_missing = []
    optional_missing = []
    addons_missing = []
    outdated_packages = []
    
    # Check tous les packages
    for pkg_name, pkg_info in REQUIRED_PACKAGES.items():
        # Extraire les infos selon le format
        if len(pkg_info) >= 6:
            import_name, pip_name, required, desc, min_ver, category = pkg_info
        elif len(pkg_info) == 5:
            import_name, pip_name, required, desc, min_ver = pkg_info
            category = "core"
        else:
            import_name, pip_name, required, desc = pkg_info
            min_ver, category = None, "core"
        
        try:
            # Cas spécial: weasyprint nécessite GTK et affiche des messages sur stderr
            # On utilise find_spec pour vérifier l'installation sans importer
            if import_name == "weasyprint":
                import importlib.util
                spec = importlib.util.find_spec("weasyprint")
                if spec is None:
                    raise ImportError("weasyprint not found")
                # Si trouvé, on considère comme installé (GTK sera vérifié à l'usage)
                continue
            
            # Supprimer les warnings ET stderr pour les autres packages problématiques
            import io
            with warnings.catch_warnings():
                warnings.filterwarnings('ignore')
                old_stderr = sys.stderr
                sys.stderr = io.StringIO()  # Capturer stderr
                try:
                    module = __import__(import_name)
                finally:
                    sys.stderr = old_stderr  # Restaurer stderr
            # Vérifier version minimale
            if min_ver:
                installed_ver = getattr(module, '__version__', 'unknown')
                if installed_ver != 'unknown':
                    try:
                        from packaging import version
                        if version.parse(installed_ver) < version.parse(min_ver):
                            outdated_packages.append((pkg_name, pip_name, installed_ver, min_ver, required))
                    except ImportError:
                        # [v2.7.1 FIX] numeric (tuple-of-int) compare instead of lexicographic string compare
                        if _version_lt(installed_ver, min_ver):
                            outdated_packages.append((pkg_name, pip_name, installed_ver, min_ver, required))
        except ImportError:
            # Package non installé
            pip_display = pip_name.split('>=')[0].split('>')[0]
            if category == "addons":
                addons_missing.append((pip_display, desc, pip_name))
            elif required:
                critical_missing.append((pip_display, desc, pip_name))
            else:
                optional_missing.append((pip_display, desc, pip_name))
        except (OSError, Exception) as e:
            # WeasyPrint et autres packages peuvent lancer OSError si les libs système manquent
            # On les considère comme non installés fonctionnellement
            pip_display = pip_name.split('>=')[0].split('>')[0]
            if category == "addons":
                addons_missing.append((pip_display, desc, pip_name))
            elif required:
                critical_missing.append((pip_display, desc, pip_name))
            else:
                optional_missing.append((pip_display, desc, pip_name))
    
    # Rien de critique à signaler - mais on continue si des addons manquent
    show_addons_info = bool(addons_missing)
    
    if not critical_missing and not outdated_packages and not show_addons_info:
        return
    
    # Afficher le banner d'avertissement
    if not silent_mode:
        print()
        print("╔" + "═" * 72 + "╗")
        print("║  ⚠️  QMC FRAMEWORK v2.6.0 - VÉRIFICATION DES DÉPENDANCES" + " " * 16 + "║")
        print("╠" + "═" * 72 + "╣")
        
        if critical_missing:
            print("║                                                                        ║")
            print("║  🔴 PACKAGES REQUIS MANQUANTS:                                         ║")
            for pip_name, desc, _ in critical_missing[:5]:
                line = f"     • {pip_name}: {desc}"
                print(f"║  {line:<70}║")
            if len(critical_missing) > 5:
                print(f"║     ... et {len(critical_missing)-5} autre(s){' ' * 53}║")
        
        if outdated_packages:
            print("║                                                                        ║")
            print("║  🟡 PACKAGES OBSOLÈTES:                                                ║")
            for pkg, pip, cur, req, _ in outdated_packages[:3]:
                line = f"     • {pkg}: v{cur} → v{req} requis"
                print(f"║  {line:<70}║")
        
        if optional_missing:
            print("║                                                                        ║")
            print("║  🔵 PACKAGES OPTIONNELS (recommandés):                                 ║")
            opt_names = [p[0] for p in optional_missing[:4]]
            line = f"     {', '.join(opt_names)}"
            print(f"║  {line:<70}║")
        
        if addons_missing:
            print("║                                                                        ║")
            print("║  🟣 IBM ADDONS v2.6.0 (optimisations avancées):                        ║")
            addon_names = [p[0].replace('qiskit-addon-', '') for p in addons_missing[:4]]
            line = f"     {', '.join(addon_names)}"
            print(f"║  {line:<70}║")
            if len(addons_missing) > 4:
                print(f"║     ... et {len(addons_missing)-4} autre(s){' ' * 53}║")
        
        # Message si tout est OK sauf les addons
        if not critical_missing and not outdated_packages and addons_missing:
            print("║                                                                        ║")
            print("║  ✅ Packages critiques: OK                                              ║")
            print("║     💡 Installez les IBM Addons pour bénéficier de v2.6.0:            ║")
            print("║        M3 (mitigation), AQC-Tensor, MPF (Trotter), etc.               ║")
        
        print("║" + " " * 72 + "║")
        print("╚" + "═" * 72 + "╝")
    
    # Construire les listes de packages à installer
    critical_packages = [pip_full for _, _, pip_full in critical_missing]
    for pkg, pip_name, _, min_ver, req in outdated_packages:
        if req:
            base_name = pip_name.split('>=')[0].split('>')[0]
            critical_packages.append(f"{base_name}>={min_ver}")
    
    optional_packages = [pip_full for _, _, pip_full in optional_missing]
    addons_packages = [pip_full for _, _, pip_full in addons_missing]
    
    # S'il n'y a rien à proposer, sortir
    if not critical_packages and not optional_packages and not addons_packages:
        return
    
    # Si seuls les addons manquent (pas de critiques), proposer quand même l'installation
    only_addons_missing = not critical_packages and not optional_packages and addons_packages
    
    # Mode automatique si demandé via env
    auto_install = os.environ.get("QMC_AUTO_INSTALL_DEPS", "").lower() in ("true", "1", "yes")
    
    def _run_pip_install(packages: List[str], quiet: bool = False) -> bool:
        """
        Exécute pip install avec affichage en temps réel de la progression.
        
        IMPORTANT: Les packages comme mthree compilent du code C/Cython
        et peuvent prendre plusieurs minutes!
        """
        import subprocess
        
        # Nettoyer les noms de packages (enlever les espaces)
        packages = [p.strip() for p in packages if p.strip()]
        if not packages:
            return True
        
        # Construire la commande de base
        pip_cmd = [sys.executable, "-m", "pip", "install"]
        
        # [v2.7.1] --break-system-packages n'est PLUS ajouté automatiquement : il
        # peut corrompre le Python système (PEP 668). On le réserve à un opt-in
        # explicite (QMC_PIP_BREAK_SYSTEM_PACKAGES=1) ; sinon on recommande un venv.
        try:
            check_result = subprocess.run(
                [sys.executable, "-m", "pip", "install", "--dry-run", "pip"],
                capture_output=True,
                text=True,
                timeout=10
            )
            if "externally-managed-environment" in check_result.stderr:
                if os.environ.get("QMC_PIP_BREAK_SYSTEM_PACKAGES", "").lower() in ("true", "1", "yes"):
                    pip_cmd.append("--break-system-packages")
                    print("  ⚠️  Environnement géré + opt-in -> --break-system-packages (risqué)")
                else:
                    print("  ⚠️  Environnement Python géré (PEP 668) détecté.")
                    print("     Recommandé : créez un venv (python -m venv .venv) puis réessayez,")
                    print("     ou forcez avec QMC_PIP_BREAK_SYSTEM_PACKAGES=1 (peut casser le système).")
        except Exception:
            pass
        
        pip_cmd.extend(packages)
        
        # Afficher la commande et l'avertissement
        print(f"\n  🔄 Installation en cours...")
        print(f"  ⏳ Certains packages (mthree) compilent du code C - peut prendre 2-5 min!")
        print(f"  📋 Commande: pip install {' '.join(packages)}")
        print()
        print("  " + "─" * 60)
        
        try:
            # IMPORTANT: Ne PAS capturer la sortie pour voir la progression!
            # On laisse pip afficher directement dans le terminal
            result = subprocess.run(
                pip_cmd,
                timeout=900  # 15 minutes max pour compilation
                # PAS de capture_output=True → affichage en temps réel
            )
            
            print("  " + "─" * 60)
            
            if result.returncode == 0:
                print("\n  ✅ Installation terminée avec succès!")
                return True
            else:
                print(f"\n  ❌ Erreur pip (code {result.returncode})")
                print("  💡 Essayez manuellement dans un terminal:")
                print(f"     pip install {' '.join(packages)}")
                return False
                    
        except subprocess.TimeoutExpired:
            print("\n  ⏰ Timeout après 15 minutes")
            print("     L'installation prend trop de temps.")
            print("     Essayez manuellement dans un terminal.")
            return False
            
        except FileNotFoundError:
            print("\n  ❌ pip non trouvé!")
            print(f"     {sys.executable} -m ensurepip --upgrade")
            return False
            
        except KeyboardInterrupt:
            print("\n  ⚠️  Installation interrompue par l'utilisateur")
            return False
            
        except Exception as e:
            print(f"\n  ❌ Erreur: {type(e).__name__}: {e}")
            print(f"  📋 Essayez manuellement:")
            print(f"     pip install {' '.join(packages)}")
            return False
    
    if auto_install and critical_packages:
        if not silent_mode:
            print("\n📦 Installation automatique (QMC_AUTO_INSTALL_DEPS=true)...")
        if _run_pip_install(critical_packages, quiet=True):
            if not silent_mode:
                print("✅ Installation réussie!\n")
        else:
            if not silent_mode:
                print("❌ Échec - installez manuellement.\n")
        return
    
    # Mode interactif - proposer l'installation
    if sys.stdin.isatty() and not silent_mode:
        print()
        print("  ┌─────────────────────────────────────────────────────────────┐")
        print("  │  OPTIONS D'INSTALLATION                                     │")
        print("  ├─────────────────────────────────────────────────────────────┤")
        
        # Cas spécial: seuls les IBM Addons manquent
        if only_addons_missing:
            print("  │  ✅ Packages critiques: Tous installés!                      │")
            print("  │                                                             │")
            print(f"  │  [1] Installer IBM ADDONS v2.6.0 ({len(addons_packages)} packages)          │")
            print("  │      M3, AQC-Tensor, MPF, OBP, SQD, Cutting                 │")
            print("  │  [2] Afficher la commande pip                               │")
            print("  │  [3] Continuer sans installer                               │")
            print("  └─────────────────────────────────────────────────────────────┘")
            print()
            
            try:
                response = input("  Votre choix [1-3]: ").strip()
                
                if response == "1":
                    print("\n  📦 Installation des IBM Addons v2.6.0...")
                    print(f"     {IBM_ADDONS_INSTALL_CMD}\n")
                    confirm = input("  Confirmer l'installation? [O/n]: ").strip().lower()
                    if confirm in ("", "o", "oui", "y", "yes"):
                        if _run_pip_install(addons_packages):
                            print("\n  ✅ Installation réussie!")
                            print("     IBM Addons disponibles: M3, AQC-Tensor, MPF, OBP, SQD, Cutting")
                            print("     Relancez votre script.\n")
                            sys.exit(0)
                
                elif response == "2":
                    print(f"\n  📋 Commande d'installation IBM Addons:")
                    print(f"  {IBM_ADDONS_INSTALL_CMD}\n")
                    input("  Appuyez sur Entrée pour continuer...")
                
                # Choix 3 = continuer
                
            except (EOFError, KeyboardInterrupt):
                print("\n")
            return
        
        # Cas normal: packages critiques manquants
        if critical_packages:
            print("  │  [1] Installer les packages REQUIS uniquement              │")
            pkg_names = ', '.join([p.split('>=')[0] for p in critical_packages[:3]])
            print(f"  │      ({len(critical_packages)} pkg: {pkg_names}...)          │")
        
        if optional_packages:
            total = len(critical_packages) + len(optional_packages)
            print(f"  │  [2] Installer REQUIS + OPTIONNELS ({total} packages)         │")
        
        if addons_packages:
            print(f"  │  [3] Installer REQUIS + IBM ADDONS ({len(critical_packages)+len(addons_packages)} packages)      │")
            print("  │      (recommandé pour profiter de v2.6.0)                  │")
        
        all_count = len(critical_packages) + len(optional_packages) + len(addons_packages)
        if all_count > len(critical_packages):
            print(f"  │  [4] Installer TOUT ({all_count} packages)                       │")
        
        print("  │  [5] Afficher les commandes pip                            │")
        print("  │  [6] Continuer sans installer                              │")
        print("  │  [7] Quitter                                               │")
        print("  └─────────────────────────────────────────────────────────────┘")
        print()
        
        try:
            response = input("  Votre choix [1-7]: ").strip()
            
            if response == "1" and critical_packages:
                print("\n  📦 Installation des packages requis...")
                print(f"     pip install {' '.join(critical_packages)}\n")
                confirm = input("  Confirmer l'installation? [O/n]: ").strip().lower()
                if confirm in ("", "o", "oui", "y", "yes"):
                    if _run_pip_install(critical_packages):
                        print("\n  ✅ Installation réussie!")
                        print("     Relancez votre script pour utiliser le framework.\n")
                        sys.exit(0)
            
            elif response == "2":
                all_packages = critical_packages + optional_packages
                print("\n  📦 Installation des packages requis + optionnels...")
                print(f"     pip install {' '.join(all_packages)}\n")
                confirm = input("  Confirmer l'installation? [O/n]: ").strip().lower()
                if confirm in ("", "o", "oui", "y", "yes"):
                    if _run_pip_install(all_packages):
                        print("\n  ✅ Installation réussie!")
                        print("     Relancez votre script pour utiliser le framework.\n")
                        sys.exit(0)
            
            elif response == "3" and addons_packages:
                all_packages = critical_packages + addons_packages
                print("\n  📦 Installation des packages requis + IBM Addons v2.6.0...")
                print(f"     pip install {' '.join(all_packages)}\n")
                confirm = input("  Confirmer l'installation? [O/n]: ").strip().lower()
                if confirm in ("", "o", "oui", "y", "yes"):
                    if _run_pip_install(all_packages):
                        print("\n  ✅ Installation réussie!")
                        print("     IBM Addons disponibles: M3, AQC-Tensor, MPF, OBP, SQD, Cutting")
                        print("     Relancez votre script pour utiliser le framework.\n")
                        sys.exit(0)
            
            elif response == "4":
                all_packages = critical_packages + optional_packages + addons_packages
                print("\n  📦 Installation de TOUS les packages...")
                print(f"     pip install {' '.join(all_packages)}\n")
                confirm = input("  Confirmer l'installation? [O/n]: ").strip().lower()
                if confirm in ("", "o", "oui", "y", "yes"):
                    if _run_pip_install(all_packages):
                        print("\n  ✅ Installation réussie!")
                        print("     Relancez votre script pour utiliser le framework.\n")
                        sys.exit(0)
            
            elif response == "5":
                print("\n  📋 Commandes d'installation:\n")
                if critical_packages:
                    print(f"  # Packages requis:")
                    print(f"  pip install {' '.join(critical_packages)}\n")
                if optional_packages:
                    print(f"  # Packages optionnels:")
                    print(f"  pip install {' '.join(optional_packages)}\n")
                if addons_packages:
                    print(f"  # IBM Addons v2.6.0 (optimisations avancées):")
                    print(f"  {IBM_ADDONS_INSTALL_CMD}\n")
                input("  Appuyez sur Entrée pour continuer...")
            
            elif response == "7":
                print("\n  Fermeture du framework.")
                sys.exit(1)
            
            # Choix 6 ou autre = continuer
            
        except (EOFError, KeyboardInterrupt):
            print("\n")  # Nouvelle ligne propre


