# =============================================================================
# CONFIGURATION ENVIRONNEMENT - RAPPORT & ARCHIVE (v2.5.18)
# =============================================================================
# 
# ⚠️ PROTECTION DES RÉSULTATS QPU ET DU BUDGET:
# Les paramètres suivants sont contrôlés par .env pour éviter les erreurs:
#
#   QMC_GENERATE_REPORT=false   # Désactive rapport HTML (déconseillé)
#   QMC_GENERATE_ARCHIVE=false  # Désactive archive JSON (déconseillé)
#   QMC_AUTO_CONFIRM=true       # Désactive confirmation QPU (DANGEREUX!)
#
