def _get_env_bool(name: str, default: bool = True) -> bool:
    """
    Lit une variable d'environnement booléenne.
    
    Args:
        name: Nom de la variable (ex: QMC_GENERATE_REPORT)
        default: Valeur par défaut si non définie
        
    Returns:
        True si 'true', '1', 'yes', 'on' (insensible à la casse)
        False si 'false', '0', 'no', 'off'
        default sinon
    """
    value = os.environ.get(name, '').lower().strip()
    if value in ('true', '1', 'yes', 'on'):
        return True
    elif value in ('false', '0', 'no', 'off'):
        return False
    return default


def _load_qmc_env_config():
    """
    Charge la configuration QMC depuis .env et variables d'environnement.
    
    Variables supportées:
        QMC_GENERATE_REPORT: true/false (défaut: true)
        QMC_GENERATE_ARCHIVE: true/false (défaut: true)
        QMC_AUTO_CONFIRM: true/false (défaut: false = confirmation obligatoire)
        QMC_LAZY_REGISTER: 0/1 (défaut: 0)
    """
    # Charger .env si présent
    env_file = Path('.env')
    if env_file.exists():
        try:
            with open(env_file, encoding='utf-8') as f:  # [v2.7.1 FIX] explicit encoding (avoid platform cp1252 mojibake on .env)
                for line in f:
                    line = line.strip()
                    if line and not line.startswith('#') and '=' in line:
                        key, value = line.split('=', 1)
                        key = key.strip()
                        value = value.strip().strip('"\'')
                        if key.startswith('QMC_'):
                            os.environ.setdefault(key, value)
        except Exception:
            pass  # Silently ignore .env errors


# Charger la config au démarrage du module
_load_qmc_env_config()

