    def plot_timeline(self, circuit, backend=None,
                      figsize: Tuple[int, int] = (14, 6),
                      filename: str = None,
                      style: str = "iqx",
                      show_idle: bool = True,
                      **kwargs) -> Optional[Any]:
        """
        [v2.6.0] Wrapper pour timeline_drawer - visualisation temporelle du circuit.
        
        Affiche le scheduling des portes sur une ligne de temps, montrant
        quand chaque porte s'exécute sur chaque qubit.
        
        Args:
            circuit: Circuit transpilé avec scheduling_method
            backend: Backend pour les durées d'instruction
            figsize: Taille de la figure
            filename: Fichier de sortie
            style: Style ("iqx", "simple", "debugging")
            show_idle: Afficher les temps d'inactivité
            
        Returns:
            Figure matplotlib ou None
        """
        try:
            from qiskit.visualization import timeline_drawer
            
            # Sélectionner le style
            style_kwargs = {}
            if style == "simple":
                try:
                    from qiskit.visualization.timeline import IQXSimple
                    style_kwargs['style'] = IQXSimple()
                except ImportError:
                    pass
            elif style == "debugging":
                try:
                    from qiskit.visualization.timeline import IQXDebugging
                    style_kwargs['style'] = IQXDebugging()
                except ImportError:
                    pass
            
            # Target pour les durées
            target = None
            if backend:
                target = getattr(backend, 'target', None)
            
            fig = timeline_drawer(
                circuit,
                target=target,
                idle_wires=show_idle,
                plot_barriers=True,
                show_delays=True,
                **style_kwargs,
                **kwargs
            )
            
            if fig and filename:
                filepath = self.output_dir / filename
                fig.savefig(filepath, dpi=self.dpi, facecolor='white',
                           bbox_inches='tight')
            
            return fig
            
        except ImportError as e:
            print(f"[WARN] timeline_drawer non disponible: {e}")
            return None
        except Exception as e:
            print(f"[ERROR] plot_timeline: {e}")
            return None
    
    def plot_circuit_image(self, circuit,
                           figsize: Tuple[int, int] = None,
                           filename: str = None,
                           output_format: str = "mpl",
                           style: str = "iqp",
                           fold: int = None,
                           scale: float = None,
                           with_layout: bool = True,
                           **kwargs) -> Optional[Any]:
        """
        [v2.6.0] Export haute qualité d'un circuit en image.
        
        Wrapper pour circuit.draw() avec options avancées.
        
        Args:
            circuit: Circuit à visualiser
            figsize: Taille personnalisée
            filename: Fichier de sortie (PNG, SVG, PDF)
            output_format: "mpl", "text", "latex"
            style: Style Qiskit ("iqp", "textbook", "bw")
            fold: Nombre de couches avant pliage
            scale: Échelle de l'image
            with_layout: Afficher le layout physique
            
        Returns:
            Figure ou texte selon output_format
        """
