class QMCSecurityError(QMCException):
    """
    [v2.5.14] Erreur de sécurité cryptographique.
    
    Levée quand une opération violerait les contraintes de sécurité
    en mode production (tentative d'accès aux logs, circuits, etc.)
    """
    def __init__(self, message: str, operation: str = None, **kwargs):
        super().__init__(
            message=message,
            code="QMC-SEC",
            details={'operation': operation, 'security_violation': True},
            recoverable=False,
            suggestion="Désactivez production_mode ou modifiez les paramètres de sécurité"
        )


# Alias pour compatibilité
SecurityError = QMCSecurityError


# =============================================================================
# RETRY DECORATOR WITH EXPONENTIAL BACKOFF
# =============================================================================

@dataclass
class RetryConfig:
    """Configuration du retry."""
    max_attempts: int = 3
    initial_delay_s: float = 1.0
    max_delay_s: float = 60.0
    exponential_base: float = 2.0
    jitter: bool = True
    retry_on: Tuple[type, ...] = (QMCConnectionError, QMCTimeoutError, QMCExecutionError)


def with_retry(config: RetryConfig = None, logger = None):
    """
    Décorateur pour retry automatique avec backoff exponentiel.
    
    Usage:
        @with_retry(RetryConfig(max_attempts=3))
        def connect_to_backend():
            ...
    
    Args:
        config: Configuration du retry
        logger: Logger optionnel pour les messages
    """
    if config is None:
        config = RetryConfig()
    
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            last_exception = None
            
            for attempt in range(1, config.max_attempts + 1):
                try:
                    return func(*args, **kwargs)
                    
                except config.retry_on as e:
                    last_exception = e
                    
                    # Check if recoverable
                    if isinstance(e, QMCException) and not e.recoverable:
                        raise
                    
                    if attempt == config.max_attempts:
                        break
                    
                    # Calculate delay with exponential backoff
                    delay = min(
                        config.initial_delay_s * (config.exponential_base ** (attempt - 1)),
                        config.max_delay_s
                    )
                    
                    # Add jitter to prevent thundering herd
                    if config.jitter:
                        delay *= (0.5 + random.random())
                    
                    # Log retry attempt
                    if logger:
                        logger.warn(
                            f"[RETRY] Attempt {attempt}/{config.max_attempts} failed: {e}. "
                            f"Retrying in {delay:.1f}s..."
                        )
                    
                    time.sleep(delay)
                    
                except Exception as e:
                    # Non-retryable exception
                    raise
            
            # All attempts failed
            if last_exception:
                if logger:
                    logger.error(f"[RETRY] All {config.max_attempts} attempts failed")
                raise last_exception
        
        return wrapper
    return decorator


# =============================================================================
# ERROR HANDLER - CENTRALIZED ERROR TRACKING
# =============================================================================

class QMCErrorHandler:
    """
    Gestionnaire centralisé des erreurs QMC.
    
    Fonctionnalités:
    - Tracking de toutes les erreurs
    - Statistiques d'erreurs
    - Export pour diagnostic
    - Suggestions automatiques
    """
    
    def __init__(self, logger = None, max_history: int = 100):
        self.logger = logger
        self.max_history = max_history
        self._errors: List[Dict] = []
        self._stats: Dict[str, int] = {}
    
    def handle(self, exception: Exception, context: str = None, 
               raise_exception: bool = True) -> Optional[Dict]:
        """
        Gère une exception de manière centralisée.
        
        Args:
            exception: L'exception à gérer
            context: Contexte additionnel (ex: "run_on_qpu")
            raise_exception: Si True, relève l'exception après logging
            
        Returns:
            Dict avec les détails de l'erreur si raise_exception=False
        """
        # Convertir en QMCException si nécessaire
        if isinstance(exception, QMCException):
            error_info = exception.to_dict()
        else:
            error_info = {
                'code': 'QMC-999',
                'message': str(exception),
                'type': type(exception).__name__,
                'recoverable': False,
                'timestamp': datetime.now().isoformat()
            }
        
        # Ajouter le contexte
        error_info['context'] = context
        
        # Tracker l'erreur
        self._errors.append(error_info)
        if len(self._errors) > self.max_history:
            self._errors.pop(0)
        
        # Mettre à jour les stats
        error_code = error_info.get('code', 'UNKNOWN')
        self._stats[error_code] = self._stats.get(error_code, 0) + 1
        
        # Logger l'erreur
        if self.logger:
            self._log_error(error_info)
        
        if raise_exception:
            raise exception
        
        return error_info
    
    def _log_error(self, error_info: Dict):
        """Log formaté de l'erreur."""
        code = error_info.get('code', 'UNKNOWN')
        message = error_info.get('message', 'Unknown error')
        context = error_info.get('context', '')
        suggestion = error_info.get('suggestion', '')
        
        # Couleurs ANSI
        R = "\033[31m"
        Y = "\033[33m"
        DIM = "\033[2m"
        X = "\033[0m"
        
        self.logger.error(f"{R}╔══ QMC ERROR ══════════════════════════════════════════════════════╗{X}")
        self.logger.error(f"{R}║{X} Code: {code:<62}{R}║{X}")
        self.logger.error(f"{R}║{X} {message:<68}{R}║{X}")
        if context:
            self.logger.error(f"{R}║{X} Context: {context:<59}{R}║{X}")
        if suggestion:
            self.logger.error(f"{R}║{X} {Y}→ {suggestion}{X:<57}{R}║{X}")
        self.logger.error(f"{R}╚═══════════════════════════════════════════════════════════════════╝{X}")
    
    def get_stats(self) -> Dict[str, int]:
        """Retourne les statistiques d'erreurs."""
        return dict(self._stats)
    
    def get_recent_errors(self, n: int = 10) -> List[Dict]:
        """Retourne les N dernières erreurs."""
        return self._errors[-n:]
    
    def get_summary(self) -> Dict:
        """Retourne un résumé des erreurs."""
        return {
            'total_errors': len(self._errors),
            'error_types': dict(self._stats),
            'most_common': max(self._stats.items(), key=lambda x: x[1]) if self._stats else None,
            'last_error': self._errors[-1] if self._errors else None
        }
    
    def export_errors(self, filepath: str):
        """Exporte les erreurs en JSON."""
        with open(filepath, 'w', encoding='utf-8') as f:  # [v2.7.1 FIX] encodage explicite
            json.dump({
                'errors': self._errors,
                'stats': self._stats,
                'exported_at': datetime.now().isoformat()
            }, f, indent=2)
    
    def clear(self):
        """Efface l'historique des erreurs."""
        self._errors.clear()
        self._stats.clear()


# =============================================================================
# SAFE EXECUTION CONTEXT MANAGER
# =============================================================================

@contextlib.contextmanager
def safe_qmc_execution(error_handler: QMCErrorHandler = None, 
                       context: str = None,
                       default_return = None,
                       suppress: bool = False):
    """
    Context manager pour exécution sécurisée.
    
    Usage:
        with safe_qmc_execution(handler, context="transpilation") as ctx:
            result = transpile_circuit(...)
            ctx.result = result
    
    Args:
        error_handler: Handler pour les erreurs
        context: Contexte de l'opération
        default_return: Valeur par défaut si erreur
        suppress: Si True, supprime l'exception et retourne default_return
    """
    class ExecutionContext:
        def __init__(self):
            self.result = default_return
            self.error = None
            self.success = True
    
    ctx = ExecutionContext()
    
    try:
        yield ctx
    except Exception as e:
        ctx.error = e
        ctx.success = False
        
        if error_handler:
            error_handler.handle(e, context=context, raise_exception=not suppress)
        elif not suppress:
            raise


