    def _create_estimator_v2(self, resilience_level: int = 1, 
                              options: Dict = None) -> 'EstimatorV2':
        """
        [v2.7.0 INTERNE] Crée un EstimatorV2 configuré. 
        Usage INTERNE uniquement — appelé par run_estimator().
        """
        from qiskit_ibm_runtime import EstimatorV2
        
        if not self._connected:
            raise QMCExecutionError("Non connecté au backend")
        
        estimator = EstimatorV2(mode=self.backend)
        estimator.options.resilience_level = resilience_level
        estimator.options.dynamical_decoupling.enable = True
        estimator.options.dynamical_decoupling.sequence_type = "XY4"
        
        if resilience_level >= 1:
            estimator.options.twirling.enable_gates = True
            estimator.options.resilience.measure_mitigation = True
        
        if resilience_level >= 2:
            estimator.options.resilience.zne_mitigation = True
            estimator.options.resilience.zne.noise_factors = [1, 3, 5]
            estimator.options.resilience.zne.extrapolator = ["exponential", "linear"]
        
        if options:
            estimator.options.update(**options)
        
        return estimator
    
    def run_estimator(self, pubs, shots: int = None, 
                      resilience_level: int = 1,
                      options: Dict = None,
                      upload_to_archive: bool = True,
                      archive_projects: List[str] = None,
                      archive_notes: str = None) -> Optional[List[Dict]]:
        """
        [v2.7.0] Exécute des PUBs via EstimatorV2 avec le pipeline COMPLET du framework.
        
        MÊME PIPELINE que run_on_qpu():
        - Estimation coût + confirmation obligatoire
        - Checkpoint pour reprise après crash
        - Monitoring robuste (reconnexion auto, timeout/appel)
        - Récupération sécurisée avec timeout
        - Rescue save IMMÉDIAT (résultats bruts sur disque)
        - Archive QMC complète (34 sections)
        - Upload QMC Archive (si configuré)
        
        Args:
            pubs: Liste de PUBs [(circuit, observable), ...] ou [(circuit, observable, params), ...]
            shots: Nombre de shots (défaut: self.default_shots)
            resilience_level: Niveau de résilience (0=brut, 1=TREX+DD, 2=+ZNE+twirl)
            options: Options EstimatorV2 personnalisées
            upload_to_archive: Upload vers QMC Archive (défaut: True)
            archive_projects: UUIDs projets QMC Archive (défaut: .env)
            archive_notes: Notes pour l'archive
            
        Returns:
            Liste de dicts avec {circuit_index, expectation_value, std_error, metadata}
            ou None si échec/annulé
            
        Example:
            >>> from qiskit.quantum_info import SparsePauliOp
            >>> obs = SparsePauliOp.from_list([("ZZ", 1.0)])
            >>> isa_circuit = fw.transpile_circuits([circuit])[0]
            >>> isa_obs = obs.apply_layout(isa_circuit.layout, num_qubits=isa_circuit.num_qubits)
            >>> results = fw.run_estimator(
            ...     pubs=[(isa_circuit, isa_obs)],
            ...     shots=8192,
            ...     resilience_level=2
            ... )
            >>> for r in results:
            ...     print(f"⟨O⟩ = {r['expectation_value']:.6f} ± {r['std_error']:.6f}")
        """
        if shots is None:
            shots = getattr(self, 'default_shots', 8192)
        
        if not self._connected:
            raise QMCExecutionError("Non connecté au backend")
        
        lnames = {0: "brut", 1: "TREX+DD", 2: "TREX+ZNE+twirl"}
        lname = lnames.get(resilience_level, f"level{resilience_level}")
        
        global_start_time = time.time()
        run_context = {
            'shots': shots,
            'circuits_count': len(pubs),
            'primitive': 'EstimatorV2',
            'resilience_level': resilience_level,
            'resilience_name': lname,
            'job_id': None,
            'status': 'STARTING',
            'qpu_time_s': 0,
        }
        execution_error = None
        results = None
        job_id = None
        
        try:
            self.logger.section(f"ESTIMATOR V2 — Level {resilience_level} ({lname})")
            self.logger.info(f"  📊 {len(pubs)} PUBs, {shots} shots")
            
            # === ESTIMATION COÛT ===
            isa_circuits = [pub[0] if isinstance(pub, tuple) else pub for pub in pubs]
            self.estimate_cost(isa_circuits, shots, display=True)
            
            # === CONFIRMATION ===
            actual_auto_confirm = QMC_AUTO_CONFIRM
            in_multijob_context = getattr(self, '_in_multijob_context', False)
            if in_multijob_context:
                actual_auto_confirm = self.auto_confirm
            
            if not actual_auto_confirm:
                if not self._confirm_qpu_submission(isa_circuits, shots):
                    self.logger.warn("❌ Envoi QPU ANNULÉ par l'utilisateur")
                    run_context['status'] = 'CANCELLED_BY_USER'
                    return None
            
            # === CRÉER ESTIMATOR (interne) ===
            estimator = self._create_estimator_v2(resilience_level, options)
            estimator.options.default_shots = shots
            
            # === SOUMISSION ===
            self.logger.info(f"  📤 Soumission {len(pubs)} PUBs...")
            job = estimator.run(pubs)
            job_id = job.job_id()
            self._last_job_id = job_id
            run_context['job_id'] = job_id
            self.logger.info(f"  🆔 Job ID: {job_id}")
            
            # === CHECKPOINT ===
            try:
                self.checkpoint_manager.save_checkpoint({
                    'job_id': job_id,
                    'type': 'estimator',
                    'resilience_level': resilience_level,
                    'n_pubs': len(pubs),
                    'shots': shots,
                    'timestamp': datetime.now().isoformat(),
                    'backend_name': self.backend_name,
                }, name=f"estimator_L{resilience_level}_{job_id[:8]}")
            except Exception:
                pass
            
            # === MONITORING ROBUSTE ===
            try:
                metrics = self._monitor_job_with_reconnect(
                    job, timeout=None,
                    poll_interval=10.0,
                    status_timeout=45.0
                )
                
                if metrics.get('connection_lost'):
                    raise QMCTimeoutError(
                        f"Connexion perdue - job_id: {job_id}",
                        job_id=job_id
                    )
            except Exception as e:
                execution_error = e
                run_context['status'] = 'MONITORING_ERROR'
                raise
            
            final_status = metrics.get('final_status', 'UNKNOWN')
            run_context['status'] = final_status
            
            if final_status in ['ERROR', 'CANCELLED']:
                error_details = self._get_job_error_details(job)
                execution_error = QMCExecutionError(
                    f"Job {final_status}: {error_details.get('error_message', '?')}",
                    job_id=job_id
                )
                raise execution_error
            
            # === RÉCUPÉRATION RÉSULTATS ===
            qpu_times = self.get_job_execution_times(job_id)
            run_context['qpu_time_s'] = qpu_times.get('qpu_time_s', 0) or 0
            
            raw_result = self._safe_get_job_result(job, timeout_seconds=120.0)
            
            # === EXTRACTION ===
            # [v2.7.1 FIX] Gère les PUB MULTI-OBSERVABLES : pr.data.evs est un ndarray
            # dont la forme = broadcast de la PUB. L'ancien float(pr.data.evs) levait un
            # TypeError pour len>1 (donc plantage APRÈS facturation du job QPU).
            results = []
            for i, pr in enumerate(raw_result):
                evs_arr = np.asarray(pr.data.evs)
                stds_arr = np.asarray(pr.data.stds) if hasattr(pr.data, 'stds') else None
                if evs_arr.ndim == 0:
                    # Observable unique -> scalaire
                    results.append({
                        'circuit_index': i,
                        'expectation_value': float(evs_arr),
                        'std_error': float(stds_arr) if stds_arr is not None else 0.0,
                        'shots': shots,
                        'resilience_level': resilience_level,
                    })
                else:
                    # Multi-observables -> liste (une valeur par observable)
                    evs_list = [float(x) for x in evs_arr.ravel()]
                    stds_list = ([float(x) for x in stds_arr.ravel()]
                                 if stds_arr is not None else [0.0] * len(evs_list))
                    results.append({
                        'circuit_index': i,
                        # compat : valeur scalaire si un seul observable, sinon liste
                        'expectation_value': evs_list[0] if len(evs_list) == 1 else evs_list,
                        'expectation_values': evs_list,
                        'std_error': stds_list[0] if len(stds_list) == 1 else stds_list,
                        'std_errors': stds_list,
                        'n_observables': len(evs_list),
                        'shots': shots,
                        'resilience_level': resilience_level,
                    })
            
            run_context['status'] = 'DONE'
            run_context['completed_at'] = datetime.now().strftime('%H:%M:%S')
            
            elapsed = time.time() - global_start_time
            self.logger.info(f"  [OK] Estimator terminé!")
            self.logger.info(f"       ⏱️  Temps total: {elapsed:.1f}s")
            self.logger.info(f"       🚀 Temps QPU: {run_context['qpu_time_s']:.2f}s")
            self.logger.info(f"       📊 {len(results)} résultats")
            
        except Exception as e:
            execution_error = e
            run_context['status'] = run_context.get('status', 'ERROR')
            run_context['total_time_s'] = time.time() - global_start_time
            raise
            
        finally:
            # === PIPELINE IDENTIQUE À run_on_qpu finally ===
            run_context['total_time_s'] = time.time() - global_start_time
            
            self.logger.info(f"")
            self.logger.info(f"  📦 Post-traitement Estimator...")
            
            # 1. Rescue save IMMÉDIAT
            if results:
                try:
                    rescue_data = {
                        'job_id': job_id,
                        'type': 'estimator',
                        'resilience_level': resilience_level,
                        'shots': shots,
                        'timestamp': datetime.now().isoformat(),
                        'results': results,
                    }
                    if hasattr(self, 'dir_manager') and self.dir_manager:
                        self.dir_manager.save_json('estimator_results', rescue_data)
                        self.logger.info(f"  💾 Résultats sauvegardés")
                except Exception:
                    pass
            
            # 2. Archive JSON complète
            actual_generate_archive = QMC_GENERATE_ARCHIVE
            if actual_generate_archive:
                try:
                    # Construire résultats compatibles format archive
                    archive_results = []
                    if results:
                        for r in results:
                            archive_results.append({
                                'circuit_index': r['circuit_index'],
                                'shots': shots,
                                'counts': {},
                                'expectation_value': r['expectation_value'],
                                'std_error': r['std_error'],
                            })
                    
                    transpiled_for_archive = [pub[0] if isinstance(pub, tuple) else pub 
                                              for pub in pubs] if pubs else None
                    
                    self._generate_auto_archive(
                        results=archive_results,
                        original_circuits=None,
                        transpiled_circuits=transpiled_for_archive,
                        run_context=run_context,
                        error=execution_error
                    )
                except Exception as archive_error:
                    self.logger.warn(f"  ⚠️ Archive: {archive_error}")
            
            # 3. Upload QMC Archive
            if actual_generate_archive and upload_to_archive:
                try:
                    uploader = get_archive_uploader(self.logger)
                    if uploader.is_enabled():
                        archive_path = self.last_archive_path
                        if archive_path and archive_path.exists():
                            upload_result = uploader.upload(
                                file_path=str(archive_path),
                                project_ids=archive_projects,
                                notes=archive_notes or f"Estimator L{resilience_level} {lname} - {job_id}",
                                job_id=job_id,
                            )
                            uploader.print_upload_report(upload_result, compact=True)
                except Exception as upload_error:
                    self.logger.warn(f"  ⚠️ Upload: {upload_error}")
            
            # 4. Rapport HTML
            actual_generate_report = QMC_GENERATE_REPORT
            if actual_generate_report:
                try:
                    self.logger.info(f"  📊 Génération du rapport HTML...")
                    self._generate_auto_report(
                        archive_results if results else None,
                        run_context, execution_error
                    )
                except Exception as report_error:
                    self.logger.warn(f"  ⚠️ Rapport: {report_error}")
        
        return results
    
    def get_execution_spans(self, job) -> Dict:
        """
        [v2.6.0] Récupère les informations de timing détaillées d'un job.
        
        Les ExecutionSpans contiennent les timestamps précis de début/fin
        d'exécution sur le QPU.
        
        Args:
            job: Job IBM Runtime
            
        Returns:
            Dict avec start, stop, duration pour chaque span
            
        Example:
            >>> job = sampler.run([circuit])
            >>> result = job.result()
            >>> spans = fw.get_execution_spans(job)
            >>> print(f"QPU time: {spans['total_duration_s']:.3f}s")
        """
        try:
            result = job.result()
            metadata = result.metadata
            
            spans_info = {
                'spans': [],
                'total_duration_s': 0,
            }
            
            if 'execution' in metadata and 'execution_spans' in metadata['execution']:
                exec_spans = metadata['execution']['execution_spans']
                
                if hasattr(exec_spans, 'spans'):
                    for span in exec_spans.spans:
                        span_info = {
                            'start': str(span.start) if hasattr(span, 'start') else None,
                            'stop': str(span.stop) if hasattr(span, 'stop') else None,
                            'size': span.size if hasattr(span, 'size') else None,
                        }
                        
                        if hasattr(span, 'start') and hasattr(span, 'stop'):
                            duration = (span.stop - span.start).total_seconds()
                            span_info['duration_s'] = duration
                            spans_info['total_duration_s'] += duration
                        
                        spans_info['spans'].append(span_info)
            
            return spans_info
            
        except Exception as e:
            if self.logger:
                self.logger.warn(f"⚠️ Could not extract execution spans: {e}")
            return {'spans': [], 'total_duration_s': 0, 'error': str(e)}
    
    # =========================================================================
    # [v2.6.0] CALIBRATION ID MANAGEMENT
    # =========================================================================
    
    def list_calibrations(self, backend_name: str = None, limit: int = 10) -> List[Dict]:
        """
        [v2.6.0] Liste les calibrations disponibles pour un backend.
        
        Args:
            backend_name: Nom du backend (défaut: self.backend_name)
            limit: Nombre max de calibrations à retourner (défaut: 10)
            
        Returns:
            Liste des calibrations avec id, date, métriques
            
        Example:
            >>> calibrations = fw.list_calibrations()
            >>> for cal in calibrations:
            ...     print(f"{cal['id']} - {cal['date']} - 2Q err: {cal['median_2q_error']:.2e}")
        """
        if not hasattr(self, 'service') or self.service is None:
            from qiskit_ibm_runtime import QiskitRuntimeService
            self.service = QiskitRuntimeService()
        
        backend_name = backend_name or getattr(self, 'backend_name', None)
        if not backend_name:
            raise ValueError("Backend name required")
        
        calibrations = []
        
        try:
            # Récupérer le backend avec ses calibrations
            backend = self.service.backend(backend_name)
            
            # Méthode 1: Via l'API properties (si disponible)
            if hasattr(backend, 'properties') and backend.properties():
                props = backend.properties()
                cal_info = {
                    'id': getattr(props, 'backend_name', 'current'),
                    'date': str(props.last_update_date) if hasattr(props, 'last_update_date') else 'N/A',
                    'backend': backend_name,
                    'qubits': backend.num_qubits,
                    'median_2q_error': None,
                    'median_readout_error': None,
                    'median_t1_us': None,
                    'median_t2_us': None,
                    'is_current': True,
                }
                
                # Extraire métriques depuis target
                if hasattr(backend, 'target') and backend.target:
                    errors_2q = []
                    errors_ro = []
                    t1_values = []
                    t2_values = []
                    
                    # Récupérer les erreurs de readout via target
                    try:
                        if 'measure' in backend.target.operation_names:
                            for qargs in backend.target.qargs_for_operation_name('measure'):
                                if qargs and len(qargs) == 1:
                                    qubit = qargs[0]
                                    inst_props = backend.target['measure'][qargs]
                                    if inst_props and hasattr(inst_props, 'error') and inst_props.error:
                                        errors_ro.append(inst_props.error)
                    except Exception:
                        pass
                    
                    # T1/T2 depuis qubit_properties
                    try:
                        qubit_props = backend.target.qubit_properties
                        if qubit_props:
                            for qubit in range(min(backend.num_qubits, len(qubit_props))):
                                qp = qubit_props[qubit]
                                if qp:
                                    if hasattr(qp, 't1') and qp.t1:
                                        t1_values.append(qp.t1 * 1e6)  # to µs
                                    if hasattr(qp, 't2') and qp.t2:
                                        t2_values.append(qp.t2 * 1e6)
                    except Exception:
                        pass
                    
                    # Chercher les gates 2Q
                    try:
                        for op_name in ['cz', 'ecr', 'cx', 'rzz']:
                            if op_name in backend.target.operation_names:
                                for qargs in backend.target.qargs_for_operation_name(op_name):
                                    if qargs and len(qargs) == 2:
                                        inst_props = backend.target[op_name][qargs]
                                        if inst_props and hasattr(inst_props, 'error') and inst_props.error is not None:
                                            if inst_props.error < 1.0:  # Filtrer les erreurs invalides
                                                errors_2q.append(inst_props.error)
                    except Exception:
                        pass
                    
                    if errors_2q:
                        cal_info['median_2q_error'] = float(np.median(errors_2q))
                    if errors_ro:
                        cal_info['median_readout_error'] = float(np.median(errors_ro))
                    if t1_values:
                        cal_info['median_t1_us'] = float(np.median(t1_values))
                    if t2_values:
                        cal_info['median_t2_us'] = float(np.median(t2_values))
                
                calibrations.append(cal_info)
            
            # Méthode 2: Via l'API calibrations (si disponible)
            # Note: Cette API peut ne pas être disponible sur tous les plans
            try:
                if hasattr(self.service, 'calibrations') or hasattr(backend, 'calibrations'):
                    # API expérimentale pour lister les calibrations historiques
                    pass
            except Exception:
                pass
            
        except Exception as e:
            if self.logger:
                self.logger.warn(f"⚠️ Erreur récupération calibrations: {e}")
        
        # Afficher dans le terminal
        self._display_calibrations_table(calibrations, backend_name)
        
        return calibrations[:limit]
    
    def _display_calibrations_table(self, calibrations: List[Dict], backend_name: str):
        """Affiche un tableau des calibrations disponibles."""
        print()
        print(f"╔══════════════════════════════════════════════════════════════════════════════╗")
        print(f"║  📅 CALIBRATIONS DISPONIBLES - {backend_name:<42} ║")
        print(f"╠══════════════════════════════════════════════════════════════════════════════╣")
        print(f"║  {'#':<3} │ {'ID':<20} │ {'Date':<20} │ {'2Q Err':<10} │ {'Current':<7} ║")
        print(f"╠══════════════════════════════════════════════════════════════════════════════╣")
        
        if not calibrations:
            print(f"║  {'Aucune calibration disponible':<74} ║")
        else:
            for i, cal in enumerate(calibrations):
                cal_id = str(cal.get('id', 'N/A'))[:20]
                cal_date = str(cal.get('date', 'N/A'))[:20]
                err_2q = f"{cal.get('median_2q_error', 0):.2e}" if cal.get('median_2q_error') else 'N/A'
                is_current = "✓" if cal.get('is_current') else ""
                print(f"║  {i+1:<3} │ {cal_id:<20} │ {cal_date:<20} │ {err_2q:<10} │ {is_current:<7} ║")
        
        print(f"╚══════════════════════════════════════════════════════════════════════════════╝")
        print()
    
    def connect_with_calibration(self, backend_name: str = None, 
                                  calibration_id: str = None,
                                  show_calibrations: bool = True,
                                  select_interactive: bool = False) -> bool:
        """
        [v2.6.0] Connexion avec sélection de calibration spécifique.
        
        Args:
            backend_name: Nom du backend
            calibration_id: ID de calibration spécifique (optionnel)
            show_calibrations: Afficher la liste des calibrations (défaut: True)
            select_interactive: Mode interactif pour sélection (défaut: False)
            
        Returns:
            True si connexion réussie
            
        Example:
            >>> # Voir les calibrations disponibles
            >>> fw.connect_with_calibration('ibm_torino', show_calibrations=True)
            >>> 
            >>> # Utiliser une calibration spécifique
            >>> fw.connect_with_calibration('ibm_torino', calibration_id='cal_abc123')
        """
        from qiskit_ibm_runtime import QiskitRuntimeService
        
        backend_name = backend_name or getattr(self, 'backend_name', None)
        if not backend_name:
            raise ValueError("Backend name required")
        
        # Initialiser le service
        if not hasattr(self, 'service') or self.service is None:
            self.service = QiskitRuntimeService()
        
        # Afficher les calibrations si demandé
        if show_calibrations and not calibration_id:
            calibrations = self.list_calibrations(backend_name)
            
            if select_interactive and calibrations:
                print("  💡 Entrez le numéro de calibration (ou Entrée pour la plus récente): ", end="")
                try:
                    choice = input().strip()
                    if choice:
                        idx = int(choice) - 1
                        if 0 <= idx < len(calibrations):
                            calibration_id = calibrations[idx].get('id')
                            if self.logger:
                                self.logger.info(f"  ✅ Calibration sélectionnée: {calibration_id}")
                except (ValueError, EOFError):
                    pass
        
        # Connexion avec calibration_id si spécifié
        try:
            kwargs = {}
            if calibration_id:
                kwargs['calibration_id'] = calibration_id
                if self.logger:
                    self.logger.info(f"  📅 Utilisation calibration: {calibration_id}")
            
            self.backend = self.service.backend(backend_name, **kwargs)
            self.backend_name = backend_name
            self._connected = True
            self._calibration_id = calibration_id
            
            if self.logger:
                self.logger.info(f"  ✅ Connecté à {backend_name}")
                if calibration_id:
                    self.logger.info(f"     Calibration: {calibration_id}")
            
            return True
            
        except Exception as e:
            if self.logger:
                self.logger.error(f"❌ Erreur connexion: {e}")
            return False
    
    # =========================================================================
    # [v2.6.0] FRACTIONAL GATES SUPPORT
    # =========================================================================
    
    def enable_fractional_gates(self, backend_name: str = None) -> bool:
        """
        [v2.6.0] Active le support des fractional gates (RX/RZZ natifs).
        
        Les fractional gates permettent une réduction de profondeur 
        jusqu'à 600% pour les circuits avec rotations (Ising, VQE, QAOA).
        
        ⚠️ Limitations:
        - Incompatible avec PEC, PEA, Pauli twirling
        - Compatible avec DD et TREX
        
        Args:
            backend_name: Nom du backend (défaut: self.backend_name)
            
        Returns:
            True si activé avec succès
            
        Example:
            >>> fw.enable_fractional_gates()
            >>> # Les circuits avec RX/RZZ seront optimisés automatiquement
        """
        from qiskit_ibm_runtime import QiskitRuntimeService
        
        backend_name = backend_name or getattr(self, 'backend_name', None)
        if not backend_name:
            raise ValueError("Backend name required")
        
        if not hasattr(self, 'service') or self.service is None:
            self.service = QiskitRuntimeService()
        
        try:
            # Reconnecter avec fractional gates
            self.backend = self.service.backend(backend_name, use_fractional_gates=True)
            self._fractional_gates_enabled = True
            
            if self.logger:
                self.logger.info(f"")
                self.logger.info(f"╔══════════════════════════════════════════════════════════════╗")
                self.logger.info(f"║  ⚡ FRACTIONAL GATES ACTIVÉS                                 ║")
                self.logger.info(f"╠══════════════════════════════════════════════════════════════╣")
                self.logger.info(f"║  Backend: {backend_name:<49} ║")
                self.logger.info(f"║  Gates natives: RX(θ), RZZ(θ)                                ║")
                self.logger.info(f"║  Réduction profondeur: jusqu'à -600%                         ║")
                self.logger.info(f"╠══════════════════════════════════════════════════════════════╣")
                self.logger.info(f"║  ⚠️  Incompatible avec: PEC, PEA, Pauli twirling             ║")
                self.logger.info(f"║  ✅ Compatible avec: DD, TREX, ZNE (gate folding)            ║")
                self.logger.info(f"╚══════════════════════════════════════════════════════════════╝")
                self.logger.info(f"")
            
            return True
            
        except Exception as e:
            if self.logger:
                self.logger.error(f"❌ Erreur activation fractional gates: {e}")
            self._fractional_gates_enabled = False
            return False
    
    def get_fractional_gate_depth_comparison(self, circuit) -> Dict:
        """
        [v2.6.0] Compare la profondeur avec/sans fractional gates.
        
        Args:
            circuit: Circuit à analyser
            
        Returns:
            Dict avec depth_standard, depth_fractional, reduction_percent
        """
        from qiskit.transpiler.preset_passmanagers import generate_preset_pass_manager
        from qiskit_ibm_runtime import QiskitRuntimeService
        
        if not hasattr(self, 'service') or self.service is None:
            self.service = QiskitRuntimeService()
        
        backend_name = getattr(self, 'backend_name', 'ibm_torino')
        
        result = {
            'depth_standard': 0,
            'depth_fractional': 0,
            'reduction_percent': 0,
            'gates_2q_standard': 0,
            'gates_2q_fractional': 0,
        }
        
        try:
            # Sans fractional gates
            backend_std = self.service.backend(backend_name, use_fractional_gates=False)
            pm_std = generate_preset_pass_manager(backend=backend_std, optimization_level=3)
            transpiled_std = pm_std.run(circuit)
            result['depth_standard'] = transpiled_std.depth()
            result['gates_2q_standard'] = transpiled_std.count_ops().get('cz', 0) + transpiled_std.count_ops().get('ecr', 0)
            
            # Avec fractional gates
            backend_frac = self.service.backend(backend_name, use_fractional_gates=True)
            pm_frac = generate_preset_pass_manager(backend=backend_frac, optimization_level=3)
            transpiled_frac = pm_frac.run(circuit)
            result['depth_fractional'] = transpiled_frac.depth()
            result['gates_2q_fractional'] = transpiled_frac.count_ops().get('cz', 0) + transpiled_frac.count_ops().get('rzz', 0)
            
            # Calcul réduction
            if result['depth_standard'] > 0:
                result['reduction_percent'] = (1 - result['depth_fractional'] / result['depth_standard']) * 100
            
            if self.logger:
                self.logger.info(f"")
                self.logger.info(f"╔══════════════════════════════════════════════════════════════╗")
                self.logger.info(f"║  📊 COMPARAISON FRACTIONAL GATES                             ║")
                self.logger.info(f"╠══════════════════════════════════════════════════════════════╣")
                self.logger.info(f"║  Standard:   depth={result['depth_standard']:<6} 2Q gates={result['gates_2q_standard']:<6}           ║")
                self.logger.info(f"║  Fractional: depth={result['depth_fractional']:<6} 2Q gates={result['gates_2q_fractional']:<6}           ║")
                self.logger.info(f"║  Réduction:  {result['reduction_percent']:.1f}%                                        ║")
                self.logger.info(f"╚══════════════════════════════════════════════════════════════╝")
            
        except Exception as e:
            if self.logger:
                self.logger.warn(f"⚠️ Erreur comparaison: {e}")
        
        return result
    
    # =========================================================================
    # [v2.6.0] DYNAMIC CIRCUITS SUPPORT
    # =========================================================================
    
    def create_dynamic_circuit(self, n_qubits: int, 
                                with_reset: bool = True,
                                with_conditional: bool = True) -> 'QuantumCircuit':
        """
        [v2.6.0] Crée un circuit dynamique de démonstration.
        
        Les circuits dynamiques permettent:
        - Mid-circuit measurements
        - Conditional operations (if/else)
        - Qubit reset
        - Feedforward classique
        
        Args:
            n_qubits: Nombre de qubits
            with_reset: Inclure des resets mid-circuit
            with_conditional: Inclure des opérations conditionnelles
            
        Returns:
            QuantumCircuit avec features dynamiques
        """
        from qiskit import QuantumCircuit, QuantumRegister, ClassicalRegister
        
        qr = QuantumRegister(n_qubits, 'q')
        cr = ClassicalRegister(n_qubits, 'c')
        circuit = QuantumCircuit(qr, cr)
        
        # Superposition initiale
        for i in range(n_qubits):
            circuit.h(qr[i])
        
        circuit.barrier()
        
        # Mid-circuit measurement
        circuit.measure(qr[0], cr[0])
        
        # Conditional operation
        if with_conditional:
            with circuit.if_test((cr[0], 1)):
                circuit.x(qr[0])  # Flip si mesuré 1
        
        # Reset mid-circuit
        if with_reset and n_qubits > 1:
            circuit.reset(qr[1])
            circuit.h(qr[1])
        
        circuit.barrier()
        
        # Mesure finale
        circuit.measure(qr, cr)
        
        return circuit
    
    def check_dynamic_circuit_support(self, circuit) -> Dict:
        """
        [v2.6.0] Vérifie si un circuit utilise des features dynamiques.
        
        Args:
            circuit: Circuit à analyser
            
        Returns:
            Dict avec has_mid_measurement, has_conditional, has_reset, etc.
        """
        result = {
            'has_mid_measurement': False,
            'has_conditional': False,
            'has_reset': False,
            'has_barrier': False,
            'is_dynamic': False,
            'dynamic_features': [],
        }
        
        # Analyser les instructions
        measurement_positions = []
        has_gates_after_measure = False
        
        for i, instruction in enumerate(circuit.data):
            op_name = instruction.operation.name
            
            if op_name == 'measure':
                measurement_positions.append(i)
            elif op_name == 'reset':
                result['has_reset'] = True
                result['dynamic_features'].append('reset')
            elif op_name == 'barrier':
                result['has_barrier'] = True
            elif op_name in ['if_else', 'switch_case', 'while_loop', 'for_loop']:
                result['has_conditional'] = True
                result['dynamic_features'].append(op_name)
        
        # Vérifier si mesures mid-circuit (pas à la fin)
        if measurement_positions:
            last_measure = max(measurement_positions)
            total_ops = len(circuit.data)
            # Si la dernière mesure n'est pas dans les dernières opérations
            if last_measure < total_ops - circuit.num_qubits - 1:
                result['has_mid_measurement'] = True
                result['dynamic_features'].append('mid_circuit_measurement')
        
        # Circuit dynamique si au moins une feature
        result['is_dynamic'] = (
            result['has_mid_measurement'] or 
            result['has_conditional'] or 
            result['has_reset']
        )
        
        return result
    
