    def enable_gen3_turbo(self, estimator_or_sampler) -> None:
        """
        [v2.6.0] Active le mode Gen3 Turbo (75x speedup).
        
        ⚠️ Incompatible avec fractional gates et dynamic circuits.
        
        Args:
            estimator_or_sampler: Primitive à configurer
            
        Example:
            >>> sampler = fw.get_sampler_v2()
            >>> fw.enable_gen3_turbo(sampler)
        """
        try:
            if hasattr(estimator_or_sampler, 'options'):
                if not hasattr(estimator_or_sampler.options, 'experimental'):
                    estimator_or_sampler.options.experimental = {}
                
                estimator_or_sampler.options.experimental['gen3_turbo'] = True
                
                if self.logger:
                    self.logger.info(f"")
                    self.logger.info(f"╔══════════════════════════════════════════════════════════════╗")
                    self.logger.info(f"║  🚀 GEN3 TURBO MODE ACTIVÉ                                   ║")
                    self.logger.info(f"╠══════════════════════════════════════════════════════════════╣")
                    self.logger.info(f"║  Speedup: jusqu'à 75x                                        ║")
                    self.logger.info(f"║  ⚠️  Incompatible avec: fractional gates, dynamic circuits   ║")
                    self.logger.info(f"╚══════════════════════════════════════════════════════════════╝")
                
        except Exception as e:
            if self.logger:
                self.logger.warn(f"⚠️ Erreur activation Gen3 Turbo: {e}")
    
    # =========================================================================
    # [v2.6.0] FAKE BACKENDS FOR LOCAL TESTING
    # =========================================================================
    
    def get_fake_backend(self, backend_type: str = 'heron') -> 'BackendV2':
        """
        [v2.6.0] Retourne un fake backend pour tests locaux.
        
        Args:
            backend_type: 'heron', 'nighthawk', 'fez', 'marrakesh', etc.
            
        Returns:
            FakeBackend pour tests sans QPU
            
        Example:
            >>> fake = fw.get_fake_backend('nighthawk')
            >>> # Tester la transpilation localement
            >>> pm = generate_preset_pass_manager(backend=fake, optimization_level=3)
        """
        try:
            from qiskit_ibm_runtime.fake_provider import (
                FakeFez, FakeMarrakesh, FakeTorino
            )
            
            # Essayer d'importer FakeNighthawk (peut ne pas exister)
            try:
                from qiskit_ibm_runtime.fake_provider import FakeNighthawk
                has_nighthawk = True
            except ImportError:
                has_nighthawk = False
            
            backend_map = {
                'fez': FakeFez,
                'marrakesh': FakeMarrakesh,
                'torino': FakeTorino,
                'heron': FakeFez,  # FakeFez est Heron r2
            }
            
            if has_nighthawk:
                backend_map['nighthawk'] = FakeNighthawk
            
            backend_type_lower = backend_type.lower()
            
            if backend_type_lower in backend_map:
                fake_backend = backend_map[backend_type_lower]()
                if self.logger:
                    self.logger.info(f"  🧪 Fake backend créé: {type(fake_backend).__name__}")
                return fake_backend
            else:
                available = list(backend_map.keys())
                raise ValueError(f"Type inconnu '{backend_type}'. Disponibles: {available}")
                
        except ImportError as e:
            if self.logger:
                self.logger.error(f"❌ Fake provider non disponible: {e}")
            raise
    
    def test_locally(self, circuits, shots: int = 1024, 
                     backend_type: str = 'heron') -> List[Dict]:
        """
        [v2.6.0] Teste les circuits localement avec un fake backend.
        
        Utile pour valider la transpilation et le code avant
        d'utiliser des ressources QPU.
        
        Args:
            circuits: Circuit(s) à tester
            shots: Nombre de shots
            backend_type: Type de fake backend
            
        Returns:
            Liste de résultats (simulés)
            
        Example:
            >>> results = fw.test_locally(circuit, shots=1024)
            >>> print(results[0]['counts'])
        """
        from qiskit import QuantumCircuit
        from qiskit.transpiler.preset_passmanagers import generate_preset_pass_manager
        from qiskit_ibm_runtime import SamplerV2
        
        # Auto-wrap
        if isinstance(circuits, QuantumCircuit):
            circuits = [circuits]
        
        if self.logger:
            self.logger.info(f"")
            self.logger.info(f"╔══════════════════════════════════════════════════════════════╗")
            self.logger.info(f"║  🧪 TEST LOCAL MODE                                          ║")
            self.logger.info(f"╠══════════════════════════════════════════════════════════════╣")
            self.logger.info(f"║  Circuits: {len(circuits):<49} ║")
            self.logger.info(f"║  Shots: {shots:<52} ║")
            self.logger.info(f"║  Backend: Fake{backend_type.capitalize():<46} ║")
            self.logger.info(f"╚══════════════════════════════════════════════════════════════╝")
        
        try:
            # Obtenir le fake backend
            fake_backend = self.get_fake_backend(backend_type)
            
            # Transpiler
            pm = generate_preset_pass_manager(backend=fake_backend, optimization_level=3)
            transpiled = pm.run(circuits)
            
            # Créer le sampler local
            sampler = SamplerV2(mode=fake_backend)
            sampler.options.default_shots = shots
            
            # Exécuter
            if not isinstance(transpiled, list):
                transpiled = [transpiled]
            
            job = sampler.run(transpiled)
            result = job.result()
            
            # Extraire les résultats
            results = []
            for i, pub_result in enumerate(result):
                counts = pub_result.data.meas.get_counts() if hasattr(pub_result.data, 'meas') else {}
                results.append({
                    'counts': counts,
                    'shots': shots,
                    'circuit_index': i,
                    'local_test': True,
                    'fake_backend': type(fake_backend).__name__,
                })
            
            if self.logger:
                self.logger.info(f"  ✅ Test local terminé: {len(results)} résultats")
            
            return results
            
        except Exception as e:
            if self.logger:
                self.logger.error(f"❌ Erreur test local: {e}")
            raise
    
    # =========================================================================
    # [v2.6.0] QPY SERIALIZATION
    # =========================================================================
    
    def save_circuits_qpy(self, circuits, filepath: str) -> str:
        """
        [v2.6.0] Sauvegarde les circuits au format QPY (compact et rapide).
        
        QPY est 10x plus compact que QASM et préserve toutes les métadonnées.
        
        Args:
            circuits: Circuit(s) à sauvegarder
            filepath: Chemin du fichier (extension .qpy ajoutée si absente)
            
        Returns:
            Chemin du fichier sauvegardé
        """
        from qiskit import qpy, QuantumCircuit
        from pathlib import Path
        
        # Auto-wrap
        if isinstance(circuits, QuantumCircuit):
            circuits = [circuits]
        
        # Ajouter extension si nécessaire
        filepath = str(filepath)
        if not filepath.endswith('.qpy'):
            filepath += '.qpy'
        
        # Sauvegarder
        with open(filepath, 'wb') as f:
            qpy.dump(circuits, f)
        
        size_kb = Path(filepath).stat().st_size / 1024
        if self.logger:
            self.logger.info(f"  💾 Circuits sauvegardés: {filepath} ({size_kb:.1f} KB)")
        
        return filepath
    
    def load_circuits_qpy(self, filepath: str) -> List['QuantumCircuit']:
        """
        [v2.6.0] Charge les circuits depuis un fichier QPY.
        
        Args:
            filepath: Chemin du fichier QPY
            
        Returns:
            Liste de QuantumCircuits
        """
        from qiskit import qpy
        
        with open(filepath, 'rb') as f:
            circuits = qpy.load(f)
        
        if self.logger:
            self.logger.info(f"  📂 Circuits chargés: {len(circuits)} depuis {filepath}")
        
        return circuits
    
    # =========================================================================
    # [v2.6.0] CIRCUIT SCHEDULE VISUALIZATION
    # =========================================================================
    
    def draw_circuit_timing(self, circuit, output_path: str = None) -> str:
        """
        [v2.6.0] Visualise le timing d'exécution d'un circuit transpilé.
        
        Utile pour debug et optimisation des circuits dynamiques.
        
        Args:
            circuit: Circuit transpilé
            output_path: Chemin de sauvegarde (optionnel)
            
        Returns:
            Chemin de l'image ou None
        """
        try:
            from qiskit_ibm_runtime.visualization import draw_circuit_schedule_timing
            import matplotlib.pyplot as plt
            
            fig = draw_circuit_schedule_timing(circuit, self.backend)
            
            if output_path:
                fig.savefig(output_path, dpi=150, bbox_inches='tight')
                if self.logger:
                    self.logger.info(f"  📊 Timing visualisé: {output_path}")
                plt.close(fig)
                return output_path
            else:
                plt.show()
                return None
                
        except ImportError:
            if self.logger:
                self.logger.warn("⚠️ draw_circuit_schedule_timing non disponible")
                self.logger.warn("   Requires qiskit-ibm-runtime >= 0.43.0")
            return None
        except Exception as e:
            if self.logger:
                self.logger.warn(f"⚠️ Erreur visualisation timing: {e}")
            return None
    
    # =========================================================================
    # [v2.6.0] ADVANCED TRANSPILATION
    # =========================================================================
    
    def transpile_with_fractional(self, circuits, optimization_level: int = 3):
        """
        [v2.6.0] Transpile avec support fractional gates optimisé.
        
        Args:
            circuits: Circuit(s) à transpiler
            optimization_level: Niveau d'optimisation (0-3)
            
        Returns:
            Circuit(s) transpilé(s)
        """
        from qiskit.transpiler.preset_passmanagers import generate_preset_pass_manager
        from qiskit_ibm_runtime import QiskitRuntimeService
        from qiskit import QuantumCircuit
        
        if not hasattr(self, 'service') or self.service is None:
            self.service = QiskitRuntimeService()
        
        backend_name = getattr(self, 'backend_name', 'ibm_torino')
        
        # Backend avec fractional gates
        backend = self.service.backend(backend_name, use_fractional_gates=True)
        
        # Pass manager
        pm = generate_preset_pass_manager(
            backend=backend,
            optimization_level=optimization_level
        )
        
        # Auto-wrap
        single_circuit = isinstance(circuits, QuantumCircuit)
        if single_circuit:
            circuits = [circuits]
        
        # Transpiler
        transpiled = pm.run(circuits)
        
        if self.logger:
            self.logger.info(f"  ⚡ Transpilation fractional gates terminée")
        
        return transpiled[0] if single_circuit else transpiled
    
    def transpile_parallel(self, circuits, n_workers: int = None,
                           optimization_level: int = 3) -> List:
        """
        [v2.7.0] Transpile les circuits en parallèle via ProcessPoolExecutor multi-CPU.
        
        ⚠️ NOTA: Depuis v2.7.0, transpile_circuits() supporte nativement le mode
        parallèle (parallel='auto'). Cette méthode est un raccourci qui force
        le parallélisme même pour un petit nombre de circuits.
        
        Args:
            circuits: Liste de circuits
            n_workers: Nombre de workers CPU (défaut: cpu_count)
            optimization_level: Niveau d'optimisation Qiskit (0-3, défaut: 3)
            
        Returns:
            Liste de circuits transpilés
            
        Example:
            # Forcer 8 workers
            transpiled = fw.transpile_parallel(circuits, n_workers=8)
            
            # Équivalent à:
            transpiled = fw.transpile_circuits(circuits, parallel='always', n_workers=8)
        """
        return self.transpile_circuits(
            circuits,
            optimization_level=optimization_level,
            parallel='always',
            n_workers=n_workers,
            show_progress=True,
        )
    
    def _generate_auto_archive(self, results: List[Dict], original_circuits, transpiled_circuits,
                               run_context: Dict, error: Exception = None):
        """
        [v2.5.17] Génère automatiquement une archive JSON COMPLÈTE.
        
        L'archive contient TOUT ce qui s'est passé pendant l'exécution:
        - Circuits originaux et transpilés (QASM, métriques)
        - État complet du QPU (calibration 156 qubits)
        - Configuration de mitigation et transpilation
        - Résultats complets avec statistiques
        - Timing détaillé
        - Erreurs avec traceback
        
        Args:
            results: Résultats de l'exécution
            original_circuits: Circuits avant transpilation
            transpiled_circuits: Circuits après transpilation
            run_context: Contexte d'exécution
            error: Exception si erreur
        """
        # [v2.6.0] Ne pas générer d'archive si pas de données utiles
        # (cas d'erreur de connexion par exemple)
        has_results = results is not None and len(results) > 0
        has_circuits = original_circuits is not None or transpiled_circuits is not None
        has_error = error is not None
        
        if not has_results and not has_circuits and not has_error:
            self.logger.warn("⚠️ Archive non générée: aucune donnée utile")
            return None
        
        # Initialiser le générateur d'archive si nécessaire
        if not hasattr(self, '_archive_generator') or self._archive_generator is None:
            self._archive_generator = ExecutionArchive(framework=self, logger=self.logger)
        
        # S'assurer que run_context n'est pas None
        if run_context is None:
            run_context = {
                'status': 'ERROR_NO_CONTEXT',
                'shots': 0,
                'circuits_count': 0,
            }
        
        # Générer l'archive
        archive_path = self._archive_generator.generate(
            results=results or [],
            circuits=original_circuits,
            transpiled_circuits=transpiled_circuits,
            run_context=run_context,
            error=error
        )
        
        if archive_path is None:
            return None
        
        # Afficher le lien vers l'archive
        size_kb = archive_path.stat().st_size / 1024
        size_str = f"{size_kb:.1f} KB" if size_kb < 1024 else f"{size_kb/1024:.1f} MB"
        
        print()
        print(f"  ╔════════════════════════════════════════════════════════════════════════════╗")
        print(f"  ║  📦 ARCHIVE JSON COMPLÈTE GÉNÉRÉE                                          ║")
        print(f"  ╠════════════════════════════════════════════════════════════════════════════╣")
        print(f"  ║  📁 {str(archive_path):<70} ║")
        print(f"  ║  📊 Taille: {size_str:<62} ║")
        print(f"  ╚════════════════════════════════════════════════════════════════════════════╝")
        print()
        
        # Sauvegarder le chemin de la dernière archive
        self._last_archive_path = archive_path
        
        return archive_path
    
    @property
    def archive_generator(self) -> 'ExecutionArchive':
        """[v2.5.17] Accès au générateur d'archives."""
        if not hasattr(self, '_archive_generator') or self._archive_generator is None:
            self._archive_generator = ExecutionArchive(framework=self, logger=self.logger)
        return self._archive_generator
    
    @property
    def last_archive_path(self) -> Optional[Path]:
        """[v2.5.17] Chemin de la dernière archive générée."""
        return getattr(self, '_last_archive_path', None)
    
    def _generate_auto_report(self, results: List[Dict], run_context: Dict, error: Exception = None,
                               transpiled_circuits: List = None):
        """
        [v2.5.17] Génère automatiquement un rapport HTML ultra-complet.
        
        Appelé automatiquement à la fin de run_on_qpu() dans le bloc finally,
        donc génère le rapport même en cas d'erreur.
        
        Args:
            results: Résultats de l'exécution (peut être None en cas d'erreur)
            run_context: Contexte d'exécution (timing, job_id, etc.)
            error: Exception si erreur pendant l'exécution
            transpiled_circuits: [v2.5.18] Circuits transpilés pour visualisation
        """
        # Initialiser le générateur de rapport si nécessaire
        if not hasattr(self, '_report_generator') or self._report_generator is None:
            self._report_generator = AutoReportGenerator(framework=self, logger=self.logger)
        
        # Générer le rapport
        report_path = self._report_generator.generate(
            results=results,
            run_context=run_context,
            error=error,
            title=None,  # Titre auto-généré basé sur le statut
            transpiled_circuits=transpiled_circuits  # [v2.5.18] Pour visualisation
        )
        
        # Afficher le lien vers le rapport
        status_emoji = "❌" if error else "✅"
        status_text = "ERROR" if error else "SUCCESS"
        
        print()
        print(f"  ╔════════════════════════════════════════════════════════════════════════════╗")
        print(f"  ║  📊 RAPPORT HTML GÉNÉRÉ                          {status_emoji} {status_text:<20}     ║")
        print(f"  ╠════════════════════════════════════════════════════════════════════════════╣")
        print(f"  ║  📁 {str(report_path):<70} ║")
        print(f"  ╚════════════════════════════════════════════════════════════════════════════╝")
        print()
        
        # Sauvegarder le chemin du dernier rapport
        self._last_report_path = report_path
        
        return report_path
    
    @property
    def report_generator(self) -> 'AutoReportGenerator':
        """[v2.5.17] Accès au générateur de rapports."""
        if not hasattr(self, '_report_generator') or self._report_generator is None:
            self._report_generator = AutoReportGenerator(framework=self, logger=self.logger)
        return self._report_generator
    
    @property  
    def last_report_path(self) -> Optional[Path]:
        """[v2.5.17] Chemin du dernier rapport généré."""
        return getattr(self, '_last_report_path', None)
    
    def open_last_report(self):
        """[v2.5.17] Ouvre le dernier rapport dans le navigateur."""
        if self.last_report_path and self.last_report_path.exists():
            self.report_generator.open_in_browser(self.last_report_path)
        else:
            self.logger.warn("Aucun rapport disponible. Exécutez run_on_qpu() d'abord.")
    
    # =========================================================================
    # [v2.7.0] MODE COLLECTION DE CIRCUITS
    # =========================================================================
    # Permet d'accumuler les circuits de plusieurs run_on_qpu() pour générer
    # un rapport unique à la fin contenant TOUS les circuits.
    #
    # Usage:
    #   fw.start_circuit_collection()
    #   fw.run_on_qpu(circuits_off, ...)  # Circuits accumulés
    #   fw.run_on_qpu(circuits_on, ...)   # Circuits accumulés
    #   ... répéter ...
    #   fw.stop_circuit_collection()  # Génère rapport avec TOUS les circuits
    #
    # Note: Compatible avec _in_multijob_context pour confirmation unique
    # =========================================================================
    
    def start_circuit_collection(self, max_circuits: int = 500):
        """
        [v2.7.0] Démarre la collection de circuits pour rapport unifié.
        
        Tous les circuits passés à run_on_qpu() seront accumulés jusqu'à
        l'appel de stop_circuit_collection() qui générera un rapport unique.
        
        Args:
            max_circuits: Limite max de circuits à collecter (défaut: 500)
                         Pour éviter une consommation mémoire excessive.
        
        Example:
            >>> fw.start_circuit_collection()
            >>> fw.run_on_qpu(circuits_off_1, ...)
            >>> fw.run_on_qpu(circuits_on_1, ...)
            >>> fw.run_on_qpu(circuits_off_2, ...)
            >>> fw.run_on_qpu(circuits_on_2, ...)
            >>> report_path = fw.stop_circuit_collection()
            >>> print(f"Rapport avec tous les circuits: {report_path}")
        """
        self._collecting_circuits = True
        self._collected_circuits = []
        self._collection_max = max_circuits
        self._collection_results = []  # Aussi collecter les résultats
        self._collection_start_time = time.time()
        self.logger.info(f"🔄 Mode collection activé (max {max_circuits} circuits)")
    
    def stop_circuit_collection(self, 
                                generate_report: bool = True,
                                report_title: str = None) -> Optional[Path]:
        """
        [v2.7.0] Arrête la collection et génère un rapport unifié.
        
        Args:
            generate_report: Si True, génère un rapport HTML avec tous les circuits
            report_title: Titre personnalisé pour le rapport
            
        Returns:
            Path du rapport généré, ou None si generate_report=False
        """
        if not getattr(self, '_collecting_circuits', False):
            self.logger.warn("⚠️ Aucune collection en cours")
            return None
        
        self._collecting_circuits = False
        collected = getattr(self, '_collected_circuits', [])
        n_collected = len(collected)
        
        elapsed = time.time() - getattr(self, '_collection_start_time', time.time())
        
        self.logger.info(f"📊 Collection terminée: {n_collected} circuits en {elapsed:.1f}s")
        
        report_path = None
        
        if generate_report and n_collected > 0:
            # Utiliser les circuits collectés pour le rapport
            self._last_transpiled_circuits = collected
            
            # [v2.7.0 FIX] Générer le rapport unifié avec les VRAIES données du framework
            # Récupérer le run_context du dernier job si disponible
            last_run_context = getattr(self, '_last_run_context', {})
            
            run_context = {
                # Données de collection
                'collection_mode': True,
                'total_circuits': n_collected,
                'collection_time_s': elapsed,
                'circuits_count': n_collected,
                
                # Données du dernier job (pour avoir backend, shots, etc.)
                'shots': last_run_context.get('shots', 0),
                'backend': self.backend_name if hasattr(self, 'backend_name') else 'N/A',
                'job_id': last_run_context.get('job_id', 'COLLECTION'),
                'optimization_level': last_run_context.get('optimization_level', 3),
                'layout_strategy': last_run_context.get('layout_strategy', 'auto'),
                
                # Timing agrégé
                'total_time_s': elapsed,
                'qpu_time_s': sum(r.get('qpu_time_s', 0) for r in getattr(self, '_collection_results', []) if isinstance(r, dict)),
                'queue_time_s': last_run_context.get('queue_time_s', 0),
                'transpile_time_s': last_run_context.get('transpile_time_s', 0),
                
                # Timestamps
                'timestamp': datetime.now().isoformat(),
                'submitted_at': last_run_context.get('submitted_at', 'N/A'),
                'completed_at': datetime.now().strftime('%H:%M:%S'),
            }
            
            title = report_title or f"QMC Collection Report - {n_collected} circuits"
            
            try:
                # Collecter tous les résultats (flatten si liste de listes)
                all_results = []
                for r in getattr(self, '_collection_results', []):
                    if isinstance(r, list):
                        all_results.extend(r)
                    elif isinstance(r, dict):
                        all_results.append(r)
                
                report_path = self.report_generator.generate(
                    results=all_results if all_results else None,
                    run_context=run_context,
                    title=title,
                    transpiled_circuits=collected
                )
                self._last_report_path = report_path
                self.logger.info(f"📄 Rapport unifié: {report_path}")
            except Exception as e:
                self.logger.warn(f"⚠️ Erreur génération rapport: {e}")
        
        # Nettoyer
        self._collected_circuits = []
        self._collection_results = []
        
        return report_path
    
    def get_collected_circuits_count(self) -> int:
        """[v2.7.0] Retourne le nombre de circuits collectés."""
        return len(getattr(self, '_collected_circuits', []))
    
    def is_collecting_circuits(self) -> bool:
        """[v2.7.0] Retourne True si le mode collection est actif."""
        return getattr(self, '_collecting_circuits', False)

    def _get_job_error_details(self, job) -> Dict[str, Any]:
        """
        [v2.5.15] Récupère les détails d'erreur d'un job IBM Quantum.
        
        Extrait toutes les informations disponibles sur l'erreur:
        - Message d'erreur
        - Code d'erreur
        - Raison de l'échec
        - Métadonnées supplémentaires
        
        Args:
            job: Objet job IBM Runtime
            
        Returns:
            Dict avec les détails de l'erreur
        """
        error_details = {
            'error_message': None,
            'error_code': None,
            'reason': None,
            'status': None,
            'backend': None,
            'creation_date': None,
            'raw_error': None,
            'job_tags': None,
        }
        
        try:
            # Status du job
            if hasattr(job, 'status'):
                try:
                    error_details['status'] = str(job.status())
                except:
                    pass
            
            # Message d'erreur - plusieurs méthodes possibles
            # Méthode 1: error_message() (Qiskit Runtime récent)
            if hasattr(job, 'error_message'):
                try:
                    msg = job.error_message()
                    if msg:
                        error_details['error_message'] = str(msg)
                except Exception as e:
                    error_details['raw_error'] = str(e)
            
            # Méthode 2: result().get_error() ou similar
            if not error_details['error_message'] and hasattr(job, 'result'):
                try:
                    result = job.result()
                    if hasattr(result, 'get_error'):
                        error_details['error_message'] = str(result.get_error())
                except Exception as e:
                    # Le result() peut lever une exception avec le message d'erreur
                    error_str = str(e)
                    if error_str and len(error_str) > 5:
                        error_details['error_message'] = error_str
            
            # Méthode 3: Attribut _error ou _error_message
            for attr in ['_error', '_error_message', 'error', '_api_error']:
                if hasattr(job, attr):
                    try:
                        val = getattr(job, attr)
                        if val:
                            error_details['error_message'] = str(val)
                            break
                    except:
                        pass
            
            # Métadonnées du job
            if hasattr(job, 'backend'):
                try:
                    backend = job.backend()
                    if hasattr(backend, 'name'):
                        error_details['backend'] = backend.name
                    else:
                        error_details['backend'] = str(backend)
                except:
                    pass
            
            # Date de création
            if hasattr(job, 'creation_date'):
                try:
                    error_details['creation_date'] = str(job.creation_date())
                except:
                    pass
            
            # Tags du job (peut contenir des infos utiles)
            if hasattr(job, 'tags'):
                try:
                    error_details['job_tags'] = job.tags()
                except:
                    pass
            
            # Méthode 4: Vérifier les métadonnées/propriétés
            if hasattr(job, 'properties'):
                try:
                    props = job.properties()
                    if props and isinstance(props, dict):
                        if 'error' in props:
                            error_details['error_message'] = str(props['error'])
                        if 'error_code' in props:
                            error_details['error_code'] = str(props['error_code'])
                except:
                    pass
            
            # Méthode 5: Accès direct aux attributs internes (fallback)
            if not error_details['error_message']:
                for attr in dir(job):
                    if 'error' in attr.lower() and not attr.startswith('__'):
                        try:
                            val = getattr(job, attr)
                            if callable(val):
                                val = val()
                            if val and str(val) not in ['None', '']:
                                if not error_details['error_message']:
                                    error_details['error_message'] = f"{attr}: {val}"
                                break
                        except:
                            pass
            
            # Méthode 6: Vérifier le job_id pour des patterns d'erreur connus
            if hasattr(job, 'job_id'):
                try:
                    job_id = job.job_id()
                    error_details['job_id'] = job_id
                except:
                    pass
                    
        except Exception as e:
            error_details['extraction_error'] = str(e)
        
        # Log les détails pour debug
        if self.logger:
            self.logger.debug(f"Job error details extracted: {error_details}")
        
        return error_details
    
    def _extract_ibm_error_details(self, exception: Exception) -> Dict[str, Any]:
        """
        [v2.5.15] Extrait les détails d'erreur d'une exception IBM.
        
        Analyse l'exception pour extraire:
        - Code d'erreur HTTP
        - Message IBM
        - Détails supplémentaires
        
        Args:
            exception: Exception levée par IBM Runtime
            
        Returns:
            Dict avec les détails extraits
        """
        details = {
            'error_code': None,
            'ibm_message': None,
            'http_status': None,
            'request_id': None,
            'raw_response': None,
        }
        
        try:
            error_str = str(exception)
            error_type = type(exception).__name__
            
            # Extraire le code HTTP si présent (ex: "401", "403", "500")
            import re
            http_match = re.search(r'\b(4\d{2}|5\d{2})\b', error_str)
            if http_match:
                details['http_status'] = int(http_match.group(1))
            
            # Chercher un code d'erreur IBM (ex: "ERROR_CODE_XXX")
            code_match = re.search(r'(ERROR[_\-]?CODE[_\-]?\w+|IBM\w+Error)', error_str, re.IGNORECASE)
            if code_match:
                details['error_code'] = code_match.group(1)
            
            # Extraire le message IBM s'il est dans un format JSON
            json_match = re.search(r'\{[^}]*"message"\s*:\s*"([^"]+)"', error_str)
            if json_match:
                details['ibm_message'] = json_match.group(1)
            
            # Chercher un request_id pour le support IBM
            req_id_match = re.search(r'request[_\-]?id["\s:]+([a-zA-Z0-9\-]+)', error_str, re.IGNORECASE)
            if req_id_match:
                details['request_id'] = req_id_match.group(1)
            
            # Vérifier les attributs de l'exception
            for attr in ['message', 'error_message', 'detail', 'response', 'status_code']:
                if hasattr(exception, attr):
                    try:
                        val = getattr(exception, attr)
                        if val:
                            if attr == 'status_code' and not details['http_status']:
                                details['http_status'] = val
                            elif attr == 'message' and not details['ibm_message']:
                                details['ibm_message'] = str(val)
                            elif attr == 'response':
                                details['raw_response'] = str(val)[:500]
                    except:
                        pass
            
            # Vérifier si c'est une exception chaînée (__cause__)
            if hasattr(exception, '__cause__') and exception.__cause__:
                cause_details = self._extract_ibm_error_details(exception.__cause__)
                for key, val in cause_details.items():
                    if val and not details.get(key):
                        details[key] = val
                        
        except Exception as e:
            details['extraction_error'] = str(e)
        
        return details
    
    def _secure_delete_job(self, job, job_id: str):
        """
        [v2.5.14] Suppression sécurisée du job IBM après récupération des résultats.
        
        🔒 SÉCURITÉ CRYPTOGRAPHIQUE:
        Cette fonction supprime le job du cloud IBM pour éviter que les calculs
        cryptographiques sensibles ne soient accessibles après exécution.
        
        ⚠️ IMPORTANT: Les résultats doivent être sauvegardés LOCALEMENT avant l'appel
        car la suppression est IRRÉVERSIBLE.
        
        Args:
            job: Objet job IBM Runtime
            job_id: ID du job pour logging
        """
        try:
            print()
            print("  ┌──────────────────────────────────────────────────────────────────────────┐")
            print("  │  🔒 MODE SÉCURISÉ - SUPPRESSION DU JOB IBM                               │")
            print("  │                                                                          │")
            print(f"  │  Job ID: {job_id:<58} │")
            print("  │                                                                          │")
            print("  │  ⚠️  Les résultats ont été sauvegardés localement.                       │")
            print("  │  🗑️  Suppression du job IBM en cours...                                  │")
            print("  └──────────────────────────────────────────────────────────────────────────┘")
            
            # Tenter la suppression via l'API IBM
            deleted = False
            
            # Méthode 1: job.delete() si disponible (Qiskit Runtime récent)
            if hasattr(job, 'delete'):
                try:
                    job.delete()
                    deleted = True
                    self.logger.info(f"🔒 Job {job_id} supprimé via job.delete()")
                except Exception as e:
                    self.logger.debug(f"job.delete() non disponible: {e}")
            
            # Méthode 2: service.delete_job() si disponible
            if not deleted and self.service and hasattr(self.service, 'delete_job'):
                try:
                    self.service.delete_job(job_id)
                    deleted = True
                    self.logger.info(f"🔒 Job {job_id} supprimé via service.delete_job()")
                except Exception as e:
                    self.logger.debug(f"service.delete_job() non disponible: {e}")
            
            # Méthode 3: Marquer pour suppression via tags (fallback)
            if not deleted:
                try:
                    # Certaines versions permettent de mettre à jour les tags
                    if hasattr(job, 'update_tags'):
                        job.update_tags(['QMC_TO_DELETE', 'CONFIDENTIAL'])
                        self.logger.warn(f"⚠️ Job {job_id} marqué pour suppression manuelle (tags)")
                    else:
                        self.logger.warn(f"⚠️ Suppression automatique non supportée - "
                                        f"supprimez manuellement le job {job_id} sur IBM Quantum Dashboard")
                except Exception as e:
                    self.logger.warn(f"⚠️ Impossible de marquer le job: {e}")
            
            if deleted:
                print("  ✅ Job supprimé avec succès - Données effacées du cloud IBM")
            else:
                print("  ⚠️  Suppression auto non disponible - Supprimez manuellement sur IBM Dashboard")
            print()
            
        except Exception as e:
            self.logger.error(f"Erreur lors de la suppression du job: {e}")
            print(f"  ❌ Erreur suppression: {e}")
            print(f"  💡 Supprimez manuellement le job {job_id} sur IBM Quantum Dashboard")
            print()
    
    def _apply_private_tags(self, job, job_id: str):
        """
        [v2.5.14] Applique les tags de confidentialité au job IBM.
        
        🔐 SÉCURITÉ: Marque le job avec des tags spéciaux pour indiquer
        qu'il contient des calculs cryptographiques sensibles.
        
        Args:
            job: Objet job IBM Runtime
            job_id: ID du job pour logging
        """
        private_tags = ['QMC_PRIVATE', 'QMC_CONFIDENTIAL', 'CRYPTO_SENSITIVE']
        
        try:
            applied = False
            
            # Méthode 1: job.update_tags() si disponible (Qiskit Runtime récent)
            if hasattr(job, 'update_tags'):
                try:
                    job.update_tags(private_tags)
                    applied = True
                    self.logger.info(f"🔐 Tags privés appliqués via job.update_tags(): {private_tags}")
                except Exception as e:
                    self.logger.debug(f"job.update_tags() échoué: {e}")
            
            # Méthode 2: service.update_job() si disponible
            if not applied and self.service:
                # Essayer différentes API selon la version de Qiskit Runtime
                if hasattr(self.service, 'update_job'):
                    try:
                        self.service.update_job(job_id, tags=private_tags)
                        applied = True
                        self.logger.info(f"🔐 Tags privés appliqués via service.update_job(): {private_tags}")
                    except Exception as e:
                        self.logger.debug(f"service.update_job() échoué: {e}")
                
                # Alternative: _api_client si disponible
                if not applied and hasattr(self.service, '_api_client'):
                    try:
                        self.service._api_client.job_update(job_id, tags=private_tags)
                        applied = True
                        self.logger.info(f"🔐 Tags privés appliqués via _api_client: {private_tags}")
                    except Exception as e:
                        self.logger.debug(f"_api_client.job_update() échoué: {e}")
            
            if applied:
                print(f"  🔐 Tags privés appliqués: {', '.join(private_tags)}")
            else:
                self.logger.warn(f"⚠️ Impossible d'appliquer les tags privés (API non supportée)")
                print(f"  ⚠️ Tags privés non appliqués (API IBM non supportée)")
                print(f"  💡 Le job sera marqué pour suppression manuelle")
                
        except Exception as e:
            self.logger.warn(f"Erreur lors de l'application des tags privés: {e}")

    def _confirm_qpu_submission(self, circuits: List, shots: int) -> bool:
        """
        [v2.5.14] Demande confirmation OBLIGATOIRE avant envoi QPU.
        
        ⚠️ SÉCURITÉ: Cette confirmation est OBLIGATOIRE par défaut pour éviter
        les envois accidentels qui consomment du temps QPU.
        
        Affiche un résumé du job INCLUANT les stats de transpilation pour 
        permettre à l'utilisateur de juger si le circuit est viable.
        
        Args:
            circuits: Liste des circuits à soumettre (déjà transpilés!)
            shots: Nombre de shots par circuit
            
        Returns:
            True si l'utilisateur confirme, False sinon
        """
        n_circuits = len(circuits)
        total_shots = n_circuits * shots
        
        # Calculer les stats des circuits TRANSPILÉS
        # [v2.7.0] Utiliser count_ops() au lieu d'itérer circuit.data (rapide sur gros circuits)
        total_depth = sum(c.depth() for c in circuits)
        total_2q = sum(
            sum(v for k, v in c.count_ops().items() if k in ['cx', 'cz', 'ecr', 'swap', 'rzz', 'rxx', 'ryy'])
            for c in circuits
        )
        max_qubits = max(c.num_qubits for c in circuits) if circuits else 0
        
        # Calculer les moyennes par circuit
        avg_depth = total_depth / n_circuits if n_circuits > 0 else 0
        avg_2q = total_2q / n_circuits if n_circuits > 0 else 0
        
        # [v2.6.0] Estimation du temps QPU avec la FORMULE OFFICIELLE IBM
        # Formule rapide IBM: temps = 2 + 0.00035 × num_executions (secondes)
        # Formule détaillée: overhead + (rep_delay + circuit_length) × num_executions
        
        num_executions = total_shots  # circuits × shots = n_circuits * shots = total_shots
        
        # Méthode 1: Formule rapide IBM officielle
        ibm_quick_time = 2.0 + 0.00035 * num_executions
        
        # Méthode 2: Estimation basée sur les durées réelles si backend disponible
        rep_delay = 250e-6  # 250µs par défaut
        avg_circuit_length = 50e-6  # 50µs typique
        
        if self.backend:
            try:
                rep_delay = getattr(self.backend, 'default_rep_delay', 250e-6) or 250e-6
            except:
                pass
            
            # Estimer la longueur du circuit à partir des portes
            # Durées typiques: 1Q~35ns, 2Q~500ns, measure~1200ns
            avg_circuit_length = (avg_2q * 500e-9 + (avg_depth - avg_2q) * 35e-9 + 1200e-9) * avg_depth
            avg_circuit_length = max(50e-6, min(200e-6, avg_circuit_length))  # Clamp 50-200µs
        
        # Nombre de sub-jobs (IBM divise les gros jobs)
        n_subjobs = max(1, n_circuits // 100, num_executions // 1_000_000)
        
        # [v2.6.0] Overhead ajusté selon la taille du job
        # IBM doc: 2s/sub-job, mais c'est pour gros jobs avec error mitigation
        # Pour petits jobs simples: ~0.5-1s d'overhead total
        if num_executions < 10_000:  # Petit job
            subjob_overhead = 0.5  # 500ms
        elif num_executions < 100_000:  # Job moyen
            subjob_overhead = 1.0 * n_subjobs
        else:  # Gros job
            subjob_overhead = 2.0 * n_subjobs
        
        # Formule détaillée IBM
        ibm_detailed_time = subjob_overhead + (rep_delay + avg_circuit_length) * num_executions
        
        # Utiliser la formule détaillée (plus précise)
        estimated_time_s = ibm_detailed_time
        
        # [v2.6.0] Info backend pour l'affichage - Janvier 2026
        backend_family = {
            'ibm_boston': 'Heron r3',
            'ibm_pittsburgh': 'Heron r3',
            'ibm_kingston': 'Heron r2',
            'ibm_fez': 'Heron r2',
            'ibm_marrakesh': 'Heron r2',
            'ibm_torino': 'Heron r1',
            'ibm_miami': 'Nighthawk r1',
        }.get(self.backend_name, 'Unknown')
        
        # Récupérer les stats de transpilation si disponibles
        trans_stats = getattr(self, '_last_transpilation_stats', None)
        
        print()
        print("  ╔═══════════════════════════════════════════════════════════════════════")
        print("  ║     ⚠️⚠️⚠️  CONFIRMATION OBLIGATOIRE AVANT ENVOI QPU  ⚠️⚠️⚠️")
        print("  ╠═══════════════════════════════════════════════════════════════════════")
        
        # Section TRANSPILATION avec recommandation
        if trans_stats:
            score = trans_stats.get('score', 50)
            overhead = trans_stats.get('overhead_2q_percent', 0)
            swaps = trans_stats.get('swaps_estimated', 0)
            recommendation = trans_stats.get('recommendation', 'WARN')
            
            # Couleur et emoji selon recommandation
            if recommendation == 'GO':
                rec_display = "🟢 GO"
                rec_msg = "Circuit bien optimisé, exécution recommandée"
            elif recommendation == 'WARN':
                rec_display = "🟡 WARN"
                rec_msg = "Overhead modéré, vérifiez si acceptable"
            else:  # NO-GO
                rec_display = "🔴 NO-GO"
                rec_msg = "⚠️ OVERHEAD EXCESSIF - Annulation recommandée!"
            
            print(f"  ║  📐 QUALITÉ TRANSPILATION:")
            print(f"  ║     • Score:         {score}/100 ({rec_display})")
            print(f"  ║     • Overhead 2Q:   {overhead:+.1f}%")
            print(f"  ║     • SWAPs estimés: ~{swaps}")
            print(f"  ║     → {rec_msg}")
            print("  ╠═══════════════════════════════════════════════════════════════════════")
        
        print(f"  ║  📊 RÉSUMÉ DU JOB:")
        print(f"  ║     • Circuits:      {n_circuits}")
        print(f"  ║     • Shots/circuit: {shots:,}")
        print(f"  ║     • Total shots:   {total_shots:,}")
        print(f"  ║     • Max qubits:    {max_qubits}")
        print(f"  ║     • Profondeur:    {avg_depth:.0f} moy/circuit ({total_depth} total)")
        print(f"  ║     • Portes 2Q:     {avg_2q:.0f} moy/circuit ({total_2q} total)")
        print("  ╠═══════════════════════════════════════════════════════════════════════")
        # [v2.6.0] Afficher les infos du backend et l'estimation basée sur formule IBM
        print(f"  ║  🖥️  Backend:         {self.backend_name} ({backend_family})")
        print(f"  ║  📐 Exécutions:      {num_executions:,} (circuits × shots)")
        if estimated_time_s < 1:
            time_str = f"~{estimated_time_s*1000:.0f}ms"
        elif estimated_time_s < 60:
            time_str = f"~{estimated_time_s:.2f}s"
        else:
            time_str = f"~{estimated_time_s/60:.1f}min"
        # Afficher aussi la formule rapide IBM pour comparaison
        if ibm_quick_time < 1:
            quick_str = f"{ibm_quick_time*1000:.0f}ms"
        elif ibm_quick_time < 60:
            quick_str = f"{ibm_quick_time:.2f}s"
        else:
            quick_str = f"{ibm_quick_time/60:.1f}min"
        print(f"  ║  ⏱️  Temps QPU estimé: {time_str}")
        print(f"  ║     └─ Formule IBM:  2 + 0.00035×{num_executions:,} = {quick_str}")
        print("  ╠═══════════════════════════════════════════════════════════════════════")
        print("  ║  💰 ATTENTION: Cet envoi va CONSOMMER du temps QPU!")
        
        # Avertissement spécial si NO-GO
        if trans_stats and trans_stats.get('recommendation') == 'NO-GO':
            print("  ╠═══════════════════════════════════════════════════════════════════════")
            print("  ║  🚨 ATTENTION: Le circuit a un overhead excessif (>100%)!")
            print("  ║     → L'exécution risque de donner des résultats inutilisables")
            print("  ║     → Recommandation: Annuler et revoir la topologie du circuit")
        
        print("  ╚═══════════════════════════════════════════════════════════════════════")
        print()
        
        # Demander confirmation
        try:
            while True:
                if trans_stats and trans_stats.get('recommendation') == 'NO-GO':
                    response = input("  🔴 Circuit déconseillé! Confirmer quand même? [oui/non]: ").strip().lower()
                else:
                    response = input("  🔴 Confirmer l'envoi sur QPU? [oui/non]: ").strip().lower()
                
                if response in ['oui', 'o', 'yes', 'y', '1']:
                    print()
                    print("  ✅ Envoi CONFIRMÉ - Soumission en cours...")
                    print()
                    return True
                elif response in ['non', 'n', 'no', '0']:
                    print()
                    print("  ❌ Envoi ANNULÉ par l'utilisateur")
                    return False
                else:
                    print("  ⚠️ Répondez 'oui' ou 'non'")
                    
        except KeyboardInterrupt:
            print("\n  ❌ Envoi ANNULÉ (Ctrl+C)")
            return False
        except EOFError:
            # Mode non-interactif (pipe, etc.) - annuler par sécurité
            print("\n  ❌ Envoi ANNULÉ (mode non-interactif détecté)")
            print("  💡 Utilisez auto_confirm=True pour les scripts automatisés")
            return False

