class SignatureScheme(Enum):
    """Schémas de signature quantique"""
    LAMPORT_IQP = "lamport_iqp"
    MERKLE_IQP = "merkle_iqp"
    WINTERNITZ_IQP = "winternitz_iqp"


class ZKPProtocol(Enum):
    """Protocoles de preuve à divulgation nulle"""
    SIGMA_IQP = "sigma_iqp"
    SCHNORR_QUANTUM = "schnorr_quantum"
    RANGE_PROOF = "range_proof"
    SET_MEMBERSHIP = "set_membership"


class TimeLockMode(Enum):
    """Modes de verrouillage temporel"""
    FORWARD = "forward"      # Ne peut pas déchiffrer AVANT une date
    EXPIRING = "expiring"    # Ne peut pas déchiffrer APRÈS une date
    WINDOW = "window"        # Déchiffrement possible dans une fenêtre


