# NOUVEAUX CIRCUIT BUILDERS
# =============================================================================

class QuantumSignatureBuilder(CircuitBuilder):
    """
    Constructeur de circuits pour signatures numériques quantiques.
    
    Référence brevet retirée (primitive générique)
    - Signature basée sur IQP avec paramètres dérivés du hash du message
    - Taille de signature indépendante de la longueur du message
    - Vérification par batch via exécution combinée
    
    Architecture:
    H⊗n → RZ(θ_key) → CZ(pattern) → RZ(φ_hash) → H⊗n → Mesure
    
    La signature = distribution quantique unique au couple (clé, message)
    """
    
    name = "quantum_signature"
    
    def __init__(self, topology: 'DynamicTopology' = None, logger: 'Logger' = None):
        super().__init__(topology, logger)
        self._signature_scheme = SignatureScheme.LAMPORT_IQP
    
    def build(self, message_hash: bytes, n_qubits: int = 50,
              key_seed: bytes = None, verification_mode: bool = False,
              add_measurements: bool = True) -> 'CircuitType':
        """
        Construit un circuit de signature quantique.
        
        Args:
            message_hash: Hash SHA-256 du message à signer
            n_qubits: Nombre de qubits
            key_seed: Graine de la clé privée (256 bits)
            verification_mode: Si True, circuit pour vérification
            add_measurements: Ajouter les mesures
        
        Returns:
            Circuit quantique de signature
        """
        from qiskit import QuantumCircuit, QuantumRegister, ClassicalRegister
        
        if key_seed is None:
            key_seed = secrets.token_bytes(32)
        
        # Convertir en bytes si nécessaire (string ou hex)
        if isinstance(message_hash, str):
            # Si c'est une string hex, décoder
            try:
                if all(c in '0123456789abcdefABCDEF' for c in message_hash):
                    message_hash = bytes.fromhex(message_hash)
                else:
                    message_hash = message_hash.encode('utf-8')
            except Exception:
                message_hash = message_hash.encode('utf-8')
        
        if len(message_hash) < 32:
            message_hash = hashlib.sha256(message_hash).digest()
        
        path = self.get_optimal_path(n_qubits)[:n_qubits]
        max_qubit = max(path) + 1
        
        qr = QuantumRegister(max_qubit, 'q')
        cr = ClassicalRegister(n_qubits, 'c') if add_measurements else None
        
        mode_str = "verify" if verification_mode else "sign"
        if cr:
            qc = QuantumCircuit(qr, cr, name=f"QSig_{mode_str}_{n_qubits}Q")
        else:
            qc = QuantumCircuit(qr, name=f"QSig_{mode_str}_{n_qubits}Q")
        
        # Layer 1: Hadamard initial
        for q in path:
            qc.h(q)
        
        qc.barrier()
        
        # Layer 2: Rotations RZ dérivées de la clé
        key_angles = self._derive_angles_from_bytes(key_seed, n_qubits)
        for i, q in enumerate(path):
            qc.rz(key_angles[i], q)
        
        qc.barrier()
        
        # Layer 3: Portes CZ - pattern dérivé de la clé
        cz_pairs = self._derive_cz_pattern(key_seed, path, self.topology)
        for q1, q2 in cz_pairs:
            qc.cz(q1, q2)
        
        qc.barrier()
        
        # Layer 4: Rotations RZ dérivées du hash du message
        hash_angles = self._derive_angles_from_bytes(message_hash, n_qubits)
        for i, q in enumerate(path):
            qc.rz(hash_angles[i], q)
        
        qc.barrier()
        
        # Layer 5: Hadamard final
        for q in path:
            qc.h(q)
        
        # Layer 6: Mesures
        if add_measurements:
            for i, q in enumerate(path):
                qc.measure(q, i)
        
        self._metadata['signature_scheme'] = self._signature_scheme.value
        self._metadata['message_hash'] = message_hash.hex()[:16] + "..."
        self._metadata['verification_mode'] = verification_mode
        self._log(f"Built Quantum Signature circuit: {n_qubits}Q, mode={mode_str}")
        
        return qc
    
    def build_batch_verification(self, signatures: List[Tuple[bytes, bytes]], 
                                  n_qubits: int = 50) -> 'CircuitType':
        """
        Construit un circuit pour vérification batch de plusieurs signatures.
        
        Args:
            signatures: Liste de tuples (message_hash, key_seed)
            n_qubits: Nombre de qubits par signature
        
        Returns:
            Circuit combiné pour vérification batch
        """
        from qiskit import QuantumCircuit, QuantumRegister, ClassicalRegister

        # [v2.7.1 FIX] L'ancien code construisait un circuit par signature mais
        # ne RETOURNAIT QUE LE PREMIER -> une seule signature était réellement
        # vérifiée. On itère désormais sur TOUTES les signatures et on les
        # compose dans un unique circuit batch, chacune sur un bloc de qubits
        # DISJOINT (et son propre registre classique), de sorte que chaque
        # signature soit effectivement exécutée/vérifiée.
        circuits = []
        for msg_hash, key_seed in signatures:
            circuit = self.build(msg_hash, n_qubits, key_seed,
                                 verification_mode=True, add_measurements=False)
            circuits.append(circuit)

        if not circuits:
            return None

        # Largeur (nombre de qubits) de chaque sous-circuit de signature
        block_width = max(c.num_qubits for c in circuits)
        n_sigs = len(circuits)

        qr = QuantumRegister(block_width * n_sigs, 'q')
        # Un registre classique par signature pour distinguer les résultats
        cregs = [ClassicalRegister(block_width, f'c{idx}') for idx in range(n_sigs)]
        combined = QuantumCircuit(qr, *cregs, name=f"QSig_batch_{n_sigs}sigs")

        for idx, sub in enumerate(circuits):
            offset = idx * block_width
            target_qubits = list(range(offset, offset + sub.num_qubits))
            # Composer le sous-circuit sur son bloc de qubits dédié
            combined.compose(sub, qubits=target_qubits, inplace=True)
            # Mesurer le bloc dans son registre classique dédié
            for q in range(sub.num_qubits):
                combined.measure(offset + q, cregs[idx][q])

        return combined
    
    def _derive_angles_from_bytes(self, data: bytes, n: int) -> List[float]:
        """Dérive n angles depuis des bytes via SHAKE-256"""
        extended = hashlib.shake_256(data).digest(n * 4)
        angles = []
        for i in range(n):
            val = struct.unpack('>I', extended[i*4:(i+1)*4])[0]
            angle = (val / (2**32)) * 2 * np.pi
            angles.append(angle)
        return angles
    
    def _derive_cz_pattern(self, seed: bytes, path: List[int], 
                           topology: 'DynamicTopology') -> List[Tuple[int, int]]:
        """Dérive le pattern CZ depuis la seed et la topologie"""
        pairs = []
        n = len(path)
        
        # Utiliser la seed pour sélectionner ~50% des connexions possibles
        hash_val = int.from_bytes(hashlib.sha256(seed).digest()[:8], 'big')
        
        for i in range(n - 1):
            # Pattern linéaire avec sélection basée sur la seed
            if (hash_val >> (i % 64)) & 1:
                pairs.append((path[i], path[i + 1]))
        
        return pairs


class ZKPBuilder(CircuitBuilder):
    """
    Constructeur de circuits pour preuves à divulgation nulle quantiques.
    
    Référence brevet retirée (primitive générique)
    - Protocole Sigma à 3 phases: Commitment → Challenge → Response
    - Preuves de connaissance de clé secrète
    - Range proofs et set membership
    
    Propriétés:
    - Completeness: Prouveur honnête convainc toujours
    - Soundness: Prouveur malhonnête échoue avec haute probabilité
    - Zero-Knowledge: Vérificateur n'apprend rien d'autre
    """
    
    name = "zkp"
    
    def __init__(self, topology: 'DynamicTopology' = None, logger: 'Logger' = None):
        super().__init__(topology, logger)
        self._protocol = ZKPProtocol.SIGMA_IQP
    
    def build(self, n_qubits: int = 50, **params) -> 'CircuitType':
        """
        Méthode build() par défaut - construit un commitment.
        
        Pour un contrôle plus fin, utiliser build_commitment(), 
        build_challenge(), ou build_response().
        """
        secret = params.get('secret', secrets.token_bytes(16))
        nonce = params.get('nonce', secrets.token_bytes(32))
        return self.build_commitment(secret, nonce, n_qubits)
    
    def build_commitment(self, secret_value: bytes, nonce: bytes = None,
                         n_qubits: int = 50, add_measurements: bool = True) -> 'CircuitType':
        """
        Phase 1: Génère un circuit de commitment.
        
        Le commitment cache la valeur secrète tout en permettant
        une vérification ultérieure.
        
        Args:
            secret_value: Valeur à prouver
            nonce: Valeur aléatoire pour le binding
            n_qubits: Nombre de qubits
        
        Returns:
            Circuit de commitment
        """
        from qiskit import QuantumCircuit, QuantumRegister, ClassicalRegister
        
        if nonce is None:
            nonce = secrets.token_bytes(32)
        
        path = self.get_optimal_path(n_qubits)[:n_qubits]
        max_qubit = max(path) + 1
        
        qr = QuantumRegister(max_qubit, 'q')
        cr = ClassicalRegister(n_qubits, 'c') if add_measurements else None
        
        if cr:
            qc = QuantumCircuit(qr, cr, name=f"ZKP_commit_{n_qubits}Q")
        else:
            qc = QuantumCircuit(qr, name=f"ZKP_commit_{n_qubits}Q")
        
        # Combiner secret et nonce
        combined = hashlib.sha256(secret_value + nonce).digest()
        
        # Hadamard initial
        for q in path:
            qc.h(q)
        
        qc.barrier()
        
        # Rotations basées sur le commitment
        commit_angles = self._derive_angles(combined, n_qubits)
        for i, q in enumerate(path):
            qc.rz(commit_angles[i], q)
        
        # Intrication
        for i in range(len(path) - 1):
            qc.cz(path[i], path[i + 1])
        
        qc.barrier()
        
        # Hadamard final
        for q in path:
            qc.h(q)
        
        if add_measurements:
            for i, q in enumerate(path):
                qc.measure(q, i)
        
        self._metadata['phase'] = 'commitment'
        self._metadata['nonce_hash'] = hashlib.sha256(nonce).hexdigest()[:16]
        self._log(f"Built ZKP Commitment circuit: {n_qubits}Q")
        
        return qc
    
    def build_challenge(self, commitment_result: Dict, 
                        n_qubits: int = 50) -> Tuple['CircuitType', bytes]:
        """
        Phase 2: Génère un challenge basé sur le commitment.
        
        Args:
            commitment_result: Résultat de l'exécution du commitment
            n_qubits: Nombre de qubits
        
        Returns:
            Tuple (circuit_challenge, challenge_bytes)
        """
        from qiskit import QuantumCircuit, QuantumRegister, ClassicalRegister
        
        # Générer le challenge depuis les counts du commitment
        counts = commitment_result.get('counts', {})
        counts_hash = hashlib.sha256(json.dumps(counts, sort_keys=True).encode()).digest()
        
        # Ajouter de l'aléatoire du vérificateur
        verifier_random = secrets.token_bytes(16)
        challenge = hashlib.sha256(counts_hash + verifier_random).digest()
        
        path = self.get_optimal_path(n_qubits)[:n_qubits]
        max_qubit = max(path) + 1
        
        qr = QuantumRegister(max_qubit, 'q')
        cr = ClassicalRegister(n_qubits, 'c')
        
        qc = QuantumCircuit(qr, cr, name=f"ZKP_challenge_{n_qubits}Q")
        
        # Circuit minimaliste pour le challenge
        challenge_angles = self._derive_angles(challenge, n_qubits)
        
        for i, q in enumerate(path):
            qc.h(q)
            qc.rz(challenge_angles[i], q)
            qc.h(q)
            qc.measure(q, i)
        
        self._metadata['phase'] = 'challenge'
        self._log(f"Built ZKP Challenge circuit: {n_qubits}Q")
        
        return qc, challenge
    
    def build_response(self, secret_value: bytes, nonce: bytes, 
                       challenge: bytes, n_qubits: int = 50,
                       add_measurements: bool = True) -> 'CircuitType':
        """
        Phase 3: Génère la réponse du prouveur.
        
        Args:
            secret_value: Valeur secrète originale
            nonce: Nonce du commitment
            challenge: Challenge du vérificateur
            n_qubits: Nombre de qubits
        
        Returns:
            Circuit de réponse
        """
        from qiskit import QuantumCircuit, QuantumRegister, ClassicalRegister
        
        path = self.get_optimal_path(n_qubits)[:n_qubits]
        max_qubit = max(path) + 1
        
        qr = QuantumRegister(max_qubit, 'q')
        cr = ClassicalRegister(n_qubits, 'c') if add_measurements else None
        
        if cr:
            qc = QuantumCircuit(qr, cr, name=f"ZKP_response_{n_qubits}Q")
        else:
            qc = QuantumCircuit(qr, name=f"ZKP_response_{n_qubits}Q")
        
        # Réponse = f(secret, nonce, challenge)
        response_data = hashlib.sha256(secret_value + nonce + challenge).digest()
        response_angles = self._derive_angles(response_data, n_qubits)
        
        # Hadamard
        for q in path:
            qc.h(q)
        
        qc.barrier()
        
        # Rotations de réponse
        for i, q in enumerate(path):
            qc.rz(response_angles[i], q)
        
        # Intrication conditionnée par le challenge
        challenge_bits = int.from_bytes(challenge[:8], 'big')
        for i in range(len(path) - 1):
            if (challenge_bits >> (i % 64)) & 1:
                qc.cz(path[i], path[i + 1])
        
        qc.barrier()
        
        # Hadamard final
        for q in path:
            qc.h(q)
        
        if add_measurements:
            for i, q in enumerate(path):
                qc.measure(q, i)
        
        self._metadata['phase'] = 'response'
        self._log(f"Built ZKP Response circuit: {n_qubits}Q")
        
        return qc
    
    def build_range_proof(self, value: int, lower: int, upper: int,
                          n_qubits: int = 50) -> 'CircuitType':
        """
        Construit une preuve que value ∈ [lower, upper] sans révéler value.
        
        Args:
            value: Valeur à prouver
            lower: Borne inférieure
            upper: Borne supérieure
            n_qubits: Nombre de qubits
        
        Returns:
            Circuit de range proof
        """
        from qiskit import QuantumCircuit, QuantumRegister, ClassicalRegister
        
        # Encoder la preuve [v2.7.1: encodage texte robuste — l'ancien struct.pack
        # '>QQQ' plantait pour value négatif ou > 2^64]
        proof_data = f"{int(value)}|{int(lower)}|{int(upper)}".encode()
        nonce = secrets.token_bytes(16)
        commitment = hashlib.sha256(proof_data + nonce).digest()
        
        path = self.get_optimal_path(n_qubits)[:n_qubits]
        max_qubit = max(path) + 1
        
        qr = QuantumRegister(max_qubit, 'q')
        cr = ClassicalRegister(n_qubits, 'c')
        
        qc = QuantumCircuit(qr, cr, name=f"ZKP_range_{lower}_{upper}")
        
        # Circuit IQP pour la range proof
        angles = self._derive_angles(commitment, n_qubits)
        
        for q in path:
            qc.h(q)
        
        for i, q in enumerate(path):
            qc.rz(angles[i], q)
        
        # [v2.7.1 FIX] Le pattern CZ est désormais dérivé du COMMITMENT (et non de
        # la valeur normalisée). L'ancien code calculait n_cz = int(normalized*(len-1))
        # ce qui (1) levait IndexError pour value > upper (n_cz >= len(path)) et
        # (2) FUITAIT la valeur secrète : le nombre de portes CZ était une fonction
        # monotone déterministe de `value`. On borne la boucle et on masque la valeur.
        # La garantie cryptographique de bornes provient de la preuve CLASSIQUE
        # QMCSigmaZK.range_prove (cf. make_range_proof) ; ce circuit n'est qu'un
        # artefact d'engagement quantique sans rôle de sécurité.
        cz_pattern = self._derive_angles(commitment, max(1, len(path) - 1))
        for i in range(len(path) - 1):
            if cz_pattern[i] > np.pi:   # ~50% des positions, déterminé par le commitment
                qc.cz(path[i], path[i + 1])

        for q in path:
            qc.h(q)

        for i, q in enumerate(path):
            qc.measure(q, i)

        self._metadata['proof_type'] = 'range'
        self._metadata['range'] = f"[{lower}, {upper}]"
        self._log(f"Built Range Proof circuit: {n_qubits}Q, range=[{lower},{upper}]")

        return qc

    # -- [v2.7.1] Preuves ZK CLASSIQUES vérifiables (garanties réelles) --
    def make_range_proof(self, value: int, lower: int, upper: int) -> Dict:
        """Produit une preuve ZK NON-INTERACTIVE et VÉRIFIABLE que value ∈ [lower, upper]
        sans révéler value (QMCSigmaZK : Pedersen + OR-proofs + Fiat-Shamir). Lève
        QMCSecurityError si value est hors bornes (au lieu de fuiter/crasher)."""
        return QMCSigmaZK.range_prove(value, lower, upper)

    @staticmethod
    def verify_range_proof(proof: Dict) -> bool:
        """Vérifie une preuve de make_range_proof. True ssi la preuve est valide."""
        return QMCSigmaZK.range_verify(proof)

    def prove_secret_knowledge(self, secret_int: int):
        """Preuve de connaissance d'un secret x (y = g^x publié). Renvoie (proof, y)."""
        x = int(secret_int) % QMCSigmaZK.Q
        proof = QMCSigmaZK.prove_knowledge(x)
        return proof, proof['y']

    @staticmethod
    def verify_secret_knowledge(proof: Dict) -> bool:
        """Vérifie une preuve de connaissance (Schnorr). True ssi valide."""
        return QMCSigmaZK.verify_knowledge(proof)
    
    def _derive_angles(self, data: bytes, n: int) -> List[float]:
        """Dérive n angles depuis des bytes"""
        extended = hashlib.shake_256(data).digest(n * 4)
        angles = []
        for i in range(n):
            val = struct.unpack('>I', extended[i*4:(i+1)*4])[0]
            angle = (val / (2**32)) * 2 * np.pi
            angles.append(angle)
        return angles


class TimeLockBuilder(CircuitBuilder):
    """
    Constructeur de circuits pour chiffrement temporel.
    
    Référence brevet retirée (primitive générique)
    - Forward time-lock: Déchiffrement impossible AVANT une date
    - Expiring time-lock: Déchiffrement impossible APRÈS une date
    - Exploite la dérive de calibration du processeur quantique
    
    Principe: Les paramètres du circuit sont liés aux caractéristiques
    de calibration qui évoluent dans le temps, créant une contrainte
    temporelle intrinsèque.
    """
    
    name = "timelock"
    
    def __init__(self, topology: 'DynamicTopology' = None, logger: 'Logger' = None):
        super().__init__(topology, logger)
        self._calibration_drift_rate = 0.001  # Dérive typique par heure
    
    def build(self, n_qubits: int = 50, **params) -> 'CircuitType':
        """
        Méthode build() par défaut - construit un forward time-lock.
        
        Pour un contrôle plus fin, utiliser build_forward_lock(), 
        build_expiring_lock(), ou build_window_lock().
        """
        data = params.get('data', secrets.token_bytes(32))
        unlock_time = params.get('unlock_time', datetime.now() + timedelta(hours=24))
        return self.build_forward_lock(data, unlock_time, n_qubits)
    
    def build_forward_lock(self, data: bytes, unlock_time: datetime,
                           n_qubits: int = 50, calibration_ref: Dict = None,
                           add_measurements: bool = True) -> 'CircuitType':
        """
        Construit un circuit "forward time-lock".
        
        Le déchiffrement ne sera possible qu'APRÈS unlock_time car le
        circuit est paramétré pour la calibration future estimée.
        
        Args:
            data: Données à protéger
            unlock_time: Date à partir de laquelle le déchiffrement est possible
            n_qubits: Nombre de qubits
            calibration_ref: Calibration de référence actuelle
            add_measurements: Ajouter les mesures
        
        Returns:
            Circuit time-locked
        """
        from qiskit import QuantumCircuit, QuantumRegister, ClassicalRegister
        
        now = datetime.now()
        hours_until_unlock = max(0, (unlock_time - now).total_seconds() / 3600)
        
        # Estimer la calibration future
        future_drift = self._estimate_calibration_drift(hours_until_unlock)
        
        path = self.get_optimal_path(n_qubits)[:n_qubits]
        max_qubit = max(path) + 1
        
        qr = QuantumRegister(max_qubit, 'q')
        cr = ClassicalRegister(n_qubits, 'c') if add_measurements else None
        
        if cr:
            qc = QuantumCircuit(qr, cr, name=f"TL_forward_{n_qubits}Q")
        else:
            qc = QuantumCircuit(qr, name=f"TL_forward_{n_qubits}Q")
        
        # Encoder le temps dans les paramètres
        time_seed = struct.pack('>d', unlock_time.timestamp()) + data[:24]
        time_angles = self._derive_angles(time_seed, n_qubits)
        
        # Hadamard initial
        for q in path:
            qc.h(q)
        
        qc.barrier()
        
        # Rotations basées sur la calibration FUTURE estimée
        for i, q in enumerate(path):
            # L'angle inclut la dérive estimée
            adjusted_angle = time_angles[i] * (1 + future_drift[i % len(future_drift)])
            qc.rz(adjusted_angle, q)
        
        # Portes CZ
        for i in range(len(path) - 1):
            qc.cz(path[i], path[i + 1])
        
        qc.barrier()
        
        # Rotations de données
        data_hash = hashlib.sha256(data).digest()
        data_angles = self._derive_angles(data_hash, n_qubits)
        for i, q in enumerate(path):
            qc.rz(data_angles[i], q)
        
        qc.barrier()
        
        # Hadamard final
        for q in path:
            qc.h(q)
        
        if add_measurements:
            for i, q in enumerate(path):
                qc.measure(q, i)
        
        self._metadata['timelock_mode'] = 'forward'
        self._metadata['unlock_time'] = unlock_time.isoformat()
        self._metadata['hours_until_unlock'] = round(hours_until_unlock, 2)
        # [v2.7.1] Ce circuit est un ARTEFACT d'engagement : il n'impose aucune
        # contrainte temporelle réelle. Pour un vrai time-lock, utiliser
        # make_forward_lock() / open_forward_lock() (puzzle RSW QMCTimeLock).
        self._metadata['security_note'] = 'circuit artifact only; use make_forward_lock for real timelock'
        self._log(f"Built Forward TimeLock: unlocks at {unlock_time.isoformat()}")

        return qc

    # -- [v2.7.1] Time-lock cryptographique RÉEL (puzzle RSW) --
    def make_forward_lock(self, data: bytes, unlock_time: datetime,
                          squarings_per_second: int = 200000) -> Dict:
        """Crée un forward time-lock RÉEL et reproductible (QMCTimeLock/RSW). Le
        nombre de carrés séquentiels est calibré sur le délai souhaité et le débit
        machine `squarings_per_second`. Renvoie un puzzle sérialisable + décodable."""
        delay_s = max(0.0, (unlock_time - datetime.now()).total_seconds())
        squarings = max(1, int(delay_s * max(1, squarings_per_second)))
        puzzle = QMCTimeLock.create(data, squarings=squarings)
        puzzle['unlock_time'] = unlock_time.isoformat()
        puzzle['squarings_per_second_assumed'] = squarings_per_second
        return puzzle

    @staticmethod
    def open_forward_lock(puzzle: Dict) -> bytes:
        """Ouvre un puzzle de make_forward_lock (effectue le travail séquentiel)."""
        return QMCTimeLock.solve(puzzle)

    def make_expiring_lock(self, data: bytes, expire_time: datetime) -> Dict:
        """[v2.7.1] EXPIRING lock honnête. Une expiration purement cryptographique
        est IMPOSSIBLE (rien n'empêche de garder une copie). On chiffre en
        AES-256-GCM sous une clé aléatoire ; l'expiration est appliquée en
        DÉTRUISANT `key_hex` à expire_time (effacement de clé = expiration)."""
        key = secrets.token_bytes(32)
        enc = QMCQuantumCrypto.aead_encrypt(key, data, aad=b"QMC-expiring")
        return {'mode': 'expiring', 'algorithm': 'AES-256-GCM + key-erasure',
                'expire_time': expire_time.isoformat(),
                'key_hex': key.hex(),  # À EFFACER à expire_time pour matérialiser l'expiration
                'nonce': enc['nonce'].hex(), 'ciphertext': enc['ciphertext'].hex(),
                'note': 'Crypto-only expiry is impossible; delete key_hex at expire_time.'}

    @staticmethod
    def open_expiring_lock(blob: Dict) -> bytes:
        if not blob.get('key_hex'):
            raise QMCSecurityError("expiring lock : clé effacée (expiré)",
                                   operation="open_expiring_lock")
        return QMCQuantumCrypto.aead_decrypt(
            bytes.fromhex(blob['key_hex']), bytes.fromhex(blob['nonce']),
            bytes.fromhex(blob['ciphertext']), aad=b"QMC-expiring")

    def build_expiring_lock(self, data: bytes, expire_time: datetime,
                            n_qubits: int = 50, calibration_ref: Dict = None,
                            add_measurements: bool = True) -> 'CircuitType':
        """
        Construit un circuit "expiring time-lock".
        
        Le déchiffrement ne sera possible que jusqu'à expire_time,
        après quoi la dérive de calibration rendra le circuit inutilisable.
        
        Args:
            data: Données à protéger
            expire_time: Date après laquelle le déchiffrement devient impossible
            n_qubits: Nombre de qubits
            calibration_ref: Calibration de référence actuelle
            add_measurements: Ajouter les mesures
        
        Returns:
            Circuit avec expiration
        """
        from qiskit import QuantumCircuit, QuantumRegister, ClassicalRegister
        
        path = self.get_optimal_path(n_qubits)[:n_qubits]
        max_qubit = max(path) + 1
        
        qr = QuantumRegister(max_qubit, 'q')
        cr = ClassicalRegister(n_qubits, 'c') if add_measurements else None
        
        if cr:
            qc = QuantumCircuit(qr, cr, name=f"TL_expire_{n_qubits}Q")
        else:
            qc = QuantumCircuit(qr, name=f"TL_expire_{n_qubits}Q")
        
        # Encoder le temps d'expiration
        expire_seed = struct.pack('>d', expire_time.timestamp()) + data[:24]
        
        # Utiliser la calibration ACTUELLE
        current_calib = self._get_current_calibration_signature()
        combined_seed = expire_seed + current_calib
        
        time_angles = self._derive_angles(combined_seed, n_qubits)
        
        # Construction du circuit
        for q in path:
            qc.h(q)
        
        qc.barrier()
        
        # Rotations étroitement liées à la calibration actuelle
        # Après expiration, la dérive causera des erreurs
        for i, q in enumerate(path):
            qc.rz(time_angles[i], q)
        
        # Pattern CZ dense pour sensibilité à la dérive
        for i in range(len(path) - 1):
            qc.cz(path[i], path[i + 1])
        
        # Couche supplémentaire pour sensibilité accrue
        for q in path:
            qc.h(q)
        
        for i in range(0, len(path) - 1, 2):
            qc.cz(path[i], path[i + 1])
        
        for q in path:
            qc.h(q)
        
        if add_measurements:
            for i, q in enumerate(path):
                qc.measure(q, i)
        
        self._metadata['timelock_mode'] = 'expiring'
        self._metadata['expire_time'] = expire_time.isoformat()
        self._log(f"Built Expiring TimeLock: expires at {expire_time.isoformat()}")
        
        return qc
    
    def build_window_lock(self, data: bytes, open_time: datetime, 
                          close_time: datetime, n_qubits: int = 50,
                          add_measurements: bool = True) -> 'CircuitType':
        """
        Construit un circuit avec fenêtre de déchiffrement.
        
        Le déchiffrement n'est possible que dans [open_time, close_time].
        
        Args:
            data: Données à protéger
            open_time: Début de la fenêtre
            close_time: Fin de la fenêtre
            n_qubits: Nombre de qubits
        
        Returns:
            Circuit avec fenêtre temporelle
        """
        from qiskit import QuantumCircuit, QuantumRegister, ClassicalRegister
        
        path = self.get_optimal_path(n_qubits)[:n_qubits]
        max_qubit = max(path) + 1
        
        qr = QuantumRegister(max_qubit, 'q')
        cr = ClassicalRegister(n_qubits, 'c') if add_measurements else None
        
        if cr:
            qc = QuantumCircuit(qr, cr, name=f"TL_window_{n_qubits}Q")
        else:
            qc = QuantumCircuit(qr, name=f"TL_window_{n_qubits}Q")
        
        # Centre de la fenêtre
        window_center = open_time + (close_time - open_time) / 2
        window_seed = struct.pack('>dd', open_time.timestamp(), close_time.timestamp())
        window_seed += data[:16]
        
        angles = self._derive_angles(window_seed, n_qubits)
        
        for q in path:
            qc.h(q)
        
        for i, q in enumerate(path):
            qc.rz(angles[i], q)
        
        for i in range(len(path) - 1):
            qc.cz(path[i], path[i + 1])
        
        for q in path:
            qc.h(q)
        
        if add_measurements:
            for i, q in enumerate(path):
                qc.measure(q, i)
        
        self._metadata['timelock_mode'] = 'window'
        self._metadata['window'] = f"[{open_time.isoformat()}, {close_time.isoformat()}]"
        self._log(f"Built Window TimeLock: [{open_time} - {close_time}]")
        
        return qc
    
    def _estimate_calibration_drift(self, hours: float) -> List[float]:
        """Estime la dérive de calibration après N heures"""
        # Modèle simplifié de dérive
        base_drift = self._calibration_drift_rate * hours
        # Variation par qubit
        n_estimates = 20
        drifts = [base_drift * (1 + 0.1 * np.sin(i * np.pi / n_estimates)) 
                  for i in range(n_estimates)]
        return drifts
    
    def _get_current_calibration_signature(self) -> bytes:
        """Génère une signature de la calibration actuelle"""
        # En production: extraire depuis backend.properties()
        timestamp = datetime.now().timestamp()
        return struct.pack('>d', timestamp)
    
    def _derive_angles(self, data: bytes, n: int) -> List[float]:
        """Dérive n angles depuis des bytes"""
        extended = hashlib.shake_256(data).digest(n * 4)
        angles = []
        for i in range(n):
            val = struct.unpack('>I', extended[i*4:(i+1)*4])[0]
            angle = (val / (2**32)) * 2 * np.pi
            angles.append(angle)
        return angles


class ObliviousTransferBuilder(CircuitBuilder):
    """
    Constructeur de circuits pour Oblivious Transfer quantique.
    
    Référence brevet retirée (primitive générique)
    - 1-of-2 OT: Le receveur choisit 1 message parmi 2 sans révéler son choix
    - 1-of-N OT: Extension à N messages
    - Le sender ne sait pas quel message a été choisi
    
    Protocole:
    1. Sender prépare N circuits IQP (un par message)
    2. Receiver exécute le circuit correspondant à son choix
    3. Seul le circuit choisi produit une distribution décodable
    """
    
    name = "oblivious_transfer"
    
    def __init__(self, topology: 'DynamicTopology' = None, logger: 'Logger' = None):
        super().__init__(topology, logger)
    
    def build(self, n_qubits: int = 50, **params) -> 'CircuitType':
        """
        Méthode build() par défaut - construit un circuit receiver.
        
        Pour un contrôle plus fin, utiliser build_sender_circuits() 
        ou build_receiver_circuit().
        """
        choice = params.get('choice', 0)
        total_messages = params.get('total_messages', 2)
        shared_seed = params.get('shared_seed', secrets.token_bytes(32))
        return self.build_receiver_circuit(choice, total_messages, shared_seed, n_qubits)
    
    def build_sender_circuits(self, messages: List[bytes], 
                               shared_seed: bytes = None,
                               n_qubits: int = 50) -> List['CircuitType']:
        """
        Construit les circuits du sender pour OT 1-of-N.
        
        Args:
            messages: Liste de N messages
            shared_seed: Seed partagée pour le protocole
            n_qubits: Nombre de qubits par circuit
        
        Returns:
            Liste de N circuits (un par message)
        """
        if shared_seed is None:
            shared_seed = secrets.token_bytes(32)
        
        circuits = []
        
        for idx, message in enumerate(messages):
            circuit = self._build_ot_circuit(
                message=message,
                index=idx,
                total=len(messages),
                shared_seed=shared_seed,
                n_qubits=n_qubits,
                role='sender'
            )
            circuits.append(circuit)
        
        self._metadata['ot_type'] = f"1-of-{len(messages)}"
        self._metadata['sender_circuits'] = len(messages)
        self._log(f"Built {len(messages)} sender circuits for 1-of-{len(messages)} OT")
        
        return circuits
    
    def build_receiver_circuit(self, choice: int, total_messages: int,
                                shared_seed: bytes, n_qubits: int = 50) -> 'CircuitType':
        """
        Construit le circuit du receiver pour OT.
        
        Args:
            choice: Index du message choisi (0 à N-1)
            total_messages: Nombre total de messages
            shared_seed: Seed partagée
            n_qubits: Nombre de qubits
        
        Returns:
            Circuit pour décoder le message choisi
        """
        circuit = self._build_ot_circuit(
            message=None,
            index=choice,
            total=total_messages,
            shared_seed=shared_seed,
            n_qubits=n_qubits,
            role='receiver'
        )
        
        self._metadata['receiver_choice'] = choice
        self._log(f"Built receiver circuit for choice {choice}/{total_messages}")
        
        return circuit
    
    def _build_ot_circuit(self, message: bytes, index: int, total: int,
                          shared_seed: bytes, n_qubits: int, 
                          role: str) -> 'CircuitType':
        """Construit un circuit OT interne"""
        from qiskit import QuantumCircuit, QuantumRegister, ClassicalRegister
        
        path = self.get_optimal_path(n_qubits)[:n_qubits]
        max_qubit = max(path) + 1
        
        qr = QuantumRegister(max_qubit, 'q')
        cr = ClassicalRegister(n_qubits, 'c')
        
        qc = QuantumCircuit(qr, cr, name=f"OT_{role}_{index}of{total}")
        
        # Dériver les paramètres depuis la seed et l'index
        index_seed = shared_seed + struct.pack('>II', index, total)
        angles = self._derive_angles(index_seed, n_qubits)
        
        # Hadamard
        for q in path:
            qc.h(q)
        
        qc.barrier()
        
        # Rotations spécifiques à l'index
        for i, q in enumerate(path):
            qc.rz(angles[i], q)
        
        # Pattern CZ dépendant de l'index
        cz_offset = index % len(path)
        for i in range(cz_offset, len(path) - 1):
            qc.cz(path[i], path[(i + 1) % len(path)])
        
        qc.barrier()
        
        # Si sender: encoder le message
        if role == 'sender' and message is not None:
            msg_hash = hashlib.sha256(message).digest()
            msg_angles = self._derive_angles(msg_hash, n_qubits)
            for i, q in enumerate(path):
                qc.rz(msg_angles[i], q)
            qc.barrier()
        
        # Hadamard final
        for q in path:
            qc.h(q)
        
        # Mesures
        for i, q in enumerate(path):
            qc.measure(q, i)
        
        return qc
    
    def _derive_angles(self, data: bytes, n: int) -> List[float]:
        """Dérive n angles depuis des bytes"""
        extended = hashlib.shake_256(data).digest(n * 4)
        angles = []
        for i in range(n):
            val = struct.unpack('>I', extended[i*4:(i+1)*4])[0]
            angle = (val / (2**32)) * 2 * np.pi
            angles.append(angle)
        return angles


# =============================================================================
# [v2.5.15] NOUVEAUX CIRCUIT BUILDERS
# =============================================================================

class GroverBuilder(CircuitBuilder):
    """
    Constructeur de circuits pour l'algorithme de Grover.
    
    L'algorithme de Grover permet une recherche quadratiquement accélérée
    dans une base de données non structurée. Utilisé dans QAEE pour 
    l'estimation d'amplitude.
    
    Paramètres:
        n_qubits: Nombre de qubits (taille de l'espace de recherche = 2^n)
        marked_states: Liste des états à trouver (entiers ou bitstrings)
        iterations: Nombre d'itérations de Grover (optimal: π/4 * √N)
        oracle_type: 'phase' (standard) ou 'boolean'
    """
    
    name = "grover"
    
    def __init__(self, topology: 'DynamicTopology' = None, logger: 'Logger' = None):
        super().__init__(topology, logger)
    
    def build(self, n_qubits: int = 5, **params) -> 'CircuitType':
        """
        Construit un circuit de Grover.
        
        Args:
            n_qubits: Nombre de qubits de recherche
            marked_states: États marqués (défaut: [0] = premier état)
            iterations: Nombre d'itérations (défaut: optimal)
            with_ancilla: Utiliser un ancilla pour l'oracle (défaut: True)
        
        Returns:
            Circuit Grover complet
        """
        from qiskit import QuantumCircuit, QuantumRegister, ClassicalRegister
        
        marked_states = params.get('marked_states', [0])
        iterations = params.get('iterations', None)
        with_ancilla = params.get('with_ancilla', True)
        seed = params.get('seed', None)
        
        # Calculer le nombre optimal d'itérations
        N = 2 ** n_qubits
        M = len(marked_states)
        # [v2.7.1 FIX] Garde anti division-par-zero : une liste marked_states
        # vide provoquait np.sqrt(N / M) -> ZeroDivisionError (et M/N plus bas).
        if M == 0:
            raise ValueError("GroverBuilder.build: marked_states ne peut pas être vide")
        if iterations is None:
            iterations = max(1, int(np.pi / 4 * np.sqrt(N / M)))
        
        # Créer le circuit
        if with_ancilla:
            qr = QuantumRegister(n_qubits + 1, 'q')
            cr = ClassicalRegister(n_qubits, 'c')
            qc = QuantumCircuit(qr, cr, name=f"Grover_{n_qubits}q_{iterations}iter")
            ancilla = n_qubits
        else:
            qr = QuantumRegister(n_qubits, 'q')
            cr = ClassicalRegister(n_qubits, 'c')
            qc = QuantumCircuit(qr, cr, name=f"Grover_{n_qubits}q_{iterations}iter")
            ancilla = None
        
        # 1. Superposition initiale
        for i in range(n_qubits):
            qc.h(i)
        
        # Préparer ancilla en |->
        if with_ancilla:
            qc.x(ancilla)
            qc.h(ancilla)
        
        qc.barrier()
        
        # 2. Itérations de Grover
        for _ in range(iterations):
            # Oracle
            self._add_oracle(qc, n_qubits, marked_states, ancilla)
            qc.barrier()
            
            # Diffuseur
            self._add_diffuser(qc, n_qubits)
            qc.barrier()
        
        # 3. Mesure
        for i in range(n_qubits):
            qc.measure(i, i)
        
        self._metadata['iterations'] = iterations
        self._metadata['marked_states'] = marked_states
        self._metadata['search_space'] = N
        self._metadata['theoretical_success'] = np.sin((2 * iterations + 1) * np.arcsin(np.sqrt(M / N))) ** 2
        
        self._log(f"Built Grover circuit: {n_qubits}q, {iterations} iterations, "
                  f"P(success) ≈ {self._metadata['theoretical_success']:.2%}")
        
        return qc
    
    def _add_oracle(self, qc, n_qubits: int, marked_states: List[int], ancilla: int = None):
        """Ajoute l'oracle de marquage"""
        for state in marked_states:
            # Convertir l'état en bits
            bits = format(state, f'0{n_qubits}b')
            
            # X sur les qubits à 0
            for i, bit in enumerate(reversed(bits)):
                if bit == '0':
                    qc.x(i)
            
            # Multi-controlled Z (ou X sur ancilla)
            if ancilla is not None:
                # MCX sur ancilla
                qc.mcx(list(range(n_qubits)), ancilla)
            else:
                # Multi-controlled Z via phase
                if n_qubits == 1:
                    qc.z(0)
                elif n_qubits == 2:
                    qc.cz(0, 1)
                else:
                    # Décomposition en CZ
                    qc.h(n_qubits - 1)
                    qc.mcx(list(range(n_qubits - 1)), n_qubits - 1)
                    qc.h(n_qubits - 1)
            
            # Défaire les X
            for i, bit in enumerate(reversed(bits)):
                if bit == '0':
                    qc.x(i)
    
    def _add_diffuser(self, qc, n_qubits: int):
        """Ajoute le diffuseur (inversion autour de la moyenne)"""
        # H sur tous les qubits
        for i in range(n_qubits):
            qc.h(i)
        
        # X sur tous
        for i in range(n_qubits):
            qc.x(i)
        
        # Multi-controlled Z
        qc.h(n_qubits - 1)
        qc.mcx(list(range(n_qubits - 1)), n_qubits - 1)
        qc.h(n_qubits - 1)
        
        # X sur tous
        for i in range(n_qubits):
            qc.x(i)
        
        # H sur tous
        for i in range(n_qubits):
            qc.h(i)


class SwapTestBuilder(CircuitBuilder):
    """
    Constructeur de circuits pour le SWAP Test.
    
    Le SWAP Test permet de mesurer la similarité (fidelité) entre deux 
    états quantiques |ψ⟩ et |φ⟩. La probabilité de mesurer 0 sur l'ancilla
    est P(0) = (1 + |⟨ψ|φ⟩|²) / 2.
    
    Très utile pour QMC Biometric (comparaison de templates quantiques).
    
    Paramètres:
        n_qubits: Nombre de qubits par registre (total = 2n + 1)
        state_prep_1: Circuit de préparation de |ψ⟩
        state_prep_2: Circuit de préparation de |φ⟩
    """
    
    name = "swap_test"
    
    def __init__(self, topology: 'DynamicTopology' = None, logger: 'Logger' = None):
        super().__init__(topology, logger)
    
    def build(self, n_qubits: int = 3, **params) -> 'CircuitType':
        """
        Construit un circuit SWAP Test.
        
        Args:
            n_qubits: Qubits par registre
            state_1: 'ghz', 'random', 'zero', ou circuit custom
            state_2: 'ghz', 'random', 'zero', ou circuit custom  
            seed: Seed pour états aléatoires
            full_measurement: Mesurer tous les qubits (pas juste ancilla)
        
        Returns:
            Circuit SWAP Test
        """
        from qiskit import QuantumCircuit, QuantumRegister, ClassicalRegister
        
        state_1 = params.get('state_1', 'ghz')
        state_2 = params.get('state_2', 'ghz')
        seed = params.get('seed', None)
        full_measurement = params.get('full_measurement', False)
        
        # Registres: 1 ancilla + n qubits état 1 + n qubits état 2
        ancilla = QuantumRegister(1, 'anc')
        reg1 = QuantumRegister(n_qubits, 'psi')
        reg2 = QuantumRegister(n_qubits, 'phi')
        
        if full_measurement:
            cr = ClassicalRegister(1 + 2 * n_qubits, 'c')
        else:
            cr = ClassicalRegister(1, 'c')
        
        qc = QuantumCircuit(ancilla, reg1, reg2, cr, name=f"SwapTest_{n_qubits}q")
        
        # 1. Préparer les états
        self._prepare_state(qc, reg1, state_1, seed)
        self._prepare_state(qc, reg2, state_2, seed + 1 if seed else None)
        
        qc.barrier()
        
        # 2. SWAP Test: H - CSWAP - H - Mesure
        qc.h(ancilla[0])
        
        # Controlled-SWAP pour chaque paire de qubits
        for i in range(n_qubits):
            qc.cswap(ancilla[0], reg1[i], reg2[i])
        
        qc.h(ancilla[0])
        
        qc.barrier()
        
        # 3. Mesure
        qc.measure(ancilla[0], 0)
        
        if full_measurement:
            for i in range(n_qubits):
                qc.measure(reg1[i], 1 + i)
                qc.measure(reg2[i], 1 + n_qubits + i)
        
        self._metadata['n_qubits_per_register'] = n_qubits
        self._metadata['total_qubits'] = 1 + 2 * n_qubits
        self._metadata['state_1'] = str(state_1)
        self._metadata['state_2'] = str(state_2)
        
        self._log(f"Built SWAP Test: {n_qubits}q per register, states: {state_1} vs {state_2}")
        
        return qc
    
    def _prepare_state(self, qc, register, state_type, seed=None):
        """Prépare un état dans un registre"""
        n = len(register)
        
        if state_type == 'zero':
            pass  # Déjà en |0...0⟩
        
        elif state_type == 'ghz':
            qc.h(register[0])
            for i in range(1, n):
                qc.cx(register[0], register[i])
        
        elif state_type == 'random':
            rng = np.random.default_rng(seed)
            for i in range(n):
                theta = rng.uniform(0, np.pi)
                phi = rng.uniform(0, 2 * np.pi)
                qc.ry(theta, register[i])
                qc.rz(phi, register[i])
            # Ajouter de l'intrication
            for i in range(n - 1):
                qc.cx(register[i], register[i + 1])
        
        elif state_type == 'plus':
            for i in range(n):
                qc.h(register[i])
        
        elif hasattr(state_type, 'data'):
            # C'est un circuit custom
            qc.compose(state_type, qubits=register, inplace=True)
    
    @staticmethod
    def compute_fidelity(counts: Dict[str, int]) -> float:
        """
        Calcule la fidélité à partir des counts du SWAP Test.
        
        P(0) = (1 + |⟨ψ|φ⟩|²) / 2
        => |⟨ψ|φ⟩|² = 2*P(0) - 1
        
        Args:
            counts: Résultats de mesure (avec ancilla en position 0 ou dernière)
        
        Returns:
            Fidélité estimée (0 à 1)
        """
        total = sum(counts.values())
        
        # Trouver les counts où ancilla = 0
        p_zero = 0
        for bitstring, count in counts.items():
            # [v2.7.1 FIX] Ne compter QUE le bit ancilla (dernière position).
            # L'ancien 'or bitstring[0]=="0"' sur-comptait P(0) en incluant un
            # qubit de données non lié sous full_measurement.
            if bitstring[-1] == '0':
                p_zero += count
        
        p_zero /= total
        fidelity = max(0, min(1, 2 * p_zero - 1))
        
        return fidelity


class QRNGBuilder(CircuitBuilder):
    """
    Constructeur de circuits pour Quantum Random Number Generator.
    
    Génère des nombres véritablement aléatoires en exploitant la 
    superposition quantique. Chaque qubit en superposition |+⟩ 
    produit un bit parfaitement aléatoire lors de la mesure.
    
    Paramètres:
        n_qubits: Nombre de bits à générer par exécution
        enhanced: Utiliser des rotations pour améliorer la qualité
        entangled: Utiliser de l'intrication (augmente la complexité)
    """
    
    name = "qrng"
    
    def __init__(self, topology: 'DynamicTopology' = None, logger: 'Logger' = None):
        super().__init__(topology, logger)
    
    def build(self, n_qubits: int = 32, **params) -> 'CircuitType':
        """
        Construit un circuit QRNG.
        
        Args:
            n_qubits: Nombre de bits aléatoires à générer
            enhanced: Mode amélioré avec rotations aléatoires (défaut: False)
            entangled: Ajouter de l'intrication (défaut: False)
            seed: Seed pour les rotations (mode enhanced)
            depth: Profondeur des couches (mode enhanced, défaut: 1)
        
        Returns:
            Circuit QRNG
        """
        from qiskit import QuantumCircuit, QuantumRegister, ClassicalRegister
        
        enhanced = params.get('enhanced', False)
        entangled = params.get('entangled', False)
        seed = params.get('seed', None)
        depth = params.get('depth', 1)
        
        # Utiliser la topologie optimale si disponible
        path = self.get_optimal_path(n_qubits)[:n_qubits]
        max_qubit = max(path) + 1 if path else n_qubits
        
        qr = QuantumRegister(max_qubit, 'q')
        cr = ClassicalRegister(n_qubits, 'c')
        
        mode_name = "enhanced" if enhanced else ("entangled" if entangled else "basic")
        qc = QuantumCircuit(qr, cr, name=f"QRNG_{n_qubits}b_{mode_name}")
        
        if enhanced:
            # Mode amélioré: rotations pseudo-aléatoires + Hadamard
            rng = np.random.default_rng(seed)
            
            for layer in range(depth):
                # Rotations aléatoires
                for i, q in enumerate(path):
                    theta = rng.uniform(0, np.pi)
                    phi = rng.uniform(0, 2 * np.pi)
                    qc.ry(theta, q)
                    qc.rz(phi, q)
                
                # Hadamard
                for q in path:
                    qc.h(q)
                
                if layer < depth - 1:
                    qc.barrier()
        
        elif entangled:
            # Mode intriqué: GHZ-like puis Hadamard
            for q in path:
                qc.h(q)
            
            # Couche d'intrication
            for i in range(len(path) - 1):
                qc.cx(path[i], path[i + 1])
            
            qc.barrier()
            
            # Hadamard final
            for q in path:
                qc.h(q)
        
        else:
            # Mode basique: juste Hadamard
            for q in path:
                qc.h(q)
        
        qc.barrier()
        
        # Mesure
        for i, q in enumerate(path):
            qc.measure(q, i)
        
        self._metadata['n_bits'] = n_qubits
        self._metadata['mode'] = mode_name
        self._metadata['depth'] = depth if enhanced else 1
        self._metadata['bits_per_shot'] = n_qubits
        
        self._log(f"Built QRNG circuit: {n_qubits} bits, mode={mode_name}")
        
        return qc
    
    @staticmethod
    def extract_random_bytes(counts: Dict[str, int], n_bytes: int = None) -> bytes:
        """
        Extrait des bytes aléatoires à partir des résultats.
        
        Args:
            counts: Résultats de mesure
            n_bytes: Nombre de bytes à extraire (défaut: tous)
        
        Returns:
            Bytes aléatoires (conditionnés)

        [v2.7.1 FIX] L'ancienne version faisait `for _ in range(count): all_bits +=
        bitstring`, ce qui (1) répétait chaque chaîne `count` fois CONSÉCUTIVEMENT
        (longs blocs périodiques -> min-entropie détruite) et (2) n'appliquait AUCUN
        extracteur/conditionnement. On applique désormais un EXTRACTEUR
        cryptographique (SHAKE-256) sur une sérialisation canonique de TOUTE la
        distribution (chaînes + multiplicités) — amplification de confidentialité —
        et on plafonne la sortie par défaut au budget de min-entropie de la source
        (NIST SP 800-90B, estimateur MCV).
        """
        if not counts:
            return b""
        # Sérialisation canonique (déterministe) de la source quantique
        buf = bytearray(b"QMC-QRNG|")
        raw_bits = []
        for bs in sorted(counts.keys()):
            clean = bs.replace(' ', '')
            c = int(counts[bs])
            buf.extend(clean.encode())
            buf.extend(b":")
            buf.extend(str(c).encode())
            buf.extend(b"|")
            raw_bits.extend((1 if ch == '1' else 0) for ch in clean for _ in range(c))
        # [v2.7.2 FIX #4] Budget d'octets « sûrs » = min-entropie CONSERVATRICE.
        # L'estimateur MCV PAR-BIT (NIST 90B §6.3.1) est structure-AVEUGLE : une source
        # déterministe comme {'01': N} y paraissait ~0,92 bit/bit (alternance 0/1
        # équilibrée) alors que sa min-entropie réelle est ~0. On prend désormais le MIN
        # entre (a) MCV par-bit × nb_bits et (b) min-entropie H∞ PAR-SYMBOLE (sur l'issue
        # COMPLÈTE de chaque shot) × nb_shots. La voie (b) capte la concentration / le
        # déterminisme et est intrinsèquement bornée par log2(nb_shots) — on ne peut pas
        # estimer plus de min-entropie que l'échantillon n'en supporte (anti-sur-estimation).
        # NOTE : budget conservateur basé sur des estimateurs MCV ; pour une assurance
        # élevée, compléter par la batterie non-IID NIST 90B (Markov/collision/compression).
        n_shots = sum(int(c) for c in counts.values())
        symbols = []
        for bs, c in counts.items():
            symbols.extend([bs.replace(' ', '')] * int(c))
        mcv_bit = QMCQuantumCrypto.min_entropy_mcv(raw_bits)    # bits / bit
        mcv_sym = QMCQuantumCrypto.min_entropy_mcv(symbols)     # bits / shot (H∞ par issue)
        total_min_entropy = min(mcv_bit * len(raw_bits), mcv_sym * n_shots)
        safe_bytes = int(total_min_entropy / 8)
        # [v2.7.1 FIX R89] Source à min-entropie nulle : NE PAS fabriquer d'aléa.
        # L'ancien repli « else 32 » émettait 32 octets SHAKE DÉTERMINISTES (prédictibles)
        # pour une source dégénérée -> on échoue fermé (fail-closed) à la place.
        if safe_bytes <= 0:
            raise QMCSecurityError(
                "QRNG: min-entropie insuffisante dans la source quantique "
                "(safe_bytes=0). Augmentez les shots/qubits ou utilisez secrets.token_bytes.",
                operation="extract_random_bytes")
        if n_bytes is None:
            n_bytes = safe_bytes
        elif int(n_bytes) > safe_bytes:
            # Ne pas extraire plus que le budget de min-entropie de la source.
            raise QMCSecurityError(
                f"QRNG: n_bytes={n_bytes} dépasse le budget de min-entropie "
                f"({safe_bytes} octets) de la source. Réduisez n_bytes ou augmentez la source.",
                operation="extract_random_bytes")
        # Extracteur SHAKE-256 : sortie uniforme de longueur arbitraire
        return hashlib.shake_256(bytes(buf)).digest(int(n_bytes))


class AmplitudeEncodingBuilder(CircuitBuilder):
    """
    Constructeur de circuits pour l'encodage d'amplitude.
    
    Encode un vecteur de données classiques dans les amplitudes d'un 
    état quantique. Un vecteur de dimension N nécessite log2(N) qubits.
    
    Exemple: [0.5, 0.5, 0.5, 0.5] → |ψ⟩ = 0.5|00⟩ + 0.5|01⟩ + 0.5|10⟩ + 0.5|11⟩
    
    Utilisé pour encoder des données biométriques, financières, etc.
    dans des états quantiques pour traitement QML.
    """
    
    name = "amplitude_encoding"
    
    def __init__(self, topology: 'DynamicTopology' = None, logger: 'Logger' = None):
        super().__init__(topology, logger)
    
    def build(self, n_qubits: int = 4, **params) -> 'CircuitType':
        """
        Construit un circuit d'encodage d'amplitude.
        
        Args:
            n_qubits: Nombre de qubits (encode 2^n amplitudes)
            data: Vecteur de données à encoder (sera normalisé)
            normalize: Normaliser automatiquement (défaut: True)
            method: 'mottonen' (exact) ou 'approx' (approximatif)
        
        Returns:
            Circuit d'encodage
        """
        from qiskit import QuantumCircuit, QuantumRegister, ClassicalRegister
        
        data = params.get('data', None)
        normalize = params.get('normalize', True)
        method = params.get('method', 'mottonen')
        add_measurement = params.get('add_measurement', True)
        
        # Si pas de données, créer un vecteur uniforme
        N = 2 ** n_qubits
        if data is None:
            data = np.ones(N) / np.sqrt(N)
        else:
            data = np.array(data, dtype=float)
        
        # Padding si nécessaire
        if len(data) < N:
            data = np.pad(data, (0, N - len(data)))
        elif len(data) > N:
            data = data[:N]
        
        # Normalisation
        if normalize:
            norm = np.linalg.norm(data)
            if norm > 0:
                data = data / norm
        
        # Créer le circuit
        qr = QuantumRegister(n_qubits, 'q')
        
        if add_measurement:
            cr = ClassicalRegister(n_qubits, 'c')
            qc = QuantumCircuit(qr, cr, name=f"AmpEnc_{n_qubits}q")
        else:
            qc = QuantumCircuit(qr, name=f"AmpEnc_{n_qubits}q")
        
        if method == 'mottonen':
            # Méthode de Möttönen et al. (exacte)
            self._mottonen_encoding(qc, data, n_qubits)
        else:
            # Méthode approximative (plus simple, moins de portes)
            self._approx_encoding(qc, data, n_qubits)
        
        if add_measurement:
            qc.barrier()
            for i in range(n_qubits):
                qc.measure(i, i)
        
        self._metadata['n_qubits'] = n_qubits
        self._metadata['data_dim'] = len(data)
        self._metadata['method'] = method
        self._metadata['data_norm'] = float(np.linalg.norm(data))
        
        self._log(f"Built amplitude encoding: {n_qubits}q, dim={N}, method={method}")
        
        return qc
    
    def _mottonen_encoding(self, qc, data: np.ndarray, n_qubits: int):
        """
        Encodage exact par la méthode de Möttönen.
        Utilise initialize() de Qiskit qui implémente cette méthode.
        """
        # Qiskit's initialize fait exactement ça
        qc.initialize(data, range(n_qubits))
        
        # Décomposer pour hardware (évite les portes unitaires génériques)
        # Note: La transpilation fera ça automatiquement
    
    def _approx_encoding(self, qc, data: np.ndarray, n_qubits: int):
        """
        Encodage approximatif avec rotations RY.
        Plus simple mais moins précis pour des données complexes.
        """
        # Calculer les angles pour chaque qubit
        # Méthode: RY rotations basées sur les probabilités marginales
        
        for qubit in range(n_qubits):
            # Calculer la probabilité marginale pour ce qubit
            prob_1 = 0
            prob_0 = 0

            for i in range(len(data)):
                # [v2.7.2 FIX] Convention LSB cohérente avec decode_amplitudes
                # (qui fait int(bitstring,2), bit j = qubit j). L'ancien
                # `(i >> (n_qubits-qubit-1))` traitait qubit 0 comme MSB -> l'état
                # encodé par la voie 'approx' était bit-inversé (index 1 -> 2 mesuré).
                bit = (i >> qubit) & 1
                if bit == 1:
                    prob_1 += data[i] ** 2
                else:
                    prob_0 += data[i] ** 2
            
            total = prob_0 + prob_1
            if total > 0:
                theta = 2 * np.arcsin(np.sqrt(prob_1 / total))
                qc.ry(theta, qubit)

        # [v2.7.1 FIX] Couche CX d'intrication SUPPRIMÉE.
        # L'encodage approximatif produit un état produit dont les
        # probabilités marginales par qubit correspondent à la cible.
        # La couche CX finale détruisait précisément ces marginales
        # (corrompant amplitudes/marges encodées) sans améliorer
        # l'approximation. Les RY seuls préservent la normalisation (unitaires).
    
    @staticmethod
    def decode_amplitudes(counts: Dict[str, int], n_qubits: int) -> np.ndarray:
        """
        Reconstruit les amplitudes (approximatives) à partir des mesures.
        
        Args:
            counts: Résultats de mesure
            n_qubits: Nombre de qubits
        
        Returns:
            Vecteur d'amplitudes estimées
        """
        N = 2 ** n_qubits
        total = sum(counts.values())

        amplitudes = np.zeros(N)
        # [v2.7.1 FIX] Garde anti division-par-zero : des counts vides
        # (total == 0) provoquaient np.sqrt(count / total).
        if total <= 0:
            return amplitudes
        for bitstring, count in counts.items():
            # Convertir bitstring en index
            # [v2.7.1 FIX] Ignorer les espaces séparateurs de registres avant int(.,2).
            idx = int(bitstring.replace(' ', ''), 2)
            amplitudes[idx] = np.sqrt(count / total)

        return amplitudes


class QPEBuilder(CircuitBuilder):
    """
    Constructeur de circuits pour Quantum Phase Estimation.
    
    Estime la phase φ d'un eigenvalue e^(2πiφ) d'un opérateur unitaire U.
    Base de nombreux algorithmes quantiques dont Shor et l'estimation d'amplitude.
    
    Paramètres:
        n_precision: Nombre de qubits de précision (détermine la précision: 2^-n)
        unitary: Opérateur unitaire U (circuit ou matrice)
        n_target: Qubits cibles pour U
    """
    
    name = "qpe"
    
    def __init__(self, topology: 'DynamicTopology' = None, logger: 'Logger' = None):
        super().__init__(topology, logger)
    
    def build(self, n_qubits: int = 4, **params) -> 'CircuitType':
        """
        Construit un circuit QPE.
        
        Args:
            n_qubits: Qubits de précision
            n_target: Qubits cibles (défaut: 1)
            unitary: Circuit unitaire ou 'T', 'S', 'Z', 'custom'
            phase: Phase à encoder si unitary='custom' (pour tests)
        
        Returns:
            Circuit QPE
        """
        from qiskit import QuantumCircuit, QuantumRegister, ClassicalRegister
        
        n_precision = n_qubits
        n_target = params.get('n_target', 1)
        unitary = params.get('unitary', 'T')
        phase = params.get('phase', None)
        
        # Registres
        precision_reg = QuantumRegister(n_precision, 'prec')
        target_reg = QuantumRegister(n_target, 'tgt')
        cr = ClassicalRegister(n_precision, 'c')
        
        qc = QuantumCircuit(precision_reg, target_reg, cr, 
                           name=f"QPE_{n_precision}p_{n_target}t")
        
        # 1. Préparer l'état propre dans target
        # Pour T gate: |1⟩ est un état propre
        qc.x(target_reg[0])
        
        # 2. Hadamard sur tous les qubits de précision
        for i in range(n_precision):
            qc.h(precision_reg[i])
        
        qc.barrier()
        
        # 3. Controlled-U^(2^k) applications
        for k in range(n_precision):
            power = 2 ** (n_precision - 1 - k)
            
            if unitary == 'T':
                # T gate: phase = 1/8
                angle = np.pi / 4 * power
                qc.cp(angle, precision_reg[k], target_reg[0])
            
            elif unitary == 'S':
                # S gate: phase = 1/4
                angle = np.pi / 2 * power
                qc.cp(angle, precision_reg[k], target_reg[0])
            
            elif unitary == 'Z':
                # Z gate: phase = 1/2
                angle = np.pi * power
                qc.cp(angle, precision_reg[k], target_reg[0])
            
            elif unitary == 'custom' and phase is not None:
                # Phase personnalisée
                angle = 2 * np.pi * phase * power
                qc.cp(angle, precision_reg[k], target_reg[0])
            
            elif hasattr(unitary, 'data'):
                # Circuit custom
                controlled_u = unitary.control(1)
                for _ in range(power):
                    qc.compose(controlled_u, 
                              qubits=[precision_reg[k]] + list(range(n_precision, n_precision + n_target)),
                              inplace=True)
        
        qc.barrier()
        
        # 4. QFT inverse sur les qubits de précision
        self._add_inverse_qft(qc, precision_reg, n_precision)
        
        qc.barrier()
        
        # 5. Mesure
        for i in range(n_precision):
            qc.measure(precision_reg[i], i)
        
        self._metadata['n_precision'] = n_precision
        self._metadata['n_target'] = n_target
        self._metadata['unitary'] = str(unitary)
        self._metadata['precision'] = 1 / (2 ** n_precision)
        
        self._log(f"Built QPE: {n_precision} precision qubits, precision=1/{2**n_precision}")
        
        return qc
    
    def _add_inverse_qft(self, qc, register, n: int):
        """Ajoute la QFT inverse.

        [v2.7.1 FIX CRITIQUE] L'ancien code appliquait une boucle de SWAP des
        qubits AVANT les portes de QFT inverse. Combiné à l'attribution des
        puissances controlled-U (precision_reg[0] = MSB) et à la convention de
        lecture extract_phase (precision_reg[0] = LSB), ce swap inversait l'ordre
        des bits et rendait TOUTES les phases estimées fausses (vérifié sur Aer :
        T->0.25 au lieu de 0.125). Le swap est supprimé ; la QFT inverse seule
        produit désormais les phases exactes pour T/S/Z/custom.
        """
        # QFT inverse gates (PAS de swap : voir note ci-dessus)
        for i in range(n):
            for j in range(i):
                angle = -np.pi / (2 ** (i - j))
                qc.cp(angle, register[j], register[i])
            qc.h(register[i])
    
    @staticmethod
    def extract_phase(counts: Dict[str, int], n_precision: int) -> float:
        """
        Extrait la phase estimée à partir des mesures.
        
        Args:
            counts: Résultats de mesure
            n_precision: Nombre de qubits de précision
        
        Returns:
            Phase estimée (entre 0 et 1)
        """
        # Trouver le bitstring le plus fréquent
        max_count = 0
        best_bitstring = None
        
        for bitstring, count in counts.items():
            if count > max_count:
                max_count = count
                best_bitstring = bitstring
        
        if best_bitstring is None:
            return 0.0
        
        # Convertir en phase
        # Le bitstring représente la fraction binaire de la phase
        # [v2.7.2 FIX] Retirer les espaces séparateurs de registres (cohérence avec
        # BV/DJ/Simon/decode) : évite ValueError si counts vient d'un flux multi-registre.
        phase_int = int(best_bitstring.replace(' ', ''), 2)
        phase = phase_int / (2 ** n_precision)
        
        return phase


class HardwareEfficientBuilder(CircuitBuilder):
    """
    Constructeur d'ansatz Hardware-Efficient pour VQE/QAOA.
    
    Génère des circuits variationnels optimisés pour l'exécution sur 
    hardware NISQ, en utilisant uniquement des portes natives et 
    respectant la topologie du processeur.
    
    Structure typique:
    - Couches de rotations RY-RZ
    - Couches d'intrication (CZ ou CX selon topologie)
    """
    
    name = "hardware_efficient"
    
    def __init__(self, topology: 'DynamicTopology' = None, logger: 'Logger' = None):
        super().__init__(topology, logger)
    
    def build(self, n_qubits: int = 4, **params) -> 'CircuitType':
        """
        Construit un ansatz hardware-efficient.
        
        Args:
            n_qubits: Nombre de qubits
            depth: Nombre de couches (défaut: 3)
            rotation_gates: Liste de portes ['ry', 'rz'] ou ['rx', 'ry', 'rz']
            entanglement: 'linear', 'full', 'circular', 'topology'
            parameter_prefix: Préfixe des paramètres (défaut: 'θ')
            barriers: Ajouter des barrières entre couches (défaut: True)
        
        Returns:
            Circuit paramétré
        """
        from qiskit import QuantumCircuit, QuantumRegister, ClassicalRegister
        from qiskit.circuit import Parameter
        
        depth = params.get('depth', 3)
        rotation_gates = params.get('rotation_gates', ['ry', 'rz'])
        entanglement = params.get('entanglement', 'linear')
        parameter_prefix = params.get('parameter_prefix', 'θ')
        barriers = params.get('barriers', True)
        add_measurement = params.get('add_measurement', True)
        
        # Utiliser la topologie si disponible
        if entanglement == 'topology':
            path = self.get_optimal_path(n_qubits)[:n_qubits]
            max_qubit = max(path) + 1 if path else n_qubits
        else:
            path = list(range(n_qubits))
            max_qubit = n_qubits
        
        qr = QuantumRegister(max_qubit, 'q')
        
        if add_measurement:
            cr = ClassicalRegister(n_qubits, 'c')
            qc = QuantumCircuit(qr, cr, name=f"HWEff_{n_qubits}q_d{depth}")
        else:
            qc = QuantumCircuit(qr, name=f"HWEff_{n_qubits}q_d{depth}")
        
        param_idx = 0
        
        for layer in range(depth):
            # Couche de rotations
            for gate_name in rotation_gates:
                for i, q in enumerate(path):
                    param = Parameter(f"{parameter_prefix}_{param_idx}")
                    param_idx += 1
                    
                    if gate_name == 'rx':
                        qc.rx(param, q)
                    elif gate_name == 'ry':
                        qc.ry(param, q)
                    elif gate_name == 'rz':
                        qc.rz(param, q)
            
            if barriers:
                qc.barrier()
            
            # Couche d'intrication
            if entanglement == 'linear' or entanglement == 'topology':
                for i in range(len(path) - 1):
                    qc.cz(path[i], path[i + 1])
            
            elif entanglement == 'circular':
                for i in range(len(path)):
                    qc.cz(path[i], path[(i + 1) % len(path)])
            
            elif entanglement == 'full':
                for i in range(len(path)):
                    for j in range(i + 1, len(path)):
                        qc.cz(path[i], path[j])
            
            if barriers and layer < depth - 1:
                qc.barrier()
        
        # Dernière couche de rotations
        for gate_name in rotation_gates:
            for i, q in enumerate(path):
                param = Parameter(f"{parameter_prefix}_{param_idx}")
                param_idx += 1
                
                if gate_name == 'rx':
                    qc.rx(param, q)
                elif gate_name == 'ry':
                    qc.ry(param, q)
                elif gate_name == 'rz':
                    qc.rz(param, q)
        
        if add_measurement:
            qc.barrier()
            for i, q in enumerate(path):
                qc.measure(q, i)
        
        self._metadata['n_qubits'] = n_qubits
        self._metadata['depth'] = depth
        self._metadata['n_parameters'] = param_idx
        self._metadata['rotation_gates'] = rotation_gates
        self._metadata['entanglement'] = entanglement
        
        self._log(f"Built HW-efficient ansatz: {n_qubits}q, depth={depth}, "
                  f"{param_idx} parameters, {entanglement} entanglement")
        
        return qc


class DeutschJozsaBuilder(CircuitBuilder):
    """
    Constructeur de circuits pour l'algorithme de Deutsch-Jozsa.
    
    Détermine si une fonction f:{0,1}^n → {0,1} est constante ou équilibrée
    en une seule requête quantique (vs 2^(n-1)+1 requêtes classiques).
    
    Premier exemple d'avantage quantique exponentiel (déterministe).
    Utile pédagogiquement et pour démontrer les oracles quantiques.
    """
    
    name = "deutsch_jozsa"
    
    def __init__(self, topology: 'DynamicTopology' = None, logger: 'Logger' = None):
        super().__init__(topology, logger)
    
    def build(self, n_qubits: int = 4, **params) -> 'CircuitType':
        """
        Construit un circuit Deutsch-Jozsa.
        
        Args:
            n_qubits: Nombre de qubits d'entrée (hors ancilla)
            oracle_type: 'constant_0', 'constant_1', 'balanced', ou 'random'
            seed: Seed pour oracle aléatoire
        
        Returns:
            Circuit DJ complet
        """
        from qiskit import QuantumCircuit, QuantumRegister, ClassicalRegister
        
        oracle_type = params.get('oracle_type', 'balanced')
        seed = params.get('seed', None)
        
        # n qubits d'entrée + 1 ancilla
        qr = QuantumRegister(n_qubits + 1, 'q')
        cr = ClassicalRegister(n_qubits, 'c')
        
        qc = QuantumCircuit(qr, cr, name=f"DJ_{n_qubits}q_{oracle_type}")
        
        # 1. Initialisation: H sur entrées, X+H sur ancilla (|->)
        for i in range(n_qubits):
            qc.h(i)
        
        qc.x(n_qubits)  # Ancilla
        qc.h(n_qubits)
        
        qc.barrier()
        
        # 2. Oracle
        # [v2.7.1 FIX] _add_oracle retourne le type RÉELLEMENT construit
        # (une demande 'random'/'balanced' pouvait silencieusement produire
        #  un oracle constant). On enregistre ce type véridique en metadata.
        built_oracle_type = self._add_oracle(qc, n_qubits, oracle_type, seed)

        qc.barrier()

        # 3. Hadamard sur les qubits d'entrée
        for i in range(n_qubits):
            qc.h(i)

        qc.barrier()

        # 4. Mesure (uniquement les qubits d'entrée)
        for i in range(n_qubits):
            qc.measure(i, i)

        self._metadata['n_qubits'] = n_qubits
        # [v2.7.1 FIX] metadata reflète le type d'oracle réellement bâti
        self._metadata['oracle_type'] = built_oracle_type
        self._metadata['requested_oracle_type'] = oracle_type
        self._metadata['expected_result'] = '0' * n_qubits if 'constant' in built_oracle_type else 'non-zero'
        
        self._log(f"Built Deutsch-Jozsa: {n_qubits}q, oracle={oracle_type}")
        
        return qc
    
    def _add_oracle(self, qc, n_qubits: int, oracle_type: str, seed=None) -> str:
        """Ajoute l'oracle f(x). Retourne le type d'oracle réellement construit."""
        ancilla = n_qubits

        if oracle_type == 'constant_0':
            # f(x) = 0 pour tout x → Ne fait rien
            return 'constant_0'

        elif oracle_type == 'constant_1':
            # f(x) = 1 pour tout x → X sur ancilla
            qc.x(ancilla)
            return 'constant_1'

        elif oracle_type == 'balanced':
            # f(x) = x_0 (premier bit) → CNOT (équilibré garanti)
            qc.cx(0, ancilla)
            return 'balanced'

        elif oracle_type == 'random':
            # [v2.7.1 FIX] Oracle ÉQUILIBRÉ garanti.
            # f(x) = a·x (mod 2) est équilibré ssi le masque a est non nul.
            # L'ancien code (rng.random() > 0.5 par qubit) pouvait produire
            # un masque entièrement nul -> oracle CONSTANT déguisé en 'random'.
            rng = np.random.default_rng(seed)
            mask = [bool(rng.integers(0, 2)) for _ in range(n_qubits)]
            if not any(mask):
                # Forcer au moins un bit du masque pour garantir l'équilibre.
                mask[int(rng.integers(0, n_qubits))] = True
            for i in range(n_qubits):
                if mask[i]:
                    qc.cx(i, ancilla)
            return 'balanced'

        # Type inconnu: ne rien faire -> constant_0
        return 'constant_0'
    
    @staticmethod
    def interpret_result(counts: Dict[str, int]) -> str:
        """
        Interprète le résultat de l'algorithme.
        
        Returns:
            'constant' si f est constante, 'balanced' sinon
        """
        # [v2.7.1 FIX] Garde sur counts vides : max() sur un dict vide levait
        # ValueError. On renvoie 'constant' (état |0...0⟩ par défaut, aucune info).
        if not counts:
            return 'constant'
        # Trouver le résultat le plus fréquent
        max_result = max(counts, key=counts.get)
        # [v2.7.1 FIX] Retirer les espaces séparateurs de registres : sinon un
        # espace (qui n'est pas '0') faussait le test all(b == '0').
        max_result = max_result.replace(' ', '')

        # Si tous les qubits sont à 0 → fonction constante
        if all(b == '0' for b in max_result):
            return 'constant'
        else:
            return 'balanced'


class BernsteinVaziraniBuilder(CircuitBuilder):
    """
    Constructeur de circuits pour l'algorithme de Bernstein-Vazirani.
    
    Trouve un string secret s ∈ {0,1}^n en une seule requête quantique,
    où l'oracle calcule f(x) = s·x (produit scalaire mod 2).
    Classiquement, il faudrait n requêtes.
    
    Utile pour démontrer l'avantage quantique et les oracles.
    """
    
    name = "bernstein_vazirani"
    
    def __init__(self, topology: 'DynamicTopology' = None, logger: 'Logger' = None):
        super().__init__(topology, logger)
    
    def build(self, n_qubits: int = 4, **params) -> 'CircuitType':
        """
        Construit un circuit Bernstein-Vazirani.
        
        Args:
            n_qubits: Nombre de qubits (longueur du secret)
            secret: String secret (ex: '1011') ou None pour aléatoire
            seed: Seed si secret aléatoire
        
        Returns:
            Circuit BV complet
        """
        from qiskit import QuantumCircuit, QuantumRegister, ClassicalRegister
        
        secret = params.get('secret', None)
        seed = params.get('seed', None)
        
        # Générer secret aléatoire si non fourni
        if secret is None:
            rng = np.random.default_rng(seed)
            secret = ''.join(str(rng.integers(0, 2)) for _ in range(n_qubits))
        
        # S'assurer que le secret a la bonne longueur
        if len(secret) < n_qubits:
            secret = secret.zfill(n_qubits)
        elif len(secret) > n_qubits:
            secret = secret[:n_qubits]
        
        # n qubits + 1 ancilla
        qr = QuantumRegister(n_qubits + 1, 'q')
        cr = ClassicalRegister(n_qubits, 'c')
        
        qc = QuantumCircuit(qr, cr, name=f"BV_{n_qubits}q_s{secret}")
        
        # 1. Initialisation
        for i in range(n_qubits):
            qc.h(i)
        
        qc.x(n_qubits)  # Ancilla
        qc.h(n_qubits)
        
        qc.barrier()
        
        # 2. Oracle: CNOT pour chaque bit à 1 dans le secret
        for i, bit in enumerate(reversed(secret)):
            if bit == '1':
                qc.cx(i, n_qubits)
        
        qc.barrier()
        
        # 3. Hadamard final
        for i in range(n_qubits):
            qc.h(i)
        
        qc.barrier()
        
        # 4. Mesure
        for i in range(n_qubits):
            qc.measure(i, i)
        
        self._metadata['n_qubits'] = n_qubits
        self._metadata['secret'] = secret
        # [v2.7.2 FIX] Le bitstring mesuré égale le secret (cf. extract_secret) :
        # l'attendu est `secret`, pas son inverse.
        self._metadata['expected_result'] = secret
        
        self._log(f"Built Bernstein-Vazirani: {n_qubits}q, secret={secret}")
        
        return qc
    
    @staticmethod
    def extract_secret(counts: Dict[str, int]) -> str:
        """
        Extrait le secret à partir des mesures.
        
        Returns:
            Le string secret trouvé
        """
        # [v2.7.1 FIX] Garde sur counts vides : max() sur un dict vide levait
        # ValueError. On renvoie une chaîne vide plutôt que de crasher.
        if not counts:
            return ''
        # [v2.7.2 FIX] Le bitstring mesuré le plus fréquent EST DÉJÀ le secret :
        # l'oracle applique cx(i, anc) pour reversed(secret), et l'ordre big-endian
        # de Qiskit (bit i = qubit i) fait que bitstring[j] == secret[j]. L'ancien
        # `[::-1]` renvoyait donc le secret INVERSÉ (vérifié : '10110' -> '01101').
        max_result = max(counts, key=counts.get).replace(' ', '')
        return max_result


class SimonBuilder(CircuitBuilder):
    """
    Constructeur de circuits pour l'algorithme de Simon.
    
    Trouve un string secret s tel que f(x) = f(y) ssi x⊕y ∈ {0, s}.
    Avantage exponentiel: O(n) requêtes quantiques vs O(2^(n/2)) classiques.
    
    Précurseur historique de l'algorithme de Shor.
    Démontre la puissance des périodes cachées.
    """
    
    name = "simon"
    
    def __init__(self, topology: 'DynamicTopology' = None, logger: 'Logger' = None):
        super().__init__(topology, logger)
    
    def build(self, n_qubits: int = 3, **params) -> 'CircuitType':
        """
        Construit un circuit de Simon.
        
        Args:
            n_qubits: Nombre de qubits d'entrée (total = 2n)
            secret: String secret s (ex: '110') ou None pour aléatoire
            seed: Seed si secret aléatoire
        
        Returns:
            Circuit Simon (une itération)
        """
        from qiskit import QuantumCircuit, QuantumRegister, ClassicalRegister
        
        secret = params.get('secret', None)
        seed = params.get('seed', None)
        
        # Générer secret aléatoire si non fourni
        if secret is None:
            rng = np.random.default_rng(seed)
            # Le secret doit avoir au moins un 1 pour être intéressant
            secret = ''.join(str(rng.integers(0, 2)) for _ in range(n_qubits))
            if secret == '0' * n_qubits:
                secret = '1' + '0' * (n_qubits - 1)
        
        if len(secret) != n_qubits:
            secret = secret.zfill(n_qubits)[:n_qubits]
        
        # 2n qubits: n entrée + n sortie
        qr_in = QuantumRegister(n_qubits, 'in')
        qr_out = QuantumRegister(n_qubits, 'out')
        cr = ClassicalRegister(n_qubits, 'c')
        
        qc = QuantumCircuit(qr_in, qr_out, cr, name=f"Simon_{n_qubits}q_s{secret}")
        
        # 1. Hadamard sur les qubits d'entrée
        for i in range(n_qubits):
            qc.h(qr_in[i])
        
        qc.barrier()
        
        # 2. Oracle f(x) → copie x dans output, puis XOR avec s si x[0]=1
        # D'abord copier x dans output
        for i in range(n_qubits):
            qc.cx(qr_in[i], qr_out[i])
        
        # Trouver le premier bit à 1 dans le secret
        first_one = -1
        for i, bit in enumerate(secret):
            if bit == '1':
                first_one = i
                break
        
        # Si s ≠ 0, ajouter l'oracle 2-to-1
        if first_one >= 0:
            # XOR output avec s, contrôlé par input[first_one]
            for i, bit in enumerate(secret):
                if bit == '1':
                    qc.cx(qr_in[n_qubits - 1 - first_one], qr_out[n_qubits - 1 - i])
        
        qc.barrier()
        
        # 3. Hadamard sur les qubits d'entrée
        for i in range(n_qubits):
            qc.h(qr_in[i])
        
        qc.barrier()
        
        # 4. Mesurer uniquement les qubits d'entrée
        for i in range(n_qubits):
            qc.measure(qr_in[i], i)
        
        self._metadata['n_qubits'] = n_qubits
        self._metadata['total_qubits'] = 2 * n_qubits
        self._metadata['secret'] = secret
        self._metadata['iterations_needed'] = n_qubits  # Pour résoudre le système
        
        self._log(f"Built Simon: {n_qubits}q input, secret={secret}")
        
        return qc
    
    @staticmethod
    def solve_secret(measurements: List[str], n_qubits: int) -> Optional[str]:
        """
        Résout le système linéaire pour trouver le secret.
        
        Args:
            measurements: Liste de n-1 résultats de mesure (orthogonaux à s)
            n_qubits: Nombre de qubits
        
        Returns:
            Le secret s, ou None si pas assez de données
        """
        # Les mesures y satisfont y·s = 0 (mod 2)
        # On doit résoudre ce système linéaire sur GF(2)
        
        if len(measurements) < n_qubits - 1:
            return None

        # [v2.7.1 FIX] Retirer les espaces séparateurs de registres dans chaque
        # mesure : sinon int(' ') levait ValueError lors du parsing des bits.
        measurements = [m.replace(' ', '') for m in measurements]

        # Construction de la matrice
        matrix = []
        for m in measurements[:n_qubits - 1]:
            row = [int(b) for b in m]
            matrix.append(row)
        
        # Résolution par élimination de Gauss (simplifié)
        # Pour une implémentation complète, utiliser sympy ou numpy avec GF(2)
        
        # Solution triviale si le système est sous-déterminé
        # Retourner une solution candidate
        try:
            # Essayer toutes les solutions possibles (brute force pour petits n)
            for candidate in range(1, 2**n_qubits):
                s = format(candidate, f'0{n_qubits}b')
                valid = True
                for m in measurements:
                    dot = sum(int(s[i]) * int(m[i]) for i in range(n_qubits)) % 2
                    if dot != 0:
                        valid = False
                        break
                if valid:
                    return s
        except Exception:
            pass
        
        return None


class TeleportationBuilder(CircuitBuilder):
    """
    Constructeur de circuits pour la téléportation quantique.
    
    Téléporte un état quantique |ψ⟩ d'Alice vers Bob en utilisant:
    - 1 paire EPR partagée
    - 2 bits classiques de communication
    
    Démontre l'intrication comme ressource et la correction classique.
    Fondamental pour le calcul quantique distribué.
    """
    
    name = "teleportation"
    
    def __init__(self, topology: 'DynamicTopology' = None, logger: 'Logger' = None):
        super().__init__(topology, logger)
    
    def build(self, n_qubits: int = 3, **params) -> 'CircuitType':
        """
        Construit un circuit de téléportation.
        
        Args:
            n_qubits: Ignoré (toujours 3 qubits pour téléportation standard)
            state_to_teleport: 'zero', 'one', 'plus', 'minus', ou angles (theta, phi)
            with_correction: Appliquer les corrections classiques (défaut: True)
            measure_all: Mesurer tous les qubits à la fin (défaut: True)
            measure_basis: 'z' (défaut) ou 'x'. En base X (Hadamard sur Bob avant
                la mesure), |+⟩/|−⟩ deviennent DÉTERMINISTES ('0'/'1') au lieu de
                50/50, ce qui rend la vérification de |+⟩/|−⟩ réellement concluante.

        Returns:
            Circuit de téléportation
        """
        from qiskit import QuantumCircuit, QuantumRegister, ClassicalRegister

        state = params.get('state_to_teleport', 'plus')
        with_correction = params.get('with_correction', True)
        measure_all = params.get('measure_all', True)
        measure_basis = str(params.get('measure_basis', 'z')).lower()
        
        # 3 qubits: q0 = état à téléporter, q1 = Alice EPR, q2 = Bob EPR
        qr = QuantumRegister(3, 'q')
        cr_alice = ClassicalRegister(2, 'alice')  # Mesures d'Alice
        
        if measure_all:
            cr_bob = ClassicalRegister(1, 'bob')  # Mesure finale de Bob
            qc = QuantumCircuit(qr, cr_alice, cr_bob, name=f"Teleport_{state}")
        else:
            qc = QuantumCircuit(qr, cr_alice, name=f"Teleport_{state}")
        
        # 1. Préparer l'état à téléporter (q0)
        self._prepare_state(qc, 0, state)
        
        qc.barrier()
        
        # 2. Créer la paire EPR entre q1 (Alice) et q2 (Bob)
        qc.h(1)
        qc.cx(1, 2)
        
        qc.barrier()
        
        # 3. Protocole de téléportation d'Alice
        # Bell measurement sur q0 et q1
        qc.cx(0, 1)
        qc.h(0)
        
        qc.barrier()
        
        # 4. Mesures d'Alice
        qc.measure(0, cr_alice[0])
        qc.measure(1, cr_alice[1])
        
        # 5. Corrections classiques de Bob (CONDITIONNELLES)
        # [v2.7.1 FIX CRITIQUE] L'ancien code appliquait X et Z de manière
        # INCONDITIONNELLE (qc.x(2); qc.z(2)), ce qui détruisait le protocole :
        # Bob recevait Z·X·(état conditionné par la mesure de Bell), donc un état
        # maximalement mixte (succès ~50% au lieu de ~100%, vérifié sur Aer).
        # Règle standard de la téléportation : Bob applique X^{m1} Z^{m0} où
        #   m0 = mesure de q0 d'Alice -> cr_alice[0]  (déclenche la correction Z)
        #   m1 = mesure de q1 d'Alice -> cr_alice[1]  (déclenche la correction X)
        # On utilise le feedforward dynamique moderne `if_test` (Qiskit >= 1.0,
        # supporté par Aer et le hardware IBM dynamic-circuits). En cas
        # d'indisponibilité, on RETIRE les corrections plutôt que d'en mettre de
        # fausses (un état non corrigé reste analysable, un état corrompu non).
        if with_correction:
            qc.barrier()
            try:
                with qc.if_test((cr_alice[1], 1)):
                    qc.x(2)  # correction X conditionnée par m1
                with qc.if_test((cr_alice[0], 1)):
                    qc.z(2)  # correction Z conditionnée par m0
            except Exception as e:
                # Pas de feedforward disponible : ne PAS appliquer de corrections
                # inconditionnelles (cela corromprait l'état). On documente que le
                # post-traitement classique est requis.
                self._metadata['correction_mode'] = 'deferred_classical_postprocess'
                self._log(f"if_test indisponible ({e}); corrections déférées au "
                          f"post-traitement classique", level=LogLevel.WARN)
        
        # 6. Mesure finale de Bob (optionnelle)
        if measure_all:
            qc.barrier()
            if measure_basis == 'x':
                # [v2.7.2] Base X : H sur Bob avant la mesure. H|+⟩=|0⟩, H|−⟩=|1⟩,
                # donc |+⟩/|−⟩ deviennent déterministes (au lieu de 50/50 en base Z).
                qc.h(2)
            qc.measure(2, cr_bob[0])

        self._metadata['state_teleported'] = str(state)
        self._metadata['with_correction'] = with_correction
        self._metadata['measure_basis'] = measure_basis
        self._metadata['n_classical_bits'] = 2
        
        self._log(f"Built Teleportation: state={state}, correction={with_correction}")
        
        return qc
    
    def _prepare_state(self, qc, qubit: int, state):
        """Prépare l'état à téléporter"""
        if state == 'zero':
            pass  # Déjà |0⟩
        elif state == 'one':
            qc.x(qubit)
        elif state == 'plus':
            qc.h(qubit)
        elif state == 'minus':
            qc.x(qubit)
            qc.h(qubit)
        elif isinstance(state, (tuple, list)) and len(state) == 2:
            # (theta, phi) pour état arbitraire
            theta, phi = state
            qc.ry(theta, qubit)
            qc.rz(phi, qubit)
        else:
            # État aléatoire
            qc.h(qubit)
            qc.t(qubit)
    
    @staticmethod
    def verify_teleportation(counts: Dict[str, int], expected_state: str,
                             measure_basis: str = 'z') -> Dict[str, Any]:
        """
        Vérifie si la téléportation a réussi.

        Args:
            counts: Résultats de mesure (format: 'bob alice1 alice0')
            expected_state: 'zero', 'one', 'plus', 'minus'
            measure_basis: base de mesure de Bob, 'z' (défaut) ou 'x'. En base Z,
                |0⟩/|1⟩ sont déterministes et |+⟩/|−⟩ donnent 50/50. En base X (le
                circuit a appliqué H sur Bob), c'est l'inverse : |+⟩→'0', |−⟩→'1'
                déterministes, ce qui rend la vérification de |+⟩/|−⟩ concluante.

        Returns:
            Dict avec statistiques de succès
        """
        total = sum(counts.values())

        # [v2.7.2] Résultat Bob attendu selon l'état ET la base de mesure.
        if measure_basis == 'x':
            expected_bob = {'plus': '0', 'minus': '1', 'zero': None, 'one': None}
        else:
            expected_bob = {'zero': '0', 'one': '1', 'plus': None, 'minus': None}

        expected = expected_bob.get(expected_state)

        if expected is not None:
            # Cas déterministe (état/base alignés) : on mesure le taux de succès.
            correct = sum(c for bs, c in counts.items() if bs and bs[0] == expected)
            success_rate = correct / total if total else 0.0

            return {
                'success_rate': success_rate,
                'expected_bob': expected,
                'measure_basis': measure_basis,
                'total_shots': total,
                'correct_shots': correct
            }
        else:
            # Cas non aligné (ex. |+⟩ mesuré en base Z) : on attend ~50/50.
            zeros = sum(c for bs, c in counts.items() if bs and bs[0] == '0')
            ones = sum(c for bs, c in counts.items() if bs and bs[0] == '1')

            return {
                'p_zero': zeros / total if total else 0.0,
                'p_one': ones / total if total else 0.0,
                'balance': abs(zeros - ones) / total if total else 0.0,
                'measure_basis': measure_basis,
                'total_shots': total
            }


