def _is_safe_webhook_url(url: str) -> bool:
    """[v2.7.1 FIX] Anti-SSRF: valide qu'une URL de webhook est sûre.

    Exige le schéma https et rejette file://, ftp://, ainsi que les hôtes
    pointant vers des adresses privées/loopback/link-local.
    """
    if not url or not isinstance(url, str):
        return False
    try:
        from urllib.parse import urlparse
        import ipaddress
        import socket

        parsed = urlparse(url.strip())
        # Schéma autorisé: https uniquement (rejette file, ftp, http, gopher, etc.)
        if parsed.scheme != 'https':
            return False

        host = parsed.hostname
        if not host:
            return False

        # Résoudre tous les enregistrements et vérifier chaque IP
        try:
            infos = socket.getaddrinfo(host, parsed.port or 443, proto=socket.IPPROTO_TCP)
        except Exception:
            return False

        for info in infos:
            sockaddr = info[4]
            ip_str = sockaddr[0]
            try:
                ip = ipaddress.ip_address(ip_str)
            except ValueError:
                return False
            # Rejeter loopback / privé / link-local / réservé / multicast / non spécifié
            if (ip.is_loopback or ip.is_private or ip.is_link_local
                    or ip.is_reserved or ip.is_multicast or ip.is_unspecified):
                return False

        return True
    except Exception:
        return False


def _safe_webhook_post(url: str, payload: bytes, headers: dict = None,
                       timeout: float = 10) -> int:
    """[v2.7.1 FIX R99/R100] POST anti-SSRF robuste vers un webhook.

    Ferme deux contournements que `_is_safe_webhook_url` + urlopen laissaient ouverts :
      - R99 (DNS rebinding / TOCTOU) : on résout l'hôte UNE fois, on valide l'IP, puis on
        ÉPINGLE cette IP au connect() (urlopen, lui, re-résout le DNS et pouvait viser une
        IP privée après coup).
      - R100 (redirections 30x) : on utilise http.client qui NE SUIT PAS les redirections
        (urlopen suivait les 30x, y compris un downgrade https->http vers 169.254.169.254).
    Lève QMCSecurityError si l'URL/IP est rejetée. Renvoie le code de statut HTTP.
    """
    import urllib.parse, socket, ssl, ipaddress, http.client
    if not _is_safe_webhook_url(url):
        raise QMCSecurityError(f"webhook URL rejetée (anti-SSRF): {url}",
                               operation="webhook_post")
    p = urllib.parse.urlparse(url.strip())
    host, port = p.hostname, (p.port or 443)
    pinned_ip = None
    for info in socket.getaddrinfo(host, port, proto=socket.IPPROTO_TCP):
        ip = ipaddress.ip_address(info[4][0])
        if not (ip.is_loopback or ip.is_private or ip.is_link_local
                or ip.is_reserved or ip.is_multicast or ip.is_unspecified):
            pinned_ip = info[4][0]
            break
    if pinned_ip is None:
        raise QMCSecurityError("webhook: aucune IP publique sûre résolue",
                               operation="webhook_post")
    path = (p.path or '/') + (('?' + p.query) if p.query else '')
    ctx = ssl.create_default_context()
    conn = http.client.HTTPSConnection(pinned_ip, port, timeout=timeout, context=ctx)
    try:
        sock = socket.create_connection((pinned_ip, port), timeout=timeout)
        conn.sock = ctx.wrap_socket(sock, server_hostname=host)  # SNI = hôte d'origine
        hdrs = dict(headers or {})
        hdrs.setdefault('Host', host)
        conn.request('POST', path, body=payload, headers=hdrs)
        resp = conn.getresponse()
        resp.read()
        return resp.status  # PAS de suivi de redirection (http.client ne le fait pas)
    finally:
        conn.close()


class NotificationManager:
    """
    Gestionnaire de notifications (Email, Slack, Discord, Webhook).
    
    Usage:
        notifier = NotificationManager()
        notifier.configure(
            email='user@example.com',
            slack_webhook='https://hooks.slack.com/...'
        )
        notifier.send('job_complete', {'job_id': 'xxx', 'status': 'DONE'})
    """
    
    def __init__(self, logger: Logger = None):
        self.logger = logger
        self._config = {
            'email': None,
            'smtp_server': 'smtp.gmail.com',
            'smtp_port': 587,
            'smtp_user': None,
            'smtp_password': None,
            'slack_webhook': None,
            'discord_webhook': None,
            'custom_webhook': None,
            'notify_on': ['job_complete', 'job_failed', 'queue_empty']
        }
        self._enabled = False
    
    def _log(self, msg: str, level: LogLevel = LogLevel.INFO):
        if self.logger:
            self.logger.log(msg, level, section='NOTIFY')
    
    def configure(self, **kwargs):
        """
        Configure les notifications.
        
        Args:
            email: Adresse email destinataire
            smtp_server: Serveur SMTP
            smtp_port: Port SMTP
            smtp_user: Utilisateur SMTP
            smtp_password: Mot de passe SMTP
            slack_webhook: URL webhook Slack
            discord_webhook: URL webhook Discord
            custom_webhook: URL webhook personnalisé
            notify_on: Liste des événements ['job_complete', 'job_failed', 'queue_empty']
        """
        for key, value in kwargs.items():
            if key in self._config:
                self._config[key] = value
        
        # Activer si au moins un canal configuré
        self._enabled = any([
            self._config['email'] and self._config['smtp_user'],
            self._config['slack_webhook'],
            self._config['discord_webhook'],
            self._config['custom_webhook']
        ])
        
        if self._enabled:
            self._log("Notifications configurees")
        else:
            self._log("Aucun canal de notification configure", LogLevel.WARN)
    
    def is_enabled(self) -> bool:
        return self._enabled
    
    def should_notify(self, event_type: str) -> bool:
        """Vérifie si on doit notifier pour cet événement."""
        return event_type in self._config.get('notify_on', [])
    
    def send(self, event_type: str, data: Dict) -> bool:
        """
        Envoie une notification.
        
        Args:
            event_type: Type d'événement ('job_complete', 'job_failed', etc.)
            data: Données de l'événement
        
        Returns:
            True si envoyé avec succès
        """
        if not self._enabled:
            return False
        
        if not self.should_notify(event_type):
            return False
        
        # Construire le message
        message = self._format_message(event_type, data)
        
        success = False
        
        # Envoyer sur tous les canaux configurés
        if self._config['slack_webhook']:
            success |= self._send_slack(message)
        
        if self._config['discord_webhook']:
            success |= self._send_discord(message)
        
        if self._config['custom_webhook']:
            success |= self._send_webhook(message, data)
        
        if self._config['email'] and self._config['smtp_user']:
            success |= self._send_email(event_type, message)
        
        return success
    
    def _format_message(self, event_type: str, data: Dict) -> str:
        """Formate le message de notification."""
        templates = {
            'job_complete': (
                "[OK] QMC Job Complete\n"
                "Job ID: {job_id}\n"
                "Status: {status}\n"
                "Backend: {backend}\n"
                "QPU Time: {qpu_time:.1f}s"
            ),
            'job_failed': (
                "[XX] QMC Job Failed\n"
                "Job ID: {job_id}\n"
                "Error: {error}\n"
                "Backend: {backend}"
            ),
            'queue_empty': (
                "[OK] QMC Queue Complete\n"
                "All jobs finished\n"
                "Total: {total}\n"
                "Completed: {completed}\n"
                "Failed: {failed}"
            ),
            'long_queue': (
                "[!!] QMC Long Queue Warning\n"
                "Backend: {backend}\n"
                "Queue length: {queue_length} jobs\n"
                "Estimated wait: {wait_time}"
            )
        }
        
        template = templates.get(event_type, "QMC Notification: {event_type}\n{data}")
        
        try:
            # Ajouter event_type et data au contexte
            context = {'event_type': event_type, 'data': str(data)}
            context.update(data)
            return template.format(**context)
        except:
            return f"QMC {event_type}: {data}"
    
    def _send_slack(self, message: str) -> bool:
        """Envoie via Slack webhook."""
        try:
            # [v2.7.1 FIX R99/R100] envoi anti-SSRF (IP épinglée + pas de redirection)
            payload = json.dumps({'text': message}).encode()
            status = _safe_webhook_post(self._config['slack_webhook'], payload,
                                        headers={'Content-Type': 'application/json'})
            if status == 200:
                self._log("Slack notification sent")
                return True
        except QMCSecurityError as e:
            self._log(f"Slack notification skipped (anti-SSRF): {e}", LogLevel.WARN)
        except Exception as e:
            self._log(f"Slack error: {e}", LogLevel.WARN)
        return False
    
    def _send_discord(self, message: str) -> bool:
        """Envoie via Discord webhook."""
        try:
            # [v2.7.1 FIX R99/R100] envoi anti-SSRF (IP épinglée + pas de redirection)
            payload = json.dumps({'content': message}).encode()
            status = _safe_webhook_post(self._config['discord_webhook'], payload,
                                        headers={'Content-Type': 'application/json'})
            if status in (200, 204):
                self._log("Discord notification sent")
                return True
        except QMCSecurityError as e:
            self._log(f"Discord notification skipped (anti-SSRF): {e}", LogLevel.WARN)
        except Exception as e:
            self._log(f"Discord error: {e}", LogLevel.WARN)
        return False
    
    def _send_webhook(self, message: str, data: Dict) -> bool:
        """Envoie via webhook personnalisé."""
        try:
            # [v2.7.1 FIX R99/R100] envoi anti-SSRF (IP épinglée + pas de redirection)
            payload = json.dumps({
                'message': message,
                'data': data,
                'timestamp': datetime.now().isoformat()
            }).encode()
            status = _safe_webhook_post(self._config['custom_webhook'], payload,
                                        headers={'Content-Type': 'application/json'})
            if status in (200, 201, 204):
                self._log("Webhook notification sent")
                return True
        except QMCSecurityError as e:
            self._log(f"Webhook notification skipped (anti-SSRF): {e}", LogLevel.WARN)
        except Exception as e:
            self._log(f"Webhook error: {e}", LogLevel.WARN)
        return False
    
    def _send_email(self, subject: str, message: str) -> bool:
        """Envoie par email."""
        try:
            import smtplib
            from email.mime.text import MIMEText
            from email.mime.multipart import MIMEMultipart
            
            msg = MIMEMultipart()
            msg['From'] = self._config['smtp_user']
            msg['To'] = self._config['email']
            msg['Subject'] = f"QMC Notification: {subject}"
            
            msg.attach(MIMEText(message, 'plain'))
            
            server = smtplib.SMTP(
                self._config['smtp_server'],
                self._config['smtp_port']
            )
            server.starttls()
            server.login(
                self._config['smtp_user'],
                self._config['smtp_password']
            )
            server.send_message(msg)
            server.quit()
            
            self._log("Email notification sent")
            return True
            
        except Exception as e:
            self._log(f"Email error: {e}", LogLevel.WARN)
        return False
    
    def notify_job_complete(self, job_id: str, status: str, 
                           backend: str = None, qpu_time: float = 0):
        """Raccourci pour notifier la fin d'un job."""
        self.send('job_complete', {
            'job_id': job_id,
            'status': status,
            'backend': backend or 'unknown',
            'qpu_time': qpu_time
        })
    
    def notify_job_failed(self, job_id: str, error: str, backend: str = None):
        """Raccourci pour notifier l'échec d'un job."""
        self.send('job_failed', {
            'job_id': job_id,
            'error': error,
            'backend': backend or 'unknown'
        })
    
    def test(self) -> bool:
        """Envoie une notification de test."""
        return self.send('job_complete', {
            'job_id': 'TEST_123',
            'status': 'DONE',
            'backend': 'test_backend',
            'qpu_time': 0.0
        })


# =============================================================================
# CIRCUIT COST ESTIMATOR - Estimation du coût avant exécution
# =============================================================================

class CircuitCostEstimator:
    """
    Estime le temps QPU et le coût avant soumission.
    
    [v2.6.0] Coefficients révisés basés sur les specs réelles IBM:
    - Repetition rate: ~10 kHz (100µs entre shots)
    - CLOPS (Circuit Layer Operations Per Second): 5000-15000 selon backend
    - Gate time: ~30ns (1Q), ~300-500ns (2Q/ECR)
    - Setup overhead: ~50-100ms par batch
    
    Usage:
        estimator = CircuitCostEstimator(framework)
        estimate = estimator.estimate(circuits, shots=4096)
        estimator.display_estimate(estimate)
    """
    
    # [v2.6.0] Coefficients empiriques RÉALISTES (basés sur IBM Heron/Eagle)
    # Ces valeurs correspondent aux temps QPU réels observés
    COEF_BASE_TIME = 0.05    # 50ms overhead par circuit (setup, communication)
    COEF_SHOT = 0.0000005    # 0.5µs par shot (repetition ~100µs mais pipeliné)
    COEF_DEPTH = 0.000005    # 5µs par niveau de profondeur (gate time ~500ns * parallélisme)
    COEF_2Q_GATE = 0.00001   # 10µs par porte 2Q (CZ ~68ns + routing)
    COEF_QUBIT = 0.00001     # 10µs par qubit (négligeable, mais scaling)
    COEF_BATCH_OVERHEAD = 0.5  # 500ms overhead fixe par batch (communication QPU)
    
    # [v2.6.0] Specs par backend (CLOPS = Circuit Layer Operations Per Second)
    # Source: IBM Quantum Platform - Janvier 2026
    BACKEND_SPECS = {
        # Heron r3 - Dernière génération
        'ibm_boston': {'clops': 340000, 'family': 'Heron r3', 'qubits': 156},
        'ibm_pittsburgh': {'clops': 330000, 'family': 'Heron r3', 'qubits': 156},
        # Heron r2
        'ibm_kingston': {'clops': 340000, 'family': 'Heron r2', 'qubits': 156},
        'ibm_fez': {'clops': 320000, 'family': 'Heron r2', 'qubits': 156},
        'ibm_marrakesh': {'clops': 300000, 'family': 'Heron r2', 'qubits': 156},
        # Heron r1
        'ibm_torino': {'clops': 290000, 'family': 'Heron r1', 'qubits': 133},
        # Nighthawk r1 - Nouvelle architecture
        'ibm_miami': {'clops': 24000, 'family': 'Nighthawk r1', 'qubits': 120},
    }
    
    def __init__(self, framework=None, logger: Logger = None):
        self.framework = framework
        self.logger = logger
        self._history = []  # Historique pour calibrer les estimations
    
    def _log(self, msg: str, level: LogLevel = LogLevel.INFO):
        if self.logger:
            self.logger.log(msg, level, section='ESTIMATE')
    
    def estimate_precise(self, circuits, shots: int = 4096) -> Dict:
        """
        [v2.6.0] Estimation PRÉCISE du temps QPU basée sur la formule officielle IBM
        et les durées réelles des instructions du backend.
        
        Formule IBM officielle (sans error mitigation avancée):
            temps = 2 + 0.00035 × num_executions (secondes)
            où num_executions = circuits × shots
        
        Formule détaillée IBM:
            temps = overhead (2s/sub-job) + (rep_delay + circuit_length) × num_executions
            - rep_delay = backend.default_rep_delay (~250µs)
            - circuit_length = somme des durées des instructions
            - backend.target[instruction][qubit].duration donne la durée exacte
        
        Args:
            circuits: Circuit(s) transpilé(s) à estimer
            shots: Nombre de shots
        
        Returns:
            Dict avec estimation précise et détails
        """
        if not isinstance(circuits, list):
            circuits = [circuits]
        
        n_circuits = len(circuits)
        num_executions = n_circuits * shots
        
        # === MÉTHODE 1: Formule rapide IBM officielle ===
        # Pour les cas sans error mitigation avancée ni rep_delay personnalisé
        ibm_quick_formula = 2.0 + 0.00035 * num_executions
        
        # === MÉTHODE 2: Formule détaillée avec durées réelles ===
        backend = None
        rep_delay = 250e-6  # 250µs par défaut
        dt = 1e-9  # 1ns par défaut
        
        if self.framework:
            backend = getattr(self.framework, 'backend', None)
            if backend:
                # Récupérer rep_delay du backend
                try:
                    rep_delay = getattr(backend, 'default_rep_delay', 250e-6)
                    if rep_delay is None:
                        rep_delay = 250e-6
                except:
                    pass
                
                # Récupérer dt (time resolution)
                try:
                    if hasattr(backend, 'target') and backend.target:
                        dt = getattr(backend.target, 'dt', 1e-9) or 1e-9
                except:
                    pass
        
        # Calculer la durée de chaque circuit
        circuit_lengths = []
        total_gates_info = {'1q': 0, '2q': 0, 'measure': 0, 'other': 0}
        
        for circuit in circuits:
            circuit_length = 0.0
            ops = dict(circuit.count_ops())
            n_qubits = circuit.num_qubits
            
            # [v2.7.0] Pour gros circuits (>40Q), utiliser count_ops() avec durées moyennes
            # au lieu d'itérer circuit.data (trop lent: 50k+ instructions)
            if n_qubits > 40:
                # Durées typiques IBM moyennes (en secondes)
                typical_durations = {
                    'x': 35e-9, 'sx': 35e-9, 'sxdg': 35e-9, 'rz': 0,
                    'id': 35e-9, 'delay': 0, 'h': 35e-9,
                    'ecr': 500e-9, 'cz': 500e-9, 'cx': 500e-9, 'swap': 1500e-9,
                    'measure': 1200e-9, 'reset': 1000e-9, 'barrier': 0,
                }
                for gate_name, count in ops.items():
                    dur = typical_durations.get(gate_name, 100e-9)
                    circuit_length += dur * count
                
                # Stats rapides
                total_gates_info['1q'] += sum(v for k, v in ops.items() 
                    if k in ['x', 'sx', 'sxdg', 'rz', 'h', 's', 't', 'sdg', 'tdg', 'id', 'ry', 'rx'])
                total_gates_info['2q'] += sum(v for k, v in ops.items() 
                    if k in ['cx', 'cz', 'ecr', 'swap', 'rzz', 'rxx', 'ryy'])
                total_gates_info['measure'] += ops.get('measure', 0)
            else:
                # Petit circuit: itération fine avec durées backend exactes
                for instruction in circuit.data:
                    gate_name = instruction.operation.name
                    qubits = [q._index if hasattr(q, '_index') else q for q in instruction.qubits]
                    i_nq = len(qubits)
                    
                    # Essayer d'obtenir la durée exacte du backend.target
                    duration = None
                    if backend and hasattr(backend, 'target') and backend.target:
                        try:
                            target = backend.target
                            if gate_name in target:
                                qubit_tuple = tuple(qubits)
                                if qubit_tuple in target[gate_name]:
                                    props = target[gate_name][qubit_tuple]
                                    if props and hasattr(props, 'duration') and props.duration:
                                        duration = props.duration
                        except:
                            pass
                    
                    if duration is None:
                        typical_durations = {
                            'x': 35e-9, 'sx': 35e-9, 'rz': 0,
                            'id': 35e-9, 'delay': 0,
                            'ecr': 500e-9, 'cz': 500e-9, 'cx': 500e-9,
                            'measure': 1200e-9, 'reset': 1000e-9,
                        }
                        duration = typical_durations.get(gate_name, 100e-9)
                    
                    circuit_length += duration
                    
                    if gate_name == 'measure':
                        total_gates_info['measure'] += 1
                    elif i_nq == 1:
                        total_gates_info['1q'] += 1
                    elif i_nq >= 2:
                        total_gates_info['2q'] += 1
                    else:
                        total_gates_info['other'] += 1
            
            circuit_lengths.append(circuit_length)
        
        # Moyenne de la longueur des circuits
        avg_circuit_length = sum(circuit_lengths) / len(circuit_lengths) if circuit_lengths else 0
        
        # Nombre de sub-jobs (IBM divise les gros jobs)
        # Estimation: 1 sub-job par ~100 circuits ou ~1M d'exécutions
        n_subjobs = max(1, n_circuits // 100, num_executions // 1_000_000)
        subjob_overhead = 2.0 * n_subjobs  # 2s par sub-job
        
        # Formule détaillée IBM
        # temps = overhead + (rep_delay + circuit_length) × num_executions
        ibm_detailed_formula = subjob_overhead + (rep_delay + avg_circuit_length) * num_executions
        
        # === RÉSULTAT FINAL ===
        # Prendre la valeur la plus réaliste (généralement la formule détaillée)
        estimated_time = ibm_detailed_formula
        
        # Détails pour l'affichage
        return {
            'estimated_qpu_time_s': round(estimated_time, 3),
            'estimated_qpu_time_str': self._format_time(estimated_time),
            'ibm_quick_formula_s': round(ibm_quick_formula, 3),
            'ibm_detailed_formula_s': round(ibm_detailed_formula, 3),
            'num_executions': num_executions,
            'n_circuits': n_circuits,
            'shots': shots,
            'n_subjobs': n_subjobs,
            'subjob_overhead_s': subjob_overhead,
            'rep_delay_us': rep_delay * 1e6,
            'avg_circuit_length_us': avg_circuit_length * 1e6,
            'circuit_lengths_us': [l * 1e6 for l in circuit_lengths],
            'gates_info': total_gates_info,
            'method': 'IBM official formula with backend.target durations',
            'formula': 'overhead + (rep_delay + circuit_length) × num_executions',
        }
    
    def _format_time(self, seconds: float) -> str:
        """Formate un temps en secondes en string lisible."""
        if seconds < 0.001:
            return f"{seconds*1e6:.0f}µs"
        elif seconds < 1:
            return f"{seconds*1000:.0f}ms"
        elif seconds < 60:
            return f"{seconds:.1f}s"
        elif seconds < 3600:
            return f"{seconds/60:.1f}min"
        else:
            return f"{seconds/3600:.1f}h"
    
    def _analyze_circuit(self, circuit) -> Dict:
        """Analyse un circuit pour extraire ses caractéristiques.
        [v2.7.0] Utilise count_ops() au lieu d'itérer circuit.data."""
        try:
            num_qubits = circuit.num_qubits
            depth = circuit.depth()
            ops = dict(circuit.count_ops())
            
            two_q_gates = sum(v for k, v in ops.items() 
                             if k in ['cx', 'cz', 'ecr', 'swap', 'rzz', 'rxx', 'ryy'])
            total_gates = sum(ops.values())
            
            return {
                'num_qubits': num_qubits,
                'depth': depth,
                'two_q_gates': two_q_gates,
                'total_gates': total_gates
            }
        except Exception as e:
            return {
                'num_qubits': 0,
                'depth': 0,
                'two_q_gates': 0,
                'total_gates': 0,
                'error': str(e)
            }
    
    def estimate(self, circuits, shots: int = 4096, 
                 backend: str = None) -> Dict:
        """
        Estime le temps et le coût d'exécution.
        
        Args:
            circuits: Circuit(s) à estimer
            shots: Nombre de shots
            backend: Backend cible (optionnel)
        
        Returns:
            Dict avec estimations détaillées
        """
        if not isinstance(circuits, list):
            circuits = [circuits]
        
        # Analyser chaque circuit
        analyses = []
        total_depth = 0
        total_2q = 0
        total_qubits = 0
        
        for circuit in circuits:
            analysis = self._analyze_circuit(circuit)
            analyses.append(analysis)
            total_depth += analysis.get('depth', 0)
            total_2q += analysis.get('two_q_gates', 0)
            total_qubits = max(total_qubits, analysis.get('num_qubits', 0))
        
        n_circuits = len(circuits)
        total_shots = n_circuits * shots
        
        # [v2.6.0] Estimation du temps QPU RÉALISTE
        # Utilise les specs du backend si disponibles
        backend_name = getattr(self.framework, 'backend_name', '') if self.framework else ''
        backend_specs = self.BACKEND_SPECS.get(backend_name, {})
        clops = backend_specs.get('clops', 5000)  # Défaut: Eagle r3
        
        # Méthode 1: Basée sur CLOPS (plus précise pour les circuits profonds)
        # CLOPS = Circuit Layer Operations Per Second
        # Temps ≈ (circuits * depth) / CLOPS
        clops_time = (n_circuits * (total_depth / n_circuits if n_circuits > 0 else 0)) / clops if clops > 0 else 0
        
        # Méthode 2: Basée sur les coefficients (pour les circuits avec beaucoup de shots)
        # Prend en compte le pipelining des shots
        base_time = self.COEF_BATCH_OVERHEAD  # Overhead fixe par batch
        circuit_time = n_circuits * self.COEF_BASE_TIME  # Overhead par circuit
        shot_time = total_shots * self.COEF_SHOT  # Temps shots (pipeliné)
        depth_time = total_depth * self.COEF_DEPTH  # Temps profondeur totale
        gate_time = total_2q * self.COEF_2Q_GATE  # Temps portes 2Q
        
        coef_time = base_time + circuit_time + shot_time + depth_time + gate_time
        
        # Utiliser le MAX des deux méthodes (pour être conservatif mais réaliste)
        # En pratique, le CLOPS domine pour les circuits profonds, les coefficients pour beaucoup de shots
        estimated_time = max(clops_time, coef_time)
        
        # Minimum réaliste: au moins 100ms de communication
        estimated_time = max(0.1, estimated_time)
        
        # Marges d'erreur
        time_min = estimated_time * 0.7
        time_max = estimated_time * 1.5
        
        # Estimation du temps de queue
        queue_estimates = {}
        if self.framework and hasattr(self.framework, 'service'):
            try:
                for b in self.framework.service.backends():
                    try:
                        status = b.status()
                        pending = status.pending_jobs if hasattr(status, 'pending_jobs') else 0
                        # Estimation: 2min par job en queue
                        wait_min = pending * 2
                        queue_estimates[b.name] = {
                            'pending_jobs': pending,
                            'estimated_wait_min': wait_min,
                            'estimated_wait_str': f"~{wait_min}min" if wait_min < 60 else f"~{wait_min//60}h{wait_min%60}min"
                        }
                    except:
                        pass
            except:
                pass
        
        # Impact sur le budget mensuel
        budget_impact = {}
        if self.framework:
            try:
                current_usage = self.framework.get_monthly_usage(days=30, animate=False)
                current_used = current_usage.get('total_time_s', 0) / 60  # en minutes
                
                # Budget mensuel typique: 10 min
                monthly_budget = 10.0
                after_job = current_used + (estimated_time / 60)
                remaining = monthly_budget - after_job
                
                budget_impact = {
                    'current_used_min': round(current_used, 2),
                    'estimated_job_min': round(estimated_time / 60, 2),
                    'after_job_min': round(after_job, 2),
                    'remaining_min': round(max(0, remaining), 2),
                    'monthly_budget_min': monthly_budget,
                    'within_budget': remaining > 0
                }
            except:
                pass
        
        result = {
            'circuits': n_circuits,
            'total_shots': total_shots,
            'max_qubits': total_qubits,
            'total_depth': total_depth,
            'total_2q_gates': total_2q,
            'circuit_analyses': analyses,
            'estimated_qpu_time': {
                'expected_s': round(estimated_time, 2),
                'min_s': round(time_min, 2),
                'max_s': round(time_max, 2),
                'expected_str': f"{estimated_time:.1f}s" if estimated_time < 60 else f"{estimated_time/60:.1f}min"
            },
            'queue_estimates': queue_estimates,
            'budget_impact': budget_impact,
            'recommendation': self._get_recommendation(estimated_time, budget_impact)
        }
        
        return result
    
    def _get_recommendation(self, estimated_time: float, budget: Dict) -> str:
        """Génère une recommandation basée sur l'estimation."""
        if budget.get('within_budget') == False:
            return "[!!] ATTENTION: Depasse le budget mensuel!"
        
        if estimated_time > 300:  # > 5 min
            return "[!!] Job long (>5min) - Verifiez les parametres"
        
        if estimated_time > 60:
            return "[OK] Job moyen - Execution recommandee"
        
        return "[OK] Job court - OK pour execution"
    
    def display_estimate(self, estimate: Dict, confirm: bool = False) -> bool:
        """
        Affiche l'estimation de manière visuelle.
        
        Args:
            estimate: Résultat de estimate()
            confirm: Demander confirmation avant de continuer
        
        Returns:
            True si confirmé ou pas de confirmation demandée
        """
        W = 62
        print()
        print("  +" + "=" * W + "+")
        print("  |" + " ESTIMATION COUT QPU ".center(W) + "|")
        print("  +" + "=" * W + "+")
        print("  |" + " " * W + "|")
        
        # Circuits
        print("  |  " + "CIRCUITS".ljust(W - 4) + "  |")
        print("  |  " + "-" * (W - 4) + "  |")
        print("  |  " + f"Nombre:        {estimate['circuits']}".ljust(W - 4) + "  |")
        print("  |  " + f"Total shots:   {estimate['total_shots']:,}".ljust(W - 4) + "  |")
        print("  |  " + f"Max qubits:    {estimate['max_qubits']}".ljust(W - 4) + "  |")
        print("  |  " + f"Profondeur:    {estimate['total_depth']}".ljust(W - 4) + "  |")
        print("  |  " + f"Portes 2Q:     {estimate['total_2q_gates']}".ljust(W - 4) + "  |")
        print("  |" + " " * W + "|")
        
        # Temps estimé
        qpu = estimate['estimated_qpu_time']
        print("  |  " + "TEMPS QPU ESTIME".ljust(W - 4) + "  |")
        print("  |  " + "-" * (W - 4) + "  |")
        print("  |  " + f"Attendu:       {qpu['expected_str']}".ljust(W - 4) + "  |")
        print("  |  " + f"Fourchette:    {qpu['min_s']:.1f}s - {qpu['max_s']:.1f}s".ljust(W - 4) + "  |")
        print("  |" + " " * W + "|")
        
        # Queue
        if estimate.get('queue_estimates'):
            print("  |  " + "TEMPS D'ATTENTE ESTIME".ljust(W - 4) + "  |")
            print("  |  " + "-" * (W - 4) + "  |")
            for backend, info in list(estimate['queue_estimates'].items())[:3]:
                line = f"{backend}: {info['estimated_wait_str']} ({info['pending_jobs']} jobs)"
                print("  |  " + f"  {line}".ljust(W - 4) + "  |")
            print("  |" + " " * W + "|")
        
        # Budget
        if estimate.get('budget_impact'):
            budget = estimate['budget_impact']
            print("  |  " + "IMPACT BUDGET MENSUEL".ljust(W - 4) + "  |")
            print("  |  " + "-" * (W - 4) + "  |")
            print("  |  " + f"Utilise:       {budget['current_used_min']:.1f} min".ljust(W - 4) + "  |")
            print("  |  " + f"Ce job:       +{budget['estimated_job_min']:.1f} min".ljust(W - 4) + "  |")
            print("  |  " + f"Apres:         {budget['after_job_min']:.1f} / {budget['monthly_budget_min']} min".ljust(W - 4) + "  |")
            print("  |  " + f"Restant:       {budget['remaining_min']:.1f} min".ljust(W - 4) + "  |")
            print("  |" + " " * W + "|")
        
        # Recommandation
        print("  |  " + estimate.get('recommendation', '').ljust(W - 4) + "  |")
        print("  |" + " " * W + "|")
        print("  +" + "=" * W + "+")
        print()
        
        if confirm:
            response = input("  Confirmer l'execution? (y/n): ").strip().lower()
            return response in ['y', 'yes', 'o', 'oui']
        
        return True
    
    def calibrate(self, actual_time: float, estimated_time: float):
        """
        Calibre les coefficients basé sur les résultats réels.
        
        Args:
            actual_time: Temps réel mesuré
            estimated_time: Temps estimé
        """
        self._history.append({
            'actual': actual_time,
            'estimated': estimated_time,
            'ratio': actual_time / estimated_time if estimated_time > 0 else 1
        })
        
        # Ajuster les coefficients si assez d'historique
        if len(self._history) >= 10:
            avg_ratio = sum(h['ratio'] for h in self._history[-10:]) / 10
            
            # Ajuster tous les coefficients
            if avg_ratio > 1.1:  # Sous-estimation
                self.COEF_BASE_TIME *= avg_ratio
                self.COEF_SHOT *= avg_ratio
                self.COEF_DEPTH *= avg_ratio
                self._log(f"Coefficients ajustes (x{avg_ratio:.2f})")
            elif avg_ratio < 0.9:  # Sur-estimation
                self.COEF_BASE_TIME *= avg_ratio
                self.COEF_SHOT *= avg_ratio
                self.COEF_DEPTH *= avg_ratio
                self._log(f"Coefficients ajustes (x{avg_ratio:.2f})")


# =============================================================================
# v2.5.16 - BATCH MANAGER INTELLIGENT
# =============================================================================

class BatchManager:
    """
    [v2.5.16] Gestionnaire intelligent de batches pour gros jobs.
    
    Découpe automatiquement les gros jobs en batches optimaux,
    gère les erreurs par batch, et permet la reprise automatique.
    
    Usage:
        batch_mgr = BatchManager(framework, max_circuits_per_batch=30)
        results = batch_mgr.submit_all(circuits, shots=4096)
        
        # Ou avec callback de progression
        results = batch_mgr.submit_all(circuits, shots=4096, 
                                       on_batch_complete=lambda i, r: print(f"Batch {i} done"))
    """
    
    def __init__(self, framework: 'QMCFramework', 
                 max_circuits_per_batch: int = 30,
                 max_shots_per_batch: int = 100000,
                 retry_failed_batches: bool = True,
                 save_intermediate: bool = True,
                 logger: Logger = None):
        """
        Args:
            framework: Instance QMCFramework connectée
            max_circuits_per_batch: Max circuits par batch (défaut: 30)
            max_shots_per_batch: Max shots totaux par batch (défaut: 100k)
            retry_failed_batches: Réessayer les batches en erreur (défaut: True)
            save_intermediate: Sauvegarder les résultats intermédiaires (défaut: True)
            logger: Logger pour les messages
        """
        self.framework = framework
        self.max_circuits = max_circuits_per_batch
        self.max_shots = max_shots_per_batch
        self.retry_failed = retry_failed_batches
        self.save_intermediate = save_intermediate
        self.logger = logger or (framework.logger if framework else None)
        
        # État
        self._batches: List[Dict] = []
        self._results: List[Dict] = []
        self._failed_batches: List[int] = []
        self._checkpoint_file: Optional[Path] = None
    
    def _log(self, msg: str, level: LogLevel = LogLevel.INFO):
        if self.logger:
            self.logger.log(msg, level, section='BATCH')
        else:
            print(f"[BATCH] {msg}")
    
    def calculate_optimal_batch_size(self, circuits: List, shots: int) -> int:
        """
        Calcule la taille optimale de batch selon les circuits et shots.
        
        Returns:
            Nombre optimal de circuits par batch
        """
        # Contrainte 1: Max circuits
        max_by_circuits = self.max_circuits
        
        # Contrainte 2: Max shots totaux
        max_by_shots = self.max_shots // shots if shots > 0 else self.max_circuits
        
        # Contrainte 3: Complexité des circuits (profondeur moyenne)
        avg_depth = sum(c.depth() for c in circuits) / len(circuits) if circuits else 10
        
        # Si circuits très profonds, réduire la taille du batch
        if avg_depth > 100:
            depth_factor = 0.5
        elif avg_depth > 50:
            depth_factor = 0.75
        else:
            depth_factor = 1.0
        
        optimal = int(min(max_by_circuits, max_by_shots) * depth_factor)
        return max(1, optimal)  # Au moins 1
    
    def split_into_batches(self, circuits: List, shots: int) -> List[List]:
        """
        Découpe une liste de circuits en batches optimaux.
        
        Returns:
            Liste de batches (chaque batch est une liste de circuits)
        """
        batch_size = self.calculate_optimal_batch_size(circuits, shots)
        
        batches = []
        for i in range(0, len(circuits), batch_size):
            batches.append(circuits[i:i + batch_size])
        
        self._log(f"Découpage: {len(circuits)} circuits → {len(batches)} batches de ~{batch_size} circuits")
        
        return batches
    
    def submit_all(self, circuits: List, shots: int = 4096,
                   on_batch_complete: Callable = None,
                   on_batch_error: Callable = None,
                   **kwargs) -> Dict[str, Any]:
        """
        Soumet tous les circuits en batches avec gestion d'erreurs.
        
        Args:
            circuits: Liste de circuits à exécuter
            shots: Nombre de shots par circuit
            on_batch_complete: Callback(batch_index, results) appelé après chaque batch
            on_batch_error: Callback(batch_index, error) appelé si erreur
            **kwargs: Arguments additionnels pour run_on_qpu
            
        Returns:
            Dict avec tous les résultats consolidés
        """
        if not circuits:
            return {'status': 'empty', 'results': [], 'batches': 0}
        
        batches = self.split_into_batches(circuits, shots)
        n_batches = len(batches)
        
        all_results = []
        batch_info = []
        failed_indices = []
        
        # Afficher le plan
        print()
        print("  ╔════════════════════════════════════════════════════════════════════════════╗")
        print("  ║  📦 BATCH MANAGER - EXÉCUTION PAR LOTS                                     ║")
        print("  ╠════════════════════════════════════════════════════════════════════════════╣")
        print(f"  ║  📊 Total circuits:  {len(circuits):<52} ║")
        print(f"  ║  📦 Nombre de batches: {n_batches:<51} ║")
        print(f"  ║  🎯 Circuits/batch:   ~{len(batches[0]) if batches else 0:<50} ║")
        print(f"  ║  🔫 Shots/circuit:    {shots:<52} ║")
        print("  ╚════════════════════════════════════════════════════════════════════════════╝")
        print()
        
        start_time = time.time()
        
        for i, batch in enumerate(batches):
            batch_start = time.time()
            
            print(f"  ┌─ Batch {i+1}/{n_batches} ({len(batch)} circuits) ─────────────────────────────────")
            
            try:
                # Soumettre le batch
                results = self.framework.run_on_qpu(batch, shots=shots, **kwargs)
                
                if results:
                    all_results.extend(results)
                    batch_info.append({
                        'index': i,
                        'circuits': len(batch),
                        'status': 'success',
                        'duration_s': time.time() - batch_start
                    })
                    
                    print(f"  └─ ✅ Batch {i+1} terminé ({time.time() - batch_start:.1f}s)")
                    
                    if on_batch_complete:
                        on_batch_complete(i, results)
                    
                    # Sauvegarder checkpoint intermédiaire
                    if self.save_intermediate:
                        self._save_checkpoint(i, all_results, batch_info)
                else:
                    raise Exception("Résultats vides")
                    
            except Exception as e:
                failed_indices.append(i)
                batch_info.append({
                    'index': i,
                    'circuits': len(batch),
                    'status': 'error',
                    'error': str(e),
                    'duration_s': time.time() - batch_start
                })
                
                print(f"  └─ ❌ Batch {i+1} ERREUR: {str(e)[:50]}")
                self._log(f"Batch {i+1} failed: {e}", LogLevel.ERROR)
                
                if on_batch_error:
                    on_batch_error(i, e)
        
        # Retry des batches en erreur si demandé
        if self.retry_failed and failed_indices:
            print()
            print(f"  ⏳ Retry des {len(failed_indices)} batches en erreur...")
            
            for idx in failed_indices[:]:  # Copie pour modifier pendant itération
                batch = batches[idx]
                try:
                    results = self.framework.run_on_qpu(batch, shots=shots, **kwargs)
                    if results:
                        all_results.extend(results)
                        batch_info[idx]['status'] = 'success_retry'
                        failed_indices.remove(idx)
                        print(f"  ✅ Batch {idx+1} récupéré au retry")
                except Exception as e:
                    print(f"  ❌ Batch {idx+1} échec définitif: {e}")
        
        total_time = time.time() - start_time
        
        # Résumé final
        success_count = sum(1 for b in batch_info if 'success' in b['status'])
        
        print()
        print("  ╔════════════════════════════════════════════════════════════════════════════╗")
        print("  ║  📊 RÉSUMÉ BATCH MANAGER                                                   ║")
        print("  ╠════════════════════════════════════════════════════════════════════════════╣")
        print(f"  ║  ✅ Batches réussis:  {success_count}/{n_batches:<47} ║")
        print(f"  ║  ❌ Batches échoués:  {len(failed_indices):<52} ║")
        print(f"  ║  📈 Résultats totaux: {len(all_results):<52} ║")
        print(f"  ║  ⏱️  Temps total:     {total_time:.1f}s                                            ║")
        print("  ╚════════════════════════════════════════════════════════════════════════════╝")
        
        return {
            'status': 'complete' if not failed_indices else 'partial',
            'results': all_results,
            'batches': batch_info,
            'total_circuits': len(circuits),
            'successful_circuits': len(all_results),
            'failed_batches': failed_indices,
            'total_time_s': total_time
        }
    
    def _save_checkpoint(self, batch_index: int, results: List, batch_info: List):
        """Sauvegarde un checkpoint intermédiaire."""
        if not self.framework or not hasattr(self.framework, 'dir_manager'):
            return
        
        try:
            checkpoint = {
                'batch_index': batch_index,
                'results_count': len(results),
                'batch_info': batch_info,
                'timestamp': datetime.now().isoformat()
            }
            
            self._checkpoint_file = self.framework.dir_manager.get_file(
                f'batch_checkpoint_{batch_index}.json'
            )
            
            with open(self._checkpoint_file, 'w', encoding='utf-8') as f:  # [v2.7.1 FIX] encoding
                json.dump(checkpoint, f, indent=2, default=str)
                
        except Exception as e:
            self._log(f"Checkpoint save failed: {e}", LogLevel.WARN)
    
    def resume_from_checkpoint(self, checkpoint_file: str) -> Optional[Dict]:
        """
        Reprend une exécution depuis un checkpoint.
        
        Args:
            checkpoint_file: Chemin vers le fichier checkpoint
            
        Returns:
            Dict avec les informations de reprise ou None
        """
        try:
            with open(checkpoint_file, 'r', encoding='utf-8') as f:  # [v2.7.1 FIX] encoding
                checkpoint = json.load(f)

            self._log(f"Reprise depuis batch {checkpoint['batch_index'] + 1}")
            return checkpoint
            
        except Exception as e:
            self._log(f"Cannot load checkpoint: {e}", LogLevel.ERROR)
            return None


# =============================================================================
# v2.5.16 - BUDGET MANAGER
# =============================================================================

class BudgetManager:
    """
    [v2.5.16] Gestionnaire de budget QPU mensuel.
    
    Permet de:
    - Définir un budget mensuel en minutes QPU
    - Suivre l'utilisation en temps réel
    - Alerter quand on approche de la limite
    - Bloquer les exécutions si dépassement
    
    Usage:
        budget = BudgetManager(framework, monthly_budget_minutes=100)
        budget.set_alert_threshold(80)  # Alerte à 80%
        
        # Vérifier avant exécution
        if budget.can_execute(estimated_minutes=2.5):
            results = fw.run_on_qpu(circuits)
            budget.record_usage(results)
    """
    
    def __init__(self, framework: 'QMCFramework' = None,
                 monthly_budget_minutes: float = 100.0,
                 alert_threshold_percent: float = 80.0,
                 block_on_exceed: bool = False,
                 logger: Logger = None):
        """
        Args:
            framework: Instance QMCFramework pour récupérer l'usage réel
            monthly_budget_minutes: Budget mensuel en minutes (défaut: 100)
            alert_threshold_percent: Seuil d'alerte en % (défaut: 80%)
            block_on_exceed: Bloquer les exécutions si budget dépassé (défaut: False)
            logger: Logger pour les messages
        """
        self.framework = framework
        self.monthly_budget = monthly_budget_minutes
        self.alert_threshold = alert_threshold_percent
        self.block_on_exceed = block_on_exceed
        self.logger = logger or (framework.logger if framework else None)
        
        # Tracking
        self._usage_records: List[Dict] = []
        self._alerts_sent: Set[int] = set()  # Thresholds déjà alertés
        # [v2.7.1 FIX] Track the active month so alert state is reset when it rolls over.
        self._alerts_month: str = datetime.now().strftime('%Y-%m')
        self._storage_file: Optional[Path] = None
        
        # Charger l'historique si disponible
        self._load_history()
    
    def _log(self, msg: str, level: LogLevel = LogLevel.INFO):
        if self.logger:
            self.logger.log(msg, level, section='BUDGET')
        else:
            print(f"[BUDGET] {msg}")
    
    def _load_history(self):
        """Charge l'historique d'usage depuis le fichier."""
        try:
            home = Path.home()
            self._storage_file = home / '.qmc_budget_history.json'
            
            if self._storage_file.exists():
                with open(self._storage_file, 'r', encoding='utf-8') as f:  # [v2.7.1 FIX] encoding
                    data = json.load(f)
                    self._usage_records = data.get('records', [])
                    self._log(f"Historique chargé: {len(self._usage_records)} enregistrements")
        except Exception as e:
            self._log(f"Cannot load history: {e}", LogLevel.WARN)
    
    def _save_history(self):
        """Sauvegarde l'historique d'usage."""
        try:
            if self._storage_file:
                with open(self._storage_file, 'w', encoding='utf-8') as f:  # [v2.7.1 FIX] encoding
                    json.dump({
                        'records': self._usage_records,
                        'monthly_budget': self.monthly_budget,
                        'last_updated': datetime.now().isoformat()
                    }, f, indent=2)
        except Exception as e:
            self._log(f"Cannot save history: {e}", LogLevel.WARN)
    
    def get_current_month_usage(self) -> float:
        """
        Retourne l'usage du mois en cours en minutes.
        
        Returns:
            Usage en minutes
        """
        now = datetime.now()
        current_month = now.strftime('%Y-%m')
        
        monthly_usage = sum(
            r.get('minutes', 0)
            for r in self._usage_records
            if r.get('month') == current_month
        )
        
        return monthly_usage
    
    def get_remaining_budget(self) -> float:
        """
        Retourne le budget restant pour le mois.
        
        Returns:
            Minutes restantes
        """
        return max(0, self.monthly_budget - self.get_current_month_usage())
    
    def get_usage_percent(self) -> float:
        """
        Retourne le pourcentage du budget utilisé.
        
        Returns:
            Pourcentage (0-100+)
        """
        if self.monthly_budget <= 0:
            return 0
        return (self.get_current_month_usage() / self.monthly_budget) * 100
    
    def can_execute(self, estimated_minutes: float) -> bool:
        """
        Vérifie si une exécution peut être faite dans le budget.
        
        Args:
            estimated_minutes: Estimation du temps QPU nécessaire
            
        Returns:
            True si OK, False si dépasserait le budget
        """
        # [v2.7.1 FIX] Roll the monthly alert state before evaluating, so a fresh month
        # re-enables alerts and the remaining budget reflects the current month.
        self._maybe_roll_month()

        remaining = self.get_remaining_budget()

        # Vérifier les alertes en premier (état d'alerte à jour)
        self._check_alerts()

        if estimated_minutes > remaining:
            self._log(f"⚠️ Budget insuffisant! Estimé: {estimated_minutes:.2f}min, "
                     f"Restant: {remaining:.2f}min", LogLevel.WARN)

            # [v2.7.1 FIX] Enforce the limit: block when configured to do so.
            if self.block_on_exceed:
                return False

        return True
    
    def _maybe_roll_month(self):
        """[v2.7.1 FIX] Reset monthly alert state when the calendar month rolls over.

        get_current_month_usage() resets to 0 at month change, but _alerts_sent
        previously kept last month's thresholds, suppressing this month's alerts.
        """
        current_month = datetime.now().strftime('%Y-%m')
        if current_month != self._alerts_month:
            self._alerts_month = current_month
            self._alerts_sent.clear()

    def _check_alerts(self):
        """Vérifie et envoie les alertes de seuil."""
        # [v2.7.1 FIX] Roll month before evaluating alerts.
        self._maybe_roll_month()
        usage_pct = self.get_usage_percent()

        # Alertes à 50%, 75%, 90%, 100%
        thresholds = [50, 75, 90, 100]
        
        for threshold in thresholds:
            if usage_pct >= threshold and threshold not in self._alerts_sent:
                self._alerts_sent.add(threshold)
                
                if threshold >= 100:
                    self._log(f"🔴 BUDGET DÉPASSÉ! Usage: {usage_pct:.1f}%", LogLevel.ERROR)
                elif threshold >= 90:
                    self._log(f"🟠 ATTENTION: Budget à {usage_pct:.1f}%", LogLevel.WARN)
                else:
                    self._log(f"🟡 Info: Budget à {usage_pct:.1f}%", LogLevel.INFO)
    
    def record_usage(self, job_result: Dict = None, minutes: float = None, 
                     job_id: str = None):
        """
        Enregistre une utilisation QPU.
        
        Args:
            job_result: Résultat de run_on_qpu (extrait le temps automatiquement)
            minutes: Temps en minutes (si pas de job_result)
            job_id: ID du job pour référence
        """
        now = datetime.now()
        
        # Extraire le temps du résultat si fourni
        if job_result and isinstance(job_result, dict):
            qpu_time = job_result.get('qpu_time_s', 0) or 0
            minutes = qpu_time / 60.0
            job_id = job_result.get('job_id', job_id)
        elif job_result and isinstance(job_result, list) and job_result:
            # Liste de résultats
            total_qpu = sum(r.get('qpu_time_s', 0) or 0 for r in job_result if isinstance(r, dict))
            minutes = total_qpu / 60.0
        
        if minutes is None or minutes <= 0:
            return
        
        record = {
            'timestamp': now.isoformat(),
            'month': now.strftime('%Y-%m'),
            'minutes': minutes,
            'job_id': job_id
        }
        
        self._usage_records.append(record)
        self._save_history()
        
        self._log(f"📝 Usage enregistré: {minutes:.3f} min (Job: {job_id or 'N/A'})")
        self._check_alerts()
    
    def fetch_real_usage(self, days: int = 30) -> float:
        """
        Récupère l'usage réel depuis IBM Quantum.
        
        Args:
            days: Nombre de jours à analyser
            
        Returns:
            Usage total en minutes
        """
        if not self.framework or not hasattr(self.framework, 'get_monthly_usage'):
            self._log("Framework non connecté, impossible de récupérer l'usage réel", LogLevel.WARN)
            return self.get_current_month_usage()
        
        try:
            usage = self.framework.get_monthly_usage(days=days, animate=False)
            if usage and 'total_time_s' in usage:
                return usage['total_time_s'] / 60.0
        except Exception as e:
            self._log(f"Erreur récupération usage: {e}", LogLevel.WARN)
        
        return self.get_current_month_usage()
    
    def display_status(self):
        """Affiche le statut du budget."""
        usage = self.get_current_month_usage()
        remaining = self.get_remaining_budget()
        pct = self.get_usage_percent()
        
        # Barre de progression
        bar_width = 40
        filled = int(bar_width * min(pct, 100) / 100)
        bar = '█' * filled + '░' * (bar_width - filled)
        
        # Couleur selon le niveau
        if pct >= 100:
            status_emoji = "🔴"
            status_text = "DÉPASSÉ"
        elif pct >= 90:
            status_emoji = "🟠"
            status_text = "CRITIQUE"
        elif pct >= 75:
            status_emoji = "🟡"
            status_text = "ATTENTION"
        else:
            status_emoji = "🟢"
            status_text = "OK"
        
        print()
        print("  ╔════════════════════════════════════════════════════════════════════════════╗")
        print("  ║  💰 STATUT BUDGET QPU                                                      ║")
        print("  ╠════════════════════════════════════════════════════════════════════════════╣")
        print(f"  ║  📅 Mois:        {datetime.now().strftime('%B %Y'):<55} ║")
        print(f"  ║  📊 Budget:      {self.monthly_budget:.1f} minutes                                         ║")
        print(f"  ║  📈 Utilisé:     {usage:.2f} minutes ({pct:.1f}%)                               ║")
        print(f"  ║  📉 Restant:     {remaining:.2f} minutes                                       ║")
        print(f"  ║  {status_emoji} Statut:      {status_text:<56} ║")
        print("  ╠════════════════════════════════════════════════════════════════════════════╣")
        print(f"  ║  [{bar}] {pct:5.1f}%  ║")
        print("  ╚════════════════════════════════════════════════════════════════════════════╝")
        print()
    
    def reset_month(self):
        """Réinitialise le compteur pour le nouveau mois."""
        self._alerts_sent.clear()
        # [v2.7.1 FIX] Keep the tracked month in sync so the auto-roll logic stays consistent.
        self._alerts_month = datetime.now().strftime('%Y-%m')
        self._log("🔄 Compteur mensuel réinitialisé")


# =============================================================================
# v2.5.16 - CIRCUIT PROFILER
# =============================================================================

class CircuitProfiler:
    """
    [v2.5.16] Analyseur de circuits quantiques AVANT transpilation.
    
    Fournit:
    - Analyse de complexité (profondeur, portes, qubits)
    - Estimation du temps d'exécution
    - Identification des goulots d'étranglement
    - Suggestions d'optimisation
    - Score de "transpilabilité"
    
    Usage:
        profiler = CircuitProfiler(framework)
        report = profiler.profile(circuit)
        profiler.display_report(report)
        
        # Ou profiler plusieurs circuits
        reports = profiler.profile_batch(circuits)
    """
    
    def __init__(self, framework: 'QMCFramework' = None, logger: Logger = None):
        """
        Args:
            framework: Instance QMCFramework pour accès backend
            logger: Logger pour les messages
        """
        self.framework = framework
        self.logger = logger or (framework.logger if framework else None)
        
        # Métriques de référence pour IBM Heron
        self.reference_metrics = {
            'gate_times_ns': {
                'rz': 0,      # Virtual (instantané)
                'sx': 25,     # ~25ns
                'x': 25,
                'cz': 68,     # ~68ns pour CZ
                'ecr': 68,    # ~68ns pour ECR
                'cx': 300,    # ~300ns (décomposé)
                'swap': 900,  # ~3x CZ
            },
            'max_depth_recommended': 100,
            'max_2q_gates_recommended': 50,
            't1_typical_us': 200,   # T1 typique
            't2_typical_us': 150,   # T2 typique
        }
    
    def _log(self, msg: str, level: LogLevel = LogLevel.INFO):
        if self.logger:
            self.logger.log(msg, level, section='PROFILER')
    
    def profile(self, circuit) -> Dict[str, Any]:
        """
        Profile un circuit quantique.
        
        Args:
            circuit: QuantumCircuit à analyser
            
        Returns:
            Dict avec le profil complet
        """
        profile = {
            'basic_metrics': {},
            'gate_analysis': {},
            'complexity_score': 0,
            'estimated_time': {},
            'bottlenecks': [],
            'suggestions': [],
            'transpile_prediction': {},
        }
        
        # 1. Métriques de base
        profile['basic_metrics'] = {
            'num_qubits': circuit.num_qubits,
            'num_clbits': circuit.num_clbits,
            'depth': circuit.depth(),
            'size': circuit.size(),  # Nombre total d'opérations
            'width': circuit.width(),  # Qubits + clbits
        }
        
        # 2. Analyse des portes
        gate_counts = dict(circuit.count_ops())
        
        # Classifier les portes
        single_qubit_gates = 0
        two_qubit_gates = 0
        multi_qubit_gates = 0
        measurements = 0
        barriers = 0
        
        two_q_gate_names = {'cx', 'cz', 'ecr', 'swap', 'iswap', 'cp', 'crx', 'cry', 'crz', 'rzz', 'rxx', 'ryy'}
        
        for gate, count in gate_counts.items():
            gate_lower = gate.lower()
            if gate_lower == 'measure':
                measurements += count
            elif gate_lower == 'barrier':
                barriers += count
            elif gate_lower in two_q_gate_names:
                two_qubit_gates += count
            elif any(x in gate_lower for x in ['ccx', 'cswap', 'mcx', 'mct']):
                multi_qubit_gates += count
            else:
                single_qubit_gates += count
        
        profile['gate_analysis'] = {
            'gate_counts': gate_counts,
            'single_qubit_gates': single_qubit_gates,
            'two_qubit_gates': two_qubit_gates,
            'multi_qubit_gates': multi_qubit_gates,
            'measurements': measurements,
            'barriers': barriers,
            'total_gates': sum(gate_counts.values()) - barriers,
        }
        
        # 3. Estimation du temps d'exécution
        estimated_ns = 0
        for gate, count in gate_counts.items():
            gate_time = self.reference_metrics['gate_times_ns'].get(gate.lower(), 50)  # 50ns par défaut
            estimated_ns += gate_time * count
        
        # Ajouter le temps de mesure (~1us par qubit mesuré)
        estimated_ns += measurements * 1000
        
        profile['estimated_time'] = {
            'circuit_time_ns': estimated_ns,
            'circuit_time_us': estimated_ns / 1000,
            'circuit_time_ms': estimated_ns / 1_000_000,
            # Estimation avec shots
            'per_1000_shots_ms': (estimated_ns / 1_000_000) * 1000,
            'per_4096_shots_s': (estimated_ns / 1_000_000_000) * 4096,
        }
        
        # 4. Score de complexité (0-100)
        depth = profile['basic_metrics']['depth']
        n_2q = two_qubit_gates
        n_qubits = profile['basic_metrics']['num_qubits']
        
        # Pénalités
        depth_penalty = min(50, depth / 2)  # Max 50 points pour la profondeur
        gate_penalty = min(30, n_2q / 2)    # Max 30 points pour les portes 2Q
        qubit_penalty = min(20, n_qubits / 8)  # Max 20 points pour les qubits
        
        complexity_score = depth_penalty + gate_penalty + qubit_penalty
        profile['complexity_score'] = min(100, complexity_score)
        
        # 5. Identification des goulots d'étranglement
        bottlenecks = []
        
        if depth > self.reference_metrics['max_depth_recommended']:
            bottlenecks.append({
                'type': 'depth',
                'severity': 'high' if depth > 200 else 'medium',
                'message': f"Profondeur élevée ({depth}) - risque de décohérence",
                'value': depth,
                'threshold': self.reference_metrics['max_depth_recommended']
            })
        
        if n_2q > self.reference_metrics['max_2q_gates_recommended']:
            bottlenecks.append({
                'type': 'two_qubit_gates',
                'severity': 'high' if n_2q > 100 else 'medium',
                'message': f"Nombreuses portes 2Q ({n_2q}) - forte accumulation d'erreurs",
                'value': n_2q,
                'threshold': self.reference_metrics['max_2q_gates_recommended']
            })
        
        if multi_qubit_gates > 0:
            bottlenecks.append({
                'type': 'multi_qubit_gates',
                'severity': 'high',
                'message': f"Portes multi-qubits ({multi_qubit_gates}) - décomposition coûteuse",
                'value': multi_qubit_gates,
                'threshold': 0
            })
        
        # Estimation du temps de cohérence
        t2_us = self.reference_metrics['t2_typical_us']
        circuit_time_us = estimated_ns / 1000
        if circuit_time_us > t2_us * 0.5:
            bottlenecks.append({
                'type': 'coherence',
                'severity': 'critical' if circuit_time_us > t2_us else 'high',
                'message': f"Circuit approche T2 ({circuit_time_us:.1f}µs vs T2={t2_us}µs)",
                'value': circuit_time_us,
                'threshold': t2_us
            })
        
        profile['bottlenecks'] = bottlenecks
        
        # 6. Suggestions d'optimisation
        suggestions = []
        
        if depth > 50:
            suggestions.append("💡 Augmenter optimization_level à 3 pour réduire la profondeur")
        
        if n_2q > 30:
            suggestions.append("💡 Utiliser VF2PostLayout pour meilleur mapping des portes 2Q")
        
        if multi_qubit_gates > 0:
            suggestions.append("💡 Décomposer les portes multi-qubits manuellement avant transpilation")
        
        if 'swap' in gate_counts and gate_counts['swap'] > 5:
            suggestions.append("💡 Réorganiser le circuit pour réduire les SWAPs")
        
        if n_qubits > 50:
            suggestions.append("💡 Considérer le découpage en sous-circuits plus petits")
        
        if not suggestions:
            suggestions.append("✅ Circuit bien optimisé pour l'exécution NISQ")
        
        profile['suggestions'] = suggestions
        
        # 7. Prédiction de transpilation
        # Estimer l'augmentation de profondeur après transpilation
        if self.framework and self.framework.backend:
            # Estimation basée sur la connectivité
            estimated_depth_increase = 1.5 if n_2q > 20 else 1.2
        else:
            estimated_depth_increase = 1.5
        
        profile['transpile_prediction'] = {
            'estimated_depth_after': int(depth * estimated_depth_increase),
            'estimated_2q_gates_after': int(n_2q * 1.3),  # +30% typique
            'success_probability': 'high' if complexity_score < 30 else ('medium' if complexity_score < 60 else 'low'),
        }
        
        return profile
    
    def profile_batch(self, circuits: List) -> List[Dict]:
        """Profile plusieurs circuits."""
        return [self.profile(c) for c in circuits]
    
    def display_report(self, profile: Dict, show_gates: bool = True):
        """
        Affiche un rapport de profil formaté.
        
        Args:
            profile: Profil généré par profile()
            show_gates: Afficher le détail des portes
        """
        basic = profile['basic_metrics']
        gates = profile['gate_analysis']
        time_est = profile['estimated_time']
        score = profile['complexity_score']
        
        # Couleur du score
        if score < 30:
            score_emoji = "🟢"
            score_label = "SIMPLE"
        elif score < 60:
            score_emoji = "🟡"
            score_label = "MODÉRÉ"
        else:
            score_emoji = "🔴"
            score_label = "COMPLEXE"
        
        print()
        print("  ╔════════════════════════════════════════════════════════════════════════════╗")
        print("  ║  🔬 PROFIL DE CIRCUIT QUANTIQUE                                            ║")
        print("  ╠════════════════════════════════════════════════════════════════════════════╣")
        print(f"  ║  📊 Qubits:       {basic['num_qubits']:<55} ║")
        print(f"  ║  📏 Profondeur:   {basic['depth']:<55} ║")
        print(f"  ║  🔢 Opérations:   {basic['size']:<55} ║")
        print("  ╠════════════════════════════════════════════════════════════════════════════╣")
        print(f"  ║  {score_emoji} Score complexité: {score:.0f}/100 ({score_label})                            ║")
        print("  ╠════════════════════════════════════════════════════════════════════════════╣")
        print("  ║  ⚙️  ANALYSE DES PORTES                                                    ║")
        print("  ╠════════════════════════════════════════════════════════════════════════════╣")
        print(f"  ║     1-qubit gates:  {gates['single_qubit_gates']:<52} ║")
        print(f"  ║     2-qubit gates:  {gates['two_qubit_gates']:<52} ║")
        if gates['multi_qubit_gates'] > 0:
            print(f"  ║     Multi-Q gates:  {gates['multi_qubit_gates']:<52} ║")
        print(f"  ║     Mesures:        {gates['measurements']:<52} ║")
        
        if show_gates and gates['gate_counts']:
            print("  ╠════════════════════════════════════════════════════════════════════════════╣")
            print("  ║  📋 DÉTAIL DES PORTES                                                      ║")
            print("  ╠════════════════════════════════════════════════════════════════════════════╣")
            
            # Top 8 portes
            sorted_gates = sorted(gates['gate_counts'].items(), key=lambda x: x[1], reverse=True)[:8]
            for gate, count in sorted_gates:
                if gate.lower() != 'barrier':
                    print(f"  ║     {gate:<15}: {count:<51} ║")
        
        print("  ╠════════════════════════════════════════════════════════════════════════════╣")
        print("  ║  ⏱️  ESTIMATION TEMPS                                                       ║")
        print("  ╠════════════════════════════════════════════════════════════════════════════╣")
        print(f"  ║     Circuit seul:    {time_est['circuit_time_us']:.2f} µs                                   ║")
        print(f"  ║     4096 shots:      {time_est['per_4096_shots_s']:.3f} s                                    ║")
        
        if profile['bottlenecks']:
            print("  ╠════════════════════════════════════════════════════════════════════════════╣")
            print("  ║  ⚠️  GOULOTS D'ÉTRANGLEMENT                                                ║")
            print("  ╠════════════════════════════════════════════════════════════════════════════╣")
            for bn in profile['bottlenecks'][:4]:
                severity_emoji = {'critical': '🔴', 'high': '🟠', 'medium': '🟡'}.get(bn['severity'], '⚪')
                msg = bn['message'][:60]
                print(f"  ║  {severity_emoji} {msg:<68} ║")
        
        print("  ╠════════════════════════════════════════════════════════════════════════════╣")
        print("  ║  💡 SUGGESTIONS                                                            ║")
        print("  ╠════════════════════════════════════════════════════════════════════════════╣")
        for sugg in profile['suggestions'][:4]:
            sugg_text = sugg[:68]
            print(f"  ║     {sugg_text:<67} ║")
        
        # Prédiction transpilation
        pred = profile['transpile_prediction']
        print("  ╠════════════════════════════════════════════════════════════════════════════╣")
        print("  ║  🔮 PRÉDICTION POST-TRANSPILATION                                          ║")
        print("  ╠════════════════════════════════════════════════════════════════════════════╣")
        print(f"  ║     Profondeur estimée:  {pred['estimated_depth_after']:<47} ║")
        print(f"  ║     Portes 2Q estimées:  {pred['estimated_2q_gates_after']:<47} ║")
        success_emoji = {'high': '🟢', 'medium': '🟡', 'low': '🔴'}.get(pred['success_probability'], '⚪')
        print(f"  ║     Probabilité succès:  {success_emoji} {pred['success_probability'].upper():<44} ║")
        
        print("  ╚════════════════════════════════════════════════════════════════════════════╝")
        print()


# =============================================================================
# v2.5.16 - RESULT COMPARATOR
# =============================================================================

class ResultComparator:
    """
    [v2.5.21] Comparateur de résultats quantiques avec Qiskit native.
    
    Compare deux ensembles de résultats (ex: simulateur vs QPU, deux backends)
    et fournit des métriques de divergence détaillées.
    
    v2.5.21: Intègre qiskit.quantum_info.hellinger_fidelity native.
    
    Usage:
        comparator = ResultComparator()
        
        # Comparer deux distributions
        comparison = comparator.compare(counts_a, counts_b)
        comparator.display_comparison(comparison)
        
        # Ou comparer des résultats de run_on_qpu
        comparison = comparator.compare_results(results_sim, results_qpu)
    """
    
    def __init__(self, logger: Logger = None):
        self.logger = logger
    
    def _log(self, msg: str, level: LogLevel = LogLevel.INFO):
        if self.logger:
            self.logger.log(msg, level, section='COMPARE')
    
    def compare(self, counts_a: Dict[str, int], counts_b: Dict[str, int],
                label_a: str = "A", label_b: str = "B") -> Dict[str, Any]:
        """
        Compare deux distributions de counts.
        
        Args:
            counts_a: Premier dict de counts {bitstring: count}
            counts_b: Second dict de counts
            label_a: Label pour A
            label_b: Label pour B
            
        Returns:
            Dict avec les métriques de comparaison
        """
        comparison = {
            'labels': (label_a, label_b),
            'metrics': {},
            'divergence': {},
            'top_differences': [],
            'summary': {}
        }
        
        # Normaliser en distributions de probabilité
        total_a = sum(counts_a.values())
        total_b = sum(counts_b.values())

        # [v2.7.1 FIX] Guard against empty distribution -> ZeroDivisionError.
        if not counts_a or not counts_b or total_a == 0 or total_b == 0:
            comparison['metrics'] = {
                'total_shots_a': total_a,
                'total_shots_b': total_b,
                'unique_outcomes_a': len(counts_a),
                'unique_outcomes_b': len(counts_b),
                'common_outcomes': len(set(counts_a.keys()) & set(counts_b.keys())),
                'total_outcomes': len(set(counts_a.keys()) | set(counts_b.keys())),
            }
            comparison['divergence'] = {
                'tvd': 1.0,
                'hellinger_fidelity': 0.0,
                'fidelity': 0.0,
                'kl_divergence': float('inf'),
                'js_divergence': float('inf'),
                'chi_squared': float('inf'),
                'qiskit_native': False,
            }
            comparison['summary'] = {
                'quality': "EMPTY",
                'color': "grey",
                'emoji': "⚪",
                'interpretation': "One or both distributions are empty - cannot compare.",
            }
            return comparison

        all_keys = set(counts_a.keys()) | set(counts_b.keys())
        
        prob_a = {k: counts_a.get(k, 0) / total_a for k in all_keys}
        prob_b = {k: counts_b.get(k, 0) / total_b for k in all_keys}
        
        # Métriques de base
        comparison['metrics'] = {
            'total_shots_a': total_a,
            'total_shots_b': total_b,
            'unique_outcomes_a': len(counts_a),
            'unique_outcomes_b': len(counts_b),
            'common_outcomes': len(set(counts_a.keys()) & set(counts_b.keys())),
            'total_outcomes': len(all_keys),
        }
        
        # 1. Total Variation Distance (TVD)
        tvd = 0.5 * sum(abs(prob_a[k] - prob_b[k]) for k in all_keys)
        
        # 2. Fidelity - v2.5.21: Utiliser Qiskit hellinger_fidelity
        hellinger_fid = QiskitQuantumInfoWrapper.hellinger_fidelity(counts_a, counts_b)
        
        # Fallback si Qiskit non disponible
        if hellinger_fid < 0:
            # Calcul manuel (overlap classique)
            hellinger_fid = sum(math.sqrt(prob_a[k] * prob_b[k]) for k in all_keys) ** 2
        
        # 3. KL Divergence (avec lissage pour éviter log(0))
        epsilon = 1e-10
        kl_div = sum(
            prob_a[k] * math.log((prob_a[k] + epsilon) / (prob_b[k] + epsilon))
            for k in all_keys if prob_a[k] > 0
        )
        
        # 4. Jensen-Shannon Divergence
        m = {k: (prob_a[k] + prob_b[k]) / 2 for k in all_keys}
        js_div = 0.5 * sum(
            prob_a[k] * math.log((prob_a[k] + epsilon) / (m[k] + epsilon))
            for k in all_keys if prob_a[k] > 0
        ) + 0.5 * sum(
            prob_b[k] * math.log((prob_b[k] + epsilon) / (m[k] + epsilon))
            for k in all_keys if prob_b[k] > 0
        )
        
        # 5. Chi-squared statistic
        chi_sq = sum(
            ((counts_a.get(k, 0) - counts_b.get(k, 0) * total_a / total_b) ** 2) / 
            max(1, counts_b.get(k, 0) * total_a / total_b)
            for k in all_keys
        )
        
        comparison['divergence'] = {
            'tvd': tvd,
            'hellinger_fidelity': hellinger_fid,  # v2.5.21: Renamed from 'fidelity'
            'fidelity': hellinger_fid,  # Keep for backward compatibility
            'kl_divergence': kl_div,
            'js_divergence': js_div,
            'chi_squared': chi_sq,
            'qiskit_native': True,  # v2.5.21 marker
        }
        
        # 6. Top différences
        differences = []
        for k in all_keys:
            diff = abs(prob_a[k] - prob_b[k])
            if diff > 0.001:  # Seuil de 0.1%
                differences.append({
                    'bitstring': k,
                    'prob_a': prob_a[k],
                    'prob_b': prob_b[k],
                    'difference': diff,
                    'percent_diff': diff * 100
                })
        
        differences.sort(key=lambda x: x['difference'], reverse=True)
        comparison['top_differences'] = differences[:10]
        
        # 7. Résumé qualitatif
        if tvd < 0.05:
            quality = "EXCELLENT"
            color = "green"
        elif tvd < 0.10:
            quality = "GOOD"
            color = "green"
        elif tvd < 0.20:
            quality = "ACCEPTABLE"
            color = "yellow"
        elif tvd < 0.35:
            quality = "MEDIOCRE"
            color = "orange"
        else:
            quality = "POOR"
            color = "red"
        
        # [v2.7.1 FIX] Add 'emoji' to summary (display_comparison reads summary['emoji']).
        quality_emoji = {
            "EXCELLENT": "🟢",
            "GOOD": "🟢",
            "ACCEPTABLE": "🟡",
            "MEDIOCRE": "🟠",
            "POOR": "🔴",
        }.get(quality, "⚪")

        comparison['summary'] = {
            'quality': quality,
            'color': color,
            'emoji': quality_emoji,
            'interpretation': self._interpret_results(tvd, hellinger_fid, comparison['metrics'])
        }

        return comparison
    
    # v2.5.21: Nouvelle méthode pour analyse complète avec Qiskit
    def analyze_with_qiskit(self, counts_a: Dict[str, int], 
                            counts_b: Dict[str, int]) -> Dict[str, Any]:
        """
        Analyse complète des counts avec QiskitQuantumInfoWrapper (v2.5.21).
        
        Args:
            counts_a: Premiers counts
            counts_b: Seconds counts
            
        Returns:
            Dict avec toutes les métriques Qiskit
        """
        analysis_a = QiskitQuantumInfoWrapper.analyze_counts(counts_a, counts_b)
        analysis_b = QiskitQuantumInfoWrapper.analyze_counts(counts_b, counts_a)
        
        return {
            'analysis_a': analysis_a,
            'analysis_b': analysis_b,
            'hellinger_fidelity': QiskitQuantumInfoWrapper.hellinger_fidelity(counts_a, counts_b),
            'comparison': self.compare(counts_a, counts_b),
        }
    
    def _interpret_results(self, tvd: float, fidelity: float, metrics: Dict) -> str:
        """Génère une interprétation textuelle."""
        if tvd < 0.05:
            return "Distributions are nearly identical. Excellent reproducibility."
        elif tvd < 0.10:
            return "Low divergence. Results consistent with expected quantum noise."
        elif tvd < 0.20:
            return "Moderate divergence. Possible noise effects or calibration differences."
        elif tvd < 0.35:
            return "Significant divergence. Check execution parameters and calibration."
        else:
            return "High divergence. Results are not comparable - likely problem."
    
    def compare_results(self, results_a: List[Dict], results_b: List[Dict],
                        label_a: str = "A", label_b: str = "B") -> Dict[str, Any]:
        """
        Compare deux listes de résultats de run_on_qpu.
        
        Args:
            results_a: Première liste de résultats
            results_b: Seconde liste de résultats
            
        Returns:
            Dict avec comparaisons circuit par circuit
        """
        if not results_a or not results_b:
            return {'error': 'Résultats vides'}
        
        # Aligner par nombre de circuits
        n_circuits = min(len(results_a), len(results_b))
        
        comparisons = []
        aggregate_tvd = []
        aggregate_fidelity = []
        
        for i in range(n_circuits):
            counts_a = results_a[i].get('counts', {})
            counts_b = results_b[i].get('counts', {})
            
            if counts_a and counts_b:
                comp = self.compare(counts_a, counts_b, label_a, label_b)
                comp['circuit_index'] = i
                comparisons.append(comp)
                
                aggregate_tvd.append(comp['divergence']['tvd'])
                aggregate_fidelity.append(comp['divergence']['fidelity'])
        
        # Statistiques agrégées
        return {
            'per_circuit': comparisons,
            'aggregate': {
                'mean_tvd': sum(aggregate_tvd) / len(aggregate_tvd) if aggregate_tvd else 0,
                'mean_fidelity': sum(aggregate_fidelity) / len(aggregate_fidelity) if aggregate_fidelity else 0,
                'max_tvd': max(aggregate_tvd) if aggregate_tvd else 0,
                'min_fidelity': min(aggregate_fidelity) if aggregate_fidelity else 0,
                'circuits_compared': len(comparisons),
            },
            'labels': (label_a, label_b)
        }
    
    def display_comparison(self, comparison: Dict, show_details: bool = True):
        """
        Affiche un rapport de comparaison formaté.
        
        Args:
            comparison: Résultat de compare() ou compare_results()
            show_details: Afficher les détails par bitstring
        """
        # Vérifier si c'est une comparaison simple ou agrégée
        if 'per_circuit' in comparison:
            self._display_aggregate_comparison(comparison)
        else:
            self._display_single_comparison(comparison, show_details)
    
    def _display_single_comparison(self, comparison: Dict, show_details: bool):
        """Affiche une comparaison simple."""
        labels = comparison['labels']
        metrics = comparison['metrics']
        div = comparison['divergence']
        summary = comparison['summary']
        
        print()
        print("  ╔════════════════════════════════════════════════════════════════════════════╗")
        print("  ║  📊 COMPARAISON DE RÉSULTATS                                               ║")
        print("  ╠════════════════════════════════════════════════════════════════════════════╣")
        print(f"  ║  📍 {labels[0]} vs {labels[1]:<62} ║")
        print("  ╠════════════════════════════════════════════════════════════════════════════╣")
        print(f"  ║  {summary.get('emoji', '⚪')} Qualité: {summary['quality']:<60} ║")  # [v2.7.1 FIX] safe emoji read
        print("  ╠════════════════════════════════════════════════════════════════════════════╣")
        print("  ║  📈 MÉTRIQUES DE DIVERGENCE                                                ║")
        print("  ╠════════════════════════════════════════════════════════════════════════════╣")
        print(f"  ║     TVD (Total Variation):    {div['tvd']:.4f}                                   ║")
        print(f"  ║     Fidelité:                 {div['fidelity']:.4f}                                   ║")
        print(f"  ║     JS Divergence:            {div['js_divergence']:.4f}                                   ║")
        print("  ╠════════════════════════════════════════════════════════════════════════════╣")
        print("  ║  📋 STATISTIQUES                                                           ║")
        print("  ╠════════════════════════════════════════════════════════════════════════════╣")
        print(f"  ║     Shots {labels[0]}:  {metrics['total_shots_a']:<54} ║")
        print(f"  ║     Shots {labels[1]}:  {metrics['total_shots_b']:<54} ║")
        print(f"  ║     Outcomes communs:         {metrics['common_outcomes']}/{metrics['total_outcomes']:<40} ║")
        
        if show_details and comparison['top_differences']:
            print("  ╠════════════════════════════════════════════════════════════════════════════╣")
            print("  ║  🔍 TOP DIFFÉRENCES                                                        ║")
            print("  ╠════════════════════════════════════════════════════════════════════════════╣")
            print(f"  ║  {'Bitstring':<20} {labels[0]:>10} {labels[1]:>10} {'Diff':>10}      ║")
            print("  ║  " + "-" * 52 + "                  ║")
            
            for diff in comparison['top_differences'][:5]:
                bs = diff['bitstring'][:18]
                pa = f"{diff['prob_a']:.3f}"
                pb = f"{diff['prob_b']:.3f}"
                d = f"{diff['percent_diff']:.1f}%"
                print(f"  ║  {bs:<20} {pa:>10} {pb:>10} {d:>10}      ║")
        
        print("  ╠════════════════════════════════════════════════════════════════════════════╣")
        interp = summary['interpretation'][:68]
        print(f"  ║  💬 {interp:<67} ║")
        print("  ╚════════════════════════════════════════════════════════════════════════════╝")
        print()
    
    def _display_aggregate_comparison(self, comparison: Dict):
        """Affiche une comparaison agrégée (plusieurs circuits)."""
        agg = comparison['aggregate']
        labels = comparison['labels']
        
        # Qualité globale basée sur TVD moyenne
        mean_tvd = agg['mean_tvd']
        if mean_tvd < 0.10:
            quality = "EXCELLENT"
            emoji = "🟢"
        elif mean_tvd < 0.20:
            quality = "BON"
            emoji = "🟢"
        elif mean_tvd < 0.35:
            quality = "ACCEPTABLE"
            emoji = "🟡"
        else:
            quality = "MÉDIOCRE"
            emoji = "🟠"
        
        print()
        print("  ╔════════════════════════════════════════════════════════════════════════════╗")
        print("  ║  📊 COMPARAISON AGRÉGÉE DE RÉSULTATS                                       ║")
        print("  ╠════════════════════════════════════════════════════════════════════════════╣")
        print(f"  ║  📍 {labels[0]} vs {labels[1]:<62} ║")
        print(f"  ║  📋 Circuits comparés: {agg['circuits_compared']:<50} ║")
        print("  ╠════════════════════════════════════════════════════════════════════════════╣")
        print(f"  ║  {emoji} Qualité globale: {quality:<54} ║")
        print("  ╠════════════════════════════════════════════════════════════════════════════╣")
        print("  ║  📈 STATISTIQUES AGRÉGÉES                                                  ║")
        print("  ╠════════════════════════════════════════════════════════════════════════════╣")
        print(f"  ║     TVD moyenne:              {agg['mean_tvd']:.4f}                                   ║")
        print(f"  ║     TVD max:                  {agg['max_tvd']:.4f}                                   ║")
        print(f"  ║     Fidélité moyenne:         {agg['mean_fidelity']:.4f}                                   ║")
        print(f"  ║     Fidélité min:             {agg['min_fidelity']:.4f}                                   ║")
        print("  ╚════════════════════════════════════════════════════════════════════════════╝")
        print()


# =============================================================================
# v2.6.0 - EXECUTION ARCHIVE v3.0 (ULTRA-COMPLET POUR ANALYSE SERVEUR)
# =============================================================================
#
# VERSIONING DE L'ARCHIVE:
#   - v3.0.0: Structure ultra-complète, état QPU complet, circuits reconstructibles
#   - v2.0.0: Structure complète (ancienne version)
#   - v1.0.0: Format basique (deprecated)
#
# COMPATIBILITÉ:
#   - Le serveur d'analyse doit vérifier archive['_schema']['version']
#   - Les versions 3.x sont backward-compatible avec parsers v3.0+
#
# =============================================================================

# Constantes de version de l'archive
ARCHIVE_SCHEMA_VERSION = "3.1.0"
ARCHIVE_SCHEMA_FORMAT = "QMC_EXECUTION_ARCHIVE_V3"


class ExecutionArchive:
    """
    [v2.6.0] Générateur d'archives JSON v3.0 ULTRA-COMPLÈTES pour analyse serveur.
    
    Cette archive contient ABSOLUMENT TOUT ce qui est nécessaire pour:
    - Reconstruire l'état complet du QPU au moment de l'exécution
    - Reconstruire les circuits (QASM + instructions détaillées)
    - Analyser les résultats sur un serveur distant
    - Reproduire l'expérience
    
    📦 STRUCTURE DE L'ARCHIVE v3.0 (30+ sections):
    │
    ├── _schema              # VERSION, format, compatibilité (TOUJOURS EN PREMIER!)
    │
    ├── 📋 METADATA & IDENTIFICATION
    │   ├── metadata         # UUID, timestamps, projet, status
    │   └── execution_id     # Identifiant unique de l'exécution
    │
    ├── 💻 ENVIRONNEMENT
    │   ├── system_info      # OS, CPU, RAM, GPU complets
    │   ├── python_env       # Python version, virtualenv, encoding
    │   ├── dependencies     # TOUTES les libs avec versions
    │   └── environment_vars # Variables d'environnement QMC/IBM
    │
    ├── ☁️ IBM QUANTUM
    │   ├── ibm_account      # Account, channel, instance, hub/group/project
    │   ├── backend          # Name, capabilities, processor, status
    │   ├── qpu_state        # ÉTAT COMPLET DE CHAQUE QUBIT (T1,T2,freq,errors)
    │   ├── gates_calibration # TOUTES les gates avec error/duration
    │   ├── topology         # Coupling map, adjacency, heavy-hex
    │   └── calibration_health # Health score, faulty/suspect qubits
    │
    ├── ⚙️ FRAMEWORK
    │   ├── framework_config # Project, mode, security, budget
    │   └── quality_thresholds # Seuils configurés
    │
    ├── 🔧 CIRCUITS (RECONSTRUCTIBLES)
    │   ├── circuits_original    # Circuits avant transpilation
    │   │   ├── qasm             # Code QASM complet
    │   │   ├── instructions     # Liste détaillée des instructions
    │   │   ├── parameters       # Paramètres si paramétrés
    │   │   └── metadata         # Depth, gates, qubits
    │   ├── circuits_transpiled  # Circuits après optimisation
    │   ├── transpilation_config # Options de transpilation
    │   └── layout_mapping       # Virtual → Physical qubits
    │
    ├── 🛡️ MITIGATION
    │   ├── mitigation_config    # Twirling, DD, ZNE, M3
    │   └── sampler_options      # Options Sampler IBM
    │
    ├── 🚀 EXÉCUTION
    │   ├── execution_info   # Job ID, shots, timing détaillé
    │   └── job_metadata     # Tags, session_id
    │
    ├── 📊 RÉSULTATS
    │   ├── results          # Counts, probabilities, fidelity
    │   ├── raw_memory       # Shots individuels
    │   └── statistics       # Entropie, uniformité
    │
    ├── 📝 LOGS & ERREURS
    │   ├── session_logs     # Logs de la session
    │   ├── warnings         # Warnings collectés
    │   └── error            # Erreur complète si échec
    │
    └── ✅ INTÉGRITÉ
        └── integrity        # SHA-256 checksums
    
    VERSIONING:
        L'archive contient TOUJOURS une section '_schema' en premier avec:
        - version: "3.0.0" (SemVer)
        - format: "QMC_EXECUTION_ARCHIVE_V3"
        - min_parser_version: "3.0.0"
        
        Le serveur d'analyse DOIT vérifier cette version pour adapter son parsing.
    
    USAGE:
        # Charger et vérifier la version
        with open('archive_xxx.json') as f:
            data = json.load(f)
        
        schema_version = data['_schema']['version']
        if not schema_version.startswith('3.'):
            raise ValueError(f"Archive version {schema_version} non supportée")
        
        # Reconstruire un circuit
        qasm = data['circuits_original'][0]['qasm']
        circuit = QuantumCircuit.from_qasm_str(qasm)
        
        # Reconstruire l'état du QPU
        qpu_state = data['qpu_state']['qubits']
        for q in qpu_state:
            print(f"Q{q['index']}: T1={q['t1_us']}µs, T2={q['t2_us']}µs")
    """
    
    def __init__(self, framework: 'QMCFramework' = None,
                 output_dir: str = None,
                 logger: Logger = None,
                 compress: bool = True,  # [v2.7.1] gzip par défaut (~80% d'espace économisé)
                 include_instructions: bool = True,
                 include_raw_memory: bool = True,
                 max_qasm_size: int = 100000):
        """
        Args:
            framework: Instance QMCFramework
            output_dir: Répertoire de sortie
            logger: Logger pour les messages
            compress: Compresser en .json.gz (défaut: True — ~80% plus petit)
            include_instructions: Inclure les instructions détaillées des circuits
            include_raw_memory: Inclure les shots individuels
            max_qasm_size: Taille max du QASM par circuit (défaut: 100KB)
        """
        self.framework = framework
        self.output_dir = Path(output_dir) if output_dir else None
        self.logger = logger or (framework.logger if framework else None)
        self.compress = compress
        self.include_instructions = include_instructions
        self.include_raw_memory = include_raw_memory
        self.max_qasm_size = max_qasm_size
        self._last_archive_path = None
        
        # UUID unique pour cette exécution
        self._execution_uuid = str(uuid.uuid4())
    
    def _log(self, msg: str, level: LogLevel = LogLevel.INFO):
        if self.logger:
            self.logger.log(msg, level, section='ARCHIVE')
        else:
            print(f"[ARCHIVE] {msg}")
    
    def _get_output_dir(self) -> Path:
        """Retourne le répertoire de sortie."""
        if self.output_dir:
            return self.output_dir
        if self.framework and hasattr(self.framework, 'dir_manager') and self.framework.dir_manager:
            return self.framework.dir_manager.run_dir
        return Path('qmc_archives')
    
    def generate(self,
                 results: List[Dict] = None,
                 circuits = None,
                 transpiled_circuits = None,
                 run_context: Dict = None,
                 error: Exception = None) -> Path:
        """
        Génère une archive JSON COMPLÈTE.
        
        Args:
            results: Résultats de l'exécution
            circuits: Circuits originaux (avant transpilation)
            transpiled_circuits: Circuits après transpilation
            run_context: Contexte d'exécution
            error: Exception si erreur
            
        Returns:
            Path vers le fichier JSON généré, ou None si rien à archiver
        """
        # [v2.6.0] Protection contre None
        if run_context is None:
            run_context = {}
        if results is None:
            results = []
        
        # Collecter TOUTES les données
        self._log(f"  📦 Archive: collecte des données (34 sections)...")
        archive = self._build_complete_archive(
            results=results,
            circuits=circuits,
            transpiled_circuits=transpiled_circuits,
            run_context=run_context,
            error=error
        )
        
        # Déterminer le chemin de sortie
        output_dir = self._get_output_dir()
        output_dir.mkdir(parents=True, exist_ok=True)
        
        # Nom du fichier
        timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
        job_id = run_context.get('job_id', 'local') if run_context else 'local'
        if job_id:
            job_id = str(job_id)[:12]
        else:
            job_id = 'local'
        status = 'ERROR' if error else 'OK'
        
        if self.compress:
            filename = f"archive_{timestamp}_{job_id}_{status}.json.gz"
            filepath = output_dir / filename
            import gzip
            with gzip.open(filepath, 'wt', encoding='utf-8') as f:
                json.dump(archive, f, indent=2, default=str, ensure_ascii=False)
        else:
            filename = f"archive_{timestamp}_{job_id}_{status}.json"
            filepath = output_dir / filename
            # [v2.7.1 FIX] Atomic write so a partial archive is never left on disk.
            class _ArchiveEncoder(json.JSONEncoder):
                def default(self, obj):
                    return str(obj)
            _atomic_write_json(filepath, archive, cls=_ArchiveEncoder)

        self._last_archive_path = filepath
        size_kb = filepath.stat().st_size / 1024
        size_mb = size_kb / 1024
        
        if size_mb > 1:
            self._log(f"📦 Archive générée: {filepath} ({size_mb:.1f} MB)")
        else:
            self._log(f"📦 Archive générée: {filepath} ({size_kb:.1f} KB)")
        
        return filepath
    
    def _build_complete_archive(self,
                                results: List[Dict],
                                circuits,
                                transpiled_circuits,
                                run_context: Dict,
                                error: Exception) -> Dict:
        """
        Construit l'archive v3.0 ULTRA-COMPLÈTE.
        
        Structure conçue pour:
        - Reconstruire l'état complet du QPU
        - Reconstruire les circuits
        - Analyse sur serveur distant
        - Compatibilité future via versioning
        """
        
        archive = {
            # ═══════════════════════════════════════════════════════════
            # SECTION 0: SCHÉMA & VERSION (TOUJOURS EN PREMIER!)
            # Le serveur d'analyse DOIT vérifier cette section
            # ═══════════════════════════════════════════════════════════
            '_schema': {
                'version': ARCHIVE_SCHEMA_VERSION,  # "3.1.0"
                'format': ARCHIVE_SCHEMA_FORMAT,    # "QMC_EXECUTION_ARCHIVE_V3"
                'min_parser_version': '3.0.0',
                'created_by': 'QMC Framework',
                'framework_version': __version__,
                'spec_url': 'https://docs.qmc-lab.com/archive-schema/v3',
            },
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 1: MÉTADONNÉES & IDENTIFICATION
            # ═══════════════════════════════════════════════════════════
            'metadata': self._collect_metadata_v3(run_context, error),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 2: ENVIRONNEMENT SYSTÈME COMPLET
            # ═══════════════════════════════════════════════════════════
            'system_info': self._collect_system_info_v3(),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 3: ENVIRONNEMENT PYTHON
            # ═══════════════════════════════════════════════════════════
            'python_env': self._collect_python_env_v3(),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 4: DÉPENDANCES (TOUTES LES LIBS)
            # ═══════════════════════════════════════════════════════════
            'dependencies': self._collect_dependencies_v3(),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 5: VARIABLES D'ENVIRONNEMENT
            # ═══════════════════════════════════════════════════════════
            'environment_vars': self._collect_environment_vars_v3(),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 6: COMPTE IBM QUANTUM
            # ═══════════════════════════════════════════════════════════
            'ibm_account': self._collect_ibm_account_v3(),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 7: BACKEND COMPLET
            # ═══════════════════════════════════════════════════════════
            'backend': self._collect_backend_info(),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 8: ÉTAT COMPLET DU QPU (TOUS LES QUBITS)
            # C'est ici qu'on stocke T1, T2, freq, errors de CHAQUE qubit
            # ═══════════════════════════════════════════════════════════
            'qpu_state': self._collect_qpu_state_v3(),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 9: CALIBRATION DES GATES
            # ═══════════════════════════════════════════════════════════
            'gates_calibration': self._collect_gates_calibration_v3(),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 10: TOPOLOGIE DU BACKEND
            # ═══════════════════════════════════════════════════════════
            'topology': self._collect_topology_v3(),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 11: HEALTH SCORE & ANALYSE CALIBRATION
            # ═══════════════════════════════════════════════════════════
            'calibration_health': self._collect_calibration_health_v3(),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 12: CONFIGURATION DU FRAMEWORK
            # ═══════════════════════════════════════════════════════════
            'framework_config': self._collect_framework_config(),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 13: SEUILS DE QUALITÉ
            # ═══════════════════════════════════════════════════════════
            'quality_thresholds': self._collect_quality_thresholds_v3(),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 14: CIRCUITS ORIGINAUX (RECONSTRUCTIBLES)
            # Contient QASM + instructions détaillées + paramètres
            # ═══════════════════════════════════════════════════════════
            'circuits_original': self._collect_circuits_v3(circuits, prefix='original'),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 15: CIRCUITS TRANSPILÉS (RECONSTRUCTIBLES)
            # ═══════════════════════════════════════════════════════════
            'circuits_transpiled': self._collect_circuits_v3(transpiled_circuits, prefix='transpiled'),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 16: CONFIGURATION TRANSPILATION
            # ═══════════════════════════════════════════════════════════
            'transpilation_config': self._collect_transpilation_config(run_context),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 17: MAPPING LAYOUT
            # ═══════════════════════════════════════════════════════════
            'layout_mapping': self._collect_layout_mapping(transpiled_circuits),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 18: CONFIGURATION MITIGATION
            # ═══════════════════════════════════════════════════════════
            'mitigation_config': self._collect_mitigation_config(),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 19: OPTIONS SAMPLER IBM
            # ═══════════════════════════════════════════════════════════
            'sampler_options': self._collect_sampler_options(),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 20: INFORMATIONS D'EXÉCUTION
            # ═══════════════════════════════════════════════════════════
            'execution': self._collect_execution_info(run_context),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 21: MÉTADONNÉES JOB IBM
            # ═══════════════════════════════════════════════════════════
            'job_metadata': self._collect_job_metadata(run_context),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 22: RÉSULTATS COMPLETS
            # ═══════════════════════════════════════════════════════════
            'results': self._collect_results(results),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 23: MÉMOIRE BRUTE (shots individuels)
            # ═══════════════════════════════════════════════════════════
            'raw_memory': self._collect_raw_memory(results) if self.include_raw_memory else None,
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 24: STATISTIQUES CALCULÉES
            # ═══════════════════════════════════════════════════════════
            'statistics': self._compute_statistics(results),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 25: LOGS DE SESSION
            # ═══════════════════════════════════════════════════════════
            'session_logs': self._collect_session_logs(),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 26: WARNINGS
            # ═══════════════════════════════════════════════════════════
            'warnings': self._collect_warnings(),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 27: ESTIMATIONS PRÉ-EXÉCUTION
            # ═══════════════════════════════════════════════════════════
            'pre_execution_estimates': self._collect_estimates(circuits, run_context),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 28: ERREUR (si présente)
            # ═══════════════════════════════════════════════════════════
            'error': self._collect_error_info(error) if error else None,
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 29: BACKEND EXTENDED (Features, Limites, Processor)
            # ═══════════════════════════════════════════════════════════
            'backend_extended': self._collect_backend_extended_v3(),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 30: USAGE & COÛTS
            # ═══════════════════════════════════════════════════════════
            'usage_and_costs': self._collect_usage_costs_v3(run_context),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 31: TRANSPILATION DÉTAILLÉE
            # ═══════════════════════════════════════════════════════════
            'transpilation_detailed': self._collect_transpilation_detailed_v3(circuits, transpiled_circuits, run_context),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 32: RÉSULTATS D'ANALYSE (XEB, Fidelity, Randomness)
            # ═══════════════════════════════════════════════════════════
            'analysis_results': self._collect_analysis_results_v3(results),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 33: TIMING DÉTAILLÉ (Timeline complète)
            # ═══════════════════════════════════════════════════════════
            'timing_detailed': self._collect_timing_detailed_v3(run_context),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 34: REPRODUCTIBILITÉ (Seeds, Git, Versions exactes)
            # ═══════════════════════════════════════════════════════════
            'reproducibility': self._collect_reproducibility_v3(),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 35: ANALYSE DES QUBITS UTILISÉS
            # ═══════════════════════════════════════════════════════════
            'qubits_analysis': self._collect_qubits_analysis_v3(transpiled_circuits),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 36: CONNEXIONS 2Q DÉTAILLÉES
            # ═══════════════════════════════════════════════════════════
            'connections_detailed': self._collect_connections_detailed_v3(),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 37: RÉSEAU & LATENCE
            # ═══════════════════════════════════════════════════════════
            'network_info': self._collect_network_info_v3(),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 38: PROCESS INFO
            # ═══════════════════════════════════════════════════════════
            'process_info': self._collect_process_info_v3(),
            
            # ═══════════════════════════════════════════════════════════
            # SECTION 40: INTÉGRITÉ (checksums)
            # ═══════════════════════════════════════════════════════════
            'integrity': {
                'results_hash': None,
                'circuits_hash': None,
                'qpu_state_hash': None,
                'archive_hash': None,
            }
        }
        
        # Calculer les checksums pour validation
        try:
            if results:
                results_str = json.dumps(results, sort_keys=True, default=str)
                archive['integrity']['results_hash'] = hashlib.sha256(results_str.encode()).hexdigest()
            if circuits:
                # [v2.7.1 FIX] Hash ALL circuits, not just the first 20, so the integrity
                # checksum actually reflects the full batch (was circuits[:20]).
                circuits_repr = str([str(c) for c in circuits])
                archive['integrity']['circuits_hash'] = hashlib.sha256(circuits_repr.encode()).hexdigest()
            if archive['qpu_state'] and archive['qpu_state'].get('qubits'):
                qpu_str = json.dumps(archive['qpu_state']['qubits'], sort_keys=True, default=str)
                archive['integrity']['qpu_state_hash'] = hashlib.sha256(qpu_str.encode()).hexdigest()
        except:
            pass
        
        return archive
    
    def _get_platform_details(self) -> Dict:
        """Récupère les détails de la plateforme."""
        import platform
        try:
            return {
                'system': platform.system(),
                'release': platform.release(),
                'version': platform.version(),
                'machine': platform.machine(),
                'processor': platform.processor(),
                'architecture': platform.architecture()[0],
            }
        except:
            return {}
    
    # ═══════════════════════════════════════════════════════════════════════════
    # NOUVELLES MÉTHODES v3.0 POUR ARCHIVE ULTRA-COMPLÈTE
    # ═══════════════════════════════════════════════════════════════════════════
    
    def _collect_metadata_v3(self, run_context: Dict, error: Exception) -> Dict:
        """[v3.0] Collecte les métadonnées avec UUID et timestamps multiples."""
        now = datetime.now()
        
        return {
            'execution_id': self._execution_uuid,
            'execution_id_short': self._execution_uuid[:8],
            'project': getattr(self.framework, 'project', 'QMC') if self.framework else 'QMC',
            'status': 'ERROR' if error else 'SUCCESS',
            
            # Timestamps multiples formats
            'generated_at': {
                'iso': now.isoformat(),
                'iso_utc': datetime.utcnow().isoformat() + 'Z',
                'unix': time.time(),
                'unix_ms': int(time.time() * 1000),
                'human': now.strftime('%Y-%m-%d %H:%M:%S'),
                'date': now.strftime('%Y-%m-%d'),
                'time': now.strftime('%H:%M:%S'),
            },
            
            # Info run
            'job_id': run_context.get('job_id') if run_context else None,
            'session_id': run_context.get('session_id') if run_context else None,
        }
    
    def _collect_system_info_v3(self) -> Dict:
        """[v3.0] Collecte les informations système COMPLÈTES."""
        import platform
        
        info = {
            'os': {
                'system': platform.system(),
                'release': platform.release(),
                'version': platform.version(),
                'platform': platform.platform(),
            },
            'machine': {
                'machine': platform.machine(),
                'processor': platform.processor(),
                'architecture': platform.architecture()[0],
                'hostname': self._get_hostname(),
            },
            'cpu': self._get_cpu_info_v3(),
            'memory': self._get_memory_info_v3(),
            'gpu': self._get_gpu_info_v3(),
        }
        
        # Info spécifique OS
        if platform.system() == 'Windows':
            info['windows'] = {
                'version': platform.win32_ver()[0],
                'build': platform.win32_ver()[1],
            }
        elif platform.system() == 'Linux':
            info['linux'] = self._get_linux_info_v3()
        elif platform.system() == 'Darwin':
            info['macos'] = {'version': platform.mac_ver()[0]}
        
        return info
    
    def _get_cpu_info_v3(self) -> Dict:
        """[v3.0] Informations CPU."""
        cpu = {
            'physical_cores': None,
            'logical_cores': os.cpu_count(),
            'max_frequency_mhz': None,
            'current_frequency_mhz': None,
            'cpu_percent': None,
        }
        try:
            import psutil
            cpu['physical_cores'] = psutil.cpu_count(logical=False)
            cpu['logical_cores'] = psutil.cpu_count(logical=True)
            cpu['cpu_percent'] = psutil.cpu_percent(interval=0.1)
            freq = psutil.cpu_freq()
            if freq:
                cpu['max_frequency_mhz'] = freq.max
                cpu['current_frequency_mhz'] = freq.current
        except ImportError:
            pass
        except Exception:
            pass
        return cpu
    
    def _get_memory_info_v3(self) -> Dict:
        """[v3.0] Informations mémoire."""
        mem = {
            'total_gb': None,
            'available_gb': None,
            'used_gb': None,
            'percent_used': None,
        }
        try:
            import psutil
            vm = psutil.virtual_memory()
            mem['total_gb'] = round(vm.total / (1024**3), 2)
            mem['available_gb'] = round(vm.available / (1024**3), 2)
            mem['used_gb'] = round(vm.used / (1024**3), 2)
            mem['percent_used'] = vm.percent
        except ImportError:
            pass
        except Exception:
            pass
        return mem
    
    def _get_gpu_info_v3(self) -> Dict:
        """[v3.0] Informations GPU."""
        gpu = {'available': False, 'nvidia': None, 'cuda_version': None, 'gpus': []}
        try:
            import subprocess
            result = subprocess.run(
                ['nvidia-smi', '--query-gpu=name,memory.total,driver_version', '--format=csv,noheader,nounits'],
                capture_output=True, text=True, timeout=5
            )
            if result.returncode == 0:
                gpu['available'] = True
                gpu['nvidia'] = True
                for line in result.stdout.strip().split('\n'):
                    parts = [p.strip() for p in line.split(',')]
                    if len(parts) >= 3:
                        gpu['gpus'].append({
                            'name': parts[0],
                            'memory_mb': int(parts[1]) if parts[1].isdigit() else parts[1],
                            'driver': parts[2],
                        })
        except:
            pass
        return gpu
    
    def _get_linux_info_v3(self) -> Dict:
        """[v3.0] Informations Linux."""
        import platform
        info = {'distribution': None, 'kernel': platform.release()}
        try:
            if os.path.exists('/etc/os-release'):
                with open('/etc/os-release', 'r', encoding='utf-8') as f:  # [v2.7.1 FIX] encoding
                    for line in f:
                        if line.startswith('PRETTY_NAME='):
                            info['distribution'] = line.split('=')[1].strip().strip('"')
                            break
        except:
            pass
        return info
    
    def _collect_python_env_v3(self) -> Dict:
        """[v3.0] Environnement Python complet."""
        return {
            'version': sys.version,
            'version_info': list(sys.version_info[:3]),
            'implementation': platform.python_implementation(),
            'executable': sys.executable,
            'prefix': sys.prefix,
            'is_virtualenv': sys.prefix != sys.base_prefix,
            'virtualenv_path': sys.prefix if sys.prefix != sys.base_prefix else None,
            'encoding': {
                'default': sys.getdefaultencoding(),
                'filesystem': sys.getfilesystemencoding(),
            },
        }
    
    def _collect_dependencies_v3(self) -> Dict:
        """[v3.0] Dépendances avec catégorisation."""
        deps = {
            'qiskit_ecosystem': {},
            'ibm_addons': {},
            'scientific': {},
            'visualization': {},
            'all_installed': {},
        }
        
        # Qiskit
        for pkg in ['qiskit', 'qiskit-ibm-runtime', 'qiskit-aer']:
            v = self._get_package_version(pkg)
            if v:
                deps['qiskit_ecosystem'][pkg] = v
        
        # IBM Addons
        for pkg in ['mthree', 'qiskit-addon-aqc-tensor', 'qiskit-addon-mpf', 
                    'qiskit-addon-obp', 'qiskit-addon-sqd', 'qiskit-addon-cutting']:
            v = self._get_package_version(pkg)
            if v:
                deps['ibm_addons'][pkg] = v
        
        # Scientific
        for pkg in ['numpy', 'scipy', 'pandas', 'networkx']:
            v = self._get_package_version(pkg)
            if v:
                deps['scientific'][pkg] = v
        
        # Visualization
        for pkg in ['matplotlib', 'plotly', 'pillow']:
            v = self._get_package_version(pkg)
            if v:
                deps['visualization'][pkg] = v
        
        # Tous les packages installés
        try:
            import importlib.metadata
            for dist in importlib.metadata.distributions():
                deps['all_installed'][dist.metadata['Name']] = dist.version
        except:
            pass
        
        deps['summary'] = {
            'qiskit_count': len(deps['qiskit_ecosystem']),
            'ibm_addons_count': len(deps['ibm_addons']),
            'total_packages': len(deps['all_installed']),
        }
        
        return deps
    
    def _get_package_version(self, package_name: str) -> Optional[str]:
        """Récupère la version d'un package."""
        try:
            import importlib.metadata
            return importlib.metadata.version(package_name)
        except:
            try:
                module_name = package_name.replace('-', '_').split('.')[0]
                module = __import__(module_name)
                return getattr(module, '__version__', 'installed')
            except:
                return None
    
    def _collect_environment_vars_v3(self) -> Dict:
        """[v3.0] Variables d'environnement pertinentes."""
        safe_vars = [
            'QMC_BACKEND', 'QMC_PROJECT', 'QMC_AUTO_CONFIRM', 
            'QMC_GENERATE_REPORT', 'QMC_GENERATE_ARCHIVE',
            'IBM_QUANTUM_TOKEN', 'IBM_QUANTUM_INSTANCE', 
            'QISKIT_IBM_TOKEN', 'QISKIT_IBM_INSTANCE',
            'PYTHONPATH', 'VIRTUAL_ENV', 'CONDA_DEFAULT_ENV',
        ]
        
        env = {'qmc_vars': {}, 'ibm_vars': {}, 'python_vars': {}}
        
        for var in safe_vars:
            value = os.environ.get(var)
            if value:
                # Masquer les tokens
                if 'TOKEN' in var or 'KEY' in var:
                    value = value[:8] + '...' if len(value) > 8 else '***'
                
                if var.startswith('QMC_'):
                    env['qmc_vars'][var] = value
                elif var.startswith('IBM_') or var.startswith('QISKIT_IBM'):
                    env['ibm_vars'][var] = value
                else:
                    env['python_vars'][var] = value
        
        return env
    
    def _collect_ibm_account_v3(self) -> Dict:
        """[v3.0] Informations compte IBM Quantum."""
        account = {
            'available': False,
            'channel': None,
            'instance': None,
            'hub': None,
            'group': None,
            'project': None,
        }
        
        if not self.framework:
            return account
        
        try:
            service = getattr(self.framework, 'service', None)
            if service:
                account['available'] = True
                account['channel'] = getattr(service, 'channel', None)
                
                instance = getattr(self.framework, '_instance', None)
                if instance and '/' in str(instance):
                    parts = str(instance).split('/')
                    if len(parts) >= 3:
                        account['hub'] = parts[0]
                        account['group'] = parts[1]
                        account['project'] = parts[2]
        except Exception as e:
            account['error'] = str(e)
        
        return account
    
    def _collect_qpu_state_v3(self) -> Dict:
        """
        [v3.0] ÉTAT COMPLET DE CHAQUE QUBIT DU QPU.
        
        Cette section permet de reconstruire l'état exact du QPU au moment du run.
        Contient pour CHAQUE qubit:
        - T1, T2 (temps de cohérence)
        - Fréquence, anharmonicité
        - Erreur de readout
        - Durée de mesure
        - Status (faulty, suspect, ok)
        """
        qpu = {
            'available': False,
            'timestamp': None,
            'calibration_id': None,
            'num_qubits': 0,
            'qubits': [],  # État de CHAQUE qubit
            'summary': {},
        }
        
        if not self.framework:
            return qpu
        
        backend = getattr(self.framework, 'backend', None)
        if not backend:
            return qpu
        
        try:
            qpu['available'] = True
            qpu['calibration_id'] = getattr(backend, 'calibration_id', None)
            
            # Timestamp de calibration
            if hasattr(backend, 'properties') and backend.properties():
                props = backend.properties()
                qpu['timestamp'] = str(props.last_update_date) if hasattr(props, 'last_update_date') else None
            
            if hasattr(backend, 'target') and backend.target:
                target = backend.target
                qpu['num_qubits'] = target.num_qubits
                
                t1_values, t2_values, ro_errors = [], [], []
                
                # COLLECTER CHAQUE QUBIT
                for qubit in range(target.num_qubits):
                    q_data = {
                        'index': qubit,
                        't1_us': None,
                        't2_us': None,
                        'frequency_ghz': None,
                        'anharmonicity_ghz': None,
                        'readout_error': None,
                        'readout_length_us': None,
                        'prob_meas0_prep1': None,
                        'prob_meas1_prep0': None,
                        'sx_error': None,
                        'sx_duration_ns': None,
                        'status': 'unknown',  # 'ok', 'suspect', 'faulty'
                    }
                    
                    # QubitProperties
                    try:
                        if hasattr(target, 'qubit_properties') and target.qubit_properties:
                            qp = target.qubit_properties[qubit]
                            if qp:
                                if hasattr(qp, 't1') and qp.t1:
                                    q_data['t1_us'] = round(qp.t1 * 1e6, 3)
                                    t1_values.append(qp.t1 * 1e6)
                                if hasattr(qp, 't2') and qp.t2:
                                    q_data['t2_us'] = round(qp.t2 * 1e6, 3)
                                    t2_values.append(qp.t2 * 1e6)
                                if hasattr(qp, 'frequency') and qp.frequency:
                                    q_data['frequency_ghz'] = round(qp.frequency / 1e9, 6)
                                if hasattr(qp, 'anharmonicity') and qp.anharmonicity:
                                    q_data['anharmonicity_ghz'] = round(qp.anharmonicity / 1e9, 6)
                    except:
                        pass
                    
                    # Erreur de mesure
                    try:
                        if 'measure' in target.operation_names:
                            for qargs in target.qargs_for_operation_name('measure'):
                                if qargs == (qubit,):
                                    mp = target['measure'][qargs]
                                    if mp:
                                        if hasattr(mp, 'error') and mp.error is not None:
                                            q_data['readout_error'] = round(mp.error, 6)
                                            ro_errors.append(mp.error)
                                        if hasattr(mp, 'duration') and mp.duration:
                                            q_data['readout_length_us'] = round(mp.duration * 1e6, 3)
                                    break
                    except:
                        pass
                    
                    # Erreur SX gate (indicateur de qualité 1Q)
                    try:
                        if 'sx' in target.operation_names:
                            for qargs in target.qargs_for_operation_name('sx'):
                                if qargs == (qubit,):
                                    sx_props = target['sx'][qargs]
                                    if sx_props:
                                        if hasattr(sx_props, 'error') and sx_props.error:
                                            q_data['sx_error'] = round(sx_props.error, 6)
                                        if hasattr(sx_props, 'duration') and sx_props.duration:
                                            q_data['sx_duration_ns'] = round(sx_props.duration * 1e9, 2)
                                    break
                    except:
                        pass
                    
                    # Déterminer le status du qubit
                    t1 = q_data['t1_us']
                    ro = q_data['readout_error']
                    if t1 is not None and t1 < 10:
                        q_data['status'] = 'faulty'
                    elif ro is not None and ro > 0.15:
                        q_data['status'] = 'faulty'
                    elif (t1 is not None and t1 < 50) or (ro is not None and ro > 0.05):
                        q_data['status'] = 'suspect'
                    else:
                        q_data['status'] = 'ok'
                    
                    qpu['qubits'].append(q_data)
                
                # Summary statistiques
                qpu['summary'] = {
                    'total_qubits': target.num_qubits,
                    't1': {
                        'mean_us': round(sum(t1_values) / len(t1_values), 2) if t1_values else None,
                        'median_us': round(sorted(t1_values)[len(t1_values)//2], 2) if t1_values else None,
                        'min_us': round(min(t1_values), 2) if t1_values else None,
                        'max_us': round(max(t1_values), 2) if t1_values else None,
                    },
                    't2': {
                        'mean_us': round(sum(t2_values) / len(t2_values), 2) if t2_values else None,
                        'median_us': round(sorted(t2_values)[len(t2_values)//2], 2) if t2_values else None,
                        'min_us': round(min(t2_values), 2) if t2_values else None,
                        'max_us': round(max(t2_values), 2) if t2_values else None,
                    },
                    'readout_error': {
                        'mean': round(sum(ro_errors) / len(ro_errors), 6) if ro_errors else None,
                        'median': round(sorted(ro_errors)[len(ro_errors)//2], 6) if ro_errors else None,
                        'min': round(min(ro_errors), 6) if ro_errors else None,
                        'max': round(max(ro_errors), 6) if ro_errors else None,
                    },
                    'qubits_ok': sum(1 for q in qpu['qubits'] if q['status'] == 'ok'),
                    'qubits_suspect': sum(1 for q in qpu['qubits'] if q['status'] == 'suspect'),
                    'qubits_faulty': sum(1 for q in qpu['qubits'] if q['status'] == 'faulty'),
                }
                
        except Exception as e:
            qpu['error'] = str(e)
        
        return qpu
    
    def _collect_gates_calibration_v3(self) -> Dict:
        """[v3.0] Calibration de TOUTES les gates."""
        gates = {
            'available': False,
            'gates_1q': [],
            'gates_2q': [],
            'summary': {},
        }
        
        if not self.framework:
            return gates
        
        backend = getattr(self.framework, 'backend', None)
        if not backend or not hasattr(backend, 'target') or not backend.target:
            return gates
        
        try:
            target = backend.target
            gates['available'] = True
            errors_1q, errors_2q = [], []
            
            # Gates 1-qubit
            for gate_name in ['sx', 'x', 'rz', 'id']:
                if gate_name in target.operation_names:
                    try:
                        for qargs in target.qargs_for_operation_name(gate_name):
                            if len(qargs) == 1:
                                gp = target[gate_name][qargs]
                                if gp:
                                    error = round(gp.error, 6) if gp.error else None
                                    if error:
                                        errors_1q.append(error)
                                    gates['gates_1q'].append({
                                        'gate': gate_name,
                                        'qubit': qargs[0],
                                        'error': error,
                                        'duration_ns': round(gp.duration * 1e9, 2) if gp.duration else None,
                                    })
                    except:
                        pass
            
            # Gates 2-qubit
            for gate_name in ['cz', 'ecr', 'cx', 'rzz']:
                if gate_name in target.operation_names:
                    try:
                        for qargs in target.qargs_for_operation_name(gate_name):
                            if len(qargs) == 2:
                                gp = target[gate_name][qargs]
                                if gp:
                                    error = round(gp.error, 6) if gp.error and gp.error < 1.0 else None
                                    if error:
                                        errors_2q.append(error)
                                    gates['gates_2q'].append({
                                        'gate': gate_name,
                                        'qubits': list(qargs),
                                        'error': error,
                                        'duration_ns': round(gp.duration * 1e9, 2) if gp.duration else None,
                                    })
                    except:
                        pass
            
            gates['summary'] = {
                'gates_1q_count': len(gates['gates_1q']),
                'gates_2q_count': len(gates['gates_2q']),
                'avg_1q_error': round(sum(errors_1q) / len(errors_1q), 6) if errors_1q else None,
                'avg_2q_error': round(sum(errors_2q) / len(errors_2q), 6) if errors_2q else None,
                'min_2q_error': round(min(errors_2q), 6) if errors_2q else None,
                'max_2q_error': round(max(errors_2q), 6) if errors_2q else None,
            }
            
        except Exception as e:
            gates['error'] = str(e)
        
        return gates
    
    def _collect_topology_v3(self) -> Dict:
        """[v3.0] Topologie complète du backend."""
        topo = {
            'available': False,
            'type': None,
            'num_qubits': None,
            'num_edges': None,
            'coupling_map': [],
            'adjacency_list': {},
        }
        
        if not self.framework:
            return topo
        
        backend = getattr(self.framework, 'backend', None)
        if not backend or not hasattr(backend, 'target') or not backend.target:
            return topo
        
        try:
            target = backend.target
            topo['available'] = True
            topo['num_qubits'] = target.num_qubits
            
            if hasattr(target, 'build_coupling_map'):
                cm = target.build_coupling_map()
                if cm:
                    edges = list(cm.get_edges())
                    topo['coupling_map'] = [list(e) for e in edges]
                    topo['num_edges'] = len(edges)
                    
                    # Adjacency list
                    adj = {}
                    for q1, q2 in edges:
                        adj.setdefault(q1, []).append(q2)
                        adj.setdefault(q2, []).append(q1)
                    topo['adjacency_list'] = {k: sorted(list(set(v))) for k, v in adj.items()}
            
            # Type de topologie
            if hasattr(backend, 'configuration'):
                config = backend.configuration()
                if config:
                    proc = getattr(config, 'processor_type', {})
                    if proc:
                        family = proc.get('family', '')
                        if 'Heron' in family or 'Eagle' in family:
                            topo['type'] = 'heavy-hex'
                            
        except Exception as e:
            topo['error'] = str(e)
        
        return topo
    
    def _collect_calibration_health_v3(self) -> Dict:
        """[v3.0] Health score et analyse de la calibration."""
        health = {
            'available': False,
            'health_score': None,
            'health_grade': None,
            'faulty_qubits': [],
            'suspect_qubits': [],
            'recommendations': [],
        }
        
        if not self.framework:
            return health
        
        try:
            # Via topology
            if hasattr(self.framework, 'topology') and self.framework.topology:
                topo = self.framework.topology
                health['available'] = True
                
                if hasattr(topo, 'faulty_qubits'):
                    health['faulty_qubits'] = list(topo.faulty_qubits)
                if hasattr(topo, 'suspect_qubits'):
                    health['suspect_qubits'] = list(topo.suspect_qubits)
                if hasattr(topo, 'health_score'):
                    health['health_score'] = topo.health_score
                if hasattr(topo, 'health_grade'):
                    health['health_grade'] = topo.health_grade
                if hasattr(topo, 'recommendations'):
                    health['recommendations'] = topo.recommendations
                    
        except Exception as e:
            health['error'] = str(e)
        
        return health
    
    def _collect_quality_thresholds_v3(self) -> Dict:
        """[v3.0] Seuils de qualité configurés."""
        thresholds = {
            'configured': False,
            'min_entropy': None,
            'max_top_prob': None,
            'min_fidelity': None,
            'min_uniformity': None,
        }
        
        if not self.framework:
            return thresholds
        
        if hasattr(self.framework, 'quality_thresholds') and self.framework.quality_thresholds:
            qt = self.framework.quality_thresholds
            thresholds['configured'] = True
            thresholds['min_entropy'] = qt.min_entropy
            thresholds['max_top_prob'] = qt.max_top_prob
            thresholds['min_fidelity'] = qt.min_fidelity
            thresholds['min_uniformity'] = qt.min_uniformity
        
        return thresholds
    
    def _collect_circuits_v3(self, circuits, prefix: str = '') -> List[Dict]:
        """
        [v3.0] Collecte les circuits avec TOUTES les informations pour reconstruction.
        
        [v2.7.0 FIX] Skip QASM serialization pour circuits >40 qubits (trop lent,
        qasm2_dumps() prend 5-30s par circuit 156Q). Garde uniquement les métriques.
        
        Contient:
        - QASM complet (pour from_qasm_str) — sauf circuits >40Q
        - Liste des instructions détaillées — sauf circuits >1000 instructions
        - Paramètres si circuit paramétré
        - Layout après transpilation
        """
        if not circuits:
            return []
        
        circuits_info = []
        
        # [v2.7.0] Seuil pour skip QASM (trop lent sur gros circuits)
        MAX_QUBITS_FOR_QASM = 40
        
        for i, circuit in enumerate(circuits):
            try:
                n_qubits = circuit.num_qubits
                ops = dict(circuit.count_ops())
                
                c_info = {
                    'index': i,
                    'name': getattr(circuit, 'name', f'{prefix}_{i}'),
                    
                    # Métriques (toujours rapides)
                    'num_qubits': n_qubits,
                    'num_clbits': circuit.num_clbits,
                    'depth': circuit.depth(),
                    'size': circuit.size(),
                    'width': circuit.width(),
                    'num_parameters': circuit.num_parameters,
                    'global_phase': str(circuit.global_phase),
                    
                    # Comptage gates (depuis ops, rapide)
                    'gate_counts': ops,
                    'num_1q_gates': sum(v for k, v in ops.items() 
                                       if k in ['h', 'x', 'y', 'z', 'rz', 'rx', 'ry', 's', 't', 
                                                'sdg', 'tdg', 'sx', 'sxdg', 'u1', 'u2', 'u3', 'id']),
                    'num_2q_gates': sum(v for k, v in ops.items() 
                                       if k in ['cx', 'cz', 'ecr', 'swap', 'rzz', 'rxx', 'ryy']),
                    'num_3q_plus': sum(v for k, v in ops.items() 
                                      if k in ['ccx', 'cswap', 'ccz']),
                    
                    # QASM pour reconstruction
                    'qasm': None,
                    'qasm_truncated': False,
                    
                    # Instructions détaillées pour reconstruction
                    'instructions': [] if self.include_instructions else None,
                    
                    # Paramètres si paramétrés
                    'parameters': None,
                    
                    # Layout après transpilation
                    'layout': None,
                }
                
                # [v2.7.0] Skip QASM pour gros circuits (trop lent: 5-30s par circuit 156Q)
                if n_qubits > MAX_QUBITS_FOR_QASM:
                    c_info['qasm'] = f"// SKIPPED: {n_qubits}Q circuit too large for QASM serialization (>{MAX_QUBITS_FOR_QASM}Q threshold)"
                    c_info['qasm_truncated'] = True
                    if i == 0:
                        self._log(f"[ARCHIVE] ⏭️ Skip QASM: {n_qubits}Q > {MAX_QUBITS_FOR_QASM}Q threshold ({len(circuits)} circuits)")
                else:
                    # QASM complet (circuits petits/moyens seulement)
                    try:
                        from qiskit.qasm2 import dumps as qasm2_dumps
                        qasm_str = qasm2_dumps(circuit)
                        if len(qasm_str) <= self.max_qasm_size:
                            c_info['qasm'] = qasm_str
                        else:
                            c_info['qasm'] = qasm_str[:self.max_qasm_size] + '\n// ... TRUNCATED ...'
                            c_info['qasm_truncated'] = True
                    except:
                        try:
                            qasm_str = circuit.qasm()
                            if len(qasm_str) <= self.max_qasm_size:
                                c_info['qasm'] = qasm_str
                        except:
                            pass
                
                # Instructions détaillées
                if self.include_instructions and len(circuit.data) <= 1000:
                    for inst in circuit.data:
                        try:
                            inst_data = {
                                'name': inst.operation.name,
                                'qubits': [q._index if hasattr(q, '_index') else str(q) for q in inst.qubits],
                                'clbits': [c._index if hasattr(c, '_index') else str(c) for c in inst.clbits],
                                'params': [str(p) for p in inst.operation.params] if inst.operation.params else [],
                            }
                            c_info['instructions'].append(inst_data)
                        except:
                            pass
                
                # Paramètres si circuit paramétré
                if circuit.num_parameters > 0:
                    try:
                        c_info['parameters'] = {
                            'count': circuit.num_parameters,
                            'names': [str(p) for p in circuit.parameters],
                        }
                    except:
                        pass
                
                # Layout après transpilation
                if hasattr(circuit, '_layout') and circuit._layout:
                    try:
                        layout = circuit._layout
                        c_info['layout'] = {}
                        if hasattr(layout, 'final_index_layout'):
                            c_info['layout']['final_layout'] = list(layout.final_index_layout())
                        if hasattr(layout, 'initial_layout'):
                            c_info['layout']['initial_layout'] = str(layout.initial_layout)
                            # Virtual to physical mapping
                            try:
                                v2p = {}
                                for vq, pq in layout.initial_layout.get_virtual_bits().items():
                                    if hasattr(vq, '_index'):
                                        v2p[vq._index] = pq
                                c_info['layout']['virtual_to_physical'] = v2p
                            except:
                                pass
                    except:
                        pass
                
                circuits_info.append(c_info)
                
            except Exception as e:
                circuits_info.append({
                    'index': i,
                    'error': str(e)
                })
        
        return circuits_info
    
    # ═══════════════════════════════════════════════════════════════════════════
    # NOUVELLES MÉTHODES v3.0 - SECTIONS ADDITIONNELLES
    # ═══════════════════════════════════════════════════════════════════════════
    
    def _collect_backend_extended_v3(self) -> Dict:
        """[v3.0] Informations étendues du backend (features, limites, processor)."""
        info = {
            'available': False,
            'status': {},
            'supported_features': {},
            'limits': {},
            'processor': {},
            'dates': {},
        }
        
        if not self.framework:
            return info
        
        backend = getattr(self.framework, 'backend', None)
        if not backend:
            return info
        
        try:
            info['available'] = True
            
            # Status temps réel
            if hasattr(backend, 'status'):
                try:
                    status = backend.status()
                    info['status'] = {
                        'operational': getattr(status, 'operational', None),
                        'pending_jobs': getattr(status, 'pending_jobs', None),
                        'status_msg': getattr(status, 'status_msg', None),
                    }
                except:
                    pass
            
            # Features supportées
            if hasattr(backend, 'target') and backend.target:
                target = backend.target
                ops = list(target.operation_names) if hasattr(target, 'operation_names') else []
                
                info['supported_features'] = {
                    'dynamic_circuits': any(x in ops for x in ['if_else', 'for_loop', 'switch_case']),
                    'mid_circuit_measurement': 'measure' in ops,
                    'classical_feedback': any(x in ops for x in ['if_else', 'c_if']),
                    'reset': 'reset' in ops,
                    'delay': 'delay' in ops,
                    'fractional_gates': 'rzz' in ops or 'rxx' in ops,
                }
            
            # Limites
            if hasattr(backend, 'configuration'):
                try:
                    config = backend.configuration()
                    if config:
                        info['limits'] = {
                            'max_shots': getattr(config, 'max_shots', None),
                            'max_circuits': getattr(backend, 'max_circuits', None),
                            'max_qubits': getattr(config, 'n_qubits', None),
                            'rep_delay_range_us': getattr(config, 'rep_delay_range', None),
                            'default_rep_delay_us': getattr(config, 'default_rep_delay', None),
                        }
                        
                        # Processor details
                        proc = getattr(config, 'processor_type', None)
                        if proc and isinstance(proc, dict):
                            info['processor'] = {
                                'family': proc.get('family'),
                                'revision': proc.get('revision'),
                                'segment': proc.get('segment'),
                            }
                        
                        # Dates
                        info['dates'] = {
                            'online_date': str(getattr(config, 'online_date', None)),
                        }
                except:
                    pass
            
            # CLOPS depuis nos données
            backend_name = getattr(backend, 'name', '')
            clops_data = {
                'ibm_torino': 290000, 'ibm_fez': 320000, 'ibm_marrakesh': 300000,
                'ibm_boston': 340000, 'ibm_pittsburgh': 330000, 'ibm_kingston': 340000,
            }
            if backend_name in clops_data:
                info['processor']['clops'] = clops_data[backend_name]
                
        except Exception as e:
            info['error'] = str(e)
        
        return info
    
    def _collect_usage_costs_v3(self, run_context: Dict) -> Dict:
        """[v3.0] Usage et coûts de l'exécution."""
        ctx = run_context or {}
        
        usage = {
            'this_execution': {
                'qpu_time_seconds': ctx.get('qpu_time_s', 0),
                'shots_executed': ctx.get('shots', 0) * ctx.get('circuits_count', 0),
                'circuits_executed': ctx.get('circuits_count', 0),
            },
            'monthly_usage': None,
            'ibm_quotas': None,
        }
        
        # Budget du framework si configuré
        if self.framework and hasattr(self.framework, 'budget_manager') and self.framework.budget_manager:
            try:
                bm = self.framework.budget_manager
                usage['monthly_usage'] = {
                    'used_minutes': getattr(bm, 'used_minutes', None),
                    'budget_minutes': getattr(bm, 'budget_minutes', None),
                    'remaining_minutes': getattr(bm, 'remaining_minutes', None),
                }
            except:
                pass
        
        return usage
    
    def _collect_transpilation_detailed_v3(self, circuits, transpiled_circuits, run_context: Dict) -> Dict:
        """[v3.0] Métriques détaillées de transpilation."""
        detail = {
            'available': False,
            'seed_transpiler': None,
            'metrics_per_circuit': [],
            'totals': {},
        }
        
        if not circuits or not transpiled_circuits:
            return detail
        
        if len(circuits) != len(transpiled_circuits):
            return detail
        
        detail['available'] = True
        ctx = run_context or {}
        detail['seed_transpiler'] = ctx.get('seed_transpiler')
        
        total_depth_before, total_depth_after = 0, 0
        total_2q_before, total_2q_after = 0, 0
        total_swaps = 0
        
        for i, (orig, trans) in enumerate(zip(circuits, transpiled_circuits)):
            try:
                depth_before = orig.depth()
                depth_after = trans.depth()
                
                # [v2.7.0] Utiliser count_ops() au lieu d'itérer circuit.data
                orig_ops = dict(orig.count_ops())
                trans_ops = dict(trans.count_ops())
                gates_2q_before = sum(v for k, v in orig_ops.items() 
                                     if k in ['cx', 'cz', 'ecr', 'swap', 'rzz', 'rxx', 'ryy'])
                gates_2q_after = sum(v for k, v in trans_ops.items() 
                                    if k in ['cx', 'cz', 'ecr', 'swap', 'rzz', 'rxx', 'ryy'])
                
                # Compter les SWAPs ajoutés (déjà dans trans_ops)
                swaps = trans_ops.get('swap', 0)
                
                metrics = {
                    'index': i,
                    'before': {'depth': depth_before, 'gates_2q': gates_2q_before},
                    'after': {'depth': depth_after, 'gates_2q': gates_2q_after},
                    'overhead': {
                        'depth_pct': round((depth_after / depth_before - 1) * 100, 1) if depth_before > 0 else 0,
                        'gates_2q_pct': round((gates_2q_after / gates_2q_before - 1) * 100, 1) if gates_2q_before > 0 else 0,
                    },
                    'swap_gates_added': swaps,
                }
                detail['metrics_per_circuit'].append(metrics)
                
                total_depth_before += depth_before
                total_depth_after += depth_after
                total_2q_before += gates_2q_before
                total_2q_after += gates_2q_after
                total_swaps += swaps
                
            except Exception as e:
                detail['metrics_per_circuit'].append({'index': i, 'error': str(e)})
        
        # Totaux
        detail['totals'] = {
            'total_depth_before': total_depth_before,
            'total_depth_after': total_depth_after,
            'depth_overhead_pct': round((total_depth_after / total_depth_before - 1) * 100, 1) if total_depth_before > 0 else 0,
            'total_2q_before': total_2q_before,
            'total_2q_after': total_2q_after,
            'gates_2q_overhead_pct': round((total_2q_after / total_2q_before - 1) * 100, 1) if total_2q_before > 0 else 0,
            'total_swaps_added': total_swaps,
        }
        
        return detail
    
    def _collect_analysis_results_v3(self, results: List[Dict]) -> Dict:
        """[v3.0] Résultats d'analyse (XEB, fidelity, randomness)."""
        analysis = {
            'xeb': {'available': False},
            'fidelity': {'available': False},
            'randomness': {'available': False},
            'correlations': {},
        }
        
        if not results:
            return analysis
        
        # Collecter depuis les résultats si présents
        for i, r in enumerate(results):
            if isinstance(r, dict):
                if 'xeb' in r:
                    analysis['xeb']['available'] = True
                    analysis['xeb'].setdefault('per_circuit', []).append({
                        'index': i, 'xeb': r['xeb']
                    })
                if 'fidelity' in r and r['fidelity'] is not None:
                    analysis['fidelity']['available'] = True
                    analysis['fidelity'].setdefault('per_circuit', []).append({
                        'index': i, 'fidelity': r['fidelity']
                    })
        
        # Calculer la fidelity moyenne si disponible
        if analysis['fidelity'].get('per_circuit'):
            fids = [x['fidelity'] for x in analysis['fidelity']['per_circuit'] if x['fidelity']]
            if fids:
                analysis['fidelity']['avg_fidelity'] = round(sum(fids) / len(fids), 4)
        
        # Tests de randomness basiques
        try:
            all_counts = {}
            total_bits = 0
            n_qubits = 0
            for r in results:
                if isinstance(r, dict) and 'counts' in r:
                    for bitstring, count in r['counts'].items():
                        # [v2.7.1 FIX] Strip register-separator spaces before counting bits;
                        # otherwise the ' ' separators were tallied as "bits" and diluted the
                        # ones/zeros ratios. Derive n_qubits from the stripped bitstring.
                        clean_bits = bitstring.replace(' ', '')
                        if not n_qubits and clean_bits:
                            n_qubits = len(clean_bits)
                        for c in range(count):
                            for bit in clean_bits:
                                if bit in all_counts:
                                    all_counts[bit] += 1
                                else:
                                    all_counts[bit] = 1
                                total_bits += 1

            if total_bits > 0:
                ones = all_counts.get('1', 0)
                zeros = all_counts.get('0', 0)
                ratio = ones / total_bits if total_bits > 0 else 0

                analysis['randomness'] = {
                    'available': True,
                    'total_bits': total_bits,
                    'n_qubits': n_qubits,
                    'ones_ratio': round(ratio, 4),
                    'zeros_ratio': round(1 - ratio, 4),
                    'balance': round(1 - abs(ratio - 0.5) * 2, 4),  # 1 = parfait, 0 = biaisé
                }
        except:
            pass
        
        return analysis
    
    def _collect_timing_detailed_v3(self, run_context: Dict) -> Dict:
        """[v3.0] Timeline détaillée de l'exécution."""
        ctx = run_context or {}
        
        timing = {
            'timeline': {},
            'durations': {},
        }
        
        # Timeline
        timeline_keys = [
            'script_start', 'framework_init', 'backend_connect',
            'circuits_built', 'transpilation_start', 'transpilation_end',
            'job_submitted', 'job_queued', 'job_running', 'job_completed',
            'results_received', 'archive_generated'
        ]
        for key in timeline_keys:
            if key in ctx:
                timing['timeline'][key] = ctx[key]
        
        # Ajouter timestamp actuel
        timing['timeline']['archive_generated'] = datetime.now().isoformat()
        
        # Durées
        timing['durations'] = {
            'total_s': ctx.get('total_time_s', 0),
            'transpilation_s': ctx.get('transpile_time_s', 0),
            'queue_wait_s': ctx.get('queue_time_s', 0),
            'qpu_execution_s': ctx.get('qpu_time_s', 0),
            'execution_s': ctx.get('execution_time_s', 0),
        }
        
        return timing
    
    def _collect_reproducibility_v3(self) -> Dict:
        """[v3.0] Informations pour reproductibilité."""
        repro = {
            'seeds': {},
            'exact_versions': {},
            'git': None,
        }
        
        # Seeds si configurés
        if self.framework:
            repro['seeds'] = {
                'numpy_seed': getattr(self.framework, '_numpy_seed', None),
                'qiskit_seed': getattr(self.framework, '_qiskit_seed', None),
                'transpiler_seed': getattr(self.framework, '_transpiler_seed', None),
            }
        
        # Versions exactes des packages critiques
        critical_packages = ['qiskit', 'qiskit-ibm-runtime', 'numpy', 'scipy']
        for pkg in critical_packages:
            v = self._get_package_version(pkg)
            if v:
                repro['exact_versions'][pkg] = v
        
        # Git info
        try:
            import subprocess
            git_info = {}
            
            result = subprocess.run(['git', 'rev-parse', '--abbrev-ref', 'HEAD'],
                                    capture_output=True, text=True, timeout=2)
            if result.returncode == 0:
                git_info['branch'] = result.stdout.strip()
            
            result = subprocess.run(['git', 'rev-parse', 'HEAD'],
                                    capture_output=True, text=True, timeout=2)
            if result.returncode == 0:
                git_info['commit'] = result.stdout.strip()[:12]
            
            result = subprocess.run(['git', 'status', '--porcelain'],
                                    capture_output=True, text=True, timeout=2)
            if result.returncode == 0:
                git_info['dirty'] = len(result.stdout.strip()) > 0
            
            if git_info:
                repro['git'] = git_info
        except:
            pass
        
        return repro
    
    def _collect_qubits_analysis_v3(self, transpiled_circuits) -> Dict:
        """[v3.0] Analyse des qubits effectivement utilisés."""
        analysis = {
            'available': False,
            'qubits_used': [],
            'num_qubits_used': 0,
            'used_qubits_quality': {},
            'connections_used': [],
            'connections_quality': {},
        }
        
        if not transpiled_circuits or not self.framework:
            return analysis
        
        backend = getattr(self.framework, 'backend', None)
        if not backend:
            return analysis
        
        try:
            # Collecter tous les qubits physiques utilisés
            used_qubits = set()
            used_connections = set()
            
            for circuit in transpiled_circuits:
                n_qubits = circuit.num_qubits
                
                # [v2.7.0] Pour gros circuits, utiliser layout info au lieu d'itérer circuit.data
                if n_qubits > 40:
                    # Approximation rapide: tous les qubits du circuit sont "utilisés"
                    if hasattr(circuit, 'layout') and circuit.layout:
                        try:
                            for j in range(circuit.num_qubits):
                                phys = circuit.layout.final_index_layout()[j]
                                used_qubits.add(phys)
                        except:
                            used_qubits.update(range(n_qubits))
                    else:
                        used_qubits.update(range(n_qubits))
                    # Skip connection extraction (trop lent pour gros circuits)
                else:
                    for inst in circuit.data:
                        qubits = []
                        for q in inst.qubits:
                            idx = q._index if hasattr(q, '_index') else None
                            if idx is not None:
                                used_qubits.add(idx)
                                qubits.append(idx)
                        
                        # Connexions 2Q
                        if len(qubits) == 2:
                            conn = tuple(sorted(qubits))
                            used_connections.add(conn)
            
            analysis['available'] = True
            analysis['qubits_used'] = sorted(list(used_qubits))
            analysis['num_qubits_used'] = len(used_qubits)
            analysis['connections_used'] = [list(c) for c in sorted(used_connections)]
            
            # Qualité des qubits utilisés (depuis qpu_state déjà collecté)
            if hasattr(backend, 'target') and backend.target:
                target = backend.target
                t1_vals, t2_vals, ro_vals = [], [], []
                
                for q in used_qubits:
                    try:
                        if hasattr(target, 'qubit_properties') and target.qubit_properties:
                            qp = target.qubit_properties[q]
                            if qp:
                                if hasattr(qp, 't1') and qp.t1:
                                    t1_vals.append(qp.t1 * 1e6)
                                if hasattr(qp, 't2') and qp.t2:
                                    t2_vals.append(qp.t2 * 1e6)
                        
                        # Readout error
                        if 'measure' in target.operation_names:
                            mp = target['measure'].get((q,))
                            if mp and hasattr(mp, 'error') and mp.error:
                                ro_vals.append(mp.error)
                    except:
                        pass
                
                if t1_vals:
                    analysis['used_qubits_quality'] = {
                        'avg_t1_us': round(sum(t1_vals) / len(t1_vals), 2),
                        'min_t1_us': round(min(t1_vals), 2),
                        'avg_t2_us': round(sum(t2_vals) / len(t2_vals), 2) if t2_vals else None,
                        'avg_readout_error': round(sum(ro_vals) / len(ro_vals), 6) if ro_vals else None,
                    }
                    
        except Exception as e:
            analysis['error'] = str(e)
        
        return analysis
    
    def _collect_connections_detailed_v3(self) -> Dict:
        """[v3.0] Détails de toutes les connexions 2Q du backend."""
        connections = {
            'available': False,
            'total_connections': 0,
            'connections': [],
            'stats': {},
        }
        
        if not self.framework:
            return connections
        
        backend = getattr(self.framework, 'backend', None)
        if not backend or not hasattr(backend, 'target') or not backend.target:
            return connections
        
        try:
            target = backend.target
            connections['available'] = True
            
            errors = []
            
            # Collecter toutes les connexions 2Q
            for gate_name in ['cz', 'ecr', 'cx', 'rzz']:
                if gate_name in target.operation_names:
                    for qargs in target.qargs_for_operation_name(gate_name):
                        if len(qargs) == 2:
                            try:
                                gp = target[gate_name][qargs]
                                if gp:
                                    error = gp.error if gp.error and gp.error < 1.0 else None
                                    duration = gp.duration * 1e9 if gp.duration else None
                                    
                                    # Classifier la qualité
                                    quality = 'unknown'
                                    if error is not None:
                                        if error < 0.01:
                                            quality = 'excellent'
                                        elif error < 0.03:
                                            quality = 'good'
                                        elif error < 0.06:
                                            quality = 'degraded'
                                        else:
                                            quality = 'poor'
                                        errors.append(error)
                                    
                                    connections['connections'].append({
                                        'qubits': list(qargs),
                                        'gate': gate_name,
                                        'error': round(error, 6) if error else None,
                                        'duration_ns': round(duration, 2) if duration else None,
                                        'quality': quality,
                                    })
                            except:
                                pass
            
            connections['total_connections'] = len(connections['connections'])
            
            # Statistiques
            if errors:
                connections['stats'] = {
                    'excellent_count': sum(1 for c in connections['connections'] if c['quality'] == 'excellent'),
                    'good_count': sum(1 for c in connections['connections'] if c['quality'] == 'good'),
                    'degraded_count': sum(1 for c in connections['connections'] if c['quality'] == 'degraded'),
                    'poor_count': sum(1 for c in connections['connections'] if c['quality'] == 'poor'),
                    'avg_error': round(sum(errors) / len(errors), 6),
                    'min_error': round(min(errors), 6),
                    'max_error': round(max(errors), 6),
                }
                
        except Exception as e:
            connections['error'] = str(e)
        
        return connections
    
    def _collect_network_info_v3(self) -> Dict:
        """[v3.0] Informations réseau."""
        network = {
            'hostname': self._get_hostname(),
            'local_ip': None,
            'proxy': {'http': None, 'https': None},
        }
        
        # IP locale
        try:
            import socket
            s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
            s.connect(("8.8.8.8", 80))
            network['local_ip'] = s.getsockname()[0]
            s.close()
        except:
            pass
        
        # Proxy
        network['proxy']['http'] = os.environ.get('HTTP_PROXY') or os.environ.get('http_proxy')
        network['proxy']['https'] = os.environ.get('HTTPS_PROXY') or os.environ.get('https_proxy')
        
        return network
    
    def _collect_process_info_v3(self) -> Dict:
        """[v3.0] Informations du processus Python."""
        proc = {
            'pid': os.getpid(),
            'memory_usage_mb': None,
            'memory_percent': None,
            'cpu_percent': None,
            'threads': None,
        }
        
        try:
            import psutil
            p = psutil.Process(os.getpid())
            mem = p.memory_info()
            proc['memory_usage_mb'] = round(mem.rss / (1024 * 1024), 2)
            proc['memory_percent'] = round(p.memory_percent(), 2)
            proc['cpu_percent'] = p.cpu_percent(interval=0.1)
            proc['threads'] = p.num_threads()
        except ImportError:
            pass
        except Exception:
            pass
        
        return proc
    
    def _collect_dependencies_versions(self) -> Dict:
        # [v2.7.1 FIX] Initialize the result dict; it was used below (deps[...]) but
        # never created, raising NameError when collecting dependency versions.
        deps = {}

        # Core Qiskit
        packages = [
            ('qiskit', 'qiskit'),
            ('qiskit_ibm_runtime', 'qiskit-ibm-runtime'),
            ('qiskit_aer', 'qiskit-aer'),
            ('qiskit_ibm_provider', 'qiskit-ibm-provider'),
            
            # IBM Addons
            ('mthree', 'mthree'),
            ('qiskit_addon_aqc_tensor', 'qiskit-addon-aqc-tensor'),
            ('qiskit_addon_mpf', 'qiskit-addon-mpf'),
            ('qiskit_addon_obp', 'qiskit-addon-obp'),
            ('qiskit_addon_sqd', 'qiskit-addon-sqd'),
            ('qiskit_addon_cutting', 'qiskit-addon-cutting'),
            
            # Scientific
            ('numpy', 'numpy'),
            ('scipy', 'scipy'),
            ('pandas', 'pandas'),
            
            # Visualization
            ('matplotlib', 'matplotlib'),
            ('plotly', 'plotly'),
            ('PIL', 'pillow'),
            
            # Utils
            ('networkx', 'networkx'),
            ('yaml', 'pyyaml'),
            ('dotenv', 'python-dotenv'),
            ('jinja2', 'jinja2'),
            ('pylatexenc', 'pylatexenc'),
        ]
        
        for module_name, display_name in packages:
            try:
                module = __import__(module_name.split('.')[0])
                version = getattr(module, '__version__', None)
                if version:
                    deps[display_name] = version
            except ImportError:
                pass
            except Exception:
                pass
        
        # WeasyPrint (détection spéciale - peut crasher sur Windows)
        try:
            from importlib.util import find_spec
            if find_spec('weasyprint'):
                import weasyprint
                deps['weasyprint'] = getattr(weasyprint, '__version__', 'installed')
        except:
            pass
        
        return deps
    
    def _collect_system_info(self) -> Dict:
        """[v2.6.0] Collecte les informations système."""
        import platform
        
        info = {
            'os': platform.system(),
            'os_version': platform.version(),
            'os_release': platform.release(),
            'architecture': platform.machine(),
            'processor': platform.processor(),
            'python_version': platform.python_version(),
            'python_implementation': platform.python_implementation(),
            'hostname': platform.node(),
        }
        
        # Infos plus détaillées selon l'OS
        if info['os'] == 'Windows':
            info['os_full'] = f"Windows {platform.win32_ver()[0]}"
        elif info['os'] == 'Linux':
            try:
                # Essayer de lire /etc/os-release
                with open('/etc/os-release', 'r', encoding='utf-8') as f:  # [v2.7.1 FIX] encoding
                    lines = f.readlines()
                    for line in lines:
                        if line.startswith('PRETTY_NAME='):
                            info['os_full'] = line.split('=')[1].strip().strip('"')
                            break
            except:
                info['os_full'] = f"Linux {info['os_release']}"
        elif info['os'] == 'Darwin':
            info['os_full'] = f"macOS {platform.mac_ver()[0]}"
        else:
            info['os_full'] = f"{info['os']} {info['os_release']}"
        
        return info
    
    def _collect_framework_config(self) -> Dict:
        """Collecte la configuration COMPLÈTE du framework."""
        config = {
            'project': None,
            'backend_name': None,
            'mode': None,
            'connected': False,
            
            # Sécurité
            'security': {
                'private': False,
                'redact_logs': False,
                'auto_delete_job': False,
                'production_mode': False,
                'auto_confirm': True,
            },
            
            # Budget
            'budget': {
                'configured': False,
                'monthly_minutes': None,
                'used_minutes': None,
                'remaining_minutes': None,
                'alert_threshold_pct': None,
            },
            
            # Qualité
            'quality_thresholds': {},
            
            # Directories
            'directories': {
                'run_dir': None,
                'base_dir': None,
            },
        }
        
        if not self.framework:
            return config
        
        fw = self.framework
        
        try:
            config['project'] = getattr(fw, 'project', None)
            config['backend_name'] = getattr(fw, 'backend_name', None)
            config['mode'] = str(getattr(fw, '_mode', None))
            config['connected'] = getattr(fw, '_connected', False)
            
            # Sécurité
            config['security']['private'] = getattr(fw, 'private', False)
            config['security']['redact_logs'] = getattr(fw, 'redact_logs', False)
            config['security']['auto_delete_job'] = getattr(fw, 'auto_delete_job', False)
            config['security']['production_mode'] = getattr(fw, 'production_mode', False)
            config['security']['auto_confirm'] = getattr(fw, 'auto_confirm', True)
            
            # Budget
            if hasattr(fw, 'budget') and fw.budget:
                budget = fw.budget
                config['budget']['configured'] = True
                config['budget']['monthly_minutes'] = getattr(budget, 'monthly_budget_minutes', None)
                if hasattr(budget, 'get_remaining'):
                    config['budget']['remaining_minutes'] = budget.get_remaining()
                if hasattr(budget, 'get_usage'):
                    usage = budget.get_usage()
                    config['budget']['used_minutes'] = usage.get('current_month_minutes')
                config['budget']['alert_threshold_pct'] = getattr(budget, 'alert_threshold_pct', None)
            
            # Qualité
            if hasattr(fw, 'quality_thresholds') and fw.quality_thresholds:
                qt = fw.quality_thresholds
                config['quality_thresholds'] = {
                    'min_entropy': qt.min_entropy,
                    'max_top_prob': qt.max_top_prob,
                    'min_fidelity': qt.min_fidelity,
                    'min_uniformity': qt.min_uniformity,
                }
            
            # Directories
            if hasattr(fw, 'dir_manager') and fw.dir_manager:
                dm = fw.dir_manager
                config['directories']['run_dir'] = str(getattr(dm, 'run_dir', None))
                config['directories']['base_dir'] = str(getattr(dm, 'base_dir', None))
                
        except Exception as e:
            config['error'] = str(e)
        
        return config
    
    def _collect_layout_mapping(self, transpiled_circuits) -> List[Dict]:
        """Collecte le mapping des qubits virtuels → physiques."""
        if not transpiled_circuits:
            return []
        
        mappings = []
        
        for i, circuit in enumerate(transpiled_circuits):
            mapping = {
                'circuit_index': i,
                'initial_layout': None,
                'final_layout': None,
                'virtual_to_physical': {},
            }
            
            try:
                if hasattr(circuit, '_layout') and circuit._layout:
                    layout = circuit._layout
                    
                    if hasattr(layout, 'initial_layout') and layout.initial_layout:
                        mapping['initial_layout'] = str(layout.initial_layout)
                        
                        # Extraire le mapping v→p
                        try:
                            for virt_qubit, phys_qubit in layout.initial_layout.get_virtual_bits().items():
                                if hasattr(virt_qubit, '_index'):
                                    mapping['virtual_to_physical'][virt_qubit._index] = phys_qubit
                        except:
                            pass
                    
                    if hasattr(layout, 'final_index_layout'):
                        mapping['final_layout'] = list(layout.final_index_layout())
                        
            except:
                pass
            
            mappings.append(mapping)
        
        return mappings
    
    def _collect_sampler_options(self) -> Dict:
        """Collecte les options du Sampler IBM."""
        options = {
            'available': False,
            'resilience_level': None,
            'optimization_level': None,
            'dynamical_decoupling': {},
            'twirling': {},
            'execution': {},
        }
        
        if not self.framework:
            return options
        
        try:
            if hasattr(self.framework, 'error_mitigation') and self.framework.error_mitigation:
                em = self.framework.error_mitigation
                options['available'] = True
                
                if hasattr(em, 'config'):
                    cfg = em.config
                    options['resilience_level'] = getattr(cfg, 'resilience_level', None)
                    options['optimization_level'] = getattr(cfg, 'optimization_level', None)
                    
                    if hasattr(cfg, 'dd_enabled'):
                        options['dynamical_decoupling'] = {
                            'enabled': cfg.dd_enabled,
                            'sequence': getattr(cfg, 'dd_sequence', None),
                        }
                    
                    if hasattr(cfg, 'twirling_enabled'):
                        options['twirling'] = {
                            'enabled': cfg.twirling_enabled,
                            'strategy': getattr(cfg, 'twirling_strategy', None),
                            'num_randomizations': getattr(cfg, 'twirling_num_randomizations', None),
                        }
        except:
            pass
        
        return options
    
    def _collect_job_metadata(self, run_context: Dict) -> Dict:
        """Collecte les métadonnées du job IBM."""
        metadata = {
            'job_id': run_context.get('job_id') if run_context else None,
            'creation_date': None,
            'tags': [],
            'session_id': None,
            'backend_options': {},
            'header': {},
        }
        
        # Les métadonnées complètes seraient récupérées du job IBM si disponible
        # Pour l'instant on stocke ce qui est dans run_context
        if run_context:
            metadata['submitted_at'] = run_context.get('submitted_at')
            metadata['completed_at'] = run_context.get('completed_at')
            metadata['status'] = run_context.get('status')
        
        return metadata
    
    def _collect_raw_memory(self, results: List[Dict]) -> List[Dict]:
        """
        Collecte la mémoire brute (shots individuels).
        
        IMPORTANT: Cette section peut être très volumineuse!
        Pour 4096 shots × 50 qubits = ~200KB par circuit
        """
        if not results:
            return []
        
        raw_memory = []
        
        for i, r in enumerate(results):
            if not isinstance(r, dict):
                continue
            
            memory_data = {
                'circuit_index': i,
                'has_memory': False,
                'memory': None,
                'memory_size': 0,
            }
            
            # La mémoire brute est parfois disponible dans les résultats
            if 'memory' in r and r['memory']:
                memory_data['has_memory'] = True
                memory_data['memory'] = r['memory']
                memory_data['memory_size'] = len(r['memory'])
            
            raw_memory.append(memory_data)
        
        return raw_memory
    
    def _collect_session_logs(self) -> List[Dict]:
        """Collecte les logs de la session."""
        logs = []
        
        if not self.framework:
            return logs
        
        try:
            if hasattr(self.framework, 'logger') and self.framework.logger:
                logger = self.framework.logger
                
                # Récupérer les derniers logs si disponibles
                if hasattr(logger, '_log_buffer'):
                    for entry in logger._log_buffer[-100:]:  # Max 100 derniers
                        logs.append({
                            'timestamp': entry.get('timestamp'),
                            'level': entry.get('level'),
                            'section': entry.get('section'),
                            'message': entry.get('message'),
                        })
        except:
            pass
        
        return logs
    
    def _collect_warnings(self) -> List[Dict]:
        """Collecte les warnings rencontrés."""
        warnings_list = []
        
        if not self.framework:
            return warnings_list
        
        try:
            if hasattr(self.framework, '_warnings') and self.framework._warnings:
                for w in self.framework._warnings[-50:]:  # Max 50
                    warnings_list.append({
                        'timestamp': w.get('timestamp'),
                        'type': w.get('type'),
                        'message': w.get('message'),
                        'context': w.get('context'),
                    })
        except:
            pass
        
        return warnings_list
    
    def _collect_estimates(self, circuits, run_context: Dict) -> Dict:
        """Collecte les estimations pré-exécution."""
        estimates = {
            'estimated_qpu_time_s': None,
            'estimated_queue_time_s': None,
            'estimated_cost_minutes': None,
            'circuit_complexity_scores': [],
        }
        
        if not self.framework or not circuits:
            return estimates
        
        try:
            # Estimations de coût si disponibles
            if hasattr(self.framework, 'circuit_cost_estimator') and self.framework.circuit_cost_estimator:
                est = self.framework.circuit_cost_estimator
                shots = run_context.get('shots', 4096) if run_context else 4096
                
                if hasattr(est, 'estimate'):
                    result = est.estimate(circuits, shots)
                    estimates['estimated_qpu_time_s'] = result.get('estimated_qpu_time_s')
                    estimates['estimated_cost_minutes'] = result.get('estimated_minutes')
            
            # Scores de complexité par circuit
            if hasattr(self.framework, 'circuit_profiler') and self.framework.circuit_profiler:
                profiler = self.framework.circuit_profiler
                for i, c in enumerate(circuits[:10]):  # Max 10
                    try:
                        profile = profiler.profile(c)
                        estimates['circuit_complexity_scores'].append({
                            'index': i,
                            'complexity_score': profile.get('complexity_score'),
                            'depth': profile.get('depth'),
                            'gate_count': profile.get('gate_count'),
                        })
                    except:
                        pass
        except:
            pass
        
        return estimates
    
    def _get_hostname(self) -> str:
        """Récupère le nom de la machine."""
        try:
            import socket
            return socket.gethostname()
        except:
            return 'unknown'
    
    def _collect_backend_info(self) -> Dict:
        """Collecte les informations du backend."""
        info = {
            'name': None,
            'version': None,
            'num_qubits': None,
            'basis_gates': [],
            'max_circuits': None,
            'max_shots': None,
            'coupling_map_size': None,
            'processor_type': None,
            'online': None,
        }
        
        if not self.framework:
            return info
        
        backend = getattr(self.framework, 'backend', None)
        if not backend:
            info['name'] = getattr(self.framework, 'backend_name', 'N/A')
            return info
        
        try:
            info['name'] = getattr(backend, 'name', str(backend))
            info['version'] = getattr(backend, 'version', None)
            
            if hasattr(backend, 'target') and backend.target:
                target = backend.target
                info['num_qubits'] = target.num_qubits
                info['basis_gates'] = list(target.operation_names) if hasattr(target, 'operation_names') else []
                
                if hasattr(target, 'build_coupling_map'):
                    cm = target.build_coupling_map()
                    if cm:
                        info['coupling_map_size'] = len(cm.get_edges())
            
            if hasattr(backend, 'max_circuits'):
                info['max_circuits'] = backend.max_circuits
            
            if hasattr(backend, 'configuration'):
                config = backend.configuration()
                if config:
                    info['max_shots'] = getattr(config, 'max_shots', None)
                    info['processor_type'] = getattr(config, 'processor_type', None)
            
            if hasattr(backend, 'status'):
                try:
                    status = backend.status()
                    info['online'] = getattr(status, 'operational', None)
                except:
                    pass
                    
        except Exception as e:
            info['error'] = str(e)
        
        return info
    
    def _collect_full_calibration(self) -> Dict:
        """Collecte la calibration COMPLÈTE du QPU."""
        calib = {
            'available': False,
            'timestamp': None,
            'num_qubits': 0,
            'qubits': [],
            'gates_1q': [],
            'gates_2q': [],
            'coupling_map': [],
            'summary': {},
        }
        
        if not self.framework:
            return calib
        
        backend = getattr(self.framework, 'backend', None)
        if not backend:
            return calib
        
        try:
            calib['available'] = True
            
            # Via backend.target (Qiskit moderne)
            if hasattr(backend, 'target') and backend.target:
                target = backend.target
                calib['num_qubits'] = target.num_qubits
                
                t1_values, t2_values, readout_errors = [], [], []
                
                # Collecter TOUS les qubits
                for qubit in range(target.num_qubits):
                    q_data = {
                        'index': qubit,
                        't1_us': None,
                        't2_us': None,
                        'frequency_ghz': None,
                        'anharmonicity_ghz': None,
                        'readout_error_pct': None,
                        'readout_length_ns': None,
                        'prob_meas0_prep1': None,
                        'prob_meas1_prep0': None,
                    }
                    
                    try:
                        if hasattr(target, 'qubit_properties') and target.qubit_properties:
                            props = target.qubit_properties[qubit]
                            if props:
                                if hasattr(props, 't1') and props.t1:
                                    q_data['t1_us'] = round(props.t1 * 1e6, 2)
                                    t1_values.append(props.t1 * 1e6)
                                if hasattr(props, 't2') and props.t2:
                                    q_data['t2_us'] = round(props.t2 * 1e6, 2)
                                    t2_values.append(props.t2 * 1e6)
                                if hasattr(props, 'frequency') and props.frequency:
                                    q_data['frequency_ghz'] = round(props.frequency / 1e9, 4)
                    except:
                        pass
                    
                    # Erreur de mesure
                    try:
                        measure_props = target.get('measure', (qubit,))
                        if measure_props:
                            if hasattr(measure_props, 'error') and measure_props.error:
                                q_data['readout_error_pct'] = round(measure_props.error * 100, 4)
                                readout_errors.append(measure_props.error * 100)
                            if hasattr(measure_props, 'duration') and measure_props.duration:
                                q_data['readout_length_ns'] = round(measure_props.duration * 1e9, 1)
                    except:
                        pass
                    
                    calib['qubits'].append(q_data)
                
                # Gates 1-qubit
                for gate_name in ['sx', 'x', 'rz', 'id']:
                    if gate_name in target.operation_names:
                        for qargs in target.qargs_for_operation_name(gate_name):
                            if len(qargs) == 1:
                                try:
                                    gate_props = target.get(gate_name, qargs)
                                    if gate_props:
                                        calib['gates_1q'].append({
                                            'gate': gate_name,
                                            'qubit': qargs[0],
                                            'error_pct': round(gate_props.error * 100, 4) if gate_props.error else None,
                                            'duration_ns': round(gate_props.duration * 1e9, 1) if gate_props.duration else None,
                                        })
                                except:
                                    pass
                
                # Gates 2-qubit
                cx_errors = []
                for gate_name in ['cx', 'ecr', 'cz', 'rzz']:
                    if gate_name in target.operation_names:
                        for qargs in target.qargs_for_operation_name(gate_name):
                            if len(qargs) == 2:
                                try:
                                    gate_props = target.get(gate_name, qargs)
                                    if gate_props:
                                        error_pct = round(gate_props.error * 100, 4) if gate_props.error else None
                                        if error_pct:
                                            cx_errors.append(error_pct)
                                        calib['gates_2q'].append({
                                            'gate': gate_name,
                                            'qubits': list(qargs),
                                            'error_pct': error_pct,
                                            'duration_ns': round(gate_props.duration * 1e9, 1) if gate_props.duration else None,
                                        })
                                except:
                                    pass
                
                # Coupling map
                if hasattr(target, 'build_coupling_map'):
                    cm = target.build_coupling_map()
                    if cm:
                        calib['coupling_map'] = [list(edge) for edge in cm.get_edges()]
                
                # Summary
                calib['summary'] = {
                    'total_qubits': target.num_qubits,
                    'avg_t1_us': round(sum(t1_values) / len(t1_values), 2) if t1_values else None,
                    'avg_t2_us': round(sum(t2_values) / len(t2_values), 2) if t2_values else None,
                    'min_t1_us': round(min(t1_values), 2) if t1_values else None,
                    'max_t1_us': round(max(t1_values), 2) if t1_values else None,
                    'avg_readout_error_pct': round(sum(readout_errors) / len(readout_errors), 4) if readout_errors else None,
                    'total_1q_gates': len(calib['gates_1q']),
                    'total_2q_gates': len(calib['gates_2q']),
                    'avg_2q_error_pct': round(sum(cx_errors) / len(cx_errors), 4) if cx_errors else None,
                    'min_2q_error_pct': round(min(cx_errors), 4) if cx_errors else None,
                    'max_2q_error_pct': round(max(cx_errors), 4) if cx_errors else None,
                    'coupling_map_edges': len(calib['coupling_map']),
                }
                
        except Exception as e:
            calib['error'] = str(e)
        
        return calib
    
    def _collect_circuits_info(self, circuits, prefix: str = '') -> List[Dict]:
        """Collecte les informations des circuits.
        
        [v2.7.0 FIX] Skip QASM et iteration sur circuit.data pour circuits >40Q.
        """
        if not circuits:
            return []
        
        MAX_QUBITS_FOR_QASM = 40
        circuits_info = []
        
        for i, circuit in enumerate(circuits):
            try:
                n_qubits = circuit.num_qubits
                ops = dict(circuit.count_ops())
                
                c_info = {
                    'index': i,
                    'name': getattr(circuit, 'name', f'{prefix}_{i}'),
                    'num_qubits': n_qubits,
                    'num_clbits': circuit.num_clbits,
                    'depth': circuit.depth(),
                    'size': circuit.size(),
                    'width': circuit.width(),
                    'num_parameters': circuit.num_parameters,
                    'global_phase': str(circuit.global_phase),
                    
                    # Analyse des gates (rapide via count_ops)
                    'gate_counts': ops,
                    'num_1q_gates': sum(v for k, v in ops.items() 
                                       if k in ['h', 'x', 'y', 'z', 'rz', 'rx', 'ry', 's', 't', 
                                                'sdg', 'tdg', 'sx', 'sxdg', 'u1', 'u2', 'u3', 'id']),
                    'num_2q_gates': sum(v for k, v in ops.items() 
                                       if k in ['cx', 'cz', 'ecr', 'swap', 'rzz', 'rxx', 'ryy']),
                    'num_3q_plus_gates': sum(v for k, v in ops.items() 
                                            if k in ['ccx', 'cswap', 'ccz']),
                    
                    # Qubits utilisés — skip iteration sur circuit.data pour gros circuits
                    'qubits_used': list(range(n_qubits)) if n_qubits > MAX_QUBITS_FOR_QASM else sorted(list(set(
                        q._index if hasattr(q, '_index') else j 
                        for inst in circuit.data 
                        for j, q in enumerate(inst.qubits)
                    ))),
                    
                    # Layout si disponible
                    'layout': None,
                    
                    # QASM (limité à 50KB par circuit)
                    'qasm': None,
                }
                
                # Layout après transpilation
                if hasattr(circuit, '_layout') and circuit._layout:
                    try:
                        layout = circuit._layout
                        if hasattr(layout, 'final_index_layout'):
                            c_info['layout'] = {
                                'final_layout': list(layout.final_index_layout()),
                            }
                        if hasattr(layout, 'initial_layout'):
                            c_info['layout'] = c_info.get('layout', {})
                            c_info['layout']['initial_layout'] = str(layout.initial_layout)
                    except:
                        pass
                
                # QASM (limité pour éviter fichiers trop gros)
                # [v2.7.0] Skip pour gros circuits (qasm2_dumps trop lent)
                if n_qubits > MAX_QUBITS_FOR_QASM:
                    c_info['qasm'] = f"// SKIPPED: {n_qubits}Q > {MAX_QUBITS_FOR_QASM}Q threshold"
                else:
                    try:
                        from qiskit.qasm2 import dumps as qasm2_dumps
                        qasm_str = qasm2_dumps(circuit)
                        if len(qasm_str) < 50000:  # Max 50KB par circuit
                            c_info['qasm'] = qasm_str
                        else:
                            c_info['qasm'] = f"[TRUNCATED - {len(qasm_str)} bytes]"
                    except:
                        try:
                            qasm_str = circuit.qasm()
                            if len(qasm_str) < 50000:
                                c_info['qasm'] = qasm_str
                        except:
                            pass
                
                circuits_info.append(c_info)
                
            except Exception as e:
                circuits_info.append({
                    'index': i,
                    'error': str(e)
                })
        
        return circuits_info
    
    def _collect_transpilation_config(self, run_context: Dict) -> Dict:
        """Collecte la configuration de transpilation."""
        config = {
            'optimization_level': run_context.get('optimization_level', 3) if run_context else 3,
            'layout_strategy': run_context.get('layout_strategy', 'none') if run_context else 'none',
            'routing_method': None,
            'translation_method': None,
            'scheduling_method': None,
            'approximation_degree': None,
            'seed_transpiler': None,
        }
        
        if self.framework:
            # Récupérer depuis le framework si disponible
            if hasattr(self.framework, 'transpile_options'):
                opts = self.framework.transpile_options
                if isinstance(opts, dict):
                    config.update({
                        'routing_method': opts.get('routing_method'),
                        'translation_method': opts.get('translation_method'),
                        'scheduling_method': opts.get('scheduling_method'),
                        'approximation_degree': opts.get('approximation_degree'),
                        'seed_transpiler': opts.get('seed_transpiler'),
                    })
        
        return config
    
    def _collect_mitigation_config(self) -> Dict:
        """Collecte la configuration de mitigation d'erreurs."""
        config = {
            'enabled': False,
            'twirling': {'enabled': False},
            'dynamical_decoupling': {'enabled': False},
            'zne': {'enabled': False},
            'measurement_error_mitigation': {'enabled': False},
        }
        
        if not self.framework:
            return config
        
        if hasattr(self.framework, 'error_mitigation') and self.framework.error_mitigation:
            em = self.framework.error_mitigation
            config['enabled'] = True
            
            try:
                summary = em.get_summary() if hasattr(em, 'get_summary') else {}
                
                if 'twirling' in summary:
                    config['twirling'] = {
                        'enabled': summary['twirling'].get('enabled', False),
                        'strategy': summary['twirling'].get('strategy'),
                        'num_randomizations': summary['twirling'].get('num_randomizations'),
                    }
                
                if 'dynamical_decoupling' in summary:
                    config['dynamical_decoupling'] = {
                        'enabled': summary['dynamical_decoupling'].get('enabled', False),
                        'sequence': summary['dynamical_decoupling'].get('sequence'),
                    }

            except Exception as e:
                # [v2.7.1 FIX] log instead of silently swallowing the mitigation-config
                # read failure (control flow unchanged: config keeps its defaults)
                self._log(f"Mitigation config collection failed: {e}", LogLevel.DEBUG)

        return config
    
    def _collect_execution_info(self, run_context: Dict) -> Dict:
        """Collecte les informations d'exécution."""
        ctx = run_context or {}
        
        return {
            'job_id': ctx.get('job_id'),
            'shots': ctx.get('shots', 0),
            'circuits_count': ctx.get('circuits_count', 0),
            
            # Timing détaillé
            'timing': {
                'total_time_s': ctx.get('total_time_s', 0),
                'queue_time_s': ctx.get('queue_time_s', 0),
                'execution_time_s': ctx.get('execution_time_s', 0),
                'qpu_time_s': ctx.get('qpu_time_s', 0),
                'transpile_time_s': ctx.get('transpile_time_s', 0),
            },
            
            # Timestamps
            'submitted_at': ctx.get('submitted_at'),
            'completed_at': ctx.get('completed_at'),
            
            # Status
            'status': ctx.get('status', 'UNKNOWN'),
        }
    
    def _collect_results(self, results: List[Dict]) -> List[Dict]:
        """
        Collecte les résultats COMPLETS.
        
        [v2.7.0] Supporte deux formats:
        - Sampler: counts={'01001': 4521, ...}
        - Estimator: expectation_value=0.342, std_error=0.005
        
        Préserve TOUS les champs additionnels du résultat (metadata, observable, etc.)
        """
        if not results:
            return []
        
        collected = []
        
        for i, r in enumerate(results):
            if not isinstance(r, dict):
                collected.append({'index': i, 'error': 'Invalid result format'})
                continue
            
            counts = r.get('counts', {})
            total_shots = sum(counts.values()) if counts else 0
            
            # Détecter le type de résultat
            is_estimator = 'expectation_value' in r
            
            result_data = {
                'index': i,
                'shots': r.get('shots', total_shots),
                'result_type': 'estimator' if is_estimator else 'sampler',
            }
            
            if is_estimator:
                # === ESTIMATOR: expectation values ===
                result_data['expectation_value'] = r.get('expectation_value')
                result_data['std_error'] = r.get('std_error', 0.0)
                result_data['observable'] = r.get('observable', '')
                result_data['resilience_level'] = r.get('resilience_level')
                # Counts vides mais présents pour compatibilité
                result_data['counts'] = counts
                result_data['num_outcomes'] = 0
                result_data['probabilities'] = {}
                result_data['top_10'] = []
            else:
                # === SAMPLER: counts ===
                result_data['num_outcomes'] = len(counts)
                result_data['counts'] = counts
                result_data['probabilities'] = {k: v / total_shots for k, v in counts.items()} if total_shots > 0 else {}
                result_data['top_10'] = sorted(
                    [{'bitstring': k, 'count': v, 'probability': v / total_shots if total_shots > 0 else 0}
                     for k, v in counts.items()],
                    key=lambda x: x['count'],
                    reverse=True
                )[:10]
            
            # Métadonnées du circuit si présentes
            result_data['circuit_depth'] = r.get('depth')
            result_data['circuit_name'] = r.get('name')
            result_data['fidelity'] = r.get('fidelity')
            result_data['memory'] = r.get('memory')
            
            # [v2.7.0] Préserver TOUS les champs additionnels (metadata, observable, etc.)
            for key, value in r.items():
                if key not in result_data and key not in ('counts',):
                    result_data[key] = value
            
            collected.append(result_data)
        
        return collected
    
    def _compute_statistics(self, results: List[Dict]) -> Dict:
        """
        Calcule les statistiques avancées.
        
        [v2.7.0] Supporte Sampler (counts) et Estimator (expectation values).
        """
        stats = {
            'global': {},
            'per_circuit': [],
        }
        
        if not results:
            return stats
        
        # [v2.7.0] Détecter le type de résultat
        is_estimator = any(r.get('expectation_value') is not None for r in results if isinstance(r, dict))
        
        if is_estimator:
            # === ESTIMATOR STATISTICS ===
            evs_values = []
            std_values = []
            
            for i, r in enumerate(results):
                if not isinstance(r, dict):
                    continue
                
                evs = r.get('expectation_value')
                std = r.get('std_error', 0.0)

                if evs is not None:
                    # [v2.7.1 FIX R141] expectation_value peut être une LISTE (PUB
                    # multi-observables). On APLATIT en échantillons scalaires pour que
                    # np.array/np.mean ne plantent pas (numpy 2.x: shape inhomogène) et
                    # qu'aucune moyenne ne soit silencieusement écrasée.
                    if isinstance(evs, (list, tuple)):
                        evs_values.extend(float(x) for x in evs)
                    else:
                        evs_values.append(float(evs))
                    if isinstance(std, (list, tuple)):
                        std_values.extend((float(x) if x else 0.0) for x in std)
                    else:
                        std_values.append(float(std) if std else 0.0)

                    stats['per_circuit'].append({
                        'index': i,
                        'result_type': 'estimator',
                        'expectation_value': evs,
                        'std_error': std,
                        'observable': r.get('observable', ''),
                    })
            
            if evs_values:
                # numpy already imported as np at module level
                evs_arr = np.array(evs_values)
                stats['global'] = {
                    'result_type': 'estimator',
                    'total_pubs': len(results),
                    'n_valid': len(evs_values),
                    'mean_expectation': round(float(np.mean(evs_arr)), 6),
                    'std_expectation': round(float(np.std(evs_arr)), 6),
                    'min_expectation': round(float(np.min(evs_arr)), 6),
                    'max_expectation': round(float(np.max(evs_arr)), 6),
                    'median_expectation': round(float(np.median(evs_arr)), 6),
                    'mean_std_error': round(float(np.mean(std_values)), 6),
                }
            
            return stats
        
        # === SAMPLER STATISTICS (original) ===
        entropies = []
        uniformities = []
        top_probs = []
        
        for i, r in enumerate(results):
            if not isinstance(r, dict):
                continue
            
            counts = r.get('counts', {})
            if not counts:
                continue
            
            total = sum(counts.values())
            n_outcomes = len(counts)
            # [v2.7.1 FIX] strip register-separator spaces so multi-register bitstrings
            # (e.g. '01 10') don't overcount qubits and inflate max_possible_outcomes
            n_qubits = len(next(iter(counts.keys())).replace(' ', '')) if counts else 0
            max_possible_outcomes = 2 ** n_qubits if n_qubits > 0 else 1
            
            # Entropie de Shannon
            entropy = 0
            for count in counts.values():
                if count > 0:
                    p = count / total
                    entropy -= p * math.log2(p)
            
            max_entropy = math.log2(n_outcomes) if n_outcomes > 1 else 1
            uniformity = (entropy / max_entropy * 100) if max_entropy > 0 else 0
            
            # Distribution
            sorted_counts = sorted(counts.items(), key=lambda x: x[1], reverse=True)
            top_prob = (sorted_counts[0][1] / total * 100) if sorted_counts else 0
            
            circuit_stats = {
                'index': i,
                'result_type': 'sampler',
                'shots': total,
                'unique_outcomes': n_outcomes,
                'max_possible_outcomes': max_possible_outcomes,
                'outcome_ratio': n_outcomes / max_possible_outcomes if max_possible_outcomes > 0 else 0,
                'entropy_bits': round(entropy, 4),
                'max_entropy_bits': round(max_entropy, 4),
                'uniformity_pct': round(uniformity, 2),
                'top_bitstring': sorted_counts[0][0] if sorted_counts else None,
                'top_probability_pct': round(top_prob, 2),
                'bottom_probability_pct': round(sorted_counts[-1][1] / total * 100, 4) if sorted_counts else 0,
                'mean_count': round(total / n_outcomes, 2) if n_outcomes > 0 else 0,
                'std_count': round(
                    math.sqrt(sum((c - total/n_outcomes)**2 for c in counts.values()) / n_outcomes), 2
                ) if n_outcomes > 1 else 0,
            }
            
            stats['per_circuit'].append(circuit_stats)
            entropies.append(entropy)
            uniformities.append(uniformity)
            top_probs.append(top_prob)
        
        if entropies:
            stats['global'] = {
                'result_type': 'sampler',
                'total_circuits': len(results),
                'total_shots': sum(sum(r.get('counts', {}).values()) for r in results if isinstance(r, dict)),
                'avg_entropy_bits': round(sum(entropies) / len(entropies), 4),
                'min_entropy_bits': round(min(entropies), 4),
                'max_entropy_bits': round(max(entropies), 4),
                'avg_uniformity_pct': round(sum(uniformities) / len(uniformities), 2),
                'avg_top_probability_pct': round(sum(top_probs) / len(top_probs), 2),
            }
        
        return stats
    
    def _collect_error_info(self, error: Exception) -> Dict:
        """Collecte les informations d'erreur."""
        return {
            'type': type(error).__name__,
            'message': str(error),
            'traceback': traceback.format_exc(),
            'args': [str(arg) for arg in error.args] if hasattr(error, 'args') else [],
        }


# =============================================================================
# v2.5.17 - AUTO REPORT GENERATOR (ULTRA-COMPLET)
# =============================================================================

class AutoReportGenerator:
    """
    [v2.5.21] Générateur de rapports HTML ULTRA-COMPLETS automatique.
    
    Génère automatiquement après chaque run_on_qpu() un rapport contenant:
    - Résumé exécutif avec statut SUCCESS/ERROR
    - Configuration complète (shots, circuits, backend, options)
    - Calibration du backend (T1, T2, erreurs, qubits utilisés)
    - Résultats détaillés par circuit avec distributions
    - Statistiques avancées (entropie, uniformité, top bitstrings)
    - Graphiques interactifs (Chart.js)
    - Timeline d'exécution (QUEUED → RUNNING → DONE)
    - Erreurs rencontrées avec diagnostic
    - Export JSON des données brutes
    - [v2.5.21] Visualisations Qiskit natives (histogrammes, gate_map, error_map)
    
    ACTIVATION AUTOMATIQUE:
        Par défaut, run_on_qpu() génère le rapport. Pour désactiver:
        results = fw.run_on_qpu(circuits, generate_report=False)
    
    Usage manuel:
        report_path = fw.report_generator.generate(results, run_context)
    """
    
    def __init__(self, framework: 'QMCFramework' = None, 
                 output_dir: str = None,
                 logger: Logger = None):
        """
        Args:
            framework: Instance QMCFramework pour métadonnées et calibration
            output_dir: Répertoire de sortie (optionnel, défaut: répertoire du framework)
            logger: Logger pour les messages
        """
        self.framework = framework
        self.output_dir = Path(output_dir) if output_dir else None
        self.logger = logger or (framework.logger if framework else None)
        self._last_report_path = None
        
        # v2.5.21: Intégration QiskitVisualizationWrapper
        self._qiskit_viz = None  # Initialisé paresseusement
    
    def _get_qiskit_viz(self) -> QiskitVisualizationWrapper:
        """Retourne le wrapper de visualisation Qiskit (lazy init)."""
        if self._qiskit_viz is None:
            out_dir = self._get_output_dir()
            self._qiskit_viz = QiskitVisualizationWrapper(output_dir=out_dir)
        return self._qiskit_viz
    
    def _log(self, msg: str, level: LogLevel = LogLevel.INFO):
        if self.logger:
            self.logger.log(msg, level, section='REPORT')
        else:
            print(f"[REPORT] {msg}")
    
    # v2.5.21: Nouvelle méthode pour générer des visualisations Qiskit
    def generate_qiskit_visualizations(self, results: List[Dict] = None,
                                        backend = None,
                                        output_dir: Path = None,
                                        run_context: Dict = None) -> Dict[str, Path]:
        """
        Génère des visualisations Qiskit pour le rapport (v2.5.21 + v2.6.0).
        
        [v2.6.0] Nouvelles visualisations:
        - Histogrammes interactifs Plotly
        - Timeline d'exécution du job
        - Export PDF du rapport
        
        Args:
            results: Résultats avec counts
            backend: Backend IBM pour gate_map/error_map
            output_dir: Répertoire de sortie
            run_context: [v2.6.0] Contexte d'exécution pour timeline
            
        Returns:
            Dict avec les paths des fichiers générés
        """
        out_dir = Path(output_dir) if output_dir else self._get_output_dir()
        out_dir.mkdir(parents=True, exist_ok=True)
        
        viz = QiskitVisualizationWrapper(output_dir=out_dir)
        generated = {}
        
        # Histogrammes des counts - [v2.5.21] Limiter à 10 circuits max pour performance
        if results:
            max_histograms = min(10, len(results))  # Max 10 histogrammes
            for i, result in enumerate(results[:max_histograms]):
                counts = result.get('counts', {})
                if counts:
                    try:
                        filename = f"histogram_circuit_{i}.png"
                        # v2.5.21: Ajouter info sur le filtrage dans le titre
                        n_states = len(counts)
                        total_shots = sum(counts.values())
                        title = f"Circuit {i} Results (Top 25/{n_states} states, {total_shots} shots)"
                        
                        fig = viz.plot_histogram(
                            counts, 
                            title=title,
                            filename=filename,
                            max_bars=25,        # Limiter à 25 barres
                            show_others=True    # Montrer "Others" pour le reste
                        )
                        if fig:
                            generated[f'histogram_{i}'] = out_dir / filename
                            try:
                                import matplotlib.pyplot as plt
                                plt.close(fig)
                            except:
                                pass
                    except Exception as e:
                        self._log(f"Histogram {i} generation failed: {e}", LogLevel.WARN)
            
            # [v2.6.0] Histogramme interactif Plotly pour le premier circuit
            if results and results[0].get('counts'):
                try:
                    all_counts = [r.get('counts', {}) for r in results[:5] if r.get('counts')]
                    if all_counts:
                        fig = viz.plot_histogram_interactive(
                            all_counts,
                            title="Interactive Results (First 5 Circuits)",
                            legend=[f"Circuit {i}" for i in range(len(all_counts))],
                            filename="histogram_interactive.html",
                            max_bars=50
                        )
                        if fig:
                            generated['histogram_interactive'] = out_dir / "histogram_interactive.html"
                except Exception as e:
                    self._log(f"Interactive histogram failed: {e}", LogLevel.WARN)
        
        # Gate map et error map du backend
        if backend:
            try:
                fig = viz.plot_gate_map(backend, filename="backend_gate_map.png")
                if fig:
                    generated['gate_map'] = out_dir / "backend_gate_map.png"
                    try:
                        import matplotlib.pyplot as plt
                        plt.close(fig)
                    except:
                        pass
            except Exception as e:
                self._log(f"Gate map generation failed: {e}", LogLevel.WARN)
            
            try:
                fig = viz.plot_error_map(backend, filename="backend_error_map.png")
                if fig:
                    generated['error_map'] = out_dir / "backend_error_map.png"
                    try:
                        import matplotlib.pyplot as plt
                        plt.close(fig)
                    except:
                        pass
            except Exception as e:
                self._log(f"Error map generation failed: {e}", LogLevel.WARN)
        
        # [v2.6.0] Timeline d'exécution du job
        if run_context:
            try:
                job_info = {
                    'queued_at': run_context.get('submitted_at'),
                    'running_at': run_context.get('running_at'),
                    'completed_at': run_context.get('completed_at'),
                }
                if job_info['queued_at'] and job_info['completed_at']:
                    fig = viz.plot_execution_timeline(job_info, filename="execution_timeline.html")
                    if fig:
                        generated['execution_timeline'] = out_dir / "execution_timeline.html"
            except Exception as e:
                self._log(f"Execution timeline failed: {e}", LogLevel.WARN)
        
        if generated:
            self._log(f"Generated {len(generated)} Qiskit visualizations")
        
        return generated
    
    def generate(self, 
                 results: List[Dict] = None,
                 run_context: Dict = None,
                 error: Exception = None,
                 title: str = None,
                 transpiled_circuits: List = None,
                 include_qiskit_viz: bool = True) -> Path:
        """
        Génère un rapport HTML ultra-complet.
        
        Args:
            results: Liste des résultats de run_on_qpu
            run_context: Contexte d'exécution (shots, backend, timing, etc.)
            error: Exception si erreur pendant l'exécution
            title: Titre personnalisé (optionnel)
            transpiled_circuits: [v2.5.18] Circuits transpilés pour visualisation
            include_qiskit_viz: [v2.5.21] Générer visualisations Qiskit (défaut: True)
            
        Returns:
            Path vers le fichier HTML généré
        """
        # [v2.5.18] Stocker les circuits pour _collect_all_data
        self._transpiled_circuits = transpiled_circuits
        
        # Collecter toutes les données
        data = self._collect_all_data(results, run_context, error)
        
        # [v2.5.21] Générer visualisations Qiskit si demandé
        if include_qiskit_viz and results:
            try:
                backend = getattr(self.framework, 'backend', None) if self.framework else None
                # [v2.6.0] Passer run_context pour timeline
                qiskit_viz_files = self.generate_qiskit_visualizations(
                    results, backend, run_context=run_context
                )
                data['qiskit_visualizations'] = {k: str(v) for k, v in qiskit_viz_files.items()}
            except Exception as e:
                self._log(f"Qiskit visualizations failed: {e}", LogLevel.WARN)
                data['qiskit_visualizations'] = {}
        
        # Générer le titre
        if not title:
            status = "ERROR" if error else "SUCCESS"
            project = data.get('project', 'QMC')
            title = f"QMC Report - {project} - {status}"
        
        # Générer le HTML (template professionnel v2.0)
        html = self._generate_professional_html(data, title)
        
        # Déterminer le répertoire de sortie
        output_dir = self._get_output_dir()
        output_dir.mkdir(parents=True, exist_ok=True)
        
        # Nom du fichier
        timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
        status_tag = "ERROR" if error else "OK"
        filename = f"report_{timestamp}_{status_tag}.html"
        filepath = output_dir / filename
        
        # Sauvegarder
        with open(filepath, 'w', encoding='utf-8') as f:
            f.write(html)
        
        self._last_report_path = filepath
        self._log(f"Report generated: {filepath}")
        
        # Sauvegarder aussi les données JSON (sans les images base64 pour éviter fichier énorme)
        json_path = output_dir / f"report_{timestamp}_{status_tag}_data.json"
        try:
            # Créer une copie sans les images base64
            data_for_json = {k: v for k, v in data.items() if k != 'circuit_images'}
            with open(json_path, 'w', encoding='utf-8') as f:
                json.dump(data_for_json, f, indent=2, default=str)
        except Exception as e:
            self._log(f"Warning: JSON export failed: {e}", LogLevel.WARN)
        
        # Nettoyer
        self._transpiled_circuits = None
        
        return filepath
    
    def _get_output_dir(self) -> Path:
        """Retourne le répertoire de sortie."""
        # Priorité: output_dir explicite > framework.dir_manager > défaut
        if self.output_dir:
            return self.output_dir
        if self.framework and hasattr(self.framework, 'dir_manager') and self.framework.dir_manager:
            return self.framework.dir_manager.run_dir
        return Path('qmc_reports')
    
    def _collect_backend_info(self) -> Dict:
        """[v2.6.0] Collecte les informations du backend pour le rapport HTML."""
        info = {
            'name': None,
            'version': None,
            'num_qubits': None,
            'basis_gates': [],
            'max_circuits': None,
            'max_shots': None,
            'coupling_map_size': None,
            'processor_type': None,
            'online': None,
        }
        
        if not self.framework:
            return info
        
        backend = getattr(self.framework, 'backend', None)
        if not backend:
            info['name'] = getattr(self.framework, 'backend_name', 'N/A')
            return info
        
        try:
            info['name'] = getattr(backend, 'name', str(backend))
            info['version'] = getattr(backend, 'version', None)
            
            if hasattr(backend, 'target') and backend.target:
                target = backend.target
                info['num_qubits'] = target.num_qubits
                info['basis_gates'] = list(target.operation_names) if hasattr(target, 'operation_names') else []
                
                if hasattr(target, 'build_coupling_map'):
                    cm = target.build_coupling_map()
                    if cm:
                        info['coupling_map_size'] = len(cm.get_edges())
            
            if hasattr(backend, 'max_circuits'):
                info['max_circuits'] = backend.max_circuits
            
            if hasattr(backend, 'configuration'):
                config = backend.configuration()
                if config:
                    info['max_shots'] = getattr(config, 'max_shots', None)
                    info['processor_type'] = getattr(config, 'processor_type', None)
            
            if hasattr(backend, 'status'):
                try:
                    status = backend.status()
                    info['online'] = getattr(status, 'operational', None)
                except:
                    pass
                    
        except Exception as e:
            info['error'] = str(e)
        
        return info
    
    def _collect_dependencies_versions(self) -> Dict[str, str]:
        """[v2.6.0] Collecte les versions des dépendances Python."""
        deps = {}
        packages = [
            'qiskit', 'qiskit-ibm-runtime', 'qiskit-aer',
            'mthree', 'qiskit-ibm-catalog',
            'numpy', 'scipy', 'matplotlib', 'pandas',
            'networkx', 'jinja2', 'weasyprint', 'plotly',
        ]
        
        for pkg in packages:
            try:
                import importlib.metadata
                deps[pkg] = importlib.metadata.version(pkg.replace('-', '_').replace('_', '-'))
            except:
                try:
                    # Fallback pour certains packages
                    mod = __import__(pkg.replace('-', '_').split('-')[0])
                    deps[pkg] = getattr(mod, '__version__', 'installed')
                except:
                    pass
        
        return deps
    
    def _collect_system_info(self) -> Dict:
        """[v2.6.0] Collecte les informations système."""
        import platform
        
        info = {
            'os': platform.system(),
            'os_version': platform.version(),
            'architecture': platform.machine(),
            'python_version': platform.python_version(),
            'python_implementation': platform.python_implementation(),
        }
        
        # Nom complet de l'OS
        if info['os'] == 'Windows':
            info['os_full'] = f"Windows {platform.win32_ver()[0]}"
        elif info['os'] == 'Linux':
            try:
                import distro
                info['os_full'] = f"{distro.name()} {distro.version()}"
            except:
                info['os_full'] = f"Linux {platform.release()}"
        elif info['os'] == 'Darwin':
            info['os_full'] = f"macOS {platform.mac_ver()[0]}"
        else:
            info['os_full'] = info['os']
        
        # Hostname
        try:
            import socket
            info['hostname'] = socket.gethostname()
        except:
            info['hostname'] = 'unknown'
        
        return info
    
    def _collect_all_data(self, results: List[Dict], run_context: Dict, error: Exception) -> Dict:
        """Collecte TOUTES les données pour le rapport."""
        data = {
            # Métadonnées
            'generated_at': datetime.now().isoformat(),
            'framework_version': __version__,
            'python_version': sys.version.split()[0],
            'status': 'ERROR' if error else 'SUCCESS',
            
            # Projet
            'project': getattr(self.framework, 'project', 'QMC') if self.framework else 'QMC',
            'backend_name': getattr(self.framework, 'backend_name', 'N/A') if self.framework else 'N/A',
            
            # Contexte d'exécution
            'run_context': run_context or {},
            
            # Résultats
            'results': results or [],
            'results_count': len(results) if results else 0,
            
            # Erreur si présente
            'error': None,
            
            # [v2.6.0] Backend info complet
            'backend_info': self._collect_backend_info(),
            
            # [v2.6.0] Versions des dépendances
            'dependencies': self._collect_dependencies_versions(),
            
            # [v2.6.0] Informations système
            'system_info': self._collect_system_info(),
            
            # Sections à remplir
            'summary': {},
            'calibration': {},
            'statistics': {},
            'timing': {},
            'charts_data': {},
        }
        
        # Extraire les infos d'erreur
        if error:
            data['error'] = {
                'type': type(error).__name__,
                'message': str(error),
                'traceback': traceback.format_exc() if error else None
            }
        
        # Extraire du run_context
        ctx = run_context or {}
        data['timing'] = {
            'total_time_s': ctx.get('total_time_s', 0),
            'queue_time_s': ctx.get('queue_time_s', 0),
            'execution_time_s': ctx.get('execution_time_s', 0),
            'qpu_time_s': ctx.get('qpu_time_s', 0),
            'transpile_time_s': ctx.get('transpile_time_s', 0),
        }
        
        data['run_context'] = {
            'shots': ctx.get('shots', 0),
            'circuits_count': ctx.get('circuits_count', len(results) if results else 0),
            'optimization_level': ctx.get('optimization_level', 3),
            'layout_strategy': ctx.get('layout_strategy', 'auto'),
            'job_id': ctx.get('job_id', 'N/A'),
            'submitted_at': ctx.get('submitted_at', 'N/A'),
            'completed_at': ctx.get('completed_at', 'N/A'),
        }
        
        # [v2.5.18] Collecter les infos de transpilation
        data['transpilation'] = self._collect_transpilation_data()
        
        # [v2.5.18] Collecter la liste des fichiers générés
        data['files'] = self._collect_generated_files()
        
        # [v2.5.18] Collecter les détails des circuits
        data['circuits_details'] = self._collect_circuits_details()
        
        # [v2.5.21] Générer les visualisations des circuits (images base64)
        # [v2.7.0 FIX] Ne pas limiter par circuits_details (peut être vide)
        # Utiliser directement les circuits stockés dans self._transpiled_circuits
        # ou framework._last_transpiled_circuits
        n_circuits = None  # None = pas de limite, _generate_circuit_images trouvera les circuits
        if self._transpiled_circuits:
            n_circuits = len(self._transpiled_circuits)
        elif self.framework and hasattr(self.framework, '_last_transpiled_circuits'):
            if self.framework._last_transpiled_circuits:
                n_circuits = len(self.framework._last_transpiled_circuits)
        data['circuit_images'] = self._generate_circuit_images(max_circuits=n_circuits)
        
        # [v2.5.18] Générer les visualisations Qiskit professionnelles
        data['qiskit_visualizations'] = self._generate_qiskit_visualizations(results)
        
        # Collecter la calibration du backend
        data['calibration'] = self._collect_calibration_data()
        
        # Calculer les statistiques des résultats
        if results:
            data['summary'] = self._calculate_summary(results)
            data['statistics'] = self._calculate_statistics(results)
            data['charts_data'] = self._prepare_charts_data(results)
        
        return data
    
    def _collect_transpilation_data(self) -> Dict:
        """
        [v2.5.18] Collecte les données de transpilation.
        [v2.7.0 FIX] Calcule depuis les circuits si stats manquantes.
        """
        trans = {
            'available': False,
            'score': None,
            'recommendation': None,
            'overhead_2q_percent': None,
            'swaps_estimated': None,
            'depth_expansion': None,
            'before': {},
            'after': {},
        }
        
        if not self.framework:
            return trans
        
        # Récupérer les stats de transpilation du framework
        stats = getattr(self.framework, '_last_transpilation_stats', None)
        if stats:
            trans['available'] = True
            trans['score'] = stats.get('score')
            trans['recommendation'] = stats.get('recommendation')
            trans['overhead_2q_percent'] = stats.get('overhead_2q_percent')
            trans['swaps_estimated'] = stats.get('swaps_estimated')
            trans['depth_expansion'] = stats.get('depth_expansion')
            trans['before'] = stats.get('before', {})
            trans['after'] = stats.get('after', {})
            return trans
        
        # [v2.7.0] Fallback: calculer depuis les circuits transpilés
        circuits = (
            getattr(self, '_transpiled_circuits', None) or
            getattr(self.framework, '_last_transpiled_circuits', None) or
            getattr(self.framework, '_collected_circuits', None)
        )
        
        if circuits and len(circuits) > 0:
            try:
                # Calculer les métriques moyennes
                depths = []
                gates_2q = []
                total_gates = []
                
                for circ in circuits:
                    if hasattr(circ, 'depth'):
                        depths.append(circ.depth())
                    if hasattr(circ, 'data'):
                        n_2q = sum(1 for inst in circ.data if len(inst.qubits) == 2)
                        gates_2q.append(n_2q)
                        total_gates.append(len(circ.data))
                
                avg_depth = sum(depths) / len(depths) if depths else 0
                avg_2q = sum(gates_2q) / len(gates_2q) if gates_2q else 0
                
                trans['available'] = True
                trans['after'] = {
                    'depth': int(avg_depth),
                    'gates_2q': int(avg_2q),
                    'n_circuits': len(circuits),
                }
                
                # Score basé sur profondeur (heuristique simple)
                # < 50 = excellent, 50-100 = good, 100-200 = ok, > 200 = poor
                if avg_depth < 50:
                    trans['score'] = 90
                    trans['recommendation'] = 'EXCELLENT'
                elif avg_depth < 100:
                    trans['score'] = 75
                    trans['recommendation'] = 'GOOD'
                elif avg_depth < 200:
                    trans['score'] = 55
                    trans['recommendation'] = 'OK'
                else:
                    trans['score'] = 35
                    trans['recommendation'] = 'DEEP'
                
            except Exception as e:
                self._log(f"[TRANSPILATION] Erreur calcul stats: {e}", LogLevel.WARN)
        
        return trans
    
    def _collect_generated_files(self) -> List[Dict]:
        """[v2.5.18] Collecte la liste des fichiers générés dans le répertoire."""
        files = []
        
        if not self.framework:
            return files
        
        # Récupérer le répertoire de sortie
        run_dir = self._get_output_dir()
        if not run_dir or not run_dir.exists():
            return files
        
        try:
            for filepath in run_dir.iterdir():
                if filepath.is_file():
                    stat = filepath.stat()
                    files.append({
                        'name': filepath.name,
                        'path': str(filepath),
                        'size_kb': round(stat.st_size / 1024, 1),
                        'extension': filepath.suffix.lower(),
                        'modified': datetime.fromtimestamp(stat.st_mtime).strftime('%H:%M:%S'),
                        'type': self._get_file_type(filepath.suffix.lower()),
                    })
        except Exception:
            pass
        
        # Trier par type puis par nom
        files.sort(key=lambda x: (x['type'], x['name']))
        return files
    
    def _get_file_type(self, extension: str) -> str:
        """Retourne le type de fichier basé sur l'extension."""
        types = {
            '.html': 'report',
            '.json': 'data',
            '.log': 'log',
            '.txt': 'text',
            '.csv': 'data',
            '.png': 'image',
            '.pdf': 'document',
            '.qasm': 'circuit',
            '.qpy': 'circuit',
        }
        return types.get(extension, 'other')
    
    def _collect_circuits_details(self) -> List[Dict]:
        """
        [v2.5.18] Collecte les détails de tous les circuits transpilés.
        [v2.7.0 FIX] Utilise les mêmes sources que _generate_circuit_images()
        """
        circuits_details = []
        
        if not self.framework:
            return circuits_details
        
        # [v2.7.0] Récupérer les circuits depuis plusieurs sources (même logique que _generate_circuit_images)
        circuits = None
        source = None
        
        # Source 1: Circuits passés directement à generate()
        circuits = getattr(self, '_transpiled_circuits', None)
        if circuits:
            source = "self._transpiled_circuits"
        
        # Fallback 2: Circuits stockés dans le framework
        if not circuits and self.framework:
            circuits = getattr(self.framework, '_last_transpiled_circuits', None)
            if circuits:
                source = "framework._last_transpiled_circuits"
        
        # Fallback 3: Circuits collectés (mode collection)
        if not circuits and self.framework:
            circuits = getattr(self.framework, '_collected_circuits', None)
            if circuits:
                source = "framework._collected_circuits"
        
        # Fallback 4: Rapport interne (ancienne méthode)
        if not circuits:
            report = getattr(self.framework, 'report', None)
            if report:
                transpiled_info = report.get('circuits_transpiled', section='transpilation')
                if transpiled_info:
                    return transpiled_info
        
        # Fallback 5: Fichier circuits.json
        if not circuits:
            run_dir = self._get_output_dir()
            circuits_file = run_dir / 'circuits.json' if run_dir else None
            if circuits_file and circuits_file.exists():
                try:
                    with open(circuits_file, encoding='utf-8') as f:  # [v2.7.1 FIX] explicit encoding (circuits.json is UTF-8; avoid platform cp1252 mojibake)
                        data = json.load(f)
                        return data.get('circuits', [])
                except Exception:
                    pass
        
        # Extraire les détails des circuits Qiskit
        if circuits:
            for i, circ in enumerate(circuits):
                try:
                    detail = {
                        'index': i,
                        'name': getattr(circ, 'name', f'circuit_{i}'),
                        'n_qubits': circ.num_qubits if hasattr(circ, 'num_qubits') else 0,
                        'depth': circ.depth() if hasattr(circ, 'depth') else 0,
                        'gates_2q': sum(1 for inst in circ.data if len(inst.qubits) == 2) if hasattr(circ, 'data') else 0,
                    }
                    circuits_details.append(detail)
                except Exception as e:
                    circuits_details.append({
                        'index': i,
                        'name': f'circuit_{i}',
                        'error': str(e)
                    })
        
        return circuits_details

    def _generate_circuit_images(self, max_circuits: int = None, max_depth: int = 50) -> List[Dict]:
        """
        [v2.5.21] Génère les visualisations des circuits en base64.
        
        Utilise Qiskit draw('mpl') pour créer des images PNG des circuits,
        puis les encode en base64 pour intégration directe dans le HTML.
        
        Args:
            max_circuits: Nombre max de circuits à visualiser (None = tous)
            max_depth: Profondeur max pour affichage complet (circuits plus profonds tronqués)
            
        Returns:
            Liste de dict avec {index, name, image_base64, width, depth, truncated}
        """
        images = []
        
        # [v2.5.21] Récupérer les circuits depuis plusieurs sources (ordre de priorité)
        circuits = None
        source = None
        
        # Source 1: Circuits passés directement à generate()
        circuits = getattr(self, '_transpiled_circuits', None)
        if circuits:
            source = "self._transpiled_circuits (passé à generate)"
        
        # Fallback 2: Circuits stockés dans le framework
        if not circuits and self.framework:
            circuits = getattr(self.framework, '_last_transpiled_circuits', None)
            if circuits:
                source = "framework._last_transpiled_circuits"
        
        # Fallback 3: Circuits originaux (non transpilés)
        if not circuits and self.framework:
            circuits = getattr(self.framework, '_last_circuits', None)
            if circuits:
                source = "framework._last_circuits (non transpilés)"
        
        if not circuits:
            self._log("[CIRCUIT_VIZ] ⚠️ Aucun circuit disponible pour visualisation", LogLevel.WARN)
            self._log("[CIRCUIT_VIZ]    Vérifiez que transpiled_circuits est passé à generate()", LogLevel.DEBUG)
            return images
        
        total_circuits = len(circuits)
        
        # [v2.5.21] Pas de limite par défaut - générer tous les circuits
        n_to_generate = total_circuits if max_circuits is None else min(total_circuits, max_circuits)
        
        self._log(f"[CIRCUIT_VIZ] Source: {source}", LogLevel.DEBUG)
        self._log(f"[CIRCUIT_VIZ] Génération de {n_to_generate}/{total_circuits} visualisations", LogLevel.INFO)
        
        if max_circuits is not None and total_circuits > max_circuits:
            self._log(f"[CIRCUIT_VIZ] ⚠️ {total_circuits - max_circuits} circuits omis (limite: {max_circuits})", LogLevel.WARN)
        
        try:
            import matplotlib
            matplotlib.use('Agg')  # Backend non-interactif
            import matplotlib.pyplot as plt
            from io import BytesIO
            import base64
        except ImportError:
            self._log("Warning: matplotlib non disponible, pas de visualisation circuits", LogLevel.WARN)
            return images
        
        # [v2.5.21] Pas de limite - dessiner tous les circuits demandés
        circuits_to_draw = circuits if max_circuits is None else circuits[:max_circuits]
        
        for i, circuit in enumerate(circuits_to_draw):
            try:
                # Obtenir les infos du circuit
                name = getattr(circuit, 'name', f'circuit_{i}')
                depth = circuit.depth()
                n_qubits = circuit.num_qubits
                
                # [v2.7.0 FIX] Skip le dessin pour circuits trop larges (freeze matplotlib)
                # Seuil: >40 qubits OU depth>200 → trop lent (30-90s par circuit)
                MAX_QUBITS_FOR_DRAW = 40
                MAX_DEPTH_FOR_DRAW = 200
                
                if n_qubits > MAX_QUBITS_FOR_DRAW or depth > MAX_DEPTH_FOR_DRAW:
                    images.append({
                        'index': i,
                        'name': name[:40] + '...' if len(name) > 40 else name,
                        'full_name': name,
                        'image_base64': None,
                        'n_qubits': n_qubits,
                        'depth': depth,
                        'truncated': True,
                        'skip_reason': f"Circuit trop large ({n_qubits}Q, depth={depth}) — "
                                      f"seuil: {MAX_QUBITS_FOR_DRAW}Q / depth {MAX_DEPTH_FOR_DRAW}",
                    })
                    if i == 0:
                        self._log(f"[CIRCUIT_VIZ] ⏭️ Skip dessin: {n_qubits}Q × depth={depth} "
                                 f"(>{MAX_QUBITS_FOR_DRAW}Q ou >{MAX_DEPTH_FOR_DRAW} depth)", LogLevel.INFO)
                    continue
                
                # Vérifier si le circuit est trop profond (mais encore dessinable)
                truncated = depth > max_depth
                circuit_to_draw = circuit
                
                # Créer la figure avec Qiskit
                fig = circuit_to_draw.draw(
                    output='mpl',
                    fold=-1 if depth <= 30 else 80,  # Fold pour circuits larges
                    scale=0.6 if depth > 20 else 0.8,
                    style={
                        'backgroundcolor': '#1a1f2e',
                        'textcolor': '#e2e8f0',
                        'subtextcolor': '#a0aec0',
                        'linecolor': '#4a5568',
                        'creglinecolor': '#718096',
                        'gatetextcolor': '#1a1f2e',
                        'gatefacecolor': '#667eea',
                        'barrierfacecolor': '#ed8936',
                        'displaycolor': {
                            'cx': ('#48bb78', '#1a1f2e'),
                            'cz': ('#4299e1', '#1a1f2e'),
                            'h': ('#f6ad55', '#1a1f2e'),
                            'x': ('#fc8181', '#1a1f2e'),
                            'measure': ('#b794f4', '#1a1f2e'),
                        }
                    },
                    plot_barriers=True,
                    idle_wires=False if n_qubits > 10 else True,
                )
                
                # Convertir en base64
                buf = BytesIO()
                fig.savefig(buf, format='png', dpi=100, bbox_inches='tight',
                           facecolor='#1a1f2e', edgecolor='none')
                plt.close(fig)
                buf.seek(0)
                
                image_base64 = base64.b64encode(buf.read()).decode('utf-8')
                
                images.append({
                    'index': i,
                    'name': name[:40] + '...' if len(name) > 40 else name,
                    'full_name': name,
                    'image_base64': image_base64,
                    'n_qubits': n_qubits,
                    'depth': depth,
                    'truncated': truncated,
                })
                
            except Exception as e:
                # En cas d'erreur, continuer avec les autres circuits
                self._log(f"Warning: Impossible de dessiner circuit {i}: {e}", LogLevel.WARN)
                continue
        
        # Fermer toutes les figures matplotlib pour libérer la mémoire
        plt.close('all')
        
        self._log(f"[CIRCUIT_VIZ] {len(images)} visualisations générées", LogLevel.DEBUG)
        
        return images
    
    def _generate_qiskit_visualizations(self, results: List[Dict]) -> Dict:
        """
        [v2.5.18] Génère des visualisations professionnelles avec Qiskit.
        
        Crée plusieurs types de graphiques:
        - Histogrammes des résultats (plot_histogram)
        - Carte d'erreurs du backend (plot_error_map)
        - Graphiques de comparaison multi-circuits
        - Heatmap de qualité des qubits
        
        Returns:
            Dict avec les images base64 par type
        """
        viz = {
            'histograms': [],      # Histogrammes par circuit
            'error_map': None,     # Carte d'erreurs du backend
            'comparison_charts': [],  # Graphiques de comparaison
            'qubit_heatmap': None,    # Heatmap des qubits
        }
        
        try:
            import matplotlib
            matplotlib.use('Agg')
            import matplotlib.pyplot as plt
            from io import BytesIO
            import base64
            import numpy as np
        except ImportError:
            return viz
        
        # IBM Carbon Design System Colors
        # Remove dark background, use light theme
        plt.style.use('default')
        plt.rcParams.update({
            'figure.facecolor': 'white',
            'axes.facecolor': 'white',
            'axes.edgecolor': '#c6c6c6',
            'axes.labelcolor': '#161616',
            'xtick.color': '#525252',
            'ytick.color': '#525252',
            'text.color': '#161616',
            'grid.color': '#e0e0e0',
        })
        
        IBM = {
            'blue_60': '#0f62fe', 'blue_50': '#4589ff', 'blue_40': '#78a9ff',
            'blue_70': '#0043ce', 'blue_80': '#002d9c',
            'gray_100': '#161616', 'gray_70': '#525252', 'gray_30': '#c6c6c6',
            'gray_20': '#e0e0e0', 'gray_10': '#f4f4f4',
            'green_60': '#198038', 'red_60': '#da1e28', 'yellow_30': '#f1c21b',
            'orange_40': '#ff832b', 'purple_60': '#8a3ffc', 'teal_50': '#009d9a',
            'cyan_50': '#1192e8', 'magenta_50': '#ee5396',
        }
        
        # === 1. HISTOGRAMMES DES RÉSULTATS (IBM Style) ===
        if results:
            try:
                from qiskit.visualization import plot_histogram
                
                # Générer histogrammes pour les 5 premiers circuits
                for i, result in enumerate(results[:5]):
                    counts = result.get('counts', {})
                    if not counts:
                        continue
                    
                    # Limiter à top 20 bitstrings
                    sorted_counts = dict(sorted(counts.items(), key=lambda x: x[1], reverse=True)[:20])
                    
                    try:
                        fig = plot_histogram(
                            sorted_counts,
                            title=f"Circuit {i}: Distribution ({sum(counts.values())} shots)",
                            figsize=(10, 4),
                            color=IBM['blue_60'],
                            bar_labels=False,
                        )
                        fig.patch.set_facecolor('white')
                        for ax in fig.axes:
                            ax.set_facecolor('white')
                            ax.tick_params(colors=IBM['gray_70'], labelsize=9)
                            ax.xaxis.label.set_color(IBM['gray_100'])
                            ax.yaxis.label.set_color(IBM['gray_100'])
                            ax.title.set_color(IBM['gray_100'])
                            ax.title.set_fontweight('normal')
                            for spine in ax.spines.values():
                                spine.set_color(IBM['gray_30'])
                        
                        buf = BytesIO()
                        fig.savefig(buf, format='png', dpi=120, bbox_inches='tight',
                                   facecolor='white', edgecolor='none')
                        plt.close(fig)
                        buf.seek(0)
                        
                        viz['histograms'].append({
                            'index': i,
                            'name': result.get('circuit_name', f'circuit_{i}'),
                            'image_base64': base64.b64encode(buf.read()).decode('utf-8'),
                            'total_shots': sum(counts.values()),
                            'unique_outcomes': len(counts),
                        })
                    except Exception as e:
                        self._log(f"Warning: Histogram {i} failed: {e}", LogLevel.WARN)
                        
            except ImportError:
                pass
        
        # === 2. GRAPHIQUE DE COMPARAISON MULTI-CIRCUITS (IBM Style) ===
        if results and len(results) > 1:
            try:
                # Graphique entropie vs uniformité - IBM Carbon Light Theme
                fig, axes = plt.subplots(1, 2, figsize=(14, 5))
                fig.patch.set_facecolor('white')
                
                circuit_indices = list(range(len(results[:20])))
                entropies = []
                uniformities = []
                top_probs = []
                
                for r in results[:20]:
                    stats = r.get('statistics', {})
                    entropies.append(stats.get('entropy_bits', 0))
                    uniformities.append(stats.get('uniformity_percent', 0))
                    top_probs.append(stats.get('top_probability', 0))
                
                # Graphique 1: Entropie par circuit
                ax1 = axes[0]
                ax1.set_facecolor('white')
                bars1 = ax1.bar(circuit_indices, entropies, color=IBM['blue_60'], width=0.7)
                mean_ent = np.mean(entropies) if entropies else 0
                ax1.axhline(y=mean_ent, color=IBM['orange_40'], linestyle='--', 
                           linewidth=1.5, label=f'Mean: {mean_ent:.2f}')
                ax1.set_xlabel('Circuit Index', color=IBM['gray_100'], fontsize=10)
                ax1.set_ylabel('Entropy (bits)', color=IBM['gray_100'], fontsize=10)
                ax1.set_title('Entropy per Circuit', color=IBM['gray_100'], fontsize=12, fontweight='normal')
                ax1.tick_params(colors=IBM['gray_70'], labelsize=9)
                ax1.legend(facecolor='white', edgecolor=IBM['gray_30'], labelcolor=IBM['gray_100'], fontsize=9)
                ax1.grid(axis='y', linestyle='-', alpha=0.3, color=IBM['gray_30'])
                for spine in ax1.spines.values():
                    spine.set_color(IBM['gray_30'])
                
                # Graphique 2: Uniformité et Top Prob
                ax2 = axes[1]
                ax2.set_facecolor('white')
                x = np.arange(len(circuit_indices))
                width = 0.35
                bars2 = ax2.bar(x - width/2, uniformities, width, label='Uniformity %', color=IBM['teal_50'])
                bars3 = ax2.bar(x + width/2, top_probs, width, label='Top Prob %', color=IBM['purple_60'])
                ax2.set_xlabel('Circuit Index', color=IBM['gray_100'], fontsize=10)
                ax2.set_ylabel('Percentage', color=IBM['gray_100'], fontsize=10)
                ax2.set_title('Uniformity vs Top Probability', color=IBM['gray_100'], fontsize=12, fontweight='normal')
                ax2.tick_params(colors=IBM['gray_70'], labelsize=9)
                ax2.legend(facecolor='white', edgecolor=IBM['gray_30'], labelcolor=IBM['gray_100'], fontsize=9)
                ax2.grid(axis='y', linestyle='-', alpha=0.3, color=IBM['gray_30'])
                for spine in ax2.spines.values():
                    spine.set_color(IBM['gray_30'])
                
                plt.tight_layout()
                
                buf = BytesIO()
                fig.savefig(buf, format='png', dpi=120, bbox_inches='tight',
                           facecolor='white', edgecolor='none')
                plt.close(fig)
                buf.seek(0)
                
                viz['comparison_charts'].append({
                    'name': 'Circuit Quality Metrics',
                    'image_base64': base64.b64encode(buf.read()).decode('utf-8'),
                })
                
            except Exception as e:
                self._log(f"Warning: Comparison chart failed: {e}", LogLevel.WARN)
        
        # === 3. HEATMAP QUALITÉ DES QUBITS (IBM Style) ===
        if self.framework:
            try:
                backend = getattr(self.framework, 'backend', None)
                if backend and hasattr(backend, 'target'):
                    target = backend.target
                    n_qubits = target.num_qubits
                    
                    # Collecter les erreurs de readout par qubit
                    readout_errors = []
                    for q in range(min(n_qubits, 156)):  # Limiter à 156 qubits max
                        try:
                            measure_props = target.get('measure', (q,))
                            if measure_props and hasattr(measure_props, 'error') and measure_props.error:
                                readout_errors.append(measure_props.error * 100)
                            else:
                                readout_errors.append(np.nan)
                        except:
                            readout_errors.append(np.nan)
                    
                    if readout_errors and not all(np.isnan(readout_errors)):
                        # Créer une grille pour la heatmap
                        grid_size = int(np.ceil(np.sqrt(len(readout_errors))))
                        grid = np.full((grid_size, grid_size), np.nan)
                        
                        for i, err in enumerate(readout_errors):
                            row = i // grid_size
                            col = i % grid_size
                            if row < grid_size and col < grid_size:
                                grid[row, col] = err
                        
                        fig, ax = plt.subplots(figsize=(10, 8))
                        fig.patch.set_facecolor('white')
                        ax.set_facecolor('white')
                        
                        # IBM-style colormap: Blue (good) to Red (bad)
                        from matplotlib.colors import LinearSegmentedColormap
                        ibm_cmap = LinearSegmentedColormap.from_list('ibm_quality',
                            [IBM['blue_60'], IBM['blue_40'], IBM['yellow_30'], IBM['orange_40'], IBM['red_60']])
                        
                        im = ax.imshow(grid, cmap=ibm_cmap, aspect='equal', vmin=0, vmax=10)
                        
                        # Colorbar
                        cbar = plt.colorbar(im, ax=ax, label='Readout Error (%)')
                        cbar.ax.yaxis.label.set_color(IBM['gray_100'])
                        cbar.ax.tick_params(colors=IBM['gray_70'])
                        
                        ax.set_title(f'Qubit Quality Heatmap ({len(readout_errors)} qubits)', 
                                    color=IBM['gray_100'], fontsize=12, fontweight='normal')
                        ax.set_xlabel('Position X', color=IBM['gray_100'], fontsize=10)
                        ax.set_ylabel('Position Y', color=IBM['gray_100'], fontsize=10)
                        ax.tick_params(colors=IBM['gray_70'])
                        
                        # Ajouter les numéros de qubits
                        for i in range(min(len(readout_errors), grid_size * grid_size)):
                            row = i // grid_size
                            col = i % grid_size
                            if row < grid_size and col < grid_size:
                                ax.text(col, row, str(i), ha='center', va='center', 
                                       fontsize=6, color='white' if grid[row, col] > 5 else IBM['gray_100'])
                        
                        plt.tight_layout()
                        
                        buf = BytesIO()
                        fig.savefig(buf, format='png', dpi=120, bbox_inches='tight',
                                   facecolor='white', edgecolor='none')
                        plt.close(fig)
                        buf.seek(0)
                        
                        viz['qubit_heatmap'] = {
                            'image_base64': base64.b64encode(buf.read()).decode('utf-8'),
                            'n_qubits': len(readout_errors),
                            'avg_error': np.nanmean(readout_errors),
                            'max_error': np.nanmax(readout_errors),
                        }
                        
            except Exception as e:
                self._log(f"Warning: Qubit heatmap failed: {e}", LogLevel.WARN)
        
        # === 4. ERROR MAP DU BACKEND (plot_error_map) - IBM Style ===
        if self.framework:
            try:
                backend = getattr(self.framework, 'backend', None)
                if backend:
                    from qiskit.visualization import plot_error_map
                    
                    fig = plot_error_map(backend, figsize=(12, 10), show_title=True)
                    fig.patch.set_facecolor('white')
                    
                    buf = BytesIO()
                    fig.savefig(buf, format='png', dpi=120, bbox_inches='tight',
                               facecolor='white', edgecolor='none')
                    plt.close(fig)
                    buf.seek(0)
                    
                    viz['error_map'] = {
                        'image_base64': base64.b64encode(buf.read()).decode('utf-8'),
                        'backend_name': getattr(backend, 'name', 'Unknown'),
                    }
                    
            except Exception as e:
                # plot_error_map peut ne pas être disponible pour tous les backends
                self._log(f"Info: Error map not available: {e}", LogLevel.DEBUG)
        
        # Fermer toutes les figures
        plt.close('all')
        
        return viz

    def _collect_calibration_data(self) -> Dict:
        """
        Collecte les données de calibration COMPLÈTES du backend.
        
        Récupère directement depuis le backend IBM :
        - Tous les qubits avec T1, T2, erreur readout, fréquence
        - Toutes les gates 2-qubit avec erreurs
        - Topologie (coupling map)
        - Date de dernière calibration
        - Statistiques globales
        """
        calib = {
            'available': False,
            'backend_name': None,
            'backend_version': None,
            'num_qubits': 0,
            'calibration_time': None,
            'basis_gates': [],
            
            # Qubits
            'qubits_info': [],
            'qubits_summary': {
                'total': 0,
                'operational': 0,
                'faulty': 0,
                'avg_t1_us': None,
                'avg_t2_us': None,
                'min_t1_us': None,
                'max_t1_us': None,
                'avg_readout_error': None,
                'worst_readout_error': None,
            },
            'faulty_qubits': [],
            
            # Gates 2-qubit
            'two_qubit_gates': [],
            'gates_summary': {
                'total_connections': 0,
                'avg_cx_error': None,
                'worst_cx_error': None,
                'best_cx_error': None,
            },
            
            # Topologie
            'coupling_map': [],
            
            # Erreur éventuelle
            'error': None,
        }
        
        if not self.framework:
            calib['error'] = "No framework available"
            return calib
        
        # Essayer d'obtenir le backend
        backend = getattr(self.framework, 'backend', None)
        if not backend:
            calib['error'] = "No backend connected"
            return calib
        
        try:
            calib['available'] = True
            calib['backend_name'] = getattr(backend, 'name', str(backend))
            calib['backend_version'] = getattr(backend, 'version', 'N/A')
            
            # === MÉTHODE 0: Via DynamicTopology (SOURCE PRIORITAIRE v2.6.0) ===
            # C'est la source la plus fiable car elle est remplie par analyze_calibration()
            topology = getattr(self.framework, 'topology', None)
            topology_has_qubit_data = topology and hasattr(topology, '_qubit_errors') and topology._qubit_errors
            topology_has_2q_data = topology and hasattr(topology, '_connection_errors') and topology._connection_errors
            
            # Récupérer calibration_time depuis topology si disponible
            if topology and hasattr(topology, 'calibration_time') and topology.calibration_time:
                calib['calibration_time'] = topology.calibration_time
            
            if topology_has_qubit_data:
                calib['num_qubits'] = topology.n_qubits
                
                # Récupérer les données des qubits depuis DynamicTopology
                t1_values, t2_values, readout_errors = [], [], []
                
                for qubit in range(topology.n_qubits):
                    q_data = topology._qubit_errors.get(qubit, {})
                    q_info = {
                        'index': qubit,
                        't1_us': round(q_data.get('t1', 0), 1) if q_data.get('t1') else None,
                        't2_us': round(q_data.get('t2', 0), 1) if q_data.get('t2') else None,
                        'readout_error': round(q_data.get('readout', 0) * 100, 3) if q_data.get('readout') else None,
                        'frequency_ghz': round(q_data.get('freq', 0) / 1e9, 3) if q_data.get('freq') else None,
                        'status': 'FAULTY' if qubit in topology.faulty_qubits else ('SUSPECT' if qubit in topology.suspect_qubits else 'OK')
                    }
                    
                    if q_data.get('t1'):
                        t1_values.append(q_data['t1'])
                    if q_data.get('t2'):
                        t2_values.append(q_data['t2'])
                    if q_data.get('readout'):
                        readout_errors.append(q_data['readout'] * 100)
                    
                    calib['qubits_info'].append(q_info)
                
                # Remplir le summary
                calib['faulty_qubits'] = list(topology.faulty_qubits)
                calib['qubits_summary']['total'] = topology.n_qubits
                calib['qubits_summary']['operational'] = topology.n_qubits - len(topology.faulty_qubits)
                calib['qubits_summary']['faulty'] = len(topology.faulty_qubits)
                
                if t1_values:
                    calib['qubits_summary']['avg_t1_us'] = round(sum(t1_values) / len(t1_values), 1)
                    calib['qubits_summary']['min_t1_us'] = round(min(t1_values), 1)
                    calib['qubits_summary']['max_t1_us'] = round(max(t1_values), 1)
                if t2_values:
                    calib['qubits_summary']['avg_t2_us'] = round(sum(t2_values) / len(t2_values), 1)
                    calib['qubits_summary']['min_t2_us'] = round(min(t2_values), 1)
                    calib['qubits_summary']['max_t2_us'] = round(max(t2_values), 1)
                if readout_errors:
                    calib['qubits_summary']['avg_readout_error'] = round(sum(readout_errors) / len(readout_errors), 3)
                    calib['qubits_summary']['worst_readout_error'] = round(max(readout_errors), 3)
                    calib['qubits_summary']['best_readout_error'] = round(min(readout_errors), 3)
                
                # Gates 2-qubit depuis _connection_errors
                if topology_has_2q_data:
                    cx_errors = []
                    for (q1, q2), error in topology._connection_errors.items():
                        cx_errors.append(error * 100)
                        calib['two_qubit_gates'].append({
                            'qubits': [q1, q2],
                            'error_pct': round(error * 100, 3),
                            'gate': topology.gate_type if hasattr(topology, 'gate_type') else 'ecr'
                        })
                    
                    if cx_errors:
                        calib['gates_summary']['total_connections'] = len(cx_errors)
                        calib['gates_summary']['avg_cx_error'] = round(sum(cx_errors) / len(cx_errors), 3)
                        calib['gates_summary']['worst_cx_error'] = round(max(cx_errors), 3)
                        calib['gates_summary']['best_cx_error'] = round(min(cx_errors), 3)
                
                # Coupling map
                if topology._coupling_map:
                    calib['coupling_map'] = list(topology._coupling_map)
                
                # [v2.6.0] Chaîne maximale de qubits contigus
                if hasattr(topology, 'get_best_path'):
                    try:
                        best_path = topology.get_best_path(min(100, topology.n_qubits))
                        calib['max_contiguous_qubits'] = {
                            'count': len(best_path),
                            'path': best_path,
                            'start': best_path[0] if best_path else None,
                            'end': best_path[-1] if best_path else None,
                        }
                    except:
                        pass
            
            # === RÉCUPÉRER LES DONNÉES 2Q DEPUIS backend.target SI MANQUANTES ===
            # Même si on a les données qubit depuis topology, on peut avoir besoin des erreurs 2Q
            if not calib['two_qubit_gates'] and hasattr(backend, 'target') and backend.target:
                target = backend.target
                cx_errors = []
                two_q_gates = ['ecr', 'cz', 'cx']  # Priorité: ECR (Eagle/Heron), CZ (Heron), CX (legacy)
                
                for gate_name in two_q_gates:
                    if gate_name in target.operation_names:
                        try:
                            for qargs in target.qargs_for_operation_name(gate_name):
                                if len(qargs) == 2:
                                    try:
                                        gate_props = target[gate_name][qargs]
                                        if gate_props and hasattr(gate_props, 'error') and gate_props.error is not None:
                                            error_pct = gate_props.error * 100
                                            cx_errors.append(error_pct)
                                            calib['two_qubit_gates'].append({
                                                'gate': gate_name.upper(),
                                                'qubits': list(qargs),
                                                'error_pct': round(error_pct, 3),
                                                'duration_ns': round(gate_props.duration * 1e9, 1) if gate_props.duration else None
                                            })
                                    except:
                                        pass
                        except:
                            pass
                        
                        # Si on a trouvé des données, pas besoin de chercher d'autres gates
                        if cx_errors:
                            break
                
                if cx_errors:
                    calib['gates_summary']['total_connections'] = len(cx_errors)
                    calib['gates_summary']['avg_cx_error'] = round(sum(cx_errors) / len(cx_errors), 3)
                    calib['gates_summary']['best_cx_error'] = round(min(cx_errors), 3)
                    calib['gates_summary']['worst_cx_error'] = round(max(cx_errors), 3)
            
            # === RÉCUPÉRER LA DATE DE CALIBRATION ===
            # Essayer plusieurs sources
            if not calib['calibration_time']:
                # Source 1: backend.properties().last_update_date
                if hasattr(backend, 'properties') and callable(backend.properties):
                    try:
                        props = backend.properties()
                        if props and hasattr(props, 'last_update_date') and props.last_update_date:
                            calib['calibration_time'] = str(props.last_update_date)
                    except:
                        pass
                
                # Source 2: backend.target (Qiskit 1.0+)
                if not calib['calibration_time'] and hasattr(backend, 'target') and backend.target:
                    target = backend.target
                    # Chercher dans les propriétés de n'importe quelle instruction
                    try:
                        for op_name in ['measure', 'sx', 'x', 'ecr', 'cz']:
                            if op_name in target.operation_names:
                                for qargs in target.qargs_for_operation_name(op_name):
                                    try:
                                        props = target[op_name][qargs]
                                        if props and hasattr(props, 'calibration') and props.calibration:
                                            # La date peut être dans calibration
                                            calib['calibration_time'] = str(props.calibration)
                                            break
                                    except:
                                        pass
                                if calib['calibration_time']:
                                    break
                    except:
                        pass
                
                # Source 3: backend.status() ou configuration
                if not calib['calibration_time']:
                    try:
                        config = backend.configuration() if hasattr(backend, 'configuration') else None
                        if config and hasattr(config, 'last_update_date'):
                            calib['calibration_time'] = str(config.last_update_date)
                    except:
                        pass
            
            # Si on a déjà les données complètes depuis topology, retourner
            if topology_has_qubit_data and calib['two_qubit_gates']:
                return calib
            
            # === MÉTHODE 1: Via backend.target (Qiskit moderne) ===
            if hasattr(backend, 'target') and backend.target:
                target = backend.target
                calib['num_qubits'] = target.num_qubits
                calib['basis_gates'] = list(target.operation_names) if hasattr(target, 'operation_names') else []
                
                # Collecter infos qubits
                t1_values, t2_values, readout_errors = [], [], []
                faulty = []
                
                for qubit in range(target.num_qubits):
                    q_info = {'index': qubit, 't1_us': None, 't2_us': None, 
                              'readout_error': None, 'frequency_ghz': None, 'status': 'OK'}
                    
                    # T1, T2 via les propriétés du qubit
                    try:
                        if hasattr(target, 'qubit_properties') and target.qubit_properties:
                            props = target.qubit_properties[qubit]
                            if props:
                                if hasattr(props, 't1') and props.t1:
                                    q_info['t1_us'] = round(props.t1 * 1e6, 1)
                                    t1_values.append(props.t1 * 1e6)
                                if hasattr(props, 't2') and props.t2:
                                    q_info['t2_us'] = round(props.t2 * 1e6, 1)
                                    t2_values.append(props.t2 * 1e6)
                                if hasattr(props, 'frequency') and props.frequency:
                                    q_info['frequency_ghz'] = round(props.frequency / 1e9, 3)
                    except:
                        pass
                    
                    # Erreur de mesure
                    try:
                        measure_props = target.get('measure', (qubit,))
                        if measure_props and hasattr(measure_props, 'error') and measure_props.error:
                            q_info['readout_error'] = round(measure_props.error * 100, 3)
                            readout_errors.append(measure_props.error * 100)
                            if measure_props.error > 0.10:  # >10% = faulty
                                q_info['status'] = 'FAULTY'
                                faulty.append(qubit)
                    except:
                        pass
                    
                    calib['qubits_info'].append(q_info)
                
                calib['faulty_qubits'] = faulty
                calib['qubits_summary']['total'] = target.num_qubits
                calib['qubits_summary']['operational'] = target.num_qubits - len(faulty)
                calib['qubits_summary']['faulty'] = len(faulty)
                
                if t1_values:
                    calib['qubits_summary']['avg_t1_us'] = round(sum(t1_values) / len(t1_values), 1)
                    calib['qubits_summary']['min_t1_us'] = round(min(t1_values), 1)
                    calib['qubits_summary']['max_t1_us'] = round(max(t1_values), 1)
                if t2_values:
                    calib['qubits_summary']['avg_t2_us'] = round(sum(t2_values) / len(t2_values), 1)
                if readout_errors:
                    calib['qubits_summary']['avg_readout_error'] = round(sum(readout_errors) / len(readout_errors), 3)
                    calib['qubits_summary']['worst_readout_error'] = round(max(readout_errors), 3)
                
                # Gates 2-qubit (CX, ECR, CZ)
                cx_errors = []
                two_q_gates = ['cx', 'ecr', 'cz']
                for gate_name in two_q_gates:
                    if gate_name in target.operation_names:
                        for qargs in target.qargs_for_operation_name(gate_name):
                            if len(qargs) == 2:
                                try:
                                    gate_props = target.get(gate_name, qargs)
                                    if gate_props and hasattr(gate_props, 'error') and gate_props.error:
                                        error_pct = gate_props.error * 100
                                        cx_errors.append(error_pct)
                                        calib['two_qubit_gates'].append({
                                            'gate': gate_name.upper(),
                                            'qubits': list(qargs),
                                            'error_pct': round(error_pct, 3),
                                            'duration_ns': round(gate_props.duration * 1e9, 1) if gate_props.duration else None
                                        })
                                except:
                                    pass
                
                if cx_errors:
                    calib['gates_summary']['total_connections'] = len(cx_errors)
                    calib['gates_summary']['avg_cx_error'] = round(sum(cx_errors) / len(cx_errors), 3)
                    calib['gates_summary']['best_cx_error'] = round(min(cx_errors), 3)
                    calib['gates_summary']['worst_cx_error'] = round(max(cx_errors), 3)
                
                # Coupling map
                if hasattr(target, 'build_coupling_map'):
                    cm = target.build_coupling_map()
                    if cm:
                        calib['coupling_map'] = [list(edge) for edge in cm.get_edges()]
            
            # === MÉTHODE 2: Via backend.properties() (ancienne API) ===
            elif hasattr(backend, 'properties') and callable(backend.properties):
                props = backend.properties()
                if props:
                    calib['calibration_time'] = str(props.last_update_date) if hasattr(props, 'last_update_date') else None
                    
                    t1_values, t2_values, readout_errors = [], [], []
                    faulty = []
                    
                    for qubit in range(props.num_qubits if hasattr(props, 'num_qubits') else 0):
                        q_info = {'index': qubit, 't1_us': None, 't2_us': None, 
                                  'readout_error': None, 'frequency_ghz': None, 'status': 'OK'}
                        
                        try:
                            t1 = props.t1(qubit)
                            if t1:
                                q_info['t1_us'] = round(t1 * 1e6, 1)
                                t1_values.append(t1 * 1e6)
                        except:
                            pass
                        
                        try:
                            t2 = props.t2(qubit)
                            if t2:
                                q_info['t2_us'] = round(t2 * 1e6, 1)
                                t2_values.append(t2 * 1e6)
                        except:
                            pass
                        
                        try:
                            freq = props.frequency(qubit)
                            if freq:
                                q_info['frequency_ghz'] = round(freq / 1e9, 3)
                        except:
                            pass
                        
                        try:
                            re = props.readout_error(qubit)
                            if re:
                                q_info['readout_error'] = round(re * 100, 3)
                                readout_errors.append(re * 100)
                                if re > 0.10:
                                    q_info['status'] = 'FAULTY'
                                    faulty.append(qubit)
                        except:
                            pass
                        
                        calib['qubits_info'].append(q_info)
                    
                    calib['num_qubits'] = len(calib['qubits_info'])
                    calib['faulty_qubits'] = faulty
                    calib['qubits_summary']['total'] = calib['num_qubits']
                    calib['qubits_summary']['operational'] = calib['num_qubits'] - len(faulty)
                    calib['qubits_summary']['faulty'] = len(faulty)
                    
                    if t1_values:
                        calib['qubits_summary']['avg_t1_us'] = round(sum(t1_values) / len(t1_values), 1)
                        calib['qubits_summary']['min_t1_us'] = round(min(t1_values), 1)
                        calib['qubits_summary']['max_t1_us'] = round(max(t1_values), 1)
                    if t2_values:
                        calib['qubits_summary']['avg_t2_us'] = round(sum(t2_values) / len(t2_values), 1)
                    if readout_errors:
                        calib['qubits_summary']['avg_readout_error'] = round(sum(readout_errors) / len(readout_errors), 3)
                        calib['qubits_summary']['worst_readout_error'] = round(max(readout_errors), 3)
            
            # === MÉTHODE 3: Via circuit_optimizer (fallback) ===
            elif hasattr(self.framework, 'circuit_optimizer') and self.framework.circuit_optimizer:
                opt = self.framework.circuit_optimizer
                
                if hasattr(opt, 'qubits') and opt.qubits:
                    t1_values, t2_values, readout_errors = [], [], []
                    
                    for q in opt.qubits:
                        q_info = {
                            'index': q.index,
                            't1_us': round(q.t1 * 1e6, 1) if q.t1 else None,
                            't2_us': round(q.t2 * 1e6, 1) if q.t2 else None,
                            'readout_error': round(q.readout_error * 100, 3) if q.readout_error else None,
                            'frequency_ghz': round(q.frequency / 1e9, 3) if q.frequency else None,
                            'status': 'FAULTY' if q.readout_error and q.readout_error > 0.10 else 'OK'
                        }
                        calib['qubits_info'].append(q_info)
                        
                        if q.t1:
                            t1_values.append(q.t1 * 1e6)
                        if q.t2:
                            t2_values.append(q.t2 * 1e6)
                        if q.readout_error:
                            readout_errors.append(q.readout_error * 100)
                    
                    calib['num_qubits'] = len(calib['qubits_info'])
                    calib['qubits_summary']['total'] = calib['num_qubits']
                    
                    if t1_values:
                        calib['qubits_summary']['avg_t1_us'] = round(sum(t1_values) / len(t1_values), 1)
                    if t2_values:
                        calib['qubits_summary']['avg_t2_us'] = round(sum(t2_values) / len(t2_values), 1)
                    if readout_errors:
                        calib['qubits_summary']['avg_readout_error'] = round(sum(readout_errors) / len(readout_errors), 3)
                
                if hasattr(opt, 'get_faulty_qubits'):
                    calib['faulty_qubits'] = list(opt.get_faulty_qubits())
                    calib['qubits_summary']['faulty'] = len(calib['faulty_qubits'])
                    calib['qubits_summary']['operational'] = calib['num_qubits'] - len(calib['faulty_qubits'])
            
            else:
                calib['error'] = "No calibration source available (target, properties, or optimizer)"
            
            # [v2.5.21] FALLBACK FINAL: Essayer framework.noise._calibration_data 
            # qui est rempli par analyze_calibration()
            if not calib['qubits_info'] and self.framework:
                noise = getattr(self.framework, 'noise', None)
                if noise:
                    cached_calib = getattr(noise, '_calibration_data', None)
                    if cached_calib and isinstance(cached_calib, dict):
                        summary_data = cached_calib.get('summary', {})
                        qubits_data = cached_calib.get('qubits', {})
                        
                        # Récupérer T1/T2/readout depuis summary
                        if summary_data:
                            t1_info = summary_data.get('t1_us', {})
                            t2_info = summary_data.get('t2_us', {})
                            re_info = summary_data.get('readout_error', {})
                            
                            if t1_info.get('mean'):
                                calib['qubits_summary']['avg_t1_us'] = t1_info['mean']
                            if t2_info.get('mean'):
                                calib['qubits_summary']['avg_t2_us'] = t2_info['mean']
                            if re_info.get('mean'):
                                calib['qubits_summary']['avg_readout_error'] = round(re_info['mean'] * 100, 3)
                            if re_info.get('max'):
                                calib['qubits_summary']['worst_readout_error'] = round(re_info['max'] * 100, 3)
                        
                        # Récupérer les infos des qubits individuels
                        if qubits_data:
                            for idx, q_data in qubits_data.items():
                                q_info = {
                                    'index': int(idx),
                                    't1_us': round(q_data.get('t1', 0) * 1e6, 1) if q_data.get('t1') else None,
                                    't2_us': round(q_data.get('t2', 0) * 1e6, 1) if q_data.get('t2') else None,
                                    'readout_error': round(q_data.get('readout_error', 0) * 100, 3) if q_data.get('readout_error') else None,
                                    'status': 'FAULTY' if q_data.get('readout_error') and q_data.get('readout_error') > 0.10 else 'OK'
                                }
                                calib['qubits_info'].append(q_info)
                            
                            calib['num_qubits'] = len(calib['qubits_info'])
                            calib['qubits_summary']['total'] = calib['num_qubits']
                            calib['available'] = True
                            calib['error'] = None
        
        except Exception as e:
            calib['error'] = f"Error collecting calibration: {str(e)}"
            import traceback
            calib['traceback'] = traceback.format_exc()
        
        return calib
    
    def _calculate_summary(self, results: List[Dict]) -> Dict:
        """Calcule le résumé global des résultats."""
        summary = {
            'total_circuits': len(results),
            'total_shots': 0,
            'total_outcomes': 0,
            'avg_outcomes_per_circuit': 0,
            'circuits_with_errors': 0,
        }
        
        all_outcomes = 0
        for r in results:
            if isinstance(r, dict):
                counts = r.get('counts', {})
                summary['total_shots'] += sum(counts.values())
                all_outcomes += len(counts)
                
                if r.get('error'):
                    summary['circuits_with_errors'] += 1
        
        summary['total_outcomes'] = all_outcomes
        if results:
            summary['avg_outcomes_per_circuit'] = round(all_outcomes / len(results), 1)
        
        return summary
    
    def _calculate_statistics(self, results: List[Dict]) -> Dict:
        """Calcule les statistiques avancées."""
        stats = {
            'per_circuit': [],
            'global': {
                'avg_entropy': 0,
                'avg_uniformity': 0,
                'avg_top_prob': 0,
            }
        }
        
        entropies = []
        uniformities = []
        top_probs = []
        
        for i, r in enumerate(results):
            if not isinstance(r, dict):
                continue
            
            counts = r.get('counts', {})
            if not counts:
                continue
            
            total = sum(counts.values())
            n_outcomes = len(counts)
            
            # Calculer l'entropie
            entropy = 0
            for count in counts.values():
                if count > 0:
                    p = count / total
                    entropy -= p * math.log2(p)
            
            # Entropie maximale possible
            max_entropy = math.log2(n_outcomes) if n_outcomes > 1 else 1
            uniformity = (entropy / max_entropy * 100) if max_entropy > 0 else 0
            
            # Top bitstrings
            sorted_counts = sorted(counts.items(), key=lambda x: x[1], reverse=True)
            top_5 = sorted_counts[:5]
            top_prob = (sorted_counts[0][1] / total * 100) if sorted_counts else 0
            
            circuit_stats = {
                'index': i,
                'shots': total,
                'unique_outcomes': n_outcomes,
                'entropy_bits': round(entropy, 3),
                'max_entropy_bits': round(max_entropy, 3),
                'uniformity_percent': round(uniformity, 1),
                'top_bitstring': sorted_counts[0][0] if sorted_counts else 'N/A',
                'top_probability': round(top_prob, 2),
                'top_5': [{'bitstring': bs, 'count': c, 'prob': round(c/total*100, 2)} 
                         for bs, c in top_5],
                'depth': r.get('depth', 'N/A'),
                'fidelity': r.get('fidelity', 'N/A'),
            }
            
            stats['per_circuit'].append(circuit_stats)
            entropies.append(entropy)
            uniformities.append(uniformity)
            top_probs.append(top_prob)
        
        # Moyennes globales
        if entropies:
            stats['global']['avg_entropy'] = round(sum(entropies) / len(entropies), 3)
            stats['global']['avg_uniformity'] = round(sum(uniformities) / len(uniformities), 1)
            stats['global']['avg_top_prob'] = round(sum(top_probs) / len(top_probs), 2)
        
        return stats
    
    def _prepare_charts_data(self, results: List[Dict]) -> Dict:
        """Prépare les données pour les graphiques Chart.js."""
        charts = {
            'distributions': [],
            'entropy_by_circuit': [],
            'uniformity_by_circuit': [],
            'labels': [],      # Pour Chart.js - bitstrings du premier circuit
            'values': [],      # Pour Chart.js - counts du premier circuit
        }
        
        first_circuit_done = False
        
        for i, r in enumerate(results):
            if not isinstance(r, dict):
                continue
            
            counts = r.get('counts', {})
            if not counts:
                continue
            
            total = sum(counts.values())
            sorted_counts = sorted(counts.items(), key=lambda x: x[1], reverse=True)[:10]
            
            # Données détaillées pour chaque circuit
            charts['distributions'].append({
                'circuit': i,
                'data': [{'bitstring': k[:12], 'probability': round(v/total*100, 2)} 
                        for k, v in sorted_counts]
            })
            
            # Pour le graphique principal (premier circuit avec données)
            if not first_circuit_done and sorted_counts:
                charts['labels'] = [k[:12] + ('...' if len(k) > 12 else '') for k, v in sorted_counts]
                charts['values'] = [v for k, v in sorted_counts]
                first_circuit_done = True
        
        return charts
    
    def _generate_professional_html(self, data: Dict, title: str) -> str:
        """
        [v2.5.19] Génère un rapport HTML professionnel style IBM/Nature.
        
        Design:
        - Palette sobre (bleu marine, gris, blanc)
        - Typographie scientifique (Inter, JetBrains Mono)
        - Pas d'emojis
        - Sections numérotées
        - Layout publication scientifique
        """
        from datetime import datetime
        
        status = data.get('status', 'UNKNOWN')
        status_class = 'success' if status == 'SUCCESS' else 'error'
        
        # Données
        timing = data.get('timing', {})
        run_ctx = data.get('run_context', {})
        stats = data.get('statistics', {}).get('global', {})
        calib = data.get('calibration', {})
        trans = data.get('transpilation', {})
        summary = data.get('summary', {})
        
        # Valeurs extraites pour éviter les problèmes de f-string
        total_shots = summary.get('total_shots', 0)
        trans_after = trans.get('after', {})
        trans_final_depth = trans_after.get('depth', 'N/A')
        
        # JSON pour charts
        # [v2.7.1 FIX] prevent HTML/script breakout from JSON embedded in <pre>/<script>
        def _json_safe(s: str) -> str:
            return s.replace('<', '\\u003c').replace('>', '\\u003e').replace('&', '\\u0026')
        charts_data = _json_safe(json.dumps(data.get('charts_data', {}), indent=2))
        full_data = _json_safe(json.dumps({k: v for k, v in data.items()
                               if k not in ['circuit_images', 'qiskit_visualizations']},
                              indent=2, default=str))
        
        # CSS Professionnel - IBM Carbon Design System
        css = '''
/* IBM Carbon Design System Color Palette */
:root {
    /* Core Blue Family */
    --ibm-blue-100: #001141;
    --ibm-blue-90: #001d6c;
    --ibm-blue-80: #002d9c;
    --ibm-blue-70: #0043ce;
    --ibm-blue-60: #0f62fe;
    --ibm-blue-50: #4589ff;
    --ibm-blue-40: #78a9ff;
    --ibm-blue-30: #a6c8ff;
    --ibm-blue-20: #d0e2ff;
    --ibm-blue-10: #edf5ff;
    
    /* Neutral Gray */
    --ibm-gray-100: #161616;
    --ibm-gray-90: #262626;
    --ibm-gray-80: #393939;
    --ibm-gray-70: #525252;
    --ibm-gray-60: #6f6f6f;
    --ibm-gray-50: #8d8d8d;
    --ibm-gray-40: #a8a8a8;
    --ibm-gray-30: #c6c6c6;
    --ibm-gray-20: #e0e0e0;
    --ibm-gray-10: #f4f4f4;
    
    /* Support Colors */
    --ibm-green-60: #198038;
    --ibm-green-50: #24a148;
    --ibm-red-60: #da1e28;
    --ibm-red-50: #fa4d56;
    --ibm-yellow-30: #f1c21b;
    --ibm-orange-40: #ff832b;
    --ibm-purple-60: #8a3ffc;
    --ibm-teal-50: #009d9a;
    --ibm-cyan-50: #1192e8;
    --ibm-magenta-50: #ee5396;
    
    /* Semantic Aliases */
    --primary: var(--ibm-blue-60);
    --primary-hover: var(--ibm-blue-70);
    --primary-light: var(--ibm-blue-50);
    --success: var(--ibm-green-60);
    --warning: var(--ibm-yellow-30);
    --danger: var(--ibm-red-60);
    --info: var(--ibm-cyan-50);
    
    /* Background */
    --bg: #ffffff;
    --bg-secondary: var(--ibm-gray-10);
    --bg-tertiary: var(--ibm-gray-20);
    --bg-inverse: var(--ibm-gray-100);
    
    /* Text */
    --text-primary: var(--ibm-gray-100);
    --text-secondary: var(--ibm-gray-70);
    --text-muted: var(--ibm-gray-50);
    --text-on-color: #ffffff;
    
    /* Border */
    --border-subtle: var(--ibm-gray-20);
    --border-strong: var(--ibm-gray-50);
    
    /* Spacing (IBM 2x Grid) */
    --spacing-01: 0.125rem;
    --spacing-02: 0.25rem;
    --spacing-03: 0.5rem;
    --spacing-04: 0.75rem;
    --spacing-05: 1rem;
    --spacing-06: 1.5rem;
    --spacing-07: 2rem;
    --spacing-08: 2.5rem;
    --spacing-09: 3rem;
}

* { box-sizing: border-box; margin: 0; padding: 0; }

body {
    font-family: 'IBM Plex Sans', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
    background: var(--bg);
    color: var(--text-primary);
    line-height: 1.5;
    font-size: 14px;
    -webkit-font-smoothing: antialiased;
}

/* Typography - IBM Plex */
h1, h2, h3, h4, h5, h6 { 
    font-family: 'IBM Plex Sans', sans-serif;
    font-weight: 600; 
    line-height: 1.25; 
    color: var(--text-primary);
    letter-spacing: 0;
}
h1 { font-size: 2rem; font-weight: 300; }
h2 { font-size: 1.25rem; font-weight: 600; margin: var(--spacing-07) 0 var(--spacing-05); }
h3 { font-size: 1rem; font-weight: 600; }

code, pre, .mono {
    font-family: 'IBM Plex Mono', 'Consolas', monospace;
}

/* Layout */
.report-container { max-width: 1584px; margin: 0 auto; }

/* Header - IBM Style */
.report-header {
    background: var(--ibm-gray-100);
    color: var(--text-on-color);
    padding: var(--spacing-07) var(--spacing-09);
    position: relative;
}
.report-header::after {
    content: '';
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
    height: 3px;
    background: var(--primary);
}
.header-content { display: flex; justify-content: space-between; align-items: flex-start; }
.header-title h1 { color: var(--text-on-color); font-weight: 400; letter-spacing: 0; }
.header-subtitle { color: var(--ibm-gray-30); font-size: 0.875rem; margin-top: var(--spacing-03); }
.header-meta { text-align: right; font-size: 0.75rem; }
.status-indicator {
    display: inline-flex;
    align-items: center;
    padding: var(--spacing-02) var(--spacing-04);
    font-weight: 400;
    font-size: 0.75rem;
    text-transform: uppercase;
    letter-spacing: 0.32px;
}
.status-indicator.success { background: var(--success); color: white; }
.status-indicator.error { background: var(--danger); color: white; }
.header-details { color: var(--ibm-gray-40); margin-top: var(--spacing-04); line-height: 1.6; }

/* Body */
.report-body { padding: var(--spacing-07) var(--spacing-09); }

/* Section Headers - IBM Style */
.section-header {
    display: flex;
    align-items: center;
    gap: var(--spacing-04);
    margin: var(--spacing-08) 0 var(--spacing-05);
    padding-bottom: var(--spacing-04);
    border-bottom: 1px solid var(--border-subtle);
}
.section-header h2 { 
    margin: 0; 
    font-size: 0.875rem; 
    font-weight: 600;
    text-transform: uppercase; 
    letter-spacing: 0.32px;
    color: var(--text-primary);
}
.section-number {
    background: var(--primary);
    color: white;
    min-width: 24px;
    height: 24px;
    border-radius: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 0.75rem;
    font-weight: 600;
}

/* Summary Cards - IBM Tile Style */
.summary-grid { 
    display: grid; 
    grid-template-columns: repeat(5, 1fr); 
    gap: 1px;
    background: var(--border-subtle);
    margin-bottom: var(--spacing-07);
}
.summary-card {
    background: var(--bg);
    padding: var(--spacing-05);
    text-align: left;
}
.summary-card.highlight { 
    background: var(--primary); 
    color: white;
}
.summary-value { 
    font-size: 2rem; 
    font-weight: 300; 
    color: var(--text-primary); 
    line-height: 1.2;
    font-family: 'IBM Plex Sans', sans-serif;
}
.summary-card.highlight .summary-value { color: white; }
.summary-label {
    font-size: 0.75rem;
    color: var(--text-secondary);
    text-transform: uppercase;
    letter-spacing: 0.32px;
    margin-top: var(--spacing-03);
}
.summary-card.highlight .summary-label { color: rgba(255,255,255,0.85); }

/* Data Tables - IBM Carbon Style */
.data-table { width: 100%; border-collapse: collapse; font-size: 0.875rem; margin: var(--spacing-05) 0; }
.data-table th {
    background: var(--ibm-gray-10);
    padding: var(--spacing-04) var(--spacing-05);
    text-align: left;
    font-weight: 600;
    border-bottom: 1px solid var(--border-strong);
    font-size: 0.75rem;
    text-transform: uppercase;
    letter-spacing: 0.32px;
    color: var(--text-primary);
}
.data-table td { 
    padding: var(--spacing-04) var(--spacing-05); 
    border-bottom: 1px solid var(--border-subtle);
    vertical-align: top;
}
.data-table tbody tr:hover td { background: var(--ibm-blue-10); }
.data-table .numeric { font-family: 'IBM Plex Mono', monospace; text-align: right; }

/* Info Panels - IBM Tile */
.info-panel {
    background: var(--bg);
    border: 1px solid var(--border-subtle);
    padding: var(--spacing-05);
    margin: var(--spacing-05) 0;
}
.info-panel-header { 
    font-weight: 600; 
    color: var(--text-primary); 
    margin-bottom: var(--spacing-04);
    font-size: 0.875rem;
}
.info-grid { display: grid; grid-template-columns: repeat(2, 1fr); gap: var(--spacing-05); }
.info-item { display: flex; flex-direction: column; }
.info-label { 
    font-size: 0.75rem; 
    color: var(--text-secondary); 
    text-transform: uppercase; 
    letter-spacing: 0.32px; 
}
.info-value { 
    font-size: 0.875rem; 
    font-weight: 500; 
    margin-top: var(--spacing-02);
    color: var(--text-primary);
}

/* Timeline - IBM Progress Indicator Style */
.timeline { 
    display: flex; 
    justify-content: space-between; 
    position: relative; 
    padding: var(--spacing-05) 0;
    margin: var(--spacing-05) 0;
}
.timeline::before {
    content: '';
    position: absolute;
    top: calc(var(--spacing-05) + 6px);
    left: 24px;
    right: 24px;
    height: 1px;
    background: var(--ibm-gray-30);
}
.timeline-step { 
    background: var(--bg); 
    position: relative; 
    z-index: 1; 
    text-align: center; 
    padding: 0 var(--spacing-04);
}
.timeline-dot { 
    width: 12px; 
    height: 12px; 
    border-radius: 50%; 
    background: var(--primary); 
    margin: 0 auto var(--spacing-03);
    border: 2px solid var(--bg);
    box-shadow: 0 0 0 2px var(--primary);
}
.timeline-label { 
    font-size: 0.75rem; 
    color: var(--text-secondary); 
    text-transform: uppercase;
    letter-spacing: 0.32px;
}
.timeline-value { font-size: 0.875rem; font-weight: 600; color: var(--text-primary); margin-top: var(--spacing-02); }

/* Charts & Visualizations */
.chart-container { 
    background: var(--bg); 
    border: 1px solid var(--border-subtle); 
    padding: var(--spacing-05); 
    margin: var(--spacing-05) 0;
}
.viz-gallery { 
    display: grid; 
    grid-template-columns: repeat(auto-fill, minmax(400px, 1fr)); 
    gap: var(--spacing-05); 
    margin: var(--spacing-05) 0;
}
.viz-item { 
    background: var(--bg); 
    border: 1px solid var(--border-subtle);
    overflow: hidden;
}
.viz-item-header { 
    padding: var(--spacing-04) var(--spacing-05); 
    background: var(--ibm-gray-10); 
    border-bottom: 1px solid var(--border-subtle); 
    font-size: 0.75rem; 
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.32px;
}
.viz-item img { width: 100%; display: block; cursor: pointer; transition: opacity 0.15s; }
.viz-item img:hover { opacity: 0.85; }

/* Score Display - IBM Gauge Style */
.score-display { 
    display: flex; 
    align-items: center; 
    gap: var(--spacing-06); 
    padding: var(--spacing-05); 
    background: var(--ibm-gray-10);
    margin: var(--spacing-05) 0;
}
.score-circle {
    width: 72px;
    height: 72px;
    border-radius: 0;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    color: white;
}
.score-circle.go { background: var(--success); }
.score-circle.warn { background: var(--warning); color: var(--ibm-gray-100); }
.score-circle.nogo { background: var(--danger); }
.score-value { font-size: 1.5rem; font-weight: 300; line-height: 1; font-family: 'IBM Plex Sans', sans-serif; }
.score-label { font-size: 0.625rem; text-transform: uppercase; margin-top: var(--spacing-02); letter-spacing: 0.32px; }
.score-details { flex: 1; }

/* Collapsible - IBM Accordion */
.collapsible-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    cursor: pointer;
    padding: var(--spacing-04) var(--spacing-05);
    background: var(--bg);
    border: 1px solid var(--border-subtle);
    margin: var(--spacing-05) 0 0;
}
.collapsible-header:hover { background: var(--ibm-gray-10); }
.collapsible-content { 
    display: none; 
    padding: var(--spacing-05); 
    border: 1px solid var(--border-subtle); 
    border-top: none;
}
.collapsible-content.active { display: block; }

/* Code/JSON Viewer - IBM Plex Mono */
.json-viewer {
    background: var(--ibm-gray-100);
    color: var(--ibm-gray-10);
    font-family: 'IBM Plex Mono', monospace;
    font-size: 0.75rem;
    padding: var(--spacing-05);
    overflow-x: auto;
    max-height: 500px;
    overflow-y: auto;
}

/* Footer */
.report-footer {
    margin-top: var(--spacing-09);
    padding: var(--spacing-05) var(--spacing-09);
    background: var(--ibm-gray-10);
    border-top: 1px solid var(--border-subtle);
    font-size: 0.75rem;
    color: var(--text-secondary);
    display: flex;
    justify-content: space-between;
}
.modal {
    display: none;
    position: fixed;
    z-index: 1000;
    left: 0;
    top: 0;
    width: 100%;
    height: 100%;
    background: rgba(0,0,0,0.9);
    justify-content: center;
    align-items: center;
}
.modal.active { display: flex; }
.modal img { max-width: 95%; max-height: 90vh; border-radius: 8px; }
.modal-close { position: absolute; top: 20px; right: 30px; color: white; font-size: 2rem; cursor: pointer; }
@media (max-width: 1200px) { .summary-grid { grid-template-columns: repeat(3, 1fr); } .viz-gallery { grid-template-columns: 1fr; } }
@media (max-width: 768px) { .summary-grid { grid-template-columns: repeat(2, 1fr); } .info-grid { grid-template-columns: 1fr; } .report-body { padding: 1rem; } }
@media print { .report-header { background: var(--primary) !important; -webkit-print-color-adjust: exact; } .collapsible-content { display: block !important; } }
'''
        
        # Générer les sections HTML
        transpilation_section = self._pro_transpilation_section(trans)
        circuits_section = self._pro_circuits_section(data.get('circuits_details', []))
        circuit_viz_section = self._pro_circuit_viz_section(data.get('circuit_images', []))
        calibration_section = self._pro_calibration_section(calib)
