# FRAMEWORK v2.5.1 EXTENSION
# =============================================================================

class QMCFramework(QMCFrameworkExtended):
    """
    QMCFramework — classe principale CONCRÈTE et complète (v2.7.1).

    [v2.7.1] Anciennement nommée QMCFramework (relique de versionnage). Le nom
    canonique est désormais `QMCFramework` ; il n'y a plus d'alias QMCFramework.

    Inclut les optimisations Qiskit 2.3+ / Runtime 0.45+ (héritées de v2.6.0).
    
    ═══════════════════════════════════════════════════════════════════════
    NOUVEAUTÉS v2.6.0 - OPTIMISATIONS QISKIT 2.3
    ═══════════════════════════════════════════════════════════════════════
    
    Support des dernières fonctionnalités IBM Quantum pour performances maximales:
    
    ⚡ FRACTIONAL GATES (use_fractional_gates=True):
       - Portes RX/RZZ natives sans décomposition
       - Réduction de -600% de profondeur pour circuits Ising/Trotter
       - Idéal pour HAWKING, VQE, simulations de dynamique
       - Incompatible avec Gen3 turbo et PEC/PEA
    
    ⚡ GEN3 TURBO MODE (gen3_turbo=True):
       - Nouveau moteur d'exécution IBM avec 75x speedup
       - Incompatible avec fractional gates et dynamic circuits
       - Activé automatiquement si fractional_gates=False
    
    ⚡ PEA MITIGATION (resilience_level=2):
       - Probabilistic Error Amplification (nouveau runtime 0.45)
       - Complète ZNE pour meilleure mitigation
    
    ⚡ DD SEQUENCE OPTIMISÉE:
       - Séquence XY4 par défaut (meilleur pour longues cohérences)
       - Alternatives: XX, XpXm
    
    Usage v2.6.0:
        # Pour circuits Ising/Trotter (HAWKING):
        fw = QMCFramework(
            project='HAWKING_V6',
            backend_name='ibm_fez',
            use_fractional_gates=True  # ← -600% depth!
        )
        
        # Pour circuits statiques sans rotations:
        fw = QMCFramework(
            project='QMC_TEST',
            backend_name='ibm_fez',
            gen3_turbo=True  # ← 75x speedup!
        )
    
    ═══════════════════════════════════════════════════════════════════════
    FONCTIONNALITÉS v2.5.x (héritées)
    ═══════════════════════════════════════════════════════════════════════
    
    v2.5.3 - Circuit Optimizer:
    - Placement automatique sur meilleurs qubits via calibration
    
    v2.5.2 - Pathfinding:
    - Algorithme DFS + backtracking pour chemins optimaux
    
    v2.5.1 - (module déplacé en externe):
    - Fingerprint 8D unique du QPU
    
    v2.5.0 - Composants avancés:
    - BackendRecommender, ResultCache, JobQueueManager
    """
    
    VERSION = "2.7.2"
    
    def __init__(self, *args, enable_cache: bool = True, 
                 cache_dir: str = '.qmc_cache', **kwargs):
        super().__init__(*args, **kwargs)
        
        # Composants existants
        self.multi_platform = MultiPlatformOrchestrator(self.logger)
        self.ml_optimizer = QuantumMLOptimizer(self.logger)
        self.enhanced_exporter = EnhancedReportExporter(logger=self.logger)
        
        # Analyzers existants
        self.xeb_advanced = XEBCrossValidationAnalyzer(self.logger)
        self.honeypot_analyzer = HoneypotAnalyzer(self.logger)
        self.quantum_advantage = QuantumAdvantageAnalyzer(self.logger)
        
        # === COMPOSANTS v2.5 ===
        self.recommender = BackendRecommender(logger=self.logger)
        self.cache = ResultCache(cache_dir=cache_dir, logger=self.logger) if enable_cache else None
        self.job_queue = JobQueueManager(framework=self, logger=self.logger)
        self.notifications = NotificationManager(logger=self.logger)
        self.cost_estimator = CircuitCostEstimator(framework=self, logger=self.logger)
        
        
        # === CIRCUIT OPTIMIZER v2.5.3 ===
        self.circuit_optimizer = None  # Chargé automatiquement après connect()
        self._auto_optimize = True  # Optimisation activée par défaut
        
        # === COMPOSANTS v2.5.16 - PRODUCTIVITÉ ===
        self._batch_manager = None  # Lazy init
        self._budget_manager = None  # Lazy init
        self._circuit_profiler = None  # Lazy init
        self._result_comparator = None  # Lazy init
        self._html_dashboard = None  # Lazy init
        
        self._enable_cache = enable_cache

        # === ADDONS IBM (M3, EPLG, CLOPS, Trotter) ===
        # [v2.7.1] Initialisés ICI, dans le vrai __init__ (auparavant injectés par
        # monkey-patch en fin de fichier, source de fragilité/RecursionError au reload).
        self._m3_wrapper = None
        self._eplg_calculator = None
        self._clops_calculator = None
        self._trotter_optimizer = None

    # =========================================================================
    # [v2.7.1] ADDONS IBM — propriétés & méthodes (anciennement monkey-patchées)
    # =========================================================================

    @property
    def m3(self) -> 'M3MitigationWrapper':
        """[v2.6.0] Accès au wrapper M3 (lazy)."""
        if self._m3_wrapper is None:
            self._m3_wrapper = M3MitigationWrapper(backend=getattr(self, 'backend', None),
                                                   logger=self.logger)
        return self._m3_wrapper

    @property
    def eplg_calculator(self) -> 'EPLGCalculator':
        """[v2.6.0] Accès au calculateur EPLG (lazy)."""
        if self._eplg_calculator is None:
            self._eplg_calculator = EPLGCalculator(framework=self, logger=self.logger)
        return self._eplg_calculator

    @property
    def clops_calculator(self) -> 'CLOPSCalculator':
        """[v2.6.0] Accès au calculateur CLOPS (lazy)."""
