# 11. PUBLICATION EXPORTER - Export LaTeX/PDF pour Publications
# =============================================================================

class PublicationExporter:
    """
    Exporte les résultats dans des formats adaptés aux publications scientifiques.
    
    Formats supportés:
    - LaTeX (figures, tableaux)
    - PDF (via LaTeX)
    - Markdown
    - INPI (format brevet français)
    
    Usage:
        exporter = PublicationExporter()
        exporter.export_latex(results, "results.tex", language='en')
        exporter.export_inpi(results, "brevet.docx")
    """
    
    def __init__(self, output_dir: str = "."):
        self.output_dir = output_dir
    
    def export_latex(self,
                     results: Dict,
                     output_path: str,
                     language: str = 'en',
                     include_figures: bool = True) -> str:
        """
        Exporte les résultats en LaTeX.
        
        Args:
            results: Résultats à exporter
            output_path: Fichier de sortie (.tex)
            language: 'en' ou 'fr'
            include_figures: Inclure les commandes figure
        """
        from datetime import datetime
        
        # Labels selon la langue
        labels = {
            'en': {
                'title': 'Quantum Experiment Results',
                'backend': 'Backend',
                'qubits': 'Qubits',
                'depth': 'Circuit Depth',
                'shots': 'Shots',
                'fidelity': 'Fidelity',
                'entropy': 'Entropy',
                'table_caption': 'Summary of experimental results',
                'figure_caption': 'Probability distribution of measured states'
            },
            'fr': {
                'title': 'Résultats d\'Expérience Quantique',
                'backend': 'Backend',
                'qubits': 'Qubits',
                'depth': 'Profondeur',
                'shots': 'Tirs',
                'fidelity': 'Fidélité',
                'entropy': 'Entropie',
                'table_caption': 'Résumé des résultats expérimentaux',
                'figure_caption': 'Distribution de probabilité des états mesurés'
            }
        }
        
        L = labels.get(language, labels['en'])
        
        latex = f'''% Generated by QMC Framework - {datetime.now().strftime("%Y-%m-%d")}
\\documentclass{{article}}
\\usepackage{{booktabs}}
\\usepackage{{graphicx}}
\\usepackage[utf8]{{inputenc}}

\\title{{{L['title']}}}
\\author{{QMC Research Lab}}
\\date{{\\today}}

\\begin{{document}}

\\maketitle

\\section{{Experimental Setup}}

\\begin{{table}}[h]
\\centering
\\caption{{{L['table_caption']}}}
\\begin{{tabular}}{{lc}}
\\toprule
\\textbf{{Parameter}} & \\textbf{{Value}} \\\\
\\midrule
{L['backend']} & {results.get('backend', {}).get('name', 'N/A')} \\\\
{L['qubits']} & {results.get('results', [{}])[0].get('n_qubits', 'N/A')} \\\\
{L['shots']} & {results.get('results', [{}])[0].get('shots', 'N/A')} \\\\
\\bottomrule
\\end{{tabular}}
\\end{{table}}

\\section{{Results}}

'''
        
        # Tableau des résultats
        if results.get('results'):
            latex += '''\\begin{table}[h]
\\centering
\\begin{tabular}{cccc}
\\toprule
\\textbf{Circuit} & \\textbf{Unique States} & \\textbf{Max Prob} & \\textbf{Entropy} \\\\
\\midrule
'''
            for r in results.get('results', []):
                counts = r.get('counts', {})
                if counts:
                    total = sum(counts.values())
                    max_prob = max(counts.values()) / total if total > 0 else 0
                    entropy = self._compute_entropy(counts)
                    latex += f"{r.get('circuit_index', 0)} & {len(counts)} & {max_prob:.4f} & {entropy:.2f} \\\\\n"
            
            latex += '''\\bottomrule
\\end{tabular}
\\end{table}

'''
        
        latex += '''\\end{document}
'''
        
        with open(output_path, 'w', encoding='utf-8') as f:
            f.write(latex)
        
        return latex
    
    def export_markdown(self, results: Dict, output_path: str) -> str:
        """Exporte les résultats en Markdown."""
        from datetime import datetime
        
        md = f'''# Quantum Experiment Results

**Generated:** {datetime.now().strftime("%Y-%m-%d %H:%M:%S")}

## Experimental Setup

| Parameter | Value |
|-----------|-------|
| Backend | {results.get('backend', {}).get('name', 'N/A')} |
| Qubits | {results.get('results', [{}])[0].get('n_qubits', 'N/A')} |
| Shots | {results.get('results', [{}])[0].get('shots', 'N/A')} |

## Results Summary

| Circuit | Unique States | Entropy |
|---------|---------------|---------|
'''
        
        for r in results.get('results', []):
            counts = r.get('counts', {})
            entropy = self._compute_entropy(counts) if counts else 0
            md += f"| {r.get('circuit_index', 0)} | {len(counts)} | {entropy:.2f} |\n"
        
        with open(output_path, 'w', encoding='utf-8') as f:
            f.write(md)
        
        return md
    
    def export_inpi_figures_prompts(self, 
                                     results: Dict,
                                     output_path: str,
                                     n_figures: int = 5) -> str:
        """
        Génère un fichier JSON de prompts pour figures INPI (N&B).
        
        Conforme aux règles INPI: noir et blanc uniquement.
        """
        import json
        
        prompts = []
        
        # Figure 1: Architecture système
        prompts.append({
            "id": "fig_1",
            "figure": "Figure 1 - Architecture du système",
            "prompt": f"Create a technical system architecture diagram in BLACK AND WHITE ONLY for patent documentation. Style: Clean technical schematic with precise lines, white background, no colors, no gradients. Show a flow from 'Entrée' through 'Circuit Quantique' ({results.get('results', [{}])[0].get('n_qubits', 'N')} qubits) to 'Mesure' and 'Résultat'. Use boxes with sharp corners, arrows for data flow. Labels in FRENCH. Format: Landscape, 300 DPI, patent-ready."
        })
        
        # Figure 2: Distribution des états
        prompts.append({
            "id": "fig_2",
            "figure": "Figure 2 - Distribution des états mesurés",
            "prompt": "Create a BAR CHART in BLACK AND WHITE ONLY showing probability distribution. X-axis: quantum states (bitstrings like '00', '01', '10', '11'). Y-axis: probability (0 to 1). Use solid black bars with white background. Include axis labels in FRENCH: 'État quantique', 'Probabilité'. No colors, gradients, or 3D effects. Patent-ready quality."
        })
        
        # Figure 3: Circuit quantique
        prompts.append({
            "id": "fig_3",
            "figure": "Figure 3 - Schéma du circuit quantique",
            "prompt": f"Create a quantum circuit diagram in BLACK AND WHITE for {results.get('results', [{}])[0].get('n_qubits', 5)} qubits. Show horizontal qubit lines, gate boxes (H, X, CNOT), and measurement symbols at the end. Use standard quantum computing notation. Clean technical drawing style, no colors. Labels: 'q0', 'q1', etc. for qubits. Format: Landscape, 300 DPI."
        })
        
        # Figure 4: Métriques de performance
        prompts.append({
            "id": "fig_4",
            "figure": "Figure 4 - Métriques de fidélité",
            "prompt": "Create a LINE GRAPH in BLACK AND WHITE showing fidelity metrics. X-axis: 'Nombre de couches' (1 to 10). Y-axis: 'Fidélité' (0 to 1). Use solid black line with data point markers (circles). Include dotted reference line at fidelity=0.9. Grid lines in light gray. Labels in FRENCH. Patent-ready quality."
        })
        
        # Figure 5: Comparaison
        prompts.append({
            "id": "fig_5",
            "figure": "Figure 5 - Tableau comparatif",
            "prompt": "Create a technical COMPARISON TABLE in BLACK AND WHITE. Headers: 'Paramètre', 'Valeur Mesurée', 'Valeur Théorique'. Rows for: Qubits, Profondeur, Fidélité, Entropie. Use clean lines, professional typography. All text in FRENCH. No shading or colors. Patent documentation style."
        })
        
        # Sauvegarder
        with open(output_path, 'w', encoding='utf-8') as f:
            json.dump(prompts[:n_figures], f, indent=2, ensure_ascii=False)
        
        return json.dumps(prompts[:n_figures], indent=2, ensure_ascii=False)
    
    def _compute_entropy(self, counts: Dict) -> float:
        """Calcule l'entropie de Shannon."""
        import numpy as np
        
        total = sum(counts.values())
        if total == 0:
            return 0.0
        
        probs = [c / total for c in counts.values()]
        return float(-sum(p * np.log2(p) for p in probs if p > 0))


# =============================================================================
# 12. INTER-QUBIT CORRELATION ANALYZER - Analyse de Corrélations Inter-Qubits
# =============================================================================

class InterQubitCorrelationAnalyzer:
    """
    Analyse les corrélations quantiques entre qubits.
    
    Permet de:
    - Détecter les qubits fortement corrélés
    - Identifier les problèmes de crosstalk
    - Optimiser le mapping des circuits
    
    Usage:
        analyzer = InterQubitCorrelationAnalyzer()
        correlations = analyzer.analyze(results)
        matrix = analyzer.get_correlation_matrix(results)
    """
    
    def analyze(self, results: List[Dict]) -> Dict[str, Any]:
        """
        Analyse complète des corrélations.
        
        Args:
            results: Résultats du framework
            
        Returns:
            Dict avec matrice de corrélation et statistiques
        """
        import numpy as np
        
        # Agréger tous les counts
        all_counts = {}
        n_qubits = None
        
        for r in results:
            counts = r.get('counts', {})
            for state, count in counts.items():
                if n_qubits is None:
                    n_qubits = len(state)
                all_counts[state] = all_counts.get(state, 0) + count
        
        if not all_counts or n_qubits is None:
            return {'error': 'No counts available'}
        
        # Calculer la matrice de corrélation
        correlation_matrix = self._compute_correlation_matrix(all_counts, n_qubits)
        
        # Identifier les paires fortement corrélées
        strong_correlations = []
        for i in range(n_qubits):
            for j in range(i + 1, n_qubits):
                corr = correlation_matrix[i, j]
                if abs(corr) > 0.5:
                    strong_correlations.append({
                        'qubits': (i, j),
                        'correlation': float(corr),
                        'type': 'positive' if corr > 0 else 'negative'
                    })
        
        # Identifier les qubits problématiques (corrélation avec tous)
        avg_correlations = np.mean(np.abs(correlation_matrix), axis=1)
        problematic_qubits = [
            int(q) for q in range(n_qubits) 
            if avg_correlations[q] > 0.3
        ]
        
        return {
            'n_qubits': n_qubits,
            'correlation_matrix': correlation_matrix.tolist(),
            'strong_correlations': sorted(
                strong_correlations, 
                key=lambda x: abs(x['correlation']), 
                reverse=True
            ),
            'problematic_qubits': problematic_qubits,
            'avg_correlation': float(np.mean(np.abs(correlation_matrix))),
            'max_correlation': float(np.max(np.abs(correlation_matrix - np.eye(n_qubits))))
        }
    
    def _compute_correlation_matrix(self, counts: Dict[str, int], n_qubits: int):
        """Calcule la matrice de corrélation entre qubits."""
        import numpy as np
        
        total = sum(counts.values())
        
        # Calculer les probabilités marginales et jointes
        p_single = np.zeros(n_qubits)  # P(q_i = 1)
        p_joint = np.zeros((n_qubits, n_qubits))  # P(q_i = 1, q_j = 1)
        
        for state, count in counts.items():
            prob = count / total
            bits = [int(b) for b in reversed(state)]
            
            for i, b in enumerate(bits):
                if b == 1:
                    p_single[i] += prob
                    for j, b2 in enumerate(bits):
                        if b2 == 1:
                            p_joint[i, j] += prob
        
        # Calculer la corrélation: Corr(i,j) = (P(i,j) - P(i)P(j)) / sqrt(Var(i)Var(j))
        correlation = np.zeros((n_qubits, n_qubits))
        
        for i in range(n_qubits):
            for j in range(n_qubits):
                if i == j:
                    correlation[i, j] = 1.0
                else:
                    cov = p_joint[i, j] - p_single[i] * p_single[j]
                    var_i = p_single[i] * (1 - p_single[i])
                    var_j = p_single[j] * (1 - p_single[j])
                    
                    if var_i > 0 and var_j > 0:
                        correlation[i, j] = cov / np.sqrt(var_i * var_j)
        
        return correlation
    
    def visualize_matrix(self, correlation_matrix: List[List[float]], output_path: str = None) -> str:
        """Génère une visualisation ASCII de la matrice."""
        import numpy as np
        
        matrix = np.array(correlation_matrix)
        n = len(matrix)
        
        # Caractères pour les niveaux de corrélation
        chars = [' ', '░', '▒', '▓', '█']
        
        output = "Correlation Matrix:\n"
        output += "    " + "".join(f"{i:3}" for i in range(n)) + "\n"
        output += "   +" + "-" * (3 * n) + "+\n"
        
        for i in range(n):
            output += f"{i:2} |"
            for j in range(n):
                val = abs(matrix[i, j])
                idx = min(int(val * 4), 4)
                output += f" {chars[idx]} "
            output += "|\n"
        
        output += "   +" + "-" * (3 * n) + "+\n"
        output += "Legend: ' '=0  '░'=0.25  '▒'=0.5  '▓'=0.75  '█'=1.0\n"
        
        if output_path:
            with open(output_path, 'w', encoding='utf-8') as f:
                f.write(output)
        
        return output


# =============================================================================
# 13. TRANSPILATION CACHE - Cache Intelligent de Transpilation
# =============================================================================

class TranspilationCache:
    """
    Cache intelligent pour les circuits transpilés.
    
    Évite de re-transpiler des circuits identiques pour le même backend,
    économisant du temps CPU significatif.
    
    Usage:
        cache = TranspilationCache(max_age_hours=24)
        
        # La transpilation utilise le cache automatiquement
        transpiled = cache.get_or_transpile(circuit, backend)
    """
    
    def __init__(self, max_age_hours: float = 24, max_entries: int = 1000):
        """
        Args:
            max_age_hours: Durée de vie max des entrées en heures
            max_entries: Nombre max d'entrées dans le cache
        """
        self.max_age_seconds = max_age_hours * 3600
        self.max_entries = max_entries
        self._cache = {}  # key -> (transpiled_circuit, timestamp, backend_info)
        self._hits = 0
        self._misses = 0
    
    def _circuit_hash(self, circuit, optimization_level: int = 3) -> str:
        """Génère un hash unique pour un circuit."""
        import hashlib

        # [v2.7.1 FIX] Use a canonical representation that INCLUDES gate parameters.
        # The previous fallback only used qubits/depth/size/op-counts, so circuits
        # differing only in gate parameters (e.g. rotation angles) collided and the
        # cache returned the wrong transpiled circuit. Prefer QASM3 (params included);
        # otherwise build a representation that incorporates each instruction's params.
        qasm = None
        try:
            from qiskit import qasm3
            qasm = qasm3.dumps(circuit)
        except Exception:
            # [v2.7.1 FIX R128] handler ÉLARGI : qasm3.dumps lève QASM3ExporterError
            # (ni ImportError ni AttributeError) sur des portes custom/opaques. L'ancien
            # except étroit laissait l'exception casser get()/put()/get_or_transpile().
            # On retombe proprement sur le fallback structurel+paramètres ci-dessous.
            qasm = None

        if qasm is None:
            try:
                # Fallback: structural signature INCLUDING gate parameters.
                instr_sig = []
                for instruction in circuit.data:
                    op = getattr(instruction, 'operation', instruction[0])
                    qargs = getattr(instruction, 'qubits', instruction[1])
                    try:
                        qubit_idx = tuple(circuit.find_bit(q).index for q in qargs)
                    except (AttributeError, TypeError):
                        qubit_idx = tuple(str(q) for q in qargs)
                    params = tuple(str(p) for p in getattr(op, 'params', ()))
                    instr_sig.append((getattr(op, 'name', str(op)), qubit_idx, params))
                qasm = (f"{circuit.num_qubits}_{circuit.depth()}_{circuit.size()}_"
                        f"{dict(circuit.count_ops())}_{instr_sig}")
            except (AttributeError, TypeError):
                qasm = (f"{circuit.num_qubits}_{circuit.depth()}_"
                        f"{circuit.size()}_{dict(circuit.count_ops())}")

        key_str = f"{qasm}_{optimization_level}"
        return hashlib.sha256(key_str.encode()).hexdigest()[:16]
    
    def _backend_hash(self, backend) -> str:
        """Génère un hash pour l'état du backend."""
        import hashlib
        
        # Inclure le nom et la date de calibration
        try:
            name = backend.name
            # Essayer d'obtenir la date de dernière calibration
            props = backend.properties() if hasattr(backend, 'properties') else None
            calib_date = props.last_update_date.isoformat() if props else "unknown"
        except:
            name = str(backend)
            calib_date = "unknown"
        
        key_str = f"{name}_{calib_date}"
        return hashlib.sha256(key_str.encode()).hexdigest()[:8]
    
    def get(self, circuit, backend, optimization_level: int = 3):
        """
        Récupère un circuit transpilé depuis le cache.
        
        Returns:
            Circuit transpilé ou None si non trouvé/expiré
        """
        import time
        
        circuit_hash = self._circuit_hash(circuit, optimization_level)
        backend_hash = self._backend_hash(backend)
        key = f"{circuit_hash}_{backend_hash}"
        
        if key in self._cache:
            transpiled, timestamp, _ = self._cache[key]
            
            # Vérifier l'expiration
            if time.time() - timestamp < self.max_age_seconds:
                self._hits += 1
                return transpiled
            else:
                # Expiré, supprimer
                del self._cache[key]
        
        self._misses += 1
        return None
    
    def put(self, circuit, backend, transpiled, optimization_level: int = 3):
        """Ajoute un circuit transpilé au cache."""
        import time
        
        circuit_hash = self._circuit_hash(circuit, optimization_level)
        backend_hash = self._backend_hash(backend)
        key = f"{circuit_hash}_{backend_hash}"
        
        # Nettoyer si cache plein
        if len(self._cache) >= self.max_entries:
            self._evict_oldest()
        
        self._cache[key] = (
            transpiled,
            time.time(),
            {'backend': backend_hash, 'opt_level': optimization_level}
        )
    
    def get_or_transpile(self, circuit, backend, optimization_level: int = 3):
        """
        Récupère depuis le cache ou transpile.
        
        Args:
            circuit: Circuit à transpiler
            backend: Backend cible
            optimization_level: Niveau d'optimisation
            
        Returns:
            Circuit transpilé
        """
        # Essayer le cache
        cached = self.get(circuit, backend, optimization_level)
        if cached is not None:
            return cached
        
        # Transpiler
        from qiskit import transpile
        transpiled = transpile(circuit, backend, optimization_level=optimization_level)
        
        # Mettre en cache
        self.put(circuit, backend, transpiled, optimization_level)
        
        return transpiled
    
    def _evict_oldest(self):
        """Supprime les entrées les plus anciennes."""
        if not self._cache:
            return
        
        # Trier par timestamp et supprimer les 10% plus anciens
        sorted_keys = sorted(
            self._cache.keys(),
            key=lambda k: self._cache[k][1]
        )
        
        n_to_remove = max(1, len(sorted_keys) // 10)
        for key in sorted_keys[:n_to_remove]:
            del self._cache[key]
    
    def clear(self):
        """Vide le cache."""
        self._cache.clear()
        self._hits = 0
        self._misses = 0
    
    def stats(self) -> Dict[str, Any]:
        """Retourne les statistiques du cache."""
        total = self._hits + self._misses
        hit_rate = self._hits / total if total > 0 else 0
        
        return {
            'entries': len(self._cache),
            'max_entries': self.max_entries,
            'hits': self._hits,
            'misses': self._misses,
            'hit_rate': hit_rate,
            'hit_rate_percent': f"{hit_rate*100:.1f}%"
        }
